def _flash(
    request: Request,
    message: str,
    level: str = "info",
    *,
    link_url: str | None = None,
    link_label: str | None = None,
) -> None:
    fl = request.session.get("flash", [])
    fl.append(
        {
            "level": level,
            "message": message,
            "link_url": str(link_url or "").strip() or None,
            "link_label": str(link_label or "").strip() or None,
        }
    )
    request.session["flash"] = fl


def _pop_flash(request: Request) -> list[dict]:
    fl = request.session.pop("flash", [])
    return fl


def _to_int(value, default: int = 0) -> int:
    try:
        return int(value or 0)
    except Exception:
        return default


def _request_relative_path(request: Request) -> str:
    path = str(request.url.path or "/").strip() or "/"
    query = str(request.url.query or "").strip()
    return f"{path}?{query}" if query else path


def _safe_return_to_path(value: str, fallback: str = "") -> str:
    raw = str(value or "").strip()
    if not raw:
        return fallback
    if not raw.startswith("/") or raw.startswith("//"):
        return fallback
    if "\\" in raw:
        return fallback
    lower = raw.lower()
    if "http:" in lower or "https:" in lower or "javascript:" in lower or "data:" in lower:
        return fallback
    parsed = urlsplit(raw)
    if parsed.scheme or parsed.netloc:
        return fallback
    return raw


def _normalize_absolute_url(value: str | None) -> str | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    parsed = urlsplit(raw)
    scheme = str(parsed.scheme or "").lower()
    if scheme not in ("http", "https"):
        return None
    if not str(parsed.netloc or "").strip():
        return None
    if any(ch in raw for ch in ("\n", "\r", "\t", " ")):
        return None
    return raw


def _normalize_product_image_url(value: str | None) -> str | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    if any(ch in raw for ch in ("\n", "\r", "\t", " ")):
        return None
    absolute = _normalize_absolute_url(raw)
    if absolute:
        return absolute
    parsed = urlsplit(raw)
    if parsed.scheme or parsed.netloc:
        return None
    path = str(parsed.path or "")
    if not (path.startswith("/uploads/") or path.startswith("/catalog/products/")):
        return None
    if "\\" in raw:
        return None
    if any(seg == ".." for seg in path.split("/")):
        return None
    return raw


def _product_image_url_keys() -> list[str]:
    return [f"image_url_{idx}" for idx in range(1, PRODUCT_IMAGE_URL_MAX + 1)]


def _catalog_product_asset_rows(
    db: Session,
    product_id: int,
    *,
    asset_type: str = "",
) -> list[ProductAsset]:
    query = db.query(ProductAsset).filter(ProductAsset.product_id == int(product_id))
    asset_type_key = str(asset_type or "").strip().lower()
    if asset_type_key:
        query = query.filter(ProductAsset.asset_type == asset_type_key)
    return query.order_by(ProductAsset.slot_no.asc(), ProductAsset.id.asc()).all()


def _catalog_product_asset_url(product_id: int, asset: ProductAsset | None) -> str:
    if not asset or int(getattr(asset, "id", 0) or 0) <= 0:
        return ""
    return f"/catalog/products/{int(product_id)}/assets/{int(asset.id)}"


def _catalog_product_asset_source_url(product_id: int, asset: ProductAsset | None) -> str:
    if not asset or int(getattr(asset, "id", 0) or 0) <= 0:
        return ""
    return f"/catalog/products/{int(product_id)}/assets/{int(asset.id)}/source"


def _catalog_pdf_preview_zoom(raw_value, *, default: float = CATALOG_PDF_PREVIEW_DEFAULT_ZOOM) -> float:
    try:
        zoom = float(raw_value)
    except Exception:
        zoom = float(default)
    if zoom < CATALOG_PDF_PREVIEW_MIN_ZOOM:
        zoom = CATALOG_PDF_PREVIEW_MIN_ZOOM
    if zoom > CATALOG_PDF_PREVIEW_MAX_ZOOM:
        zoom = CATALOG_PDF_PREVIEW_MAX_ZOOM
    return round(float(zoom), 2)


def _catalog_render_pdf_page_png(pdf_path: Path, *, page_no: int, zoom: float) -> tuple[bytes, int, int]:
    if not pdf_path.is_file():
        raise FileNotFoundError("PDF-Datei fehlt.")
    document = fitz.open(str(pdf_path))
    try:
        page_count = max(1, int(document.page_count or 0))
        safe_page_no = min(max(1, int(page_no or 1)), page_count)
        page = document.load_page(safe_page_no - 1)
        pix = page.get_pixmap(matrix=fitz.Matrix(float(zoom), float(zoom)), alpha=False)
        return pix.tobytes("png"), safe_page_no, page_count
    finally:
        document.close()


def _catalog_pdf_page_count(pdf_path: Path | None) -> int:
    if pdf_path is None or not pdf_path.is_file():
        return 1
    document = fitz.open(str(pdf_path))
    try:
        return max(1, int(document.page_count or 0))
    except Exception:
        return 1
    finally:
        document.close()


def _catalog_product_asset_pdf_path(db: Session, *, product: Product, asset: ProductAsset) -> Path | None:
    abs_path = product_asset_abs_path(str(asset.local_path or "").strip())
    if (not abs_path or not abs_path.is_file()) and str(asset.source_url_raw or "").strip():
        try:
            asset = materialize_product_asset(db, product=product, asset=asset)
            db.commit()
        except Exception:
            db.rollback()
            asset.download_status = "failed"
            asset.updated_at = _utcnow_naive()
            db.add(asset)
            db.commit()
        abs_path = product_asset_abs_path(str(asset.local_path or "").strip())
    if abs_path and abs_path.is_file():
        return abs_path
    return None


def _catalog_parse_pdf_marker(raw_value) -> dict[str, object] | None:
    raw = str(raw_value or "").strip()
    if not raw:
        return None
    try:
        payload = json.loads(raw)
    except Exception:
        return None
    if not isinstance(payload, dict):
        return None
    try:
        page = max(1, int(payload.get("page") or 1))
        x = float(payload.get("x") or 0.0)
        y = float(payload.get("y") or 0.0)
        w = float(payload.get("w") or 0.0)
        h = float(payload.get("h") or 0.0)
    except Exception:
        return None
    if w <= 0.0 or h <= 0.0:
        return None
    x = min(max(x, 0.0), 100.0)
    y = min(max(y, 0.0), 100.0)
    w = min(max(w, 0.1), 100.0 - x)
    h = min(max(h, 0.1), 100.0 - y)
    return {
        "page": page,
        "x": round(x, 3),
        "y": round(y, 3),
        "w": round(w, 3),
        "h": round(h, 3),
    }


def _catalog_product_document_assets(db: Session, product: Product | None) -> list[dict[str, object]]:
    if not product:
        return []
    rows = _catalog_product_asset_rows(db, int(product.id))
    out: list[dict[str, object]] = []
    seen: set[str] = set()
    for row in rows:
        asset_type = str(row.asset_type or "").strip().lower()
        if asset_type not in {"datasheet_pdf", "manual_pdf", "energy_label", "other"}:
            continue
        key = f"{asset_type}:{int(row.slot_no or 0)}:{str(row.local_path or row.source_url_raw or '')}"
        if key in seen:
            continue
        seen.add(key)
        out.append(
            {
                "row": row,
                "asset_type": asset_type,
                "label": {
                    "datasheet_pdf": "Datenblatt",
                    "manual_pdf": "Bedienungsanleitung",
                    "energy_label": "Energielabel",
                    "other": "Dokument",
                }.get(asset_type, "Dokument"),
                "detail_url": _catalog_product_asset_url(int(product.id), row),
                "viewer_url": _catalog_product_asset_source_url(int(product.id), row),
                "source_url": str(row.source_url_raw or "").strip(),
                "has_local_file": bool(str(row.local_path or "").strip()),
                "download_status": str(row.download_status or ""),
                "mime_type": str(row.mime_type or ""),
                "extracted_text": str(row.extracted_text or ""),
                "is_pdf": str(row.mime_type or "").strip().lower() == "application/pdf" or asset_type.endswith("_pdf"),
            }
        )
    return out


def _catalog_product_datasheet_text(db: Session, product: Product | None) -> str:
    if not product or int(getattr(product, "id", 0) or 0) <= 0:
        return ""
    row = (
        db.query(ProductAsset)
        .filter(
            ProductAsset.product_id == int(product.id),
            ProductAsset.asset_type == "datasheet_pdf",
            ProductAsset.extracted_text.isnot(None),
        )
        .order_by(ProductAsset.updated_at.desc(), ProductAsset.id.desc())
        .first()
    )
    return str(getattr(row, "extracted_text", "") or "").strip()


def _catalog_latest_datasheet_asset(db: Session, product_id: int) -> ProductAsset | None:
    return (
        db.query(ProductAsset)
        .filter(
            ProductAsset.product_id == int(product_id),
            ProductAsset.asset_type == "datasheet_pdf",
        )
        .order_by(ProductAsset.updated_at.desc(), ProductAsset.id.desc())
        .first()
    )


def _catalog_enqueue_import_pdf_review(
    db: Session,
    *,
    import_run_id: int,
    product: Product,
    datasheet_asset: ProductAsset,
) -> tuple[ImportPdfReview, bool]:
    row = (
        db.query(ImportPdfReview)
        .filter(
            ImportPdfReview.import_run_id == int(import_run_id),
            ImportPdfReview.product_id == int(product.id),
            ImportPdfReview.product_asset_id == int(datasheet_asset.id),
        )
        .one_or_none()
    )
    created = row is None
    if row is None:
        row = ImportPdfReview(
            import_run_id=int(import_run_id),
            product_id=int(product.id),
            product_asset_id=int(datasheet_asset.id),
            status="pending",
            created_at=_utcnow_naive(),
        )
    if str(row.status or "").strip().lower() != "approved":
        row.status = "pending"
        row.review_json = row.review_json or _json_dump({})
    row.updated_at = _utcnow_naive()
    db.add(row)
    db.flush()
    return row, created


def _catalog_import_pdf_review_query(db: Session, *, import_run_id: int):
    return (
        db.query(ImportPdfReview)
        .filter(ImportPdfReview.import_run_id == int(import_run_id))
        .order_by(
            case((ImportPdfReview.status == "pending", 0), (ImportPdfReview.status == "skipped", 1), else_=2),
            ImportPdfReview.id.asc(),
        )
    )


def _catalog_next_import_pdf_review(
    db: Session,
    *,
    import_run_id: int,
    after_review_id: int = 0,
) -> ImportPdfReview | None:
    query = _catalog_import_pdf_review_query(db, import_run_id=int(import_run_id)).filter(ImportPdfReview.status == "pending")
    if int(after_review_id or 0) > 0:
        row = query.filter(ImportPdfReview.id > int(after_review_id)).first()
        if row is not None:
            return row
    return query.first()


def _catalog_learning_pdf_reviews(
    db: Session,
    *,
    import_run_id: int,
    limit: int = 2,
) -> list[ImportPdfReview]:
    return list(_catalog_import_pdf_review_query(db, import_run_id=int(import_run_id)).limit(max(1, int(limit or 2))).all())


def _catalog_next_learning_pdf_review(
    db: Session,
    *,
    import_run_id: int,
    after_review_id: int = 0,
    limit: int = 2,
) -> tuple[ImportPdfReview | None, int, int]:
    rows = _catalog_learning_pdf_reviews(db, import_run_id=int(import_run_id), limit=limit)
    if not rows:
        return None, 0, 0
    start_index = 0
    if int(after_review_id or 0) > 0:
        for idx, row in enumerate(rows):
            if int(row.id) == int(after_review_id):
                start_index = idx + 1
                break
    for idx in range(start_index, len(rows)):
        row = rows[idx]
        if str(row.status or "").strip().lower() == "pending":
            return row, idx + 1, len(rows)
    for idx, row in enumerate(rows):
        if str(row.status or "").strip().lower() == "pending":
            return row, idx + 1, len(rows)
    return None, len(rows), len(rows)


def _catalog_auto_apply_pending_import_pdf_reviews(
    db: Session,
    *,
    import_run: ImportRun,
    exclude_review_ids: set[int] | None = None,
) -> dict[str, int]:
    exclude_review_ids = {int(value) for value in set(exclude_review_ids or set()) if int(value or 0) > 0}
    query = (
        db.query(ImportPdfReview)
        .filter(
            ImportPdfReview.import_run_id == int(import_run.id),
            ImportPdfReview.status == "pending",
        )
        .order_by(ImportPdfReview.id.asc())
    )
    if exclude_review_ids:
        query = query.filter(~ImportPdfReview.id.in_(sorted(exclude_review_ids)))
    rows = query.all()
    applied_review_count = 0
    applied_value_count = 0
    updated_product_ids: set[int] = set()
    for review in rows:
        product = db.get(Product, int(review.product_id or 0))
        asset = db.get(ProductAsset, int(review.product_asset_id or 0))
        if product is None or asset is None:
            review.status = "skipped"
            review.reviewed_at = _utcnow_naive()
            review.updated_at = _utcnow_naive()
            review.review_json = _json_dump({"status": "auto_skipped", "reason": "Produkt oder Datenblatt fehlt."})
            db.add(review)
            continue
        attrs = _applicable_attributes(db, int(product.device_kind_id or 0), None)
        datasheet_text = str(getattr(asset, "extracted_text", "") or "").strip()
        suggestions, notes = _catalog_collect_pdf_attribute_suggestions(
            db,
            attrs,
            pdf_text=datasheet_text,
            manufacturer_id=int(product.manufacturer_id or 0) or None,
            device_kind_id=int(product.device_kind_id or 0) or None,
        )
        review_items: list[dict[str, object]] = []
        product_changed = False
        for attr in attrs:
            suggestion = dict(suggestions.get(int(attr.id)) or {})
            confirmed_value = str(suggestion.get("value") or "").strip()
            if not confirmed_value:
                continue
            existing_value = (
                db.query(ProductAttributeValue.value_text)
                .filter(
                    ProductAttributeValue.product_id == int(product.id),
                    ProductAttributeValue.attribute_id == int(attr.id),
                )
                .scalar()
            )
            if str(existing_value or "").strip() != confirmed_value:
                _catalog_upsert_product_attribute_value(
                    db,
                    product_id=int(product.id),
                    attribute_id=int(attr.id),
                    value_text=confirmed_value,
                )
                product_changed = True
                applied_value_count += 1
            review_items.append(
                {
                    "attribute_id": int(attr.id),
                    "attribute_name": str(attr.name or "").strip(),
                    "source_label": str(suggestion.get("source_label") or "").strip(),
                    "source_value": str(suggestion.get("source_value") or "").strip(),
                    "confirmed_value": confirmed_value,
                    "auto_applied": True,
                }
            )
        if product_changed:
            _refresh_product_search_blob(db, product, kind_name=str(getattr(db.get(DeviceKind, int(product.device_kind_id or 0)), "name", "") or ""))
            updated_product_ids.add(int(product.id))
        review.status = "approved"
        review.reviewed_at = _utcnow_naive()
        review.updated_at = _utcnow_naive()
        review.review_json = _json_dump(
            {
                "status": "auto_applied",
                "items": review_items,
                "notes": [str(note) for note in notes[:8]],
            }
        )
        db.add(review)
        applied_review_count += 1
    for product_id in sorted(updated_product_ids):
        product = db.get(Product, int(product_id))
        if product is not None:
            write_product_outbox_event(db, product, event_type="ProductUpdated")
    return {
        "reviews": applied_review_count,
        "values": applied_value_count,
    }


def _product_image_urls(product: Product | None, db: Session | None = None) -> list[str]:
    if not product:
        return []
    return [str(slot["url"]) for slot in _product_image_slots(product, db=db) if slot.get("url")]


def _product_image_slots(product: Product | None, db: Session | None = None) -> list[dict[str, object]]:
    if not product:
        return []
    asset_map: dict[int, ProductAsset] = {}
    if db is not None and int(getattr(product, "id", 0) or 0) > 0:
        for row in _catalog_product_asset_rows(db, int(product.id), asset_type="image"):
            slot_no = int(getattr(row, "slot_no", 0) or 0)
            if slot_no <= 0 or slot_no in asset_map:
                continue
            asset_map[slot_no] = row
    out: list[dict[str, object]] = []
    for idx in range(1, PRODUCT_IMAGE_ASSET_SLOT_MAX + 1):
        asset = asset_map.get(int(idx))
        asset_url = _catalog_product_asset_url(int(product.id), asset) if asset is not None else ""
        if not asset_url and asset is not None:
            asset_url = str(getattr(asset, "source_url_raw", "") or "").strip()
        normalized_asset = _normalize_product_image_url(asset_url) or asset_url
        out.append(
            {
                "index": int(idx),
                "key": f"image_url_{idx}",
                "raw_value": "",
                "has_value": asset is not None,
                "url": normalized_asset or "",
                "asset": asset,
                "source_label": "Asset" if asset is not None else "",
            }
        )
    return out


def _product_primary_image_url(product: Product | None, db: Session | None = None) -> str | None:
    if not product:
        return None
    for slot in _product_image_slots(product, db=db):
        fallback = str(slot.get("url") or "").strip()
        if fallback:
            return fallback
    return None


def _manufacturer_datasheet_var2_source(raw: str | None) -> str:
    value = str(raw or "").strip().lower()
    if value not in ("sales_name", "material_no"):
        return "sales_name"
    return value


