def _catalog_scope_compact_key(raw: str | None) -> str:
    return _catalog_scope_label_key(raw).replace(" ", "")


_CATALOG_DEVICE_KIND_SCOPE_ALIASES: dict[str, tuple[str, ...]] = {
    "kuehl gefrier kombination": (
        "kuehl gefrierkombination",
        "kuehl / gefrierkombination",
        "kuehl / gefrier kombination",
        "kuehl gefrier kombi",
        "kuehl gefrierkombi",
    ),
    "gefrierschrank": (
        "gefriergeraete",
        "gefrier geraete",
    ),
    "dampf backofen": (
        "dampfbackofen",
    ),
    "kochfeld dunstabzug": (
        "kochfeld mit integriertem abzug",
        "kochfeld integrierter abzug",
        "kochfeldabzug",
    ),
}


def _catalog_scope_row_keys(row: object, *, attr_name: str = "name") -> set[str]:
    raw_value = getattr(row, attr_name, None)
    label_key = _catalog_scope_label_key(raw_value)
    compact_key = _catalog_scope_compact_key(raw_value)
    keys = {key for key in (label_key, compact_key) if key}
    if isinstance(row, DeviceKind):
        for canonical_name, aliases in _CATALOG_DEVICE_KIND_SCOPE_ALIASES.items():
            canonical_key = _catalog_scope_label_key(canonical_name)
            if canonical_key != label_key:
                continue
            keys.add(_catalog_scope_compact_key(canonical_name))
            for alias in aliases:
                alias_label = _catalog_scope_label_key(alias)
                alias_compact = _catalog_scope_compact_key(alias)
                if alias_label:
                    keys.add(alias_label)
                if alias_compact:
                    keys.add(alias_compact)
            break
    return keys


def _catalog_scope_lookup_map(rows: list[object], *, attr_name: str = "name") -> dict[str, list[object]]:
    out: dict[str, list[object]] = {}
    for row in rows:
        for key in _catalog_scope_row_keys(row, attr_name=attr_name):
            out.setdefault(key, []).append(row)
    return out


def _catalog_resolve_named_row(raw_value: str | None, lookup_map: dict[str, list[object]]) -> object | None:
    label_key = _catalog_scope_label_key(raw_value)
    compact_key = _catalog_scope_compact_key(raw_value)
    search_keys = [key for key in (label_key, compact_key) if key]
    if not search_keys:
        return None
    exact_rows: dict[int, object] = {}
    for key in search_keys:
        for row in list(lookup_map.get(key) or []):
            row_id = int(getattr(row, "id", 0) or 0)
            if row_id > 0:
                exact_rows[row_id] = row
    if len(exact_rows) == 1:
        return next(iter(exact_rows.values()))
    if len(exact_rows) > 1:
        return None
    partial_hits: list[object] = []
    for candidate_key, rows in lookup_map.items():
        for key in search_keys:
            if key == candidate_key:
                partial_hits.extend(rows)
                break
            if len(key) >= 4 and (key in candidate_key or candidate_key in key):
                partial_hits.extend(rows)
                break
    unique_ids: dict[int, object] = {}
    for row in partial_hits:
        row_id = int(getattr(row, "id", 0) or 0)
        if row_id > 0 and row_id not in unique_ids:
            unique_ids[row_id] = row
    if len(unique_ids) == 1:
        return next(iter(unique_ids.values()))
    return None


_ASSET_RULE_PLACEHOLDER_RE = re.compile(r"\{\{\s*([a-z0-9_]+)\s*\}\}", flags=re.I)


def _catalog_asset_rule_values(
    product: Product | None,
    *,
    manufacturer: Manufacturer | None = None,
    device_kind: DeviceKind | None = None,
) -> dict[str, str]:
    if not product:
        return {}
    return {
        "ean": str(getattr(product, "ean", "") or "").strip(),
        "material_no": str(getattr(product, "material_no", "") or "").strip(),
        "sales_name": str(getattr(product, "sales_name", "") or "").strip(),
        "title_1": str(getattr(product, "product_title_1", "") or "").strip(),
        "title_2": str(getattr(product, "product_title_2", "") or "").strip(),
        "manufacturer": str(getattr(manufacturer, "name", "") or getattr(product, "manufacturer", "") or "").strip(),
        "manufacturer_slug": slugify(str(getattr(manufacturer, "name", "") or getattr(product, "manufacturer", "") or "").strip()),
        "device_kind": str(getattr(device_kind, "name", "") or "").strip(),
        "device_kind_slug": slugify(str(getattr(device_kind, "name", "") or "").strip()),
    }


def _catalog_render_asset_rule_url(
    template: str | None,
    *,
    source_field: str | None,
    values: dict[str, str],
) -> str:
    raw_template = str(template or "").strip()
    if not raw_template:
        return ""

    rendered = raw_template
    placeholders = list(dict.fromkeys(_ASSET_RULE_PLACEHOLDER_RE.findall(raw_template)))
    if placeholders:
        for placeholder in placeholders:
            replacement = str(values.get(str(placeholder).strip().lower()) or "").strip()
            if not replacement:
                return ""
            rendered = re.sub(
                r"\{\{\s*" + re.escape(str(placeholder)) + r"\s*\}\}",
                quote(replacement, safe=""),
                rendered,
                flags=re.I,
            )
    else:
        source_key = str(source_field or "").strip().lower()
        source_value = str(values.get(source_key) or "").strip()
        if source_key and not source_value:
            return ""
        if "{value}" in rendered:
            rendered = rendered.replace("{value}", quote(source_value, safe=""))
        elif "%s" in rendered:
            rendered = rendered.replace("%s", quote(source_value, safe=""), 1)
        elif source_key and raw_template.endswith(("/", "=")):
            rendered = raw_template + quote(source_value, safe="")
    return _normalize_absolute_url(rendered) or ""


def _catalog_build_asset_url_from_rules(
    db: Session,
    *,
    product: Product | None,
    asset_type: str,
    manufacturer: Manufacturer | None = None,
    device_kind: DeviceKind | None = None,
) -> str:
    if not product:
        return ""
    if manufacturer is None and int(getattr(product, "manufacturer_id", 0) or 0) > 0:
        manufacturer = db.get(Manufacturer, int(product.manufacturer_id))
    if device_kind is None and int(getattr(product, "device_kind_id", 0) or 0) > 0:
        device_kind = db.get(DeviceKind, int(product.device_kind_id))
    scope_ids = [None]
    if int(getattr(product, "manufacturer_id", 0) or 0) > 0:
        scope_ids.insert(0, int(product.manufacturer_id))
    values = _catalog_asset_rule_values(product, manufacturer=manufacturer, device_kind=device_kind)
    rules = (
        db.query(AssetLinkRule)
        .filter(
            AssetLinkRule.active == True,
            AssetLinkRule.asset_type == str(asset_type or "").strip().lower(),
            or_(
                AssetLinkRule.manufacturer_id.is_(None),
                AssetLinkRule.manufacturer_id == (int(product.manufacturer_id or 0) or None),
            ),
        )
        .order_by(
            case((AssetLinkRule.manufacturer_id.is_(None), 1), else_=0),
            AssetLinkRule.priority.asc(),
            AssetLinkRule.id.asc(),
        )
        .all()
    )
    for rule in rules:
        if getattr(rule, "manufacturer_id", None) not in scope_ids:
            continue
        candidate = _catalog_render_asset_rule_url(
            str(getattr(rule, "url_template", "") or ""),
            source_field=str(getattr(rule, "source_field", "") or ""),
            values=values,
        )
        if candidate:
            return candidate
    return ""


def _build_product_datasheet_url(db: Session, manufacturer: Manufacturer | None, product: Product | None) -> str:
    if not product:
        return ""
    rule_url = _catalog_build_asset_url_from_rules(
        db,
        product=product,
        asset_type="datasheet_pdf",
        manufacturer=manufacturer,
    )
    if rule_url:
        return rule_url
    if not manufacturer:
        return ""
    v1 = str(getattr(manufacturer, "datasheet_var_1", "") or "").strip()
    v3 = str(getattr(manufacturer, "datasheet_var_3", "") or "").strip()
    v4 = str(getattr(manufacturer, "datasheet_var_4", "") or "").strip()
    var2_source = _manufacturer_datasheet_var2_source(getattr(manufacturer, "datasheet_var2_source", "sales_name"))

    source_value = ""
    if var2_source == "material_no":
        source_value = str(getattr(product, "material_no", "") or "").strip()
        if not source_value:
            source_value = str(getattr(product, "sales_name", "") or "").strip()
    else:
        source_value = str(getattr(product, "sales_name", "") or "").strip()
        if not source_value:
            source_value = str(getattr(product, "material_no", "") or "").strip()

    v2 = quote(source_value, safe="") if source_value else ""

    candidate = f"{v1}{v2}{v3}{v4}".strip()
    normalized = _normalize_absolute_url(candidate)
    return normalized or ""


def _catalog_has_product_asset(db: Session, *, product_id: int, asset_type: str) -> bool:
    return (
        db.query(ProductAsset.id)
        .filter(
            ProductAsset.product_id == int(product_id),
            ProductAsset.asset_type == str(asset_type or "").strip().lower(),
        )
        .first()
        is not None
    )


def _download_pdf_bytes(url: str, timeout_seconds: int = 20) -> tuple[bytes, str]:
    req = url_request.Request(
        url,
        headers={
            "User-Agent": "KDA-Lager/1.0",
            "Accept": "application/pdf,application/octet-stream;q=0.8,*/*;q=0.5",
        },
    )
    with url_request.urlopen(req, timeout=timeout_seconds) as resp:  # nosec B310
        content_type = str(resp.headers.get("Content-Type") or "").strip().lower()
        payload = resp.read(PRODUCT_DATASHEET_MAX_BYTES + 1)
    if not payload:
        raise ValueError("Leere Antwort erhalten.")
    if len(payload) > PRODUCT_DATASHEET_MAX_BYTES:
        raise ValueError("Datei ist größer als 15 MB.")
    if payload[:5] != b"%PDF-":
        raise ValueError("Antwort ist kein PDF.")
    return payload, (content_type or "application/pdf")


def _attach_product_datasheet(db: Session, product_id: int, source_url: str, payload: bytes, mime_type: str) -> Attachment:
    dirs = ensure_dirs()
    rel_dir = Path("datasheets") / str(int(product_id))
    abs_dir = dirs["uploads"] / rel_dir
    abs_dir.mkdir(parents=True, exist_ok=True)
    file_name = f"datasheet_{dt.datetime.utcnow().strftime('%Y%m%d%H%M%S')}_{uuid.uuid4().hex[:8]}.pdf"
    abs_path = abs_dir / file_name
    abs_path.write_bytes(payload)

    parsed = urlsplit(source_url or "")
    original_name = Path(str(parsed.path or "").strip()).name or "datenblatt.pdf"
    row = Attachment(
        entity_type=PRODUCT_DATASHEET_ATTACHMENT_TYPE,
        entity_id=int(product_id),
        filename=str(rel_dir / file_name),
        original_name=original_name,
        mime_type=(mime_type or "application/pdf"),
        size_bytes=len(payload),
    )
    db.add(row)
    db.flush()
    return row


def _latest_product_datasheet(db: Session, product_id: int) -> Attachment | None:
    return (
        db.query(Attachment)
        .filter(
            Attachment.entity_type == PRODUCT_DATASHEET_ATTACHMENT_TYPE,
            Attachment.entity_id == int(product_id),
        )
        .order_by(Attachment.id.desc())
        .first()
    )


def _fetch_and_store_product_datasheet(
    db: Session,
    product: Product | None,
    manufacturer: Manufacturer | None,
    force_download: bool = False,
) -> tuple[bool, str]:
    if not product or not getattr(product, "id", None):
        return False, ""
    source_url = _build_product_datasheet_url(db, manufacturer, product)
    if not source_url:
        return False, ""
    if (not force_download) and _latest_product_datasheet(db, int(product.id)):
        return False, source_url
    payload, content_type = _download_pdf_bytes(source_url)
    _attach_product_datasheet(
        db=db,
        product_id=int(product.id),
        source_url=source_url,
        payload=payload,
        mime_type=content_type,
    )
    return True, source_url


def _form_scalar(form_data: dict[str, str | list[str]], key: str, fallback: str = "") -> str:
    raw = form_data.get(key, fallback)
    if isinstance(raw, list):
        if not raw:
            return fallback
        return str(raw[0])
    return str(raw if raw is not None else fallback)


def _extract_form_data(form) -> dict[str, str | list[str]]:
    data: dict[str, str | list[str]] = {}
    seen: set[str] = set()
    for key in form.keys():
        if key in seen:
            continue
        seen.add(key)
        values: list[str] = []
        for raw in form.getlist(key):
            if isinstance(raw, UploadFile):
                continue
            if getattr(raw, "filename", None):
                continue
            values.append(str(raw))
        if not values:
            continue
        data[key] = values if len(values) > 1 else values[0]
    return data


def _sanitize_draft_form_data(form_data: dict[str, str | list[str]]) -> dict[str, str | list[str]]:
    clean: dict[str, str | list[str]] = {}
    for key, raw in (form_data or {}).items():
        lower = str(key or "").strip().lower()
        if not lower:
            continue
        if any(term in lower for term in FORM_DRAFT_SENSITIVE_TERMS):
            continue
        if isinstance(raw, list):
            items = [str(v)[:500] for v in raw if str(v).strip()]
            if items:
                clean[key] = items
            continue
        clean[key] = str(raw or "")[:2000]
    return clean


def _draft_get(request: Request, key: str) -> dict[str, str | list[str]] | None:
    key = (key or "").strip()
    if not key:
        return None
    store = request.session.get(FORM_DRAFTS_SESSION_KEY, {})
    if not isinstance(store, dict):
        request.session[FORM_DRAFTS_SESSION_KEY] = {}
        return None
    row = store.get(key)
    if not isinstance(row, dict):
        return None
    ts_raw = str(row.get("ts") or "").strip()
    if not ts_raw:
        return None
    try:
        ts = dt.datetime.fromisoformat(ts_raw)
    except Exception:
        ts = None
    now = dt.datetime.utcnow().replace(tzinfo=None)
    if ts is None or (now - ts).total_seconds() > FORM_DRAFT_TTL_SECONDS:
        store.pop(key, None)
        request.session[FORM_DRAFTS_SESSION_KEY] = store
        return None
    data = row.get("form_data")
    if not isinstance(data, dict):
        return None
    return data


def _draft_set(request: Request, key: str, form_data: dict[str, str | list[str]]) -> None:
    key = (key or "").strip()
    if not key:
        return
    clean = _sanitize_draft_form_data(form_data)
    store = request.session.get(FORM_DRAFTS_SESSION_KEY, {})
    if not isinstance(store, dict):
        store = {}
    store[key] = {
        "ts": dt.datetime.utcnow().replace(tzinfo=None).isoformat(),
        "form_data": clean,
    }
    request.session[FORM_DRAFTS_SESSION_KEY] = store


def _draft_clear(request: Request, key: str) -> None:
    key = (key or "").strip()
    if not key:
        return
    store = request.session.get(FORM_DRAFTS_SESSION_KEY, {})
    if not isinstance(store, dict):
        return
    if key in store:
        store.pop(key, None)
        request.session[FORM_DRAFTS_SESSION_KEY] = store


def _first_error_field_id(form_errors: dict[str, str], field_ids: dict[str, str]) -> str:
    for field_key in form_errors.keys():
        if field_key.startswith("attr_"):
            suffix = field_key.split("_", 1)[1]
            return f"attr_{suffix}"
        field_id = field_ids.get(field_key)
        if field_id:
            return field_id
    return ""


def _apply_product_attribute_form_values(
    attrs: list[AttributeDef],
    val_map: dict[int, str],
    val_multi_map: dict[int, list[str]],
    form_data: dict[str, str | list[str]],
) -> None:
    if not form_data:
        return
    for attr in attrs:
        key = f"attr_{int(attr.id)}"
        if key not in form_data:
            continue
        raw = form_data.get(key)
        if attr.value_type == "enum" and bool(attr.is_multi):
            if isinstance(raw, list):
                selected = [str(v).strip() for v in raw if str(v).strip()]
            else:
                selected = [str(raw).strip()] if str(raw or "").strip() else []
            val_multi_map[attr.id] = selected
            val_map[attr.id] = json.dumps(selected, ensure_ascii=False) if selected else ""
            continue
        if isinstance(raw, list):
            raw = raw[0] if raw else ""
        val_map[attr.id] = str(raw or "").strip()


def _rerender_template_response(response):
    template = getattr(response, "template", None)
    context = getattr(response, "context", None)
    if template is None or not isinstance(context, dict):
        return response
    content = template.render(context)
    response.body = response.render(content)
    response.headers["content-length"] = str(len(response.body))
    return response


