def _role_flags(user) -> dict[str, bool]:
    role = ""
    try:
        role = (getattr(user, "role", "") or "").strip().lower()
    except Exception:
        role = ""
    return {
        "is_admin": role == "admin",
        "can_settings": role == "admin",
        "can_inventory": role in ("admin", "lagerist", "techniker", "lesen"),
        "can_inventory_write": role in ("admin", "lagerist"),
        "can_reserve": role in ("admin", "lagerist", "techniker"),
        "can_catalog_write": role == "admin",
        "can_readonly": role in ("admin", "lagerist", "techniker", "lesen"),
    }


def _wants_json(request: Request) -> bool:
    accept = (request.headers.get("accept") or "").lower()
    return request.url.path.startswith("/api/") or "application/json" in accept


def _internal_service_orders_enabled() -> bool:
    raw = (os.environ.get("INTERNAL_SERVICE_ORDERS_ENABLED") or "1").strip().lower()
    return raw not in {"0", "false", "off", "no"}


def _require_internal_service_orders_enabled() -> None:
    if not _internal_service_orders_enabled():
        raise HTTPException(status_code=404)


def _ensure_crm_service_order_schema() -> None:
    engine = get_engine()
    Base.metadata.create_all(
        bind=engine,
        tables=[
            Attachment.__table__,
            CrmCase.__table__,
            RoleAssignment.__table__,
            ExternalIdentity.__table__,
            ExternalLink.__table__,
            CustomerObject.__table__,
            OutsmartWorkorder.__table__,
            CrmTimelineEvent.__table__,
        ],
    )
    with engine.begin() as conn:
        case_cols = {row[1] for row in conn.exec_driver_sql("PRAGMA table_info(crm_cases)").fetchall()}
        for column_sql in (
            "order_type VARCHAR(40)",
            "proposed_start_at DATETIME",
            "proposed_end_at DATETIME",
            "customer_visible_note TEXT",
            "material_summary TEXT",
            "spare_part_status VARCHAR(30)",
            "spare_part_note TEXT",
            "schedule_hint TEXT",
            "next_step VARCHAR(30)",
        ):
            column_name = column_sql.split(" ", 1)[0]
            if column_name not in case_cols:
                conn.exec_driver_sql(f"ALTER TABLE crm_cases ADD COLUMN {column_sql}")
        conn.exec_driver_sql("CREATE INDEX IF NOT EXISTS ix_crm_cases_order_type ON crm_cases(order_type)")
        conn.exec_driver_sql("CREATE INDEX IF NOT EXISTS ix_crm_cases_next_step ON crm_cases(next_step)")


def _mail_compose_url(*, customer_id: int | None = None, case_id: int | None = None, to_email: str | None = None) -> str:
    params: dict[str, str] = {}
    if int(customer_id or 0) > 0:
        params["customer_id"] = str(int(customer_id))
    if _internal_service_orders_enabled() and int(case_id or 0) > 0:
        params["case_id"] = str(int(case_id))
    email_value = str(to_email or "").strip()
    if email_value:
        params["to_email"] = email_value
    query = urlencode(params)
    return f"/mail/verfassen?{query}" if query else "/mail/verfassen"


@app.on_event("startup")
def startup():
    timings: list[tuple[str, float]] = []

    def _run_step(label: str, fn):
        start = dt.datetime.now()
        result = fn()
        duration = (dt.datetime.now() - start).total_seconds()
        timings.append((label, duration))
        return result

    _run_step("ensure_dirs", ensure_dirs)
    _run_step("mkdir_spare_parts", lambda: SPARE_PART_UPLOAD_DIR.mkdir(parents=True, exist_ok=True))
    _run_step("mkdir_repair_events", lambda: REPAIR_EVENT_UPLOAD_DIR.mkdir(parents=True, exist_ok=True))
    engine = _run_step("get_engine", get_engine)
    if os.environ.get("DEV_CREATE_ALL", "0").strip() == "1":
        Base.metadata.create_all(bind=engine)
    for label, fn in [
        ("_ensure_products_ean_column", _ensure_products_ean_column),
        ("_ensure_products_extra_columns", _ensure_products_extra_columns),
        ("_cleanup_products_ern_legacy", _cleanup_products_ern_legacy),
        ("_ensure_attribute_defs_columns", _ensure_attribute_defs_columns),
        ("_ensure_inventory_bin_schema", _ensure_inventory_bin_schema),
        ("_ensure_extended_tables", _ensure_extended_tables),
        ("_ensure_product_sets_schema", _ensure_product_sets_schema),
        ("_ensure_prompt_pack5_schema", _ensure_prompt_pack5_schema),
        ("_ensure_prompt_pack9_schema", _ensure_prompt_pack9_schema),
        ("_ensure_prompt_pack10_schema", _ensure_prompt_pack10_schema),
        ("_ensure_prompt_pack11_schema", _ensure_prompt_pack11_schema),
        ("_ensure_prompt_pack12_schema", _ensure_prompt_pack12_schema),
        ("_ensure_catalog_v2_schema", _ensure_catalog_v2_schema),
        ("_ensure_ui_preferences_schema", _ensure_ui_preferences_schema),
        ("_ensure_system_settings_schema", _ensure_system_settings_schema),
        ("_ensure_item_type_field_rules_schema", _ensure_item_type_field_rules_schema),
        ("_ensure_spare_part_capture_schema", _ensure_spare_part_capture_schema),
        ("_ensure_crm_service_order_schema", _ensure_crm_service_order_schema),
        ("_migrate_item_type_rules_for_device_kind_only", _migrate_item_type_rules_for_device_kind_only),
        ("_migrate_legacy_condition_codes", _migrate_legacy_condition_codes),
    ]:
        _run_step(label, fn)
    # seed defaults
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        _run_step("_seed_defaults", lambda: _seed_defaults(db))
    finally:
        db.close()
    total = sum(duration for _, duration in timings)
    slow_parts = ", ".join(f"{label}={duration:.3f}s" for label, duration in sorted(timings, key=lambda item: item[1], reverse=True)[:6])
    logger.info("startup_sync_complete total=%.3fs top=%s", total, slow_parts)


@app.on_event("startup")
async def startup_background_jobs():
    start = dt.datetime.now()
    task = getattr(app.state, "startup_maintenance_task", None)
    if task is None or task.done():
        app.state.startup_maintenance_task = asyncio.create_task(_startup_maintenance_loop())
    if EMAIL_SENDER_ENABLED:
        task = getattr(app.state, "email_sender_task", None)
        if task is None or task.done():
            app.state.email_sender_task = asyncio.create_task(_email_sender_loop())
    if EMAIL_IMAP_ENABLED:
        task = getattr(app.state, "email_imap_task", None)
        if task is None or task.done():
            app.state.email_imap_task = asyncio.create_task(_email_imap_loop())
    task = getattr(app.state, "outsmart_sync_task", None)
    if task is None or task.done():
        app.state.outsmart_sync_task = asyncio.create_task(_outsmart_sync_loop())
    task = getattr(app.state, "sevdesk_sync_task", None)
    if task is None or task.done():
        app.state.sevdesk_sync_task = asyncio.create_task(_sevdesk_sync_loop())
    task = getattr(app.state, "paperless_sync_task", None)
    if task is None or task.done():
        app.state.paperless_sync_task = asyncio.create_task(_paperless_sync_loop())
    task = getattr(app.state, "background_job_task", None)
    if task is None or task.done():
        app.state.background_job_task = asyncio.create_task(_background_job_loop())
    duration = (dt.datetime.now() - start).total_seconds()
    logger.info("startup_background_jobs_complete total=%.3fs", duration)


@app.on_event("shutdown")
async def shutdown_background_jobs():
    for name in ("startup_maintenance_task", "email_sender_task", "email_imap_task", "outsmart_sync_task", "sevdesk_sync_task", "paperless_sync_task", "background_job_task"):
        task = getattr(app.state, name, None)
        if task is None:
            continue
        if not task.done():
            task.cancel()
            try:
                await task
            except asyncio.CancelledError:
                pass
        setattr(app.state, name, None)


def _ensure_products_ean_column() -> None:
    engine = get_engine()
    with engine.begin() as conn:
        cols = {row[1] for row in conn.exec_driver_sql("PRAGMA table_info(products)").fetchall()}
        if "ean" not in cols:
            conn.exec_driver_sql("ALTER TABLE products ADD COLUMN ean VARCHAR(32)")
        conn.exec_driver_sql("CREATE INDEX IF NOT EXISTS ix_products_ean ON products(ean)")


def _ensure_products_extra_columns() -> None:
    engine = get_engine()
    with engine.begin() as conn:
        cols = {row[1] for row in conn.exec_driver_sql("PRAGMA table_info(products)").fetchall()}
        if "item_type" not in cols:
            conn.exec_driver_sql("ALTER TABLE products ADD COLUMN item_type VARCHAR(30) DEFAULT 'material'")
        if "sales_name" not in cols:
            conn.exec_driver_sql("ALTER TABLE products ADD COLUMN sales_name VARCHAR(200)")
        if "manufacturer_name" not in cols:
            conn.exec_driver_sql("ALTER TABLE products ADD COLUMN manufacturer_name VARCHAR(200)")
        if "product_title_1" not in cols:
            conn.exec_driver_sql("ALTER TABLE products ADD COLUMN product_title_1 VARCHAR(200)")
        if "product_title_2" not in cols:
            conn.exec_driver_sql("ALTER TABLE products ADD COLUMN product_title_2 VARCHAR(200)")
        if "material_no" not in cols:
            conn.exec_driver_sql("ALTER TABLE products ADD COLUMN material_no VARCHAR(120)")
        if "image_url" not in cols:
            conn.exec_driver_sql("ALTER TABLE products ADD COLUMN image_url VARCHAR(600)")
        if "active" not in cols:
            conn.exec_driver_sql("ALTER TABLE products ADD COLUMN active BOOLEAN DEFAULT 1")
        for idx in range(1, PRODUCT_IMAGE_URL_MAX + 1):
            col_name = f"image_url_{idx}"
            if col_name not in cols:
                conn.exec_driver_sql(f"ALTER TABLE products ADD COLUMN {col_name} VARCHAR(600)")
        conn.exec_driver_sql("CREATE INDEX IF NOT EXISTS ix_products_material_no ON products(material_no)")
        conn.exec_driver_sql("CREATE INDEX IF NOT EXISTS ix_products_item_type ON products(item_type)")
        conn.exec_driver_sql("CREATE INDEX IF NOT EXISTS ix_products_active ON products(active)")
        conn.exec_driver_sql("UPDATE products SET item_type='material' WHERE item_type IS NULL OR TRIM(item_type)=''")
        conn.exec_driver_sql("UPDATE products SET track_mode='quantity' WHERE track_mode IS NULL OR track_mode!='quantity'")
        conn.exec_driver_sql("UPDATE products SET active=1 WHERE active IS NULL")


def _cleanup_products_ern_legacy() -> None:
    engine = get_engine()
    with engine.begin() as conn:
        conn.exec_driver_sql("DROP INDEX IF EXISTS ix_products_ern")
        cols = {row[1] for row in conn.exec_driver_sql("PRAGMA table_info(products)").fetchall()}
        if "ern" not in cols:
            return
        try:
            conn.exec_driver_sql("ALTER TABLE products DROP COLUMN ern")
        except Exception:
            # Fallback for SQLite variants without DROP COLUMN support.
            pass


