def _parse_date_input(raw: str | None) -> dt.datetime | None:
    text = (raw or "").strip()
    if not text:
        return None
    for fmt in ("%Y-%m-%d", "%d.%m.%Y"):
        try:
            return dt.datetime.strptime(text, fmt)
        except Exception:
            continue
    raise ValueError("Ungültiges Datum.")


def _parse_datetime_input(raw: str | None) -> dt.datetime | None:
    text = (raw or "").strip()
    if not text:
        return None
    for candidate in (text, text.replace("T", " ")):
        try:
            return dt.datetime.fromisoformat(candidate)
        except Exception:
            continue
    for fmt in ("%d.%m.%Y %H:%M", "%d.%m.%Y %H.%M"):
        try:
            return dt.datetime.strptime(text, fmt)
        except Exception:
            continue
    raise ValueError("Ungültiges Datum/Uhrzeit.")


def _format_date_local(value: dt.datetime | None) -> str:
    if not value:
        return "-"
    try:
        return value.strftime("%d.%m.%Y")
    except Exception:
        return str(value)


def _format_datetime_local(value: dt.datetime | None) -> str:
    if not value:
        return "-"
    try:
        return value.strftime("%d.%m.%Y %H:%M")
    except Exception:
        return str(value)


