def _mail_templates(db: Session) -> list[MailTemplate]:
    existing = {str(row.template_key or ""): row for row in db.query(MailTemplate).all()}
    created = False
    for payload in MAIL_TEMPLATE_DEFAULTS:
        key = str(payload.get("template_key") or "")
        row = existing.get(key)
        if row is None:
            row = MailTemplate(
                template_key=key,
                name=str(payload.get("name") or key),
                subject_template=str(payload.get("subject_template") or ""),
                body_template=str(payload.get("body_template") or ""),
                active=True,
                created_at=_utcnow_naive(),
            )
            db.add(row)
            created = True
            continue
        changed = False
        if not str(row.name or "").strip():
            row.name = str(payload.get("name") or key)
            changed = True
        if not str(row.subject_template or "").strip():
            row.subject_template = str(payload.get("subject_template") or "")
            changed = True
        if not str(row.body_template or "").strip():
            row.body_template = str(payload.get("body_template") or "")
            changed = True
        if changed:
            db.add(row)
    if created:
        db.flush()
    return db.query(MailTemplate).order_by(MailTemplate.active.desc(), MailTemplate.name.asc(), MailTemplate.id.asc()).all()


def _mail_render_template_text(text: str | None, context: dict[str, object]) -> str:
    result = str(text or "")
    for key, value in context.items():
        result = result.replace(f"{{{{ {key} }}}}", str(value or ""))
        result = result.replace(f"{{{{{key}}}}}", str(value or ""))
    return result.strip()


def _mail_attachment_abs_path(file_path: str | None) -> Path | None:
    rel = str(file_path or "").strip()
    if not rel:
        return None
    abs_path = ensure_dirs()["uploads"] / rel
    return abs_path if abs_path.exists() else None


def _mail_auto_target_flash_entry(db: Session, payload: dict[str, object]) -> dict[str, str]:
    case_id = _to_int(payload.get("case_id"), 0)
    customer_id = _to_int(payload.get("customer_id"), 0)
    subject = _crm_clean_text(payload.get("subject")) or "(ohne Betreff)"
    if _internal_service_orders_enabled() and case_id > 0:
        row = db.get(CrmCase, case_id)
        if row:
            return {
                "message": f"Mail automatisch zugeordnet: {row.case_no} | {row.title}",
                "link_url": f"/serviceauftraege/{int(row.id)}",
                "link_label": "Zum Serviceauftrag",
            }
    if customer_id > 0:
        row = db.get(MasterCustomer, customer_id)
        if row:
            party = db.get(Party, int(row.party_id or 0))
            label = f"{row.customer_no_internal} | {party.display_name if party else 'Kunde'}"
            return {
                "message": f"Mail automatisch zugeordnet: {label}",
                "link_url": f"/crm/kunden/{int(row.id)}",
                "link_label": "Zum Kunden",
            }
    thread_id = _to_int(payload.get("thread_id"), 0)
    if thread_id > 0:
        return {
            "message": f"Mail automatisch erkannt: {subject}",
            "link_url": f"/mail/threads/{thread_id}",
            "link_label": "Zum Thread",
        }
    return {"message": f"Mail automatisch erkannt: {subject}", "link_url": "", "link_label": ""}


