def _mail_assign_thread(db: Session, thread: MailThread, *, customer_id: int | None, case_id: int | None, status: str = "assigned") -> None:
    customer_value = int(customer_id or 0)
    case_value = int(case_id or 0) if _internal_service_orders_enabled() else 0
    if customer_value > 0:
        thread.master_customer_id = customer_value
    if case_value > 0:
        thread.case_id = case_value
    thread.status = "waiting" if status == "suggested" else "open"
    db.add(thread)
    message_rows = db.query(EmailMessage).filter(EmailMessage.thread_id == int(thread.id)).all()
    for row in message_rows:
        if customer_value > 0:
            row.master_customer_id = customer_value
        if case_value > 0:
            row.case_id = case_value
        row.assignment_status = status
        db.add(row)


def _mail_backfill_legacy_threads(db: Session, limit: int = 200) -> None:
    rows = (
        db.query(EmailMessage)
        .filter(EmailMessage.thread_id.is_(None))
        .order_by(EmailMessage.id.asc())
        .limit(max(1, int(limit)))
        .all()
    )
    for row in rows:
        suggestion = mail_suggest_assignments(
            db,
            from_email=str(row.from_email or ""),
            to_emails=str(row.to_emails or ""),
            cc_emails=str(row.cc_emails or ""),
            subject=str(row.subject or ""),
            body_text=str(row.body_text or row.snippet or ""),
            in_reply_to=str(row.in_reply_to or ""),
            references_header=str(row.references_header or ""),
            attachment_names=[],
        )
        customer_ids = list(suggestion.get("customer_ids") or [])
        case_ids = list(suggestion.get("case_ids") or []) if _internal_service_orders_enabled() else []
        thread = (
            db.get(MailThread, int(suggestion.get("thread_id") or 0))
            if int(suggestion.get("thread_id") or 0) > 0
            else None
        )
        if thread is None:
            subject_normalized = mail_normalize_subject(row.subject or row.snippet or f"Nachricht {row.id}")
            thread = (
                db.query(MailThread)
                .filter(MailThread.subject_normalized == subject_normalized)
                .order_by(MailThread.last_message_at.desc(), MailThread.id.desc())
                .first()
            )
        if thread is None:
            thread = MailThread(
                subject_normalized=mail_normalize_subject(row.subject or row.snippet or f"Nachricht {row.id}"),
                master_customer_id=customer_ids[0] if len(customer_ids) == 1 else (int(row.master_customer_id or 0) or None),
                case_id=case_ids[0] if len(case_ids) == 1 else ((int(row.case_id or 0) or None) if _internal_service_orders_enabled() else None),
                status="open",
                last_message_at=row.received_at or row.sent_at or row.fetched_at or _utcnow_naive(),
                created_at=row.fetched_at or _utcnow_naive(),
            )
            db.add(thread)
            db.flush()
        row.thread_id = int(thread.id)
        if len(customer_ids) == 1 and int(row.master_customer_id or 0) <= 0:
            row.master_customer_id = int(customer_ids[0])
        if len(case_ids) == 1 and int(row.case_id or 0) <= 0:
            row.case_id = int(case_ids[0])
        if not _internal_service_orders_enabled():
            row.case_id = None
        row.assignment_status = str(suggestion.get("status") or row.assignment_status or "unassigned")
        if int(thread.master_customer_id or 0) <= 0 and int(row.master_customer_id or 0) > 0:
            thread.master_customer_id = int(row.master_customer_id)
        if _internal_service_orders_enabled() and int(thread.case_id or 0) <= 0 and int(row.case_id or 0) > 0:
            thread.case_id = int(row.case_id)
        thread.last_message_at = row.received_at or row.sent_at or row.fetched_at or thread.last_message_at or _utcnow_naive()
        db.add(thread)
        db.add(row)
    if rows:
        db.flush()


def _mail_thread_rows(
    db: Session,
    *,
    q: str = "",
    status: str = "",
    assignment: str = "",
    limit: int = 120,
    show_spam: bool = False,
) -> list[dict[str, object]]:
    _mail_backfill_legacy_threads(db, limit=300)
    query = db.query(MailThread)
    service_orders_enabled = _internal_service_orders_enabled()
    status_norm = (status or "").strip().lower()
    if status_norm in ("open", "waiting", "closed"):
        query = query.filter(MailThread.status == status_norm)
    rows = query.order_by(func.coalesce(MailThread.last_message_at, MailThread.created_at).desc(), MailThread.id.desc()).limit(max(1, int(limit))).all()
    latest_map = _mail_thread_latest_message_map(db, [int(row.id) for row in rows])
    out: list[dict[str, object]] = []
    q_norm = (q or "").strip().lower()
    assignment_norm = (assignment or "").strip().lower()
    customers = {int(row.id): row for row in db.query(MasterCustomer).filter(MasterCustomer.id.in_([int(item.master_customer_id) for item in rows if int(item.master_customer_id or 0) > 0])).all()} if rows else {}
    cases = {int(row.id): row for row in db.query(CrmCase).filter(CrmCase.id.in_([int(item.case_id) for item in rows if int(item.case_id or 0) > 0])).all()} if service_orders_enabled and rows else {}
    party_ids = [int(row.party_id) for row in customers.values()]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids)).all()} if party_ids else {}
    for row in rows:
        latest = latest_map.get(int(row.id))
        effective_case_id = int(row.case_id or 0) if service_orders_enabled else 0
        spam_reason = _mail_thread_spam_reason(latest)
        search_blob = " ".join(
            [
                str(latest.subject if latest else ""),
                str(latest.from_email if latest else ""),
                str(row.subject_normalized or ""),
                str(cases.get(effective_case_id).case_no if cases.get(effective_case_id) else ""),
                str(customers.get(int(row.master_customer_id or 0)).customer_no_internal if customers.get(int(row.master_customer_id or 0)) else ""),
                str(parties.get(int(customers.get(int(row.master_customer_id or 0)).party_id or 0)).display_name if customers.get(int(row.master_customer_id or 0)) and parties.get(int(customers.get(int(row.master_customer_id or 0)).party_id or 0)) else ""),
            ]
        ).lower()
        if q_norm and q_norm not in search_blob:
            continue
        if spam_reason and not bool(show_spam):
            continue
        if assignment_norm == "unassigned" and (int(row.master_customer_id or 0) > 0 or effective_case_id > 0):
            continue
        if assignment_norm == "assigned" and int(row.master_customer_id or 0) <= 0 and effective_case_id <= 0:
            continue
        out.append(
            {
                "thread": row,
                "latest": latest,
                "customer": customers.get(int(row.master_customer_id or 0)),
                "customer_party": parties.get(int(customers.get(int(row.master_customer_id or 0)).party_id or 0)) if customers.get(int(row.master_customer_id or 0)) else None,
                "crm_case": cases.get(effective_case_id) if service_orders_enabled else None,
                "spam_reason": spam_reason,
            }
        )
    return out


def _document_search_blob(item: DocumentInboxItem) -> str:
    parts = [
        str(item.title or ""),
        str(item.correspondent or ""),
        str(item.document_type or ""),
        _document_inbox_kind_label(getattr(item, "draft_kind", "")),
        _document_inbox_workflow_label(_document_inbox_effective_workflow_state(item)),
    ]
    try:
        meta = json.loads(item.metadata_json or "{}")
        if isinstance(meta, dict):
            for key in ("content", "ocr", "title", "original_file_name", "correspondent_name"):
                value = meta.get(key)
                if value not in (None, ""):
                    parts.append(str(value))
    except Exception:
        pass
    return "\n".join(parts)


def _paperless_customer_candidate_items(db: Session, customer_id: int, limit: int = 12) -> list[DocumentInboxItem]:
    context = _paperless_customer_matching_context(db, int(customer_id))
    if context is None:
        return []
    linked_doc_ids = {
        str(row.paperless_document_id or "").strip()
        for row in _paperless_links_for_object(db, "customer", int(customer_id))
        if str(row.paperless_document_id or "").strip()
    }
    rows = (
        db.query(DocumentInboxItem)
        .filter(
            DocumentInboxItem.suggested_object_type == "customer",
            DocumentInboxItem.suggested_object_id == int(customer_id),
            DocumentInboxItem.status != "matched",
        )
        .all()
    )
    filtered: list[DocumentInboxItem] = []
    for row in rows:
        if str(row.paperless_document_id or "").strip() in linked_doc_ids:
            continue
        score, _reasons, _details, matched_refs = _paperless_customer_document_match(
            text=_document_search_blob(row),
            title=row.title,
            document_type=row.document_type,
            correspondent=row.correspondent,
            customer=context["customer"],
            party=context["party"],
            default_address=context["default_address"],
            identities=context["identities"],
            contact_rows=context["contact_rows"],
            workorder_refs=context["workorder_refs"],
        )
        if score >= 14 and matched_refs:
            filtered.append(row)
    filtered.sort(
        key=lambda row: (
            -int(_json_dict(row.metadata_json).get("customer_scan", {}).get("score") or 0),
            -int(_json_dict(row.metadata_json).get("customer_scan", {}).get("priority_rank") or 0),
            -(int((row.created_date or dt.datetime.min).timestamp()) if row.created_date else 0),
            -int(row.id or 0),
        ),
        reverse=False,
    )
    return filtered[: max(1, int(limit or 12))]


def _paperless_workorder_ref_tokens(value: str | None) -> list[str]:
    text = _crm_clean_text(value).upper()
    if not text:
        return []
    out: list[str] = []
    seen: set[str] = set()
    pattern = r"\b((?:AF|SA)[\s/_-]*\d{2,}|WB[\s/_-]*\d{4}[\s/_-]*\d{3,})\b"
    for match in re.findall(pattern, text):
        token = re.sub(r"[^A-Z0-9]", "", str(match or "").upper())
        if not token or token in seen:
            continue
        seen.add(token)
        out.append(token)
    return out


def _paperless_document_workorder_refs(*values: str | None) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    for value in values:
        for token in _paperless_workorder_ref_tokens(value):
            if token in seen:
                continue
            seen.add(token)
            out.append(token)
    return out


def _paperless_document_is_customer_excluded(*values: str | None) -> bool:
    raw_text = " ".join(str(value or "") for value in values).lower()
    normalized = _crm_normalize_key(raw_text)
    if re.search(r"\bkonto[\s_/-]*\d{0,16}[\s_/-]*auszug\b", raw_text):
        return True
    exclusion_terms = (
        "kontoauszug",
        "geschaeftsgirokonto",
        "kontostand am",
        "auszug nr",
        "umsatzanzeige",
        "umsatzauszug",
        "kontoumsaetze",
        "bankstatement",
        "zahlungsavis",
        "lastschriftavis",
    )
    return any(term in raw_text for term in exclusion_terms) or any(
        key in normalized
        for key in ("kontoauszug", "geschaeftsgirokonto", "umsatzanzeige", "umsatzauszug", "zahlungsavis", "lastschriftavis")
    )


def _paperless_customer_name_terms(party: Party, contact_rows: list[dict[str, object]] | None = None) -> list[str]:
    terms: list[str] = []
    seen: set[str] = set()

    def add_term(value: str | None) -> None:
        text = _crm_clean_text(value)
        if len(text) < 3:
            return
        key = _crm_normalize_key(text)
        if key.isdigit():
            return
        if key in seen:
            return
        seen.add(key)
        terms.append(text)

    def add_name_variants(value: str | None) -> None:
        text = _crm_clean_text(value)
        if not text:
            return
        add_term(text)
        parts = [part for part in re.split(r"\s+", text) if _crm_clean_text(part)]
        if len(parts) >= 2:
            add_term(parts[-1])

    add_name_variants(party.display_name)
    for item in list(contact_rows or [])[:6]:
        party_row = item.get("party")
        if party_row:
            add_name_variants(getattr(party_row, "display_name", None))
    return terms[:6]


def _paperless_customer_outsmart_refs(db: Session, customer_id: int, limit: int = 12) -> list[str]:
    refs: list[str] = []
    seen: set[str] = set()

    def add_ref(value: str | None) -> None:
        for token in _paperless_workorder_ref_tokens(value):
            if token in seen:
                continue
            seen.add(token)
            refs.append(token)

    local_rows = (
        db.query(OutsmartWorkorder)
        .filter(OutsmartWorkorder.master_customer_id == int(customer_id))
        .order_by(OutsmartWorkorder.updated_at.desc(), OutsmartWorkorder.id.desc())
        .limit(max(1, int(limit)))
        .all()
    )
    for row in local_rows:
        payload = _json_dict(row.raw_json)
        add_ref(row.workorder_no)
        add_ref(payload.get("JobNr"))
        add_ref(payload.get("Reference"))
        add_ref(payload.get("ExternalReference"))
        add_ref(payload.get("OrderNr"))
    for item in _customer_outsmart_stage_workorder_rows(db, int(customer_id), limit=max(1, int(limit))):
        row = item.get("row")
        if not row:
            continue
        payload = _json_dict(getattr(row, "raw_json", ""))
        add_ref(getattr(row, "workorder_no", None))
        add_ref(payload.get("JobNr"))
        add_ref(payload.get("Reference"))
        add_ref(payload.get("ExternalReference"))
        add_ref(payload.get("OrderNr"))
    return refs[: max(1, int(limit))]


def _paperless_customer_search_terms(
    db: Session,
    customer: MasterCustomer,
    party: Party,
    default_address: CrmAddress | None,
    identities: list[ExternalIdentity],
    contact_rows: list[dict[str, object]] | None = None,
) -> list[str]:
    terms: list[str] = []
    seen: set[str] = set()

    def add_term(value: str | None, *, min_len: int = 4) -> None:
        text = _crm_clean_text(value)
        if len(text) < min_len:
            return
        key = _crm_normalize_key(text)
        if key in seen:
            return
        seen.add(key)
        terms.append(text)

    name_terms = _paperless_customer_name_terms(party, contact_rows)
    workorder_refs = _paperless_customer_outsmart_refs(db, int(customer.id), limit=8)
    if name_terms and workorder_refs:
        for ref in workorder_refs[:8]:
            for name_term in name_terms[:4]:
                add_term(f"{name_term} {ref}", min_len=6)
                add_term(f"{ref} {name_term}", min_len=6)
        return terms[:12]

    add_term(customer.customer_no_internal, min_len=3)
    for name_term in name_terms:
        add_term(name_term)
    if default_address:
        add_term(default_address.email, min_len=6)
        add_term(default_address.phone, min_len=6)
        zip_city = _crm_clean_text(f"{default_address.zip_code or ''} {default_address.city or ''}")
        add_term(zip_city, min_len=8)
    for row in identities:
        add_term(row.external_key, min_len=4)
        add_term(row.external_id, min_len=4)
    for item in list(contact_rows or [])[:4]:
        row = item.get("row")
        party_row = item.get("party")
        if party_row:
            add_term(getattr(party_row, "display_name", None))
        if row:
            add_term(getattr(row, "email", None), min_len=6)
            add_term(getattr(row, "phone", None), min_len=6)
    return terms[:8]


def _paperless_customer_inbox_search_terms(
    customer: MasterCustomer,
    party: Party,
    default_address: CrmAddress | None,
    identities: list[ExternalIdentity],
    contact_rows: list[dict[str, object]] | None = None,
) -> list[str]:
    terms: list[str] = []
    seen: set[str] = set()

    def add_term(value: str | None, *, min_len: int = 3) -> None:
        text = _crm_clean_text(value)
        if len(text) < min_len:
            return
        if re.fullmatch(r"\d{1,5}", text):
            return
        key = _crm_normalize_key(text)
        if key in seen:
            return
        seen.add(key)
        terms.append(text)

    add_term(customer.customer_no_internal, min_len=3)
    for value in _paperless_customer_name_terms(party, contact_rows):
        add_term(value, min_len=3)
    if default_address:
        add_term(default_address.email, min_len=6)
        add_term(default_address.phone, min_len=6)
        add_term(_crm_clean_text(f"{default_address.street or ''} {default_address.house_no or ''}"), min_len=5)
        add_term(default_address.street, min_len=4)
    for row in identities:
        add_term(row.external_key, min_len=4)
        add_term(row.external_id, min_len=4)
    for item in list(contact_rows or [])[:4]:
        row = item.get("row")
        party_row = item.get("party")
        if party_row:
            add_term(getattr(party_row, "display_name", None), min_len=3)
        if row:
            add_term(getattr(row, "email", None), min_len=6)
            add_term(getattr(row, "phone", None), min_len=6)
    return terms[:12]


def _paperless_customer_topic_boost(text: str) -> tuple[int, list[str]]:
    blob = _crm_normalize_key(text)
    if not blob:
        return 0, []
    topics = [
        ("Rechnung", ("rechnung", "invoice", "re26", "re24")),
        ("Angebot", ("angebot", "order", "an-", "angebotnr")),
        ("Auftrag", ("auftrag", "bestellung", "arbeitsauftrag")),
        ("Kundendienst", ("kundendienst", "service", "reparatur", "wartung")),
    ]
    score = 0
    reasons: list[str] = []
    for label, keys in topics:
        if any(key in blob for key in keys):
            score += 2
            reasons.append(label)
    return score, reasons


def _paperless_customer_match_score(
    *,
    text: str,
    customer: MasterCustomer,
    party: Party,
    default_address: CrmAddress | None,
    identities: list[ExternalIdentity],
    contact_rows: list[dict[str, object]] | None = None,
    workorder_refs: list[str] | None = None,
) -> tuple[int, list[str], dict[str, object]]:
    blob = _crm_normalize_key(text)
    score = 0
    reasons: list[str] = []
    details: dict[str, object] = {"matched_name": "", "matched_ref": ""}
    if not blob:
        return score, reasons, details

    def hit(value: str | None) -> bool:
        key = _crm_normalize_key(value)
        return bool(key) and key in blob

    name_hits: list[str] = []
    for value in _paperless_customer_name_terms(party, contact_rows):
        if hit(value):
            name_hits.append(value)
    ref_hits: list[str] = []
    for value in list(workorder_refs or [])[:12]:
        if _crm_normalize_key(value) and _crm_normalize_key(value) in blob:
            ref_hits.append(value)

    if list(workorder_refs or []):
        if not name_hits or not ref_hits:
            return 0, [], details
        score += 6
        reasons.append("Name")
        score += 8
        reasons.append("OutSmart-Auftrag")
        details["matched_name"] = name_hits[0]
        details["matched_ref"] = ref_hits[0]
    elif name_hits:
        details["matched_name"] = name_hits[0]
        score += 4
        reasons.append("Name")

    if hit(customer.customer_no_internal):
        score += 6
        reasons.append("Kundennummer")
    if hit(party.display_name):
        score += 5
        reasons.append("Anzeigename")
    if default_address:
        if _crm_normalize_email(default_address.email) and _crm_normalize_email(default_address.email) in blob:
            score += 6
            reasons.append("E-Mail")
        street_house = _crm_clean_text(f"{default_address.street or ''} {default_address.house_no or ''}")
        if street_house and hit(street_house):
            score += 4
            reasons.append("Strasse/Hausnummer")
        elif hit(default_address.street):
            score += 2
            reasons.append("Strasse")
        phone_key = _crm_normalize_key(default_address.phone)
        if phone_key and phone_key in blob:
            score += 3
            reasons.append("Telefon")
        if hit(default_address.zip_code) and hit(default_address.city):
            score += 2
            reasons.append("PLZ/Ort")
    for row in identities:
        key = _crm_clean_text(row.external_key or row.external_id)
        if len(key) >= 4 and hit(key):
            score += 4
            reasons.append(f"{_crm_external_system_label(row.system_name)}-Kennung")
            break
    for item in list(contact_rows or [])[:4]:
        row = item.get("row")
        party_row = item.get("party")
        if party_row and hit(getattr(party_row, "display_name", None)):
            score += 3
            reasons.append("Ansprechpartner")
            break
        if row and _crm_normalize_email(getattr(row, "email", None)) and _crm_normalize_email(getattr(row, "email", None)) in blob:
            score += 3
            reasons.append("Kontakt-Mail")
            break
        phone_key = _crm_normalize_key(getattr(row, "phone", None) if row else "")
        if phone_key and phone_key in blob:
            score += 2
            reasons.append("Kontakt-Telefon")
            break
    topic_score, topic_reasons = _paperless_customer_topic_boost(text)
    score += topic_score
    for label in topic_reasons:
        reasons.append(f"Dokumenttyp: {label}")
    return score, reasons, details


def _paperless_customer_matching_context(db: Session, customer_id: int) -> dict[str, object] | None:
    customer = db.get(MasterCustomer, int(customer_id))
    if customer is None:
        return None
    party = db.get(Party, int(customer.party_id or 0))
    if party is None:
        return None
    addresses = (
        db.query(CrmAddress)
        .filter(CrmAddress.party_id == int(party.id))
        .order_by(CrmAddress.is_default.desc(), CrmAddress.id.asc())
        .all()
    )
    default_address = _crm_pick_default_address(addresses)
    contact_rows_raw = (
        db.query(CustomerContactPerson)
        .filter(CustomerContactPerson.master_customer_id == int(customer.id))
        .order_by(CustomerContactPerson.active.desc(), CustomerContactPerson.id.asc())
        .all()
    )
    contact_party_ids = [int(row.party_id) for row in contact_rows_raw if int(row.party_id or 0) > 0]
    contact_parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(contact_party_ids)).all()} if contact_party_ids else {}
    contact_rows = [{"row": row, "party": contact_parties.get(int(row.party_id or 0))} for row in contact_rows_raw]
    identities = (
        db.query(ExternalIdentity)
        .filter(ExternalIdentity.master_customer_id == int(customer.id))
        .order_by(ExternalIdentity.system_name.asc(), ExternalIdentity.id.asc())
        .all()
    )
    workorder_refs = _paperless_customer_outsmart_refs(db, int(customer.id), limit=24)
    return {
        "customer": customer,
        "party": party,
        "default_address": default_address,
        "contact_rows": contact_rows,
        "identities": identities,
        "workorder_refs": workorder_refs,
    }


def _paperless_customer_document_match(
    *,
    text: str,
    title: str | None,
    document_type: str | None,
    correspondent: str | None,
    customer: MasterCustomer,
    party: Party,
    default_address: CrmAddress | None,
    identities: list[ExternalIdentity],
    contact_rows: list[dict[str, object]] | None = None,
    workorder_refs: list[str] | None = None,
) -> tuple[int, list[str], dict[str, object], list[str]]:
    if _paperless_document_is_customer_excluded(title, document_type, correspondent, text):
        return 0, ["Ausschluss: Kontoauszug/Bankbeleg"], {"matched_name": "", "matched_ref": ""}, []
    effective_refs = [str(value or "").strip() for value in list(workorder_refs or []) if str(value or "").strip()]
    if not effective_refs:
        return 0, [], {"matched_name": "", "matched_ref": ""}, []
    score, reasons, details = _paperless_customer_match_score(
        text=text,
        customer=customer,
        party=party,
        default_address=default_address,
        identities=identities,
        contact_rows=contact_rows,
        workorder_refs=effective_refs,
    )
    matched_refs = [ref for ref in _paperless_document_workorder_refs(title, document_type, correspondent, text) if ref in set(effective_refs)]
    if not details.get("matched_name") or not matched_refs:
        return 0, reasons, details, []
    return score, reasons, details, matched_refs


def _paperless_scan_customer_documents(
    db: Session,
    *,
    customer: MasterCustomer,
    party: Party,
    default_address: CrmAddress | None,
    identities: list[ExternalIdentity],
    contact_rows: list[dict[str, object]] | None = None,
    limit: int = 16,
) -> dict[str, int]:
    settings = _paperless_settings(db, include_secret=True)
    if not bool(settings.get("enabled")) or not bool(settings.get("token")):
        raise ValueError("Paperless ist nicht aktiviert oder es fehlt das API-Token.")
    workorder_refs = _paperless_customer_outsmart_refs(db, int(customer.id), limit=8)
    if not workorder_refs:
        return {"queries": 0, "fetched": 0, "suggested": 0}
    terms = _paperless_customer_search_terms(db, customer, party, default_address, identities, contact_rows)
    if not terms:
        return {"queries": 0, "fetched": 0, "suggested": 0}
    linked_doc_ids = {
        str(row.paperless_document_id or "").strip()
        for row in _paperless_links_for_object(db, "customer", int(customer.id))
        if str(row.paperless_document_id or "").strip()
    }
    fetched = 0
    suggested = 0
    seen_doc_ids: set[str] = set()
    per_query_limit = max(8, min(int(limit or 16), 24))
    for term in terms:
        rows = paperless_list_documents(settings, limit=per_query_limit, query=term)
        for payload in rows:
            document_id = str(payload.get("id") or payload.get("document_id") or "").strip()
            if not document_id or document_id in seen_doc_ids or document_id in linked_doc_ids:
                continue
            seen_doc_ids.add(document_id)
            item = _upsert_document_inbox_item(db, payload)
            if item is None:
                continue
            fetched += 1
            if str(item.status or "").strip() == "matched":
                continue
            score, reasons, match_details, matched_refs = _paperless_customer_document_match(
                text=_document_search_blob(item),
                title=item.title,
                document_type=item.document_type,
                correspondent=item.correspondent,
                customer=customer,
                party=party,
                default_address=default_address,
                identities=identities,
                contact_rows=contact_rows,
                workorder_refs=workorder_refs,
            )
            if score < 14 or not matched_refs:
                continue
            _, topic_reasons = _paperless_customer_topic_boost(_document_search_blob(item))
            priority_rank = 0
            if "Rechnung" in topic_reasons:
                priority_rank = 4
            elif "Angebot" in topic_reasons:
                priority_rank = 3
            elif "Auftrag" in topic_reasons:
                priority_rank = 2
            elif "Kundendienst" in topic_reasons:
                priority_rank = 1
            item.suggested_object_type = "customer"
            item.suggested_object_id = int(customer.id)
            meta = _json_dict(item.metadata_json)
            meta["customer_scan"] = {
                "customer_id": int(customer.id),
                "score": score,
                "reasons": reasons,
                "priority_rank": priority_rank,
                "topic_reasons": topic_reasons,
                "workorder_refs": workorder_refs[:8],
                "matched_name": str(match_details.get("matched_name") or ""),
                "matched_ref": str(match_details.get("matched_ref") or ""),
                "matched_workorder_refs": matched_refs,
            }
            item.metadata_json = json.dumps(meta, ensure_ascii=False)
            db.add(item)
            suggested += 1
    return {"queries": len(terms), "fetched": fetched, "suggested": suggested}


def _document_match_candidates(db: Session, item: DocumentInboxItem) -> dict[str, list[object]]:
    text = _document_search_blob(item).lower()
    customers = []
    for row in db.query(MasterCustomer).order_by(MasterCustomer.id.desc()).limit(200).all():
        if str(row.customer_no_internal or "").lower() in text:
            customers.append(row)
    cases = []
    if _internal_service_orders_enabled():
        for row in db.query(CrmCase).order_by(CrmCase.id.desc()).limit(200).all():
            if str(row.case_no or "").lower() in text:
                cases.append(row)
    repairs = []
    for row in db.query(RepairOrder).order_by(RepairOrder.id.desc()).limit(200).all():
        if str(row.repair_no or "").lower() in text:
            repairs.append(row)
    orders = []
    for row in db.query(PurchaseOrder).order_by(PurchaseOrder.id.desc()).limit(200).all():
        tokens = [str(row.po_number or "").lower(), str(row.order_no or "").lower()]
        if any(token and token in text for token in tokens):
            orders.append(row)
    receipts = []
    for row in db.query(GoodsReceipt).order_by(GoodsReceipt.id.desc()).limit(200).all():
        if str(row.receipt_no or "").lower() in text:
            receipts.append(row)
    invoices = []
    for row in db.query(PurchaseInvoice).order_by(PurchaseInvoice.id.desc()).limit(200).all():
        if str(row.invoice_no or "").lower() in text:
            invoices.append(row)
    return {
        "customers": customers[:20],
        "cases": cases[:20],
        "repairs": repairs[:20],
        "orders": orders[:20],
        "receipts": receipts[:20],
        "invoices": invoices[:20],
    }


def _document_timeline_targets(db: Session, object_type: str, object_id: int) -> dict[str, int | None]:
    kind = str(object_type or "").strip()
    if kind == "customer":
        return {"master_customer_id": int(object_id), "case_id": None}
    if kind == "case":
        if not _internal_service_orders_enabled():
            return {"master_customer_id": None, "case_id": None}
        row = db.get(CrmCase, int(object_id))
        customer_id = None
        if row:
            role = (
                db.query(RoleAssignment)
                .filter(RoleAssignment.case_id == int(row.id), RoleAssignment.role_type == CRM_ROLE_ORDERING_PARTY)
                .first()
            )
            customer_id = int(role.master_customer_id or 0) or None if role else None
        return {"master_customer_id": customer_id, "case_id": int(object_id)}
    if kind == "repair_order":
        return {"master_customer_id": None, "case_id": None}
    return {"master_customer_id": None, "case_id": None}


def _document_timeline_add(
    db: Session,
    *,
    object_type: str,
    object_id: int,
    title: str,
    paperless_document_id: str | None = None,
    external_ref: str | None = None,
) -> None:
    targets = _document_timeline_targets(db, object_type, object_id)
    if int(targets.get("master_customer_id") or 0) <= 0 and int(targets.get("case_id") or 0) <= 0:
        return
    ref = external_ref or (f"paperless:{paperless_document_id}" if paperless_document_id else f"{object_type}:{object_id}:{title}")
    exists = (
        db.query(CrmTimelineEvent)
        .filter(CrmTimelineEvent.source_system == "paperless", CrmTimelineEvent.external_ref == ref)
        .first()
    )
    if exists:
        return
    db.add(
        CrmTimelineEvent(
            case_id=int(targets.get("case_id") or 0) or None,
            master_customer_id=int(targets.get("master_customer_id") or 0) or None,
            source_system="paperless",
            event_type="document",
            title=title,
            body=f"Dokument zugeordnet: {object_type} #{int(object_id)}",
            event_ts=_utcnow_naive(),
            external_ref=ref,
            meta_json=json.dumps({"paperless_document_id": paperless_document_id or "", "object_type": object_type, "object_id": int(object_id)}, ensure_ascii=False),
            created_at=_utcnow_naive(),
        )
    )


def _store_uploaded_attachment(
    *,
    entity_type: str,
    entity_id: int,
    upload: UploadFile,
) -> Attachment:
    original_name = Path(str(upload.filename or "").strip()).name or "dokument"
    safe_name = re.sub(r"[^A-Za-z0-9._-]+", "_", original_name).strip("._") or "dokument"
    rel_dir = Path("documents") / str(entity_type) / str(int(entity_id))
    abs_dir = ensure_dirs()["uploads"] / rel_dir
    abs_dir.mkdir(parents=True, exist_ok=True)
    file_name = f"{dt.datetime.utcnow().strftime('%Y%m%d%H%M%S')}_{uuid.uuid4().hex[:8]}_{safe_name}"
    abs_path = abs_dir / file_name
    payload = upload.file.read() or b""
    abs_path.write_bytes(payload)
    return Attachment(
        entity_type=str(entity_type),
        entity_id=int(entity_id),
        filename=str(rel_dir / file_name),
        original_name=original_name,
        mime_type=str(upload.content_type or "application/octet-stream"),
        size_bytes=len(payload),
        created_at=_utcnow_naive(),
    )


def _attachments_for_entity(db: Session, entity_type: str, entity_id: int) -> list[Attachment]:
    return (
        db.query(Attachment)
        .filter(Attachment.entity_type == str(entity_type), Attachment.entity_id == int(entity_id))
        .order_by(Attachment.id.desc())
        .all()
    )


def _json_dict(raw: str | None) -> dict[str, object]:
    try:
        payload = json.loads(raw or "{}")
    except Exception:
        return {}
    return payload if isinstance(payload, dict) else {}


def _accounting_accounts(db: Session, *, active_only: bool = True) -> list[AccountingAccount]:
    query = db.query(AccountingAccount)
    if active_only:
        query = query.filter(AccountingAccount.active == True)
    return (
        query.order_by(
            AccountingAccount.favorite.desc(),
            AccountingAccount.account_framework.asc(),
            AccountingAccount.account_number.asc(),
            AccountingAccount.id.asc(),
        )
        .all()
    )


def _accounting_account_label(row: AccountingAccount | None) -> str:
    if row is None:
        return "-"
    number = str(row.account_number or "").strip()
    label = str(row.label or "").strip()
    framework = str(row.account_framework or "").strip()
    parts = [part for part in (framework, number, label) if part]
    return " | ".join(parts) if parts else f"Konto {int(row.id)}"


def _accounting_account_keywords(row: AccountingAccount | None) -> list[str]:
    if row is None:
        return []
    try:
        payload = json.loads(row.keywords_json or "[]")
    except Exception:
        payload = []
    if not isinstance(payload, list):
        return []
    return [str(item or "").strip() for item in payload if str(item or "").strip()]


def _accounting_category_choices(db: Session) -> list[str]:
    existing = [
        str(item[0] or "").strip()
        for item in db.query(AccountingAccount.category)
        .filter(AccountingAccount.category.isnot(None))
        .distinct()
        .all()
    ]
    return merged_category_choices(existing)


def _accounting_account_value(raw: str | None) -> str:
    text = str(raw or "").strip()
    if not text:
        return ""
    match = re.search(r"\b(\d{3,8})\b", text)
    return str(match.group(1) or "").strip() if match else text


def _accounting_account_category(db: Session, account_number: str | None) -> str:
    row = _find_accounting_account_by_number(db, account_number)
    return str(row.category or "").strip() if row is not None else ""


def _import_standard_skr03_accounts(db: Session) -> dict[str, int]:
    summary = {"created": 0, "updated": 0}
    for payload in local_skr03_seed():
        account_number = str(payload.get("account_number") or "").strip()
        if not account_number:
            continue
        row = (
            db.query(AccountingAccount)
            .filter(AccountingAccount.account_framework == "SKR03", AccountingAccount.account_number == account_number)
            .one_or_none()
        )
        is_new = row is None
        if row is None:
            row = AccountingAccount(
                account_framework="SKR03",
                account_number=account_number,
                created_at=_utcnow_naive(),
            )
        row.label = str(payload.get("label") or row.label or "").strip() or row.label
        row.category = str(payload.get("category") or row.category or "").strip() or row.category
        row.source_type = "import"
        row.active = True
        keywords = [str(item or "").strip() for item in list(payload.get("keywords") or []) if str(item or "").strip()]
        if keywords and not _accounting_account_keywords(row):
            row.keywords_json = json.dumps(keywords, ensure_ascii=False)
        row.updated_at = _utcnow_naive()
        db.add(row)
        summary["created" if is_new else "updated"] += 1
    db.flush()
    return summary


def _sync_sevdesk_receipt_guidance_accounts(db: Session) -> dict[str, int]:
    summary = {"created": 0, "updated": 0}
    settings = _sevdesk_settings(db, include_secret=True)
    if not bool(settings.get("enabled")) or not str(settings.get("api_token") or "").strip():
        return summary
    rows = sevdesk_get_receipt_guidance_accounts(settings, receipt_kind="expense")
    for payload in rows:
        account_number = str(payload.get("accountNumber") or "").strip()
        if not account_number:
            continue
        row = (
            db.query(AccountingAccount)
            .filter(AccountingAccount.account_number == account_number)
            .order_by(AccountingAccount.favorite.desc(), AccountingAccount.id.asc())
            .first()
        )
        is_new = row is None
        if row is None:
            row = AccountingAccount(
                account_framework="SKR03",
                account_number=account_number,
                created_at=_utcnow_naive(),
            )
        row.label = str(payload.get("accountName") or row.label or account_number).strip()
        row.category = str(row.category or "Sachkonto").strip() or "Sachkonto"
        row.source_type = "sevdesk"
        row.sevdesk_account_datev_id = str(payload.get("accountDatevId") or row.sevdesk_account_datev_id or "").strip() or row.sevdesk_account_datev_id
        allowed_tax_rules = payload.get("allowedTaxRules") if isinstance(payload, dict) else []
        if isinstance(allowed_tax_rules, list) and allowed_tax_rules:
            first_rule = allowed_tax_rules[0] if isinstance(allowed_tax_rules[0], dict) else {}
            if isinstance(first_rule, dict):
                first_rule_id = str(first_rule.get("id") or "").strip()
                if first_rule_id:
                    row.default_tax_rule_id = first_rule_id
        description_parts = [
            str(payload.get("description") or "").strip(),
            " ".join([str(item or "").strip() for item in list(payload.get("allowedReceiptTypes") or []) if str(item or "").strip()]),
        ]
        description_text = " | ".join([part for part in description_parts if part])
        if description_text and not str(row.note or "").strip():
            row.note = description_text[:500]
        keywords = [str(payload.get("accountName") or "").strip().lower()]
        for token in re.split(r"[^a-z0-9]+", str(payload.get("description") or "").lower()):
            token = str(token or "").strip()
            if len(token) >= 4:
                keywords.append(token)
        merged_keywords = list(dict.fromkeys([item for item in _accounting_account_keywords(row) + keywords if item]))[:18]
        if merged_keywords:
            row.keywords_json = json.dumps(merged_keywords, ensure_ascii=False)
        row.active = True
        row.updated_at = _utcnow_naive()
        db.add(row)
        summary["created" if is_new else "updated"] += 1
    db.flush()
    return summary


def _find_accounting_account_by_number(db: Session, account_number: str | None) -> AccountingAccount | None:
    number = _accounting_account_value(account_number)
    if not number:
        return None
    return (
        db.query(AccountingAccount)
        .filter(AccountingAccount.account_number == number)
        .order_by(AccountingAccount.favorite.desc(), AccountingAccount.id.asc())
        .first()
    )


def _purchase_document_supported(filename: str | None, mime_type: str | None) -> bool:
    name = str(filename or "").strip().lower()
    mime = str(mime_type or "").strip().lower()
    if name.endswith((".pdf", ".png", ".jpg", ".jpeg")):
        return True
    return mime in {"application/pdf", "image/png", "image/jpeg", "image/jpg"}


def _purchase_document_storage_path(original_name: str | None) -> Path:
    safe_name = re.sub(r"[^A-Za-z0-9._-]+", "_", Path(str(original_name or "").strip()).name or "beleg").strip("._") or "beleg"
    rel_dir = Path(PURCHASE_DOCUMENT_INBOX_DIRNAME)
    abs_dir = ensure_dirs()["uploads"] / rel_dir
    abs_dir.mkdir(parents=True, exist_ok=True)
    file_name = f"{dt.datetime.utcnow().strftime('%Y%m%d%H%M%S')}_{uuid.uuid4().hex[:8]}_{safe_name}"
    return abs_dir / file_name


def _purchase_document_merge_metadata(existing_raw: str | None, payload: dict[str, object] | None = None) -> dict[str, object]:
    merged = _json_dict(existing_raw)
    if isinstance(payload, dict):
        merged.update(payload)
    return merged


def _document_inbox_kind_choices() -> list[tuple[str, str]]:
    return [
        ("eingangsrechnung", "Eingangsrechnung"),
        ("ausgangsrechnung", "Ausgangsrechnung"),
        ("lieferschein", "Lieferschein"),
        ("avis", "AVIS"),
        ("kontoauszug", "Kontoauszug"),
        ("gutschrift", "Gutschrift"),
        ("bonus", "Bonus"),
        ("verrechnung", "Verrechnung"),
        ("bestellung", "Bestellung"),
        ("servicebericht", "Servicebericht"),
        ("sonstiges", "Sonstiges"),
    ]


def _document_inbox_workflow_choices() -> list[tuple[str, str]]:
    return [
        ("draft", "Entwurf"),
        ("classified", "Klassifiziert"),
        ("matched", "Zugeordnet"),
        ("prepared", "Erfasst"),
        ("synced", "Nach sevDesk gespiegelt"),
        ("settled", "Abgeglichen"),
    ]


def _document_inbox_normalize_kind(value: str | None) -> str:
    key = _crm_normalize_key(value)
    mapping = {
        "eingangsrechnung": "eingangsrechnung",
        "incominginvoice": "eingangsrechnung",
        "ausgangsrechnung": "ausgangsrechnung",
        "outgoinginvoice": "ausgangsrechnung",
        "kundenrechnung": "ausgangsrechnung",
        "lieferschein": "lieferschein",
        "wareneingang": "lieferschein",
        "deliverynote": "lieferschein",
        "avis": "avis",
        "zahlungsavis": "avis",
        "kontoauszug": "kontoauszug",
        "bankstatement": "kontoauszug",
        "gutschrift": "gutschrift",
        "creditnote": "gutschrift",
        "bonus": "bonus",
        "verrechnung": "verrechnung",
        "bestellung": "bestellung",
        "purchaseorder": "bestellung",
        "service": "servicebericht",
        "servicebericht": "servicebericht",
        "sonstiges": "sonstiges",
        "sonstige": "sonstiges",
        "other": "sonstiges",
    }
    return mapping.get(key, "")


def _document_inbox_kind_label(value: str | None) -> str:
    key = _document_inbox_normalize_kind(value)
    labels = {item[0]: item[1] for item in _document_inbox_kind_choices()}
    return labels.get(key, "Offen")


def _document_inbox_normalize_workflow(value: str | None) -> str:
    key = _crm_normalize_key(value)
    mapping = {
        "draft": "draft",
        "entwurf": "draft",
        "classified": "classified",
        "klassifiziert": "classified",
        "matched": "matched",
        "zugeordnet": "matched",
        "prepared": "prepared",
        "erfasst": "prepared",
        "synced": "synced",
        "gespiegelt": "synced",
        "settled": "settled",
        "abgeglichen": "settled",
        "bezahlt": "settled",
    }
    return mapping.get(key, "")


def _document_inbox_workflow_label(value: str | None) -> str:
    key = _document_inbox_normalize_workflow(value)
    labels = {item[0]: item[1] for item in _document_inbox_workflow_choices()}
    return labels.get(key, "Entwurf")


def _document_inbox_workflow_rank(value: str | None) -> int:
    key = _document_inbox_normalize_workflow(value)
    order = {"draft": 0, "classified": 1, "matched": 2, "prepared": 3, "synced": 4, "settled": 5}
    return int(order.get(key, 0))


def _document_inbox_effective_workflow_state(item: DocumentInboxItem | None) -> str:
    if item is None:
        return "draft"
    value = _document_inbox_normalize_workflow(getattr(item, "workflow_state", ""))
    if value:
        return value
    if str(getattr(item, "suggested_object_type", "") or "").strip() and int(getattr(item, "suggested_object_id", 0) or 0) > 0:
        if str(getattr(item, "suggested_object_type", "") or "").strip() in {"purchase_order", "goods_receipt", "purchase_invoice", "incoming_voucher_draft", "invoice_draft"}:
            return "prepared"
        return "matched"
    if _document_inbox_normalize_kind(getattr(item, "draft_kind", "")):
        return "classified"
    return "draft"


def _document_inbox_progress_state(item: DocumentInboxItem, workflow_state: str | None, *, force: bool = False) -> DocumentInboxItem:
    desired = _document_inbox_normalize_workflow(workflow_state)
    if not desired:
        return item
    current = _document_inbox_effective_workflow_state(item)
    if force or _document_inbox_workflow_rank(desired) >= _document_inbox_workflow_rank(current):
        item.workflow_state = desired
    return item


def _document_inbox_guess_kind(item: DocumentInboxItem | None, *, ai_output: dict[str, object] | None = None) -> str:
    if item is None:
        return ""
    meta = _json_dict(item.metadata_json)
    text = "\n".join(
        [
            str(getattr(item, "title", "") or ""),
            str(getattr(item, "correspondent", "") or ""),
            str(getattr(item, "document_type", "") or ""),
            str(meta.get("original_file_name") or ""),
            str(meta.get("subject") or ""),
            str(meta.get("ocr") or ""),
            str(meta.get("content") or ""),
        ]
    ).lower()
    if any(token in text for token in ("kontoauszug", "bank statement", "umsatzanzeige")):
        return "kontoauszug"
    if any(token in text for token in ("zahlungsavis", "avis", "remittance advice")):
        return "avis"
    if any(token in text for token in ("bonusabrechnung", "bonusvereinbarung", "jahresbonus")):
        return "bonus"
    if any(token in text for token in ("verrechnung", "aufrechnung", "saldenausgleich")):
        return "verrechnung"
    if any(token in text for token in ("gutschrift", "credit note", "storno")):
        return "gutschrift"
    if any(token in text for token in ("ausgangsrechnung", "kundenrechnung")):
        return "ausgangsrechnung"
    if any(token in text for token in ("lieferschein", "delivery note", "lieferung")):
        return "lieferschein"
    if any(token in text for token in ("bestellung", "purchase order", "order no")):
        return "bestellung"
    if any(token in text for token in ("servicebericht", "kundendienst", "einsatzbericht", "reparaturbericht")):
        return "servicebericht"
    ai_kind = _document_inbox_normalize_kind(str((ai_output or {}).get("doc_kind") or ""))
    if ai_kind:
        return ai_kind
    if any(token in text for token in ("rechnung", "invoice", "rg-", "beleg")):
        return "eingangsrechnung"
    return ""


def _document_inbox_apply_classification(
    item: DocumentInboxItem,
    *,
    draft_kind: str | None = None,
    workflow_state: str | None = None,
) -> DocumentInboxItem:
    if draft_kind is not None:
        normalized_kind = _document_inbox_normalize_kind(draft_kind)
        item.draft_kind = normalized_kind or None
        if normalized_kind:
            _document_inbox_progress_state(item, "classified")
        elif not str(getattr(item, "suggested_object_type", "") or "").strip():
            item.workflow_state = "draft"
    if workflow_state is not None:
        normalized_workflow = _document_inbox_normalize_workflow(workflow_state)
        item.workflow_state = normalized_workflow or None
    return item


def _document_inbox_next_action(item: DocumentInboxItem | None, *, draft_kind: str | None = None) -> dict[str, str]:
    if item is None or int(getattr(item, "id", 0) or 0) <= 0:
        return {"label": "", "url": "", "hint": ""}
    kind = _document_inbox_normalize_kind(draft_kind) or _document_inbox_normalize_kind(getattr(item, "draft_kind", ""))
    if kind in {"eingangsrechnung", "gutschrift", "bonus", "verrechnung"}:
        return {
            "label": "Zur Ausgabe-Erfassung",
            "url": f"/einkauf/voucher/vorbereiten?document_inbox_id={int(item.id)}",
            "hint": "Beleg wird als Eingangsbeleg in die Voucher-Erfassung übernommen.",
        }
    if kind == "avis":
        return {
            "label": "Zum AVIS-Klärfall",
            "url": f"/finanzen/abgleich?document_inbox_id={int(item.id)}",
            "hint": "AVIS wird in den Zahlungsabgleich mit Transaktions- und Voucher-Vorschlägen überführt.",
        }
    if kind == "lieferschein":
        return {
            "label": "Zum Wareneingang",
            "url": f"/einkauf/wareneingaenge/neu?document_inbox_id={int(item.id)}",
            "hint": "Lieferschein wird in den Wareneingang überführt.",
        }
    if kind == "bestellung":
        return {
            "label": "Zur Bestellung",
            "url": f"/einkauf/bestellungen/neu?document_inbox_id={int(item.id)}",
            "hint": "Dokument wird in die Bestellerfassung überführt.",
        }
    if kind == "ausgangsrechnung":
        return {
            "label": "Zur Ausgangsrechnung",
            "url": f"/crm/rechnungen/neu?document_inbox_id={int(item.id)}",
            "hint": "Dokument wird in die CRM-Rechnungserfassung übernommen.",
        }
    if kind == "kontoauszug":
        return {
            "label": "Zum Kontoabgleich",
            "url": f"/finanzen/abgleich?document_inbox_id={int(item.id)}",
            "hint": "Kontoauszug wird mit sevDesk-Transaktionen und offenen Belegen abgeglichen.",
        }
    if kind == "servicebericht":
        return {
            "label": "",
            "url": "",
            "hint": "Für diesen Belegtyp ist der spezialisierte Erfassungsweg noch nicht separat verdrahtet.",
        }
    return {"label": "", "url": "", "hint": "Belegtyp festlegen, um den passenden Erfassungsweg zu öffnen."}


def _document_inbox_overview(
    db: Session,
    item: DocumentInboxItem | None,
    *,
    source_view: dict[str, object] | None = None,
    ai_output: dict[str, object] | None = None,
) -> dict[str, object]:
    if item is None:
        return {
            "source": source_view or {},
            "draft_kind": "",
            "draft_kind_label": "Offen",
            "suggested_kind": "",
            "suggested_kind_label": "",
            "workflow_state": "draft",
            "workflow_label": "Entwurf",
            "next_action": {"label": "", "url": "", "hint": ""},
        }
    source = source_view or _document_inbox_source_view(db, item)
    current_kind = _document_inbox_normalize_kind(getattr(item, "draft_kind", ""))
    suggested_kind = _document_inbox_guess_kind(item, ai_output=ai_output) if not current_kind else ""
    effective_kind = current_kind or suggested_kind
    workflow_state = _document_inbox_effective_workflow_state(item)
    return {
        "source": source,
        "draft_kind": current_kind,
        "draft_kind_label": _document_inbox_kind_label(current_kind),
        "suggested_kind": suggested_kind,
        "suggested_kind_label": _document_inbox_kind_label(suggested_kind) if suggested_kind else "",
        "effective_kind": effective_kind,
        "effective_kind_label": _document_inbox_kind_label(effective_kind),
        "workflow_state": workflow_state,
        "workflow_label": _document_inbox_workflow_label(workflow_state),
        "next_action": _document_inbox_next_action(item, draft_kind=effective_kind),
    }


def _document_inbox_ai_input_payload(item: DocumentInboxItem) -> dict[str, object]:
    return {
        "paperless_document_id": str(item.paperless_document_id or ""),
        "title": str(item.title or ""),
        "correspondent": str(item.correspondent or ""),
        "document_type": str(item.document_type or ""),
        "metadata": str(item.metadata_json or ""),
    }


def _document_inbox_ai_result(db: Session, item: DocumentInboxItem) -> dict[str, object] | None:
    return ai_classify_document(
        db,
        settings=_openai_settings(db, include_secret=True),
        input_payload=_document_inbox_ai_input_payload(item),
        related_object_id=int(item.id),
    )


def _document_inbox_source_kind(item: DocumentInboxItem | None, meta: dict[str, object] | None = None) -> str:
    if item is None:
        return ""
    meta = meta if isinstance(meta, dict) else _json_dict(item.metadata_json)
    value = str(getattr(item, "source_kind", "") or "").strip().lower()
    if value == "mail_attachment":
        return "email_attachment"
    if value:
        return value
    meta_source = str(meta.get("source") or "").strip().lower()
    if meta_source == "mail_attachment":
        return "email_attachment"
    if meta_source:
        return meta_source
    if int(getattr(item, "source_mail_attachment_id", 0) or _to_int(meta.get("attachment_id"), 0)) > 0:
        return "email_attachment"
    if str(getattr(item, "paperless_document_id", "") or "").strip():
        return "paperless"
    return ""


def _document_inbox_source_label(source_kind: str | None) -> str:
    mapping = {
        "paperless": "Paperless",
        "manual_upload": "Upload",
        "local_upload": "Upload",
        "email_attachment": "E-Mail",
    }
    key = str(source_kind or "").strip().lower()
    if key == "mail_attachment":
        key = "email_attachment"
    return mapping.get(key, key or "-")


def _document_inbox_apply_source(
    item: DocumentInboxItem,
    *,
    source_kind: str | None = None,
    mail_thread_id: int | None = None,
    mail_message_id: int | None = None,
    mail_attachment_id: int | None = None,
    metadata: dict[str, object] | None = None,
) -> DocumentInboxItem:
    meta = metadata if isinstance(metadata, dict) else {}
    resolved_kind = str(source_kind or meta.get("source") or "").strip().lower()
    if resolved_kind == "mail_attachment":
        resolved_kind = "email_attachment"
    if resolved_kind:
        item.source_kind = resolved_kind
    if mail_thread_id is None:
        mail_thread_id = _to_int(meta.get("mail_thread_id"), 0) or None
    if mail_message_id is None:
        mail_message_id = _to_int(meta.get("mail_message_id"), 0) or None
    if mail_attachment_id is None:
        mail_attachment_id = _to_int(meta.get("attachment_id"), 0) or None
    item.source_mail_thread_id = int(mail_thread_id) if int(mail_thread_id or 0) > 0 else item.source_mail_thread_id
    item.source_mail_message_id = int(mail_message_id) if int(mail_message_id or 0) > 0 else item.source_mail_message_id
    item.source_mail_attachment_id = int(mail_attachment_id) if int(mail_attachment_id or 0) > 0 else item.source_mail_attachment_id
    return item


def _document_inbox_source_view(
    db: Session,
    item: DocumentInboxItem | None,
    *,
    meta: dict[str, object] | None = None,
    message_lookup: dict[int, EmailMessage] | None = None,
    thread_lookup: dict[int, MailThread] | None = None,
) -> dict[str, object]:
    if item is None:
        return {"kind": "", "label": "-", "tone": "draft", "detail": "", "subject": "", "from_email": "", "mail_url": ""}
    meta = meta if isinstance(meta, dict) else _json_dict(item.metadata_json)
    kind = _document_inbox_source_kind(item, meta)
    message_id = int(getattr(item, "source_mail_message_id", 0) or _to_int(meta.get("mail_message_id"), 0) or 0)
    attachment_id = int(getattr(item, "source_mail_attachment_id", 0) or _to_int(meta.get("attachment_id"), 0) or 0)
    thread_id = int(getattr(item, "source_mail_thread_id", 0) or _to_int(meta.get("mail_thread_id"), 0) or 0)
    message = None
    if message_id > 0:
        message = message_lookup.get(message_id) if message_lookup is not None else db.get(EmailMessage, message_id)
        if thread_id <= 0 and message is not None and int(message.thread_id or 0) > 0:
            thread_id = int(message.thread_id or 0)
    thread = thread_lookup.get(thread_id) if thread_lookup is not None and thread_id > 0 else (db.get(MailThread, thread_id) if thread_id > 0 else None)
    subject = str(getattr(message, "subject", "") or meta.get("subject") or "").strip()
    from_email = str(getattr(message, "from_email", "") or meta.get("from_email") or "").strip()
    original_name = str(meta.get("original_file_name") or meta.get("filename") or "").strip()
    detail = ""
    tone = "draft"
    if kind == "email_attachment":
        tone = "match"
        detail = " | ".join([part for part in [from_email, subject] if part]) or (f"Anhang #{attachment_id}" if attachment_id > 0 else "")
    elif kind in {"manual_upload", "local_upload"}:
        tone = "open"
        detail = original_name or "Manuell hochgeladen"
    else:
        tone = "draft"
        detail = str(item.correspondent or "").strip()
    if not detail and thread is not None:
        detail = str(thread.subject_normalized or "").strip()
    mail_url = f"/mail/threads/{thread_id}#mail-message-{message_id}" if thread_id > 0 and message_id > 0 else ""
    return {
        "kind": kind,
        "label": _document_inbox_source_label(kind),
        "tone": tone,
        "detail": detail,
        "subject": subject,
        "from_email": from_email,
        "mail_url": mail_url,
    }


def _document_inbox_source_views(db: Session, items: list[DocumentInboxItem]) -> dict[int, dict[str, object]]:
    meta_map = {int(item.id): _json_dict(item.metadata_json) for item in items if item is not None}
    message_ids: set[int] = set()
    thread_ids: set[int] = set()
    for item in items:
        if item is None:
            continue
        meta = meta_map.get(int(item.id), {})
        message_id = int(getattr(item, "source_mail_message_id", 0) or _to_int(meta.get("mail_message_id"), 0) or 0)
        thread_id = int(getattr(item, "source_mail_thread_id", 0) or _to_int(meta.get("mail_thread_id"), 0) or 0)
        if message_id > 0:
            message_ids.add(message_id)
        if thread_id > 0:
            thread_ids.add(thread_id)
    message_lookup = {
        int(row.id): row
        for row in db.query(EmailMessage).filter(EmailMessage.id.in_(sorted(message_ids))).all()
    } if message_ids else {}
    for row in message_lookup.values():
        if int(row.thread_id or 0) > 0:
            thread_ids.add(int(row.thread_id or 0))
    thread_lookup = {
        int(row.id): row
        for row in db.query(MailThread).filter(MailThread.id.in_(sorted(thread_ids))).all()
    } if thread_ids else {}
    return {
        int(item.id): _document_inbox_source_view(
            db,
            item,
            meta=meta_map.get(int(item.id), {}),
            message_lookup=message_lookup,
            thread_lookup=thread_lookup,
        )
        for item in items
        if item is not None
    }


def _purchase_document_source_abs_path(db: Session, item: DocumentInboxItem) -> Path | None:
    meta = _json_dict(item.metadata_json)
    local_path = str(meta.get("local_file_path") or "").strip()
    if local_path:
        abs_path = Path(local_path)
        if abs_path.is_file():
            return abs_path
    attachment_id = int(getattr(item, "source_mail_attachment_id", 0) or _to_int(meta.get("attachment_id"), 0) or 0)
    if attachment_id > 0:
        attachment = db.get(MailAttachment, attachment_id)
        if attachment is not None:
            return _mail_attachment_abs_path(attachment.file_path)
    return None


def _purchase_document_preview_kind(db: Session, item: DocumentInboxItem) -> str:
    abs_path = _purchase_document_source_abs_path(db, item)
    if abs_path is None:
        return "remote"
    suffix = abs_path.suffix.lower()
    if suffix == ".pdf":
        return "pdf"
    if suffix in {".png", ".jpg", ".jpeg"}:
        return "image"
    return "file"


def _purchase_document_text(db: Session, item: DocumentInboxItem) -> str:
    meta = _json_dict(item.metadata_json)
    for key in ("content", "ocr", "text"):
        value = str(meta.get(key) or "").strip()
        if value:
            return value
    abs_path = _purchase_document_source_abs_path(db, item)
    if abs_path is not None and abs_path.suffix.lower() == ".pdf":
        try:
            return str(agreement_extract_pdf_text(abs_path) or "").strip()
        except Exception:
            return ""
    return ""


def _purchase_document_extract_result(db: Session, item: DocumentInboxItem) -> dict[str, object] | None:
    supplier_name = str(item.correspondent or "").strip()
    input_payload = {
        "text": _purchase_document_text(db, item),
        "description": str(item.title or "").strip(),
        "supplier_name": supplier_name,
        "correspondent": supplier_name,
        "paperless_document_id": str(item.paperless_document_id or "").strip(),
    }
    if not any(str(value or "").strip() for value in input_payload.values()):
        return None
    return ai_extract_incoming_invoice(
        db,
        settings=_openai_settings(db, include_secret=True),
        input_payload=input_payload,
        related_object_type="document_inbox_item",
        related_object_id=int(item.id),
    )


def _purchase_document_prefill(
    db: Session,
    item: DocumentInboxItem,
) -> tuple[dict[str, str | list[str]], int, list[dict[str, str]], dict[str, object] | None]:
    extract_result = _purchase_document_extract_result(db, item)
    extract_output = dict((extract_result or {}).get("output") or {})
    supplier_id = _to_int(extract_output.get("supplier_candidate"), 0)
    supplier = db.get(Supplier, supplier_id) if supplier_id > 0 else None
    description = str(extract_output.get("invoice_no") or item.title or "").strip()
    net_total = extract_output.get("amounts", {}).get("net_total") if isinstance(extract_output.get("amounts"), dict) else None
    tax_total = extract_output.get("amounts", {}).get("tax_total") if isinstance(extract_output.get("amounts"), dict) else None
    gross_total = extract_output.get("amounts", {}).get("gross_total") if isinstance(extract_output.get("amounts"), dict) else None
    ai_voucher_result = ai_suggest_voucher_accounting(
        db,
        settings=_openai_settings(db, include_secret=True),
        input_payload={
            "text": _purchase_document_text(db, item),
            "description": description,
            "supplier_name": supplier.name if supplier else str(item.correspondent or ""),
        },
        related_object_id=int(item.id),
    ) if description or supplier else None
    ai_voucher_output = dict((ai_voucher_result or {}).get("output") or {})
    line_rows = _voucher_line_rows([])
    line_rows[0]["account_datev_id"] = str(ai_voucher_output.get("suggested_account_datev") or "")
    line_rows[0]["tax_rule_id"] = str(ai_voucher_output.get("suggested_tax_rule") or "")
    line_rows[0]["cost_center_id"] = str(ai_voucher_output.get("suggested_cost_center") or "")
    line_rows[0]["comment"] = description
    if net_total is not None:
        line_rows[0]["sum_net"] = _format_eur(_to_int(net_total)).replace(" €", "")
    if gross_total is not None:
        line_rows[0]["sum_gross"] = _format_eur(_to_int(gross_total)).replace(" €", "")
    form_data: dict[str, str | list[str]] = {
        "description": description,
        "linked_document_id": str(item.paperless_document_id or ""),
        "paperless_document_id": str(item.paperless_document_id or ""),
        "document_inbox_id": str(int(item.id)),
        "voucher_date": str(extract_output.get("invoice_date") or ""),
        "due_date": str(extract_output.get("due_date") or ""),
        "net_total": _format_eur(int(net_total)).replace(" €", "") if net_total is not None else "",
        "tax_total": _format_eur(int(tax_total)).replace(" €", "") if tax_total is not None else "",
        "gross_total": _format_eur(int(gross_total)).replace(" €", "") if gross_total is not None else "",
        "currency": "EUR",
    }
    return form_data, int(supplier.id) if supplier else 0, line_rows, extract_result


def _document_inbox_finance_context(db: Session, item: DocumentInboxItem | None) -> dict[str, object]:
    if item is None or int(getattr(item, "id", 0) or 0) <= 0:
        return {
            "kind": "",
            "kind_label": "",
            "search_query": "",
            "date_from": "",
            "date_to": "",
            "payment_match": {"rows": [], "best": None, "auto_candidate": None, "error": ""},
            "voucher_candidates": [],
            "extract_result": None,
            "supplier_name": "",
            "invoice_no": "",
            "gross_total": 0,
            "stored_match": None,
        }
    extract_result = _purchase_document_extract_result(db, item)
    extract_output = dict((extract_result or {}).get("output") or {})
    amount_payload = extract_output.get("amounts") if isinstance(extract_output.get("amounts"), dict) else {}
    gross_total = _to_int(amount_payload.get("gross_total"), 0)
    supplier_id = _to_int(extract_output.get("supplier_candidate"), 0)
    supplier = db.get(Supplier, supplier_id) if supplier_id > 0 else None
    source_view = _document_inbox_source_view(db, item)
    supplier_name = str(getattr(supplier, "name", "") or item.correspondent or source_view.get("from_email") or "").strip()
    invoice_no = str(extract_output.get("invoice_no") or "").strip()
    description = str(invoice_no or item.title or source_view.get("subject") or "").strip()
    voucher_date = _crm_coerce_datetime(extract_output.get("invoice_date"))
    due_date = _crm_coerce_datetime(extract_output.get("due_date"))
    context = _voucher_match_context(
        None,
        supplier_name=supplier_name,
        purchase_invoice_no=invoice_no,
        description=description,
        gross_total=gross_total,
        voucher_date=voucher_date,
        due_date=due_date,
    )
    settings = _sevdesk_settings(db, include_secret=True)
    payment_match = _voucher_transaction_candidate_rows(db, settings, context=context, limit=8)
    reference_tokens = [str(token or "").strip() for token in list(context.get("reference_tokens") or []) if str(token or "").strip()]
    search_terms: list[str] = []
    if supplier_name:
        search_terms.append(supplier_name)
    if invoice_no:
        search_terms.append(invoice_no)
    elif reference_tokens:
        search_terms.append(reference_tokens[0])
    elif str(source_view.get("subject") or "").strip():
        search_terms.append(str(source_view.get("subject") or "").strip())
    search_query = " ".join(dict.fromkeys([term for term in search_terms if term]))[:140]
    anchor_ts = item.created_date or voucher_date or due_date or _utcnow_naive()
    date_from = (anchor_ts.date() - dt.timedelta(days=45)).isoformat()
    date_to = (anchor_ts.date() + dt.timedelta(days=45)).isoformat()
    document_text = "\n".join(
        [
            str(item.title or ""),
            str(item.correspondent or ""),
            str(source_view.get("subject") or ""),
            _purchase_document_text(db, item),
        ]
    )
    document_text_norm = _crm_normalize_key(document_text)
    document_text_lower = document_text.lower()
    voucher_rows = (
        db.query(IncomingVoucherDraft)
        .filter(IncomingVoucherDraft.status.in_(("prepared", "pushed", "booked")))
        .order_by(IncomingVoucherDraft.due_date.asc(), IncomingVoucherDraft.id.desc())
        .limit(80)
        .all()
    )
    supplier_map = {int(row.id): row for row in _active_suppliers(db)}
    invoice_map = {
        int(row.id): row
        for row in db.query(PurchaseInvoice)
        .filter(PurchaseInvoice.id.in_([int(entry.purchase_invoice_id) for entry in voucher_rows if int(entry.purchase_invoice_id or 0) > 0]))
        .all()
    } if voucher_rows else {}
    voucher_candidates: list[dict[str, object]] = []
    supplier_name_norm = _crm_normalize_key(supplier_name)
    for row in voucher_rows:
        supplier_row = supplier_map.get(int(row.supplier_id or 0))
        purchase_invoice = invoice_map.get(int(row.purchase_invoice_id or 0))
        voucher_context = _voucher_match_context(
            row,
            supplier_name=str(getattr(supplier_row, "name", "") or ""),
            purchase_invoice_no=str(getattr(purchase_invoice, "invoice_no", "") or ""),
        )
        reasons: list[str] = []
        score = 0
        row_amount = abs(int(row.gross_total or 0))
        if gross_total > 0 and row_amount == abs(int(gross_total)):
            score += 1
            reasons.append("Betrag identisch")
        supplier_row_norm = _crm_normalize_key(str(getattr(supplier_row, "name", "") or ""))
        if supplier_name_norm and supplier_row_norm and (supplier_name_norm in supplier_row_norm or supplier_row_norm in document_text_norm):
            score += 1
            reasons.append("Lieferant erkannt")
        ref_hits = [token for token in list(voucher_context.get("reference_tokens") or []) if str(token or "").lower() in document_text_lower]
        if ref_hits:
            score += 1
            reasons.append("Referenz erkannt")
        if score <= 0:
            continue
        voucher_candidates.append(
            {
                "row": row,
                "supplier": supplier_row,
                "invoice": purchase_invoice,
                "score": score,
                "reasons": reasons,
                "gross_total": row_amount,
            }
        )
    voucher_candidates.sort(
        key=lambda payload: (
            -int(payload.get("score") or 0),
            abs(int(payload.get("gross_total") or 0) - abs(int(gross_total or 0))) if gross_total else 0,
            int(payload["row"].id),
        )
    )
    draft_kind = _document_inbox_normalize_kind(getattr(item, "draft_kind", "")) or _document_inbox_guess_kind(item)
    return {
        "kind": draft_kind,
        "kind_label": _document_inbox_kind_label(draft_kind),
        "search_query": search_query,
        "date_from": date_from,
        "date_to": date_to,
        "payment_match": payment_match,
        "voucher_candidates": voucher_candidates[:10],
        "extract_result": extract_result,
        "supplier_name": supplier_name,
        "invoice_no": invoice_no,
        "gross_total": gross_total,
        "stored_match": _transaction_match_view(
            _transaction_match_link(db, object_type="document_inbox_item", object_id=int(item.id)),
            document_inbox_id=int(item.id),
        ),
    }


def _purchase_document_upload_to_inbox(
    db: Session,
    *,
    abs_path: Path,
    title: str,
    mime_type: str,
    metadata: dict[str, object] | None = None,
    created_at: dt.datetime | None = None,
) -> DocumentInboxItem:
    settings = _paperless_settings(db, include_secret=True)
    if not bool(settings.get("enabled")) or not bool(str(settings.get("base_url") or "").strip()):
        raise ValueError("Paperless ist für den Einkaufs-Dokumenteneingang erforderlich.")
    result = paperless_upload_document(
        abs_path,
        settings,
        title=title,
        mime=mime_type or "application/octet-stream",
        created=(created_at or _utcnow_naive()).date().isoformat(),
    )
    document_id = str(result.get("document_id") or "").strip()
    if not document_id:
        raise ValueError("Paperless hat keine Dokument-ID zurückgegeben.")
    item = None
    try:
        payload = paperless_get_document(settings, document_id)
        if payload:
            item = _upsert_document_inbox_item(db, payload)
    except Exception:
        item = None
    if item is None:
        item = _document_inbox_item_from_paperless_id(db, document_id)
    if item is None:
        item = DocumentInboxItem(
            paperless_document_id=document_id,
            title=title,
            source_kind="paperless",
            workflow_state="draft",
            status="new",
            created_date=created_at or _utcnow_naive(),
            created_at=_utcnow_naive(),
        )
    item.title = str(item.title or title or "").strip() or item.title
    item.status = "new"
    if not str(item.workflow_state or "").strip():
        item.workflow_state = _document_inbox_effective_workflow_state(item)
    merged_meta = _purchase_document_merge_metadata(item.metadata_json, metadata or {})
    _document_inbox_apply_source(item, metadata=merged_meta)
    item.metadata_json = json.dumps(merged_meta, ensure_ascii=False) if merged_meta else item.metadata_json
    if item.created_date is None:
        item.created_date = created_at or _utcnow_naive()
    db.add(item)
    db.flush()
    return item


def _purchase_auto_import_mail_attachments(db: Session, *, limit: int = 3) -> dict[str, int]:
    enabled = _bool_from_setting(_system_setting_get(db, PURCHASE_AUTO_IMPORT_MAIL, "1"), default=True)
    settings = _paperless_settings(db, include_secret=True)
    if not enabled or not bool(settings.get("enabled")) or not bool(settings.get("token")):
        return {"processed": 0, "imported": 0, "errors": 0}
    last_attachment_id = _to_int(_system_setting_get(db, PURCHASE_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, "0"), 0)
    rows = (
        db.query(MailAttachment, EmailMessage)
        .join(EmailMessage, EmailMessage.id == MailAttachment.mail_message_id)
        .filter(MailAttachment.id > int(last_attachment_id))
        .order_by(MailAttachment.id.asc())
        .limit(max(1, int(limit)))
        .all()
    )
    processed = 0
    imported = 0
    errors = 0
    current_last_id = int(last_attachment_id)
    for attachment, message in rows:
        current_last_id = max(current_last_id, int(attachment.id))
        if str(message.assignment_status or "").strip().lower() == "spam":
            processed += 1
            _system_setting_set(db, PURCHASE_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, str(current_last_id))
            db.commit()
            continue
        if not _purchase_document_supported(attachment.filename, attachment.mime_type):
            processed += 1
            _system_setting_set(db, PURCHASE_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, str(current_last_id))
            db.commit()
            continue
        if str(attachment.paperless_document_id or "").strip():
            processed += 1
            _system_setting_set(db, PURCHASE_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, str(current_last_id))
            db.commit()
            continue
        abs_path = _mail_attachment_abs_path(attachment.file_path)
        if abs_path is None or not abs_path.is_file():
            errors += 1
            processed += 1
            _system_setting_set(db, PURCHASE_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, str(current_last_id))
            db.commit()
            continue
        try:
            item = _purchase_document_upload_to_inbox(
                db,
                abs_path=abs_path,
                title=str(attachment.filename or abs_path.name),
                mime_type=str(attachment.mime_type or "application/octet-stream"),
                metadata={
                    "source": "email_attachment",
                    "mail_thread_id": int(message.thread_id or 0),
                    "mail_message_id": int(message.id),
                    "attachment_id": int(attachment.id),
                    "local_file_path": str(abs_path),
                    "subject": str(message.subject or ""),
                    "from_email": str(message.from_email or ""),
                    "filename": str(attachment.filename or abs_path.name),
                },
                created_at=message.received_at or _utcnow_naive(),
            )
            attachment.paperless_document_id = str(item.paperless_document_id or "")
            db.add(attachment)
            imported += 1
        except Exception:
            errors += 1
        processed += 1
        _system_setting_set(db, PURCHASE_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, str(current_last_id))
        db.commit()
    return {"processed": processed, "imported": imported, "errors": errors}


def _document_object_url(object_type: str, object_id: int) -> str:
    mapping = {
        "document_inbox_item": f"/einkauf/dokumente/{int(object_id)}",
        "customer": f"/crm/kunden/{int(object_id)}",
        "case": f"/serviceauftraege/{int(object_id)}" if _internal_service_orders_enabled() else "",
        "purchase_order": f"/einkauf/bestellungen/{int(object_id)}",
        "goods_receipt": f"/einkauf/wareneingaenge/{int(object_id)}",
        "purchase_invoice": f"/einkauf/rechnungen/{int(object_id)}",
        "incoming_voucher_draft": f"/einkauf/voucher/{int(object_id)}",
        "invoice_draft": f"/crm/rechnungen/{int(object_id)}",
        "supplier": f"/stammdaten/lieferanten/{int(object_id)}",
        "repair_order": f"/inventory/reparaturen/{int(object_id)}",
        "supplier_condition_set": f"/einkauf/konditionen/{int(object_id)}",
    }
    return mapping.get(str(object_type or "").strip(), "")


def _document_object_exists(db: Session, object_type: str, object_id: int) -> bool:
    target_id = int(object_id or 0)
    if target_id <= 0:
        return False
    if str(object_type or "").strip() == "case" and not _internal_service_orders_enabled():
        return False
    mapping = {
        "document_inbox_item": DocumentInboxItem,
        "customer": MasterCustomer,
        "case": CrmCase,
        "purchase_order": PurchaseOrder,
        "goods_receipt": GoodsReceipt,
        "purchase_invoice": PurchaseInvoice,
        "incoming_voucher_draft": IncomingVoucherDraft,
        "invoice_draft": InvoiceDraft,
        "supplier": Supplier,
        "repair_order": RepairOrder,
        "supplier_condition_set": SupplierConditionSet,
    }
    model = mapping.get(str(object_type or "").strip())
    return bool(model and db.get(model, target_id))


def _document_object_label(db: Session, object_type: str, object_id: int) -> str:
    target_id = int(object_id or 0)
    if target_id <= 0:
        return "-"
    kind = str(object_type or "").strip()
    if kind == "document_inbox_item":
        row = db.get(DocumentInboxItem, target_id)
        return f"Beleg-Entwurf | {str(getattr(row, 'title', '') or getattr(row, 'paperless_document_id', '') or f'Dokument {target_id}')}" if row else "-"
    if kind == "customer":
        row = db.get(MasterCustomer, target_id)
        if not row:
            return "-"
        party = db.get(Party, int(row.party_id))
        return f"{row.customer_no_internal} | {party.display_name if party else 'Kunde'}"
    if kind == "case":
        if not _internal_service_orders_enabled():
            return "-"
        row = db.get(CrmCase, target_id)
        return f"{row.case_no} | {row.title}" if row else "-"
    if kind == "purchase_order":
        row = db.get(PurchaseOrder, target_id)
        return (row.order_no or row.po_number) if row else "-"
    if kind == "goods_receipt":
        row = db.get(GoodsReceipt, target_id)
        return (row.receipt_no or f"WE-{target_id:06d}") if row else "-"
    if kind == "purchase_invoice":
        row = db.get(PurchaseInvoice, target_id)
        return row.invoice_no if row else "-"
    if kind == "incoming_voucher_draft":
        row = db.get(IncomingVoucherDraft, target_id)
        if row is None:
            return "-"
        return str(row.description or row.sevdesk_voucher_id or f"Voucher {int(row.id)}")
    if kind == "invoice_draft":
        row = db.get(InvoiceDraft, target_id)
        return _invoice_draft_reference_label(row) if row else "-"
    if kind == "supplier":
        row = db.get(Supplier, target_id)
        return row.name if row else "-"
    if kind == "repair_order":
        row = db.get(RepairOrder, target_id)
        return row.repair_no or f"REP-{target_id:06d}" if row else "-"
    if kind == "supplier_condition_set":
        row = db.get(SupplierConditionSet, target_id)
        return row.name if row else "-"
    return f"{kind} #{target_id}"


def _document_link_item_to_target(
    db: Session,
    *,
    item: DocumentInboxItem,
    object_type: str,
    object_id: int,
) -> None:
    target_type = str(object_type or "").strip()
    target_id = int(object_id or 0)
    if not _document_object_exists(db, target_type, target_id):
        raise ValueError("Zielobjekt wurde nicht gefunden.")
    document_tx_match = _transaction_match_link(db, object_type="document_inbox_item", object_id=int(item.id))
    _link_inbox_item_to_object(db, item=item, object_type=target_type, object_id=target_id)
    if target_type == "purchase_order":
        row = db.get(PurchaseOrder, target_id)
        if row and not str(row.paperless_document_id or "").strip():
            row.paperless_document_id = item.paperless_document_id
            db.add(row)
    elif target_type == "goods_receipt":
        row = db.get(GoodsReceipt, target_id)
        if row and not str(row.paperless_document_id or "").strip():
            row.paperless_document_id = item.paperless_document_id
            db.add(row)
    elif target_type == "purchase_invoice":
        row = db.get(PurchaseInvoice, target_id)
        if row and not str(row.paperless_document_id or "").strip():
            row.paperless_document_id = item.paperless_document_id
            db.add(row)
    elif target_type == "incoming_voucher_draft":
        row = db.get(IncomingVoucherDraft, target_id)
        if row and not str(row.paperless_document_id or "").strip():
            row.paperless_document_id = item.paperless_document_id
            db.add(row)
        if row is not None and document_tx_match is not None:
            _persist_transaction_match(
                db,
                object_type="incoming_voucher_draft",
                object_id=int(row.id),
                tx_id=str(document_tx_match.external_key or ""),
                check_account_id=str(document_tx_match.external_row_id or ""),
            )
    elif target_type == "invoice_draft":
        row = db.get(InvoiceDraft, target_id)
        if row is not None and document_tx_match is not None:
            _persist_transaction_match(
                db,
                object_type="invoice_draft",
                object_id=int(row.id),
                tx_id=str(document_tx_match.external_key or ""),
                check_account_id=str(document_tx_match.external_row_id or ""),
            )


def _document_inbox_item_from_paperless_id(db: Session, paperless_document_id: str | None) -> DocumentInboxItem | None:
    document_id = str(paperless_document_id or "").strip()
    if not document_id:
        return None
    return (
        db.query(DocumentInboxItem)
        .filter(DocumentInboxItem.paperless_document_id == document_id)
        .order_by(DocumentInboxItem.id.desc())
        .first()
    )


def _upsert_uploaded_document_item(
    db: Session,
    *,
    paperless_document_id: str,
    title: str,
    object_type: str,
    object_id: int,
    metadata: dict[str, object] | None = None,
) -> DocumentInboxItem:
    row = _document_inbox_item_from_paperless_id(db, paperless_document_id)
    if row is None:
        row = DocumentInboxItem(
            paperless_document_id=str(paperless_document_id),
            source_kind="paperless",
            workflow_state="draft",
            created_at=_utcnow_naive(),
        )
    row.title = str(title or "").strip() or row.title
    row.status = "matched"
    row.suggested_object_type = str(object_type or "").strip() or None
    row.suggested_object_id = int(object_id or 0) or None
    row.created_date = row.created_date or _utcnow_naive()
    if metadata:
        merged_meta = _purchase_document_merge_metadata(row.metadata_json, metadata)
        _document_inbox_apply_source(row, metadata=merged_meta)
        row.metadata_json = json.dumps(merged_meta, ensure_ascii=False)
    db.add(row)
    db.flush()
    return row


def _crm_first_service_location(db: Session, customer_id: int) -> ServiceLocation | None:
    if int(customer_id or 0) <= 0:
        return None
    return (
        db.query(ServiceLocation)
        .filter(ServiceLocation.master_customer_id == int(customer_id), ServiceLocation.active == True)
        .order_by(ServiceLocation.id.asc())
        .first()
    )


def _mail_thread_subject(thread: MailThread | None, messages: list[EmailMessage]) -> str:
    for row in reversed(messages):
        text = str(row.subject or "").strip()
        if text:
            return text
    subject = str(thread.subject_normalized if thread else "").strip()
    return subject or "(ohne Betreff)"


def _mail_default_recipient(db: Session, customer: MasterCustomer | None, crm_case: CrmCase | None = None) -> str:
    target_customer = customer
    if target_customer is None and crm_case is not None:
        role = (
            db.query(RoleAssignment)
            .filter(RoleAssignment.case_id == int(crm_case.id), RoleAssignment.role_type == CRM_ROLE_ORDERING_PARTY)
            .first()
        )
        if role and int(role.master_customer_id or 0) > 0:
            target_customer = db.get(MasterCustomer, int(role.master_customer_id))
    if target_customer is None:
        return ""
    contact = (
        db.query(CustomerContactPerson)
        .filter(
            CustomerContactPerson.master_customer_id == int(target_customer.id),
            CustomerContactPerson.active == True,
            CustomerContactPerson.email.is_not(None),
        )
        .order_by(CustomerContactPerson.id.asc())
        .first()
    )
    if contact and str(contact.email or "").strip():
        return str(contact.email or "").strip()
    default_address = (
        db.query(CrmAddress)
        .filter(CrmAddress.party_id == int(target_customer.party_id), CrmAddress.active == True)
        .order_by(CrmAddress.is_default.desc(), CrmAddress.id.asc())
        .first()
    )
    return str(default_address.email or "").strip() if default_address else ""


BACKGROUND_JOB_ACTIVE_STATUSES = ("queued", "running")
BACKGROUND_JOB_POLL_INTERVAL_SECONDS = 1.0
BACKGROUND_JOB_HEARTBEAT_TIMEOUT_SECONDS = 300


def _sync_job_progress_payload(raw: str | None) -> dict[str, object]:
    return _json_dict(raw)


def _sync_job_set_progress(row: ExternalSyncJob, payload: dict[str, object]) -> None:
    row.progress_json = json.dumps(payload, ensure_ascii=False) if payload else None


def _sync_job_progress_merge(row: ExternalSyncJob, updates: dict[str, object]) -> dict[str, object]:
    payload = _sync_job_progress_payload(row.progress_json)
    for key, value in updates.items():
        if value is None:
            continue
        payload[str(key)] = value
    _sync_job_set_progress(row, payload)
    return payload


def _sync_job_log_append_text(existing: str | None, text: str | None) -> str | None:
    current = str(existing or "").strip()
    addition = str(text or "").strip()
    if not addition:
        return current or None
    if not current:
        return addition
    if addition in current:
        return current
    return f"{current}\n{addition}"


def _sync_job_title_default(entity_type: str, system_name: str = "") -> str:
    mapping = {
        "customer_init_outsmart": "OutSmart-Initialimport",
        "customer_init_sevdesk": "sevDesk-Initialimport",
        "customer_init_matching": "Kunden-Matching",
        "customer_init_ai_review": "KI-Review Kunden-Initialisierung",
        "customer_init_materialize": "Master-Kunden erzeugen",
        "catalog_import_run": "CSV-Katalogimport",
    }
    key = str(entity_type or "").strip().lower()
    if key in mapping:
        return mapping[key]
    system = str(system_name or "").strip()
    if system:
        return f"{system}: {entity_type}"
    return str(entity_type or "Hintergrundjob")


def _sync_job_eta_seconds(row: ExternalSyncJob, progress: dict[str, object]) -> int | None:
    total_count = _to_int(progress.get("total_count"), 0)
    processed_count = _to_int(progress.get("processed_count"), 0)
    if total_count <= 0 or processed_count <= 0 or not row.started_at:
        return None
    elapsed = max(0.0, (_utcnow_naive() - row.started_at).total_seconds())
    if elapsed <= 0:
        return None
    rate = processed_count / elapsed
    if rate <= 0:
        return None
    remaining = max(0, total_count - processed_count)
    return int(round(remaining / rate))


def _sync_job_view(row: ExternalSyncJob) -> dict[str, object]:
    progress = _sync_job_progress_payload(row.progress_json)
    return {
        "id": int(row.id),
        "job_key": str(row.job_key or ""),
        "lock_key": str(row.lock_key or ""),
        "title": str(row.title or _sync_job_title_default(row.entity_type, row.system_name)),
        "system_name": str(row.system_name or ""),
        "direction": str(row.direction or ""),
        "entity_type": str(row.entity_type or ""),
        "status": str(row.status or ""),
        "queued_at": row.queued_at.isoformat() if row.queued_at else None,
        "started_at": row.started_at.isoformat() if row.started_at else None,
        "heartbeat_at": row.heartbeat_at.isoformat() if row.heartbeat_at else None,
        "finished_at": row.finished_at.isoformat() if row.finished_at else None,
        "log_text": str(row.log_text or ""),
        "result_url": str(row.result_url or ""),
        "progress": progress,
        "eta_seconds": _sync_job_eta_seconds(row, progress),
    }


def _start_sync_job(
    db: Session,
    *,
    system_name: str,
    direction: str,
    entity_type: str,
    log_text: str = "",
    status: str = "running",
    job_key: str = "",
    lock_key: str = "",
    title: str = "",
    progress: dict[str, object] | None = None,
    result_url: str = "",
) -> ExternalSyncJob:
    now = _utcnow_naive()
    normalized_status = str(status or "running").strip().lower() or "running"
    row = ExternalSyncJob(
        system_name=str(system_name),
        direction=str(direction),
        entity_type=str(entity_type),
        job_key=str(job_key or "").strip() or None,
        lock_key=str(lock_key or "").strip() or None,
        title=str(title or "").strip() or _sync_job_title_default(entity_type, system_name),
        status=normalized_status,
        queued_at=now,
        started_at=now if normalized_status == "running" else None,
        heartbeat_at=now if normalized_status == "running" else None,
        result_url=str(result_url or "").strip() or None,
        progress_json=json.dumps(progress or {}, ensure_ascii=False) if progress else None,
        log_text=(log_text or "").strip() or None,
    )
    db.add(row)
    db.flush()
    return row


def _finish_sync_job(db: Session, row: ExternalSyncJob, *, status: str, log_text: str, result_url: str | None = None) -> None:
    row.status = str(status)
    row.finished_at = _utcnow_naive()
    row.heartbeat_at = row.finished_at
    row.log_text = (log_text or "").strip() or row.log_text
    if result_url is not None:
        row.result_url = str(result_url or "").strip() or None
    db.add(row)


def _sync_job_update_progress(
    db: Session,
    row: ExternalSyncJob,
    *,
    phase: str | None = None,
    phase_detail: str | None = None,
    total_count: int | None = None,
    processed_count: int | None = None,
    success_count: int | None = None,
    error_count: int | None = None,
    local_decision_count: int | None = None,
    openai_decision_count: int | None = None,
    cached_decision_count: int | None = None,
    current_item_label: str | None = None,
    current_item_ref: str | None = None,
    note: str | None = None,
    log_text: str | None = None,
    result_url: str | None = None,
    commit: bool = False,
) -> dict[str, object]:
    updates: dict[str, object] = {
        "phase": str(phase or "").strip() or None,
        "phase_detail": str(phase_detail or "").strip() or None,
        "total_count": int(total_count) if total_count is not None and int(total_count) >= 0 else None,
        "processed_count": int(processed_count) if processed_count is not None and int(processed_count) >= 0 else None,
        "success_count": int(success_count) if success_count is not None and int(success_count) >= 0 else None,
        "error_count": int(error_count) if error_count is not None and int(error_count) >= 0 else None,
        "local_decision_count": int(local_decision_count) if local_decision_count is not None and int(local_decision_count) >= 0 else None,
        "openai_decision_count": int(openai_decision_count) if openai_decision_count is not None and int(openai_decision_count) >= 0 else None,
        "cached_decision_count": int(cached_decision_count) if cached_decision_count is not None and int(cached_decision_count) >= 0 else None,
        "current_item_label": str(current_item_label or "").strip() or None,
        "current_item_ref": str(current_item_ref or "").strip() or None,
        "note": str(note or "").strip() or None,
    }
    payload = _sync_job_progress_merge(row, updates)
    row.heartbeat_at = _utcnow_naive()
    if log_text:
        row.log_text = _sync_job_log_append_text(row.log_text, log_text)
    if result_url is not None:
        row.result_url = str(result_url or "").strip() or None
    db.add(row)
    if commit:
        db.commit()
    else:
        db.flush()
    return payload


def _sync_job_existing_active(db: Session, *, lock_key: str = "", job_key: str = "") -> ExternalSyncJob | None:
    query = db.query(ExternalSyncJob).filter(ExternalSyncJob.status.in_(BACKGROUND_JOB_ACTIVE_STATUSES))
    if str(job_key or "").strip():
        row = query.filter(ExternalSyncJob.job_key == str(job_key).strip()).order_by(ExternalSyncJob.id.desc()).first()
        if row is not None:
            return row
    if str(lock_key or "").strip():
        row = query.filter(ExternalSyncJob.lock_key == str(lock_key).strip()).order_by(ExternalSyncJob.id.desc()).first()
        if row is not None:
            return row
    return None


def _enqueue_sync_job(
    db: Session,
    *,
    system_name: str,
    direction: str,
    entity_type: str,
    title: str,
    job_key: str,
    lock_key: str,
    log_text: str = "",
    progress: dict[str, object] | None = None,
    result_url: str = "",
) -> tuple[ExternalSyncJob, bool]:
    existing = _sync_job_existing_active(db, lock_key=lock_key, job_key=job_key)
    if existing is not None:
        return existing, False
    row = _start_sync_job(
        db,
        system_name=system_name,
        direction=direction,
        entity_type=entity_type,
        log_text=log_text,
        status="queued",
        job_key=job_key,
        lock_key=lock_key,
        title=title,
        progress=progress,
        result_url=result_url,
    )
    return row, True


def _latest_sync_job_for_key(db: Session, job_key: str) -> ExternalSyncJob | None:
    key = str(job_key or "").strip()
    if not key:
        return None
    return db.query(ExternalSyncJob).filter(ExternalSyncJob.job_key == key).order_by(ExternalSyncJob.id.desc()).first()


def _background_job_recover_stale_running_jobs(stale_after_seconds: int = 0) -> int:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        query = db.query(ExternalSyncJob).filter(ExternalSyncJob.status == "running")
        stale_seconds = max(0, int(stale_after_seconds or 0))
        if stale_seconds > 0:
            cutoff = _utcnow_naive() - dt.timedelta(seconds=stale_seconds)
            query = query.filter(or_(ExternalSyncJob.heartbeat_at.is_(None), ExternalSyncJob.heartbeat_at < cutoff))
        rows = query.all()
        changed = False
        for row in rows:
            row.status = "failed"
            row.finished_at = _utcnow_naive()
            row.heartbeat_at = row.finished_at
            if stale_seconds > 0:
                message = f"Hintergrundjob wurde ohne Heartbeat > {stale_seconds}s als blockiert markiert."
            else:
                message = "Hintergrundjob wurde nach App-Neustart als abgebrochen markiert."
            row.log_text = _sync_job_log_append_text(row.log_text, message)
            db.add(row)
            changed = True
        if changed:
            db.commit()
        else:
            db.rollback()
        return len(rows)
    except Exception:
        db.rollback()
        return 0
    finally:
        db.close()


def _background_job_claim_next_id() -> int:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        row = (
            db.query(ExternalSyncJob)
            .filter(ExternalSyncJob.status == "queued")
            .order_by(case((ExternalSyncJob.queued_at.is_(None), 1), else_=0), ExternalSyncJob.queued_at.asc(), ExternalSyncJob.id.asc())
            .first()
        )
        if row is None:
            return 0
        if str(row.lock_key or "").strip():
            active_same_lock = (
                db.query(ExternalSyncJob)
                .filter(
                    ExternalSyncJob.id != int(row.id),
                    ExternalSyncJob.lock_key == str(row.lock_key or "").strip(),
                    ExternalSyncJob.status == "running",
                )
                .count()
            )
            if active_same_lock:
                db.rollback()
                return 0
        row.status = "running"
        row.started_at = row.started_at or _utcnow_naive()
        row.heartbeat_at = _utcnow_naive()
        db.add(row)
        db.commit()
        return int(row.id)
    except Exception:
        db.rollback()
        return 0
    finally:
        db.close()


def _background_job_fail(job_id: int, message: str) -> None:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        row = db.get(ExternalSyncJob, int(job_id))
        if row is None:
            db.rollback()
            return
        _finish_sync_job(db, row, status="failed", log_text=message)
        db.commit()
    except Exception:
        db.rollback()
    finally:
        db.close()


def _run_background_job_by_id(job_id: int) -> None:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        row = db.get(ExternalSyncJob, int(job_id))
        if row is None:
            db.rollback()
            return
        job_key = str(row.job_key or "").strip()
        if job_key == "customer_init_outsmart":
            _customer_init_import_outsmart(db, job=row)
            db.commit()
            return
        if job_key == "customer_init_sevdesk":
            _customer_init_import_sevdesk(db, job=row)
            db.commit()
            return
        if job_key == "customer_init_matching":
            _customer_init_build_clusters(db, job=row)
            db.commit()
            return
        if job_key == "customer_init_ai_review":
            _customer_init_ai_review_clusters(db, job=row)
            db.commit()
            return
        if job_key == "customer_init_materialize":
            _customer_init_materialize_ready_clusters(db, job=row)
            db.commit()
            return
        if job_key.startswith("catalog_import_run:"):
            _catalog_import_execute_job(db, row)
            db.commit()
            return
        raise ValueError(f"Unbekannter Hintergrundjob: {job_key or row.entity_type}")
    except Exception as exc:
        db.rollback()
        _background_job_fail(int(job_id), str(exc))
    finally:
        db.close()


async def _background_job_loop():
    await asyncio.sleep(BACKGROUND_TASK_STARTUP_DELAY_SECONDS)
    await asyncio.to_thread(_background_job_recover_stale_running_jobs)
    while True:
        try:
            await asyncio.to_thread(_background_job_recover_stale_running_jobs, BACKGROUND_JOB_HEARTBEAT_TIMEOUT_SECONDS)
            job_id = await asyncio.to_thread(_background_job_claim_next_id)
            if job_id <= 0:
                await asyncio.sleep(BACKGROUND_JOB_POLL_INTERVAL_SECONDS)
                continue
            await asyncio.to_thread(_run_background_job_by_id, int(job_id))
        except asyncio.CancelledError:
            raise
        except Exception:
            await asyncio.sleep(BACKGROUND_JOB_POLL_INTERVAL_SECONDS)


def _upsert_external_link(
    db: Session,
    *,
    system_name: str,
    object_type: str,
    object_id: int,
    external_key: str,
    external_row_id: str | None = None,
    deep_link_url: str | None = None,
) -> ExternalLink:
    row = (
        db.query(ExternalLink)
        .filter(
            ExternalLink.system_name == str(system_name),
            ExternalLink.object_type == str(object_type),
            ExternalLink.object_id == int(object_id),
        )
        .one_or_none()
    )
    if not row:
        row = ExternalLink(
            system_name=str(system_name),
            object_type=str(object_type),
            object_id=int(object_id),
            external_key=str(external_key),
            external_row_id=(external_row_id or "").strip() or None,
            deep_link_url=(deep_link_url or "").strip() or None,
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
    else:
        row.external_key = str(external_key)
        row.external_row_id = (external_row_id or "").strip() or row.external_row_id
        row.deep_link_url = (deep_link_url or "").strip() or row.deep_link_url
        row.updated_at = _utcnow_naive()
    db.add(row)
    db.flush()
    return row


SEVDESK_TRANSACTION_LINK_SYSTEM = "sevdesk_transaction"


def _transaction_match_local_url(tx_id: str, *, document_inbox_id: int = 0) -> str:
    tx_value = str(tx_id or "").strip()
    if not tx_value:
        return ""
    target = f"/finanzen/transaktionen/{quote(tx_value)}"
    if int(document_inbox_id or 0) > 0:
        target = f"{target}?document_inbox_id={int(document_inbox_id)}"
    return target


def _transaction_match_link(db: Session, *, object_type: str, object_id: int) -> ExternalLink | None:
    target_type = str(object_type or "").strip()
    target_id = int(object_id or 0)
    if not target_type or target_id <= 0:
        return None
    return (
        db.query(ExternalLink)
        .filter(
            ExternalLink.system_name == SEVDESK_TRANSACTION_LINK_SYSTEM,
            ExternalLink.object_type == target_type,
            ExternalLink.object_id == target_id,
        )
        .one_or_none()
    )


def _transaction_match_view(link: ExternalLink | None, *, document_inbox_id: int = 0) -> dict[str, object] | None:
    if link is None:
        return None
    tx_id = str(link.external_key or "").strip()
    if not tx_id:
        return None
    check_account_id = str(link.external_row_id or "").strip()
    effective_document_inbox_id = int(document_inbox_id or 0)
    if effective_document_inbox_id <= 0 and str(link.object_type or "").strip() == "document_inbox_item":
        effective_document_inbox_id = int(link.object_id or 0)
    return {
        "tx_id": tx_id,
        "check_account_id": check_account_id,
        "url": _transaction_match_local_url(tx_id, document_inbox_id=effective_document_inbox_id),
        "object_type": str(link.object_type or "").strip(),
        "object_id": int(link.object_id or 0),
    }


def _resolve_transaction_match(
    db: Session,
    *,
    object_refs: list[tuple[str, int]],
    document_inbox_id: int = 0,
) -> dict[str, object] | None:
    for object_type, object_id in object_refs:
        view = _transaction_match_view(
            _transaction_match_link(db, object_type=object_type, object_id=object_id),
            document_inbox_id=document_inbox_id,
        )
        if view:
            return view
    return None


def _transaction_match_rows_for_tx(db: Session, tx_id: str) -> list[dict[str, object]]:
    tx_value = str(tx_id or "").strip()
    if not tx_value:
        return []
    rows = (
        db.query(ExternalLink)
        .filter(
            ExternalLink.system_name == SEVDESK_TRANSACTION_LINK_SYSTEM,
            ExternalLink.external_key == tx_value,
        )
        .order_by(ExternalLink.object_type.asc(), ExternalLink.object_id.asc())
        .all()
    )
    out: list[dict[str, object]] = []
    for row in rows:
        object_type = str(row.object_type or "").strip()
        object_id = int(row.object_id or 0)
        if not _document_object_exists(db, object_type, object_id):
            continue
        out.append(
            {
                "row": row,
                "object_type": object_type,
                "object_id": object_id,
                "label": _document_object_label(db, object_type, object_id),
                "url": _document_object_url(object_type, object_id),
            }
        )
    return out


def _persist_transaction_match(
    db: Session,
    *,
    object_type: str,
    object_id: int,
    tx_id: str,
    check_account_id: str = "",
    document_inbox_id: int = 0,
) -> ExternalLink | None:
    target_type = str(object_type or "").strip()
    target_id = int(object_id or 0)
    tx_value = str(tx_id or "").strip()
    if not target_type or target_id <= 0 or not tx_value:
        return None
    return _upsert_external_link(
        db,
        system_name=SEVDESK_TRANSACTION_LINK_SYSTEM,
        object_type=target_type,
        object_id=target_id,
        external_key=tx_value,
        external_row_id=str(check_account_id or "").strip() or None,
        deep_link_url=_transaction_match_local_url(
            tx_value,
            document_inbox_id=document_inbox_id if target_type == "document_inbox_item" else 0,
        ),
    )


def _persist_transaction_match_bundle(
    db: Session,
    *,
    tx_id: str,
    check_account_id: str = "",
    document_item: DocumentInboxItem | None = None,
    voucher: IncomingVoucherDraft | None = None,
    invoice_draft: InvoiceDraft | None = None,
) -> None:
    tx_value = str(tx_id or "").strip()
    if not tx_value:
        return
    if document_item is not None and int(getattr(document_item, "id", 0) or 0) > 0:
        _persist_transaction_match(
            db,
            object_type="document_inbox_item",
            object_id=int(document_item.id),
            tx_id=tx_value,
            check_account_id=check_account_id,
            document_inbox_id=int(document_item.id),
        )
        _document_inbox_progress_state(document_item, "matched")
        db.add(document_item)
    if voucher is not None and int(getattr(voucher, "id", 0) or 0) > 0:
        _persist_transaction_match(
            db,
            object_type="incoming_voucher_draft",
            object_id=int(voucher.id),
            tx_id=tx_value,
            check_account_id=check_account_id,
        )
    if invoice_draft is not None and int(getattr(invoice_draft, "id", 0) or 0) > 0:
        _persist_transaction_match(
            db,
            object_type="invoice_draft",
            object_id=int(invoice_draft.id),
            tx_id=tx_value,
            check_account_id=check_account_id,
        )


def _build_plaintext_export(title: str, lines: list[str]) -> Path:
    temp_dir = Path(tempfile.mkdtemp(prefix="kda_einkauf_"))
    target = temp_dir / f"{slugify(title) or 'dokument'}.txt"
    target.write_text("\n".join(lines).strip() + "\n", encoding="utf-8")
    return target


def _mobile_display_name(product: Product | None) -> str:
    if not product:
        return ""
    item_type = _normalize_item_type(getattr(product, "item_type", ""), fallback="material")
    if item_type == "appliance":
        sales_name = str(getattr(product, "sales_name", "") or "").strip()
        if sales_name:
            return sales_name
    name = str(getattr(product, "name", "") or "").strip()
    if name:
        return name
    return f"Produkt {int(getattr(product, 'id', 0) or 0)}"


def _mobile_manufacturer_label(product: Product | None, fallback_name: str = "") -> str:
    if not product:
        return str(fallback_name or "").strip()
    for value in (
        getattr(product, "manufacturer_name", ""),
        getattr(product, "manufacturer", ""),
        fallback_name,
    ):
        text = str(value or "").strip()
        if text:
            return text
    return "-"


def _mobile_catalog_feature_filters(
    db: Session,
    *,
    kind_id: int,
    query_params,
) -> list[dict[str, object]]:
    selected_kind_id = int(kind_id or 0)
    if selected_kind_id <= 0:
        return []
    feature_defs = (
        db.query(FeatureDef)
        .filter(FeatureDef.device_kind_id == int(selected_kind_id), FeatureDef.filterable == True)
        .order_by(FeatureDef.label_de.asc(), FeatureDef.id.asc())
        .limit(24)
        .all()
    )
    filters: list[dict[str, object]] = []
    for feature_def in feature_defs:
        fid = int(feature_def.id)
        data_type = str(feature_def.data_type or "text")
        filter_row: dict[str, object] = {
            "id": fid,
            "label": str(feature_def.label_de or feature_def.key or f"Merkmal {fid}"),
            "data_type": data_type,
            "text_mode": "canonical",
            "value": "",
            "min": "",
            "max": "",
            "min_value": None,
            "max_value": None,
            "options": [],
            "min_options": [],
            "max_options": [],
            "bool_options": [],
        }
        if data_type == "number":
            number_values, has_more = _feature_filter_number_options(
                db,
                device_kind_id=int(selected_kind_id),
                feature_def_id=fid,
                limit=FEATURE_FILTER_OPTION_LIMIT,
            )
            number_options = [
                {"value": _format_feature_number_option(value), "label": _format_feature_number_option(value), "disabled": False}
                for value in number_values
            ]
            if has_more:
                number_options.append({"value": "", "label": "(weitere Werte vorhanden ...)", "disabled": True})
            filter_row["min_options"] = list(number_options)
            filter_row["max_options"] = list(number_options)

            raw_min = str(query_params.get(f"f_{fid}_min") or "").strip()
            raw_max = str(query_params.get(f"f_{fid}_max") or "").strip()
            min_selected = _resolve_number_filter_selection(raw_min, number_values)
            max_selected = _resolve_number_filter_selection(raw_max, number_values)

            min_label = str(min_selected[0]) if min_selected else ""
            max_label = str(max_selected[0]) if max_selected else ""
            min_value = float(min_selected[1]) if min_selected else None
            max_value = float(max_selected[1]) if max_selected else None
            if min_value is not None and max_value is not None and min_value > max_value:
                min_label, max_label = max_label, min_label
                min_value, max_value = max_value, min_value

            filter_row["min"] = min_label
            filter_row["max"] = max_label
            filter_row["min_value"] = min_value
            filter_row["max_value"] = max_value
        elif data_type == "bool":
            bool_values = _feature_filter_bool_options(db, device_kind_id=int(selected_kind_id), feature_def_id=fid)
            bool_options: list[dict[str, object]] = []
            if True in bool_values:
                bool_options.append({"value": "1", "label": "Ja", "disabled": False})
            if False in bool_values:
                bool_options.append({"value": "0", "label": "Nein", "disabled": False})
            filter_row["bool_options"] = bool_options
            raw_bool = str(query_params.get(f"f_{fid}") or "").strip().lower()
            if raw_bool in ("1", "true", "ja") and True in bool_values:
                filter_row["value"] = "1"
            elif raw_bool in ("0", "false", "nein") and False in bool_values:
                filter_row["value"] = "0"
        else:
            text_options, has_more, text_mode = _feature_filter_text_options(
                db,
                device_kind_id=int(selected_kind_id),
                feature_def_id=fid,
                limit=FEATURE_FILTER_OPTION_LIMIT,
            )
            filter_row["text_mode"] = text_mode
            options_for_ui = list(text_options)
            if has_more:
                options_for_ui.append({"value": "", "label": "(weitere Werte vorhanden ...)", "disabled": True, "option_id": 0})
            filter_row["options"] = options_for_ui

            raw_filter_value = str(query_params.get(f"f_{fid}") or "").strip()
            if text_mode == "legacy_text":
                if raw_filter_value:
                    selected_opt = next(
                        (
                            row
                            for row in text_options
                            if str(row.get("value") or "").strip().casefold() == raw_filter_value.casefold()
                        ),
                        None,
                    )
                    if selected_opt and not bool(selected_opt.get("disabled")):
                        filter_row["value"] = str(selected_opt.get("value") or "")
            else:
                raw_option_id = _to_int(raw_filter_value, 0)
                if raw_option_id > 0:
                    selected_opt = next(
                        (row for row in text_options if int(row.get("option_id") or 0) == int(raw_option_id)),
                        None,
                    )
                    if not selected_opt:
                        selected_row = (
                            db.query(FeatureOption.id, FeatureOption.label_de, FeatureOption.canonical_key, FeatureOption.active)
                            .filter(
                                FeatureOption.id == int(raw_option_id),
                                FeatureOption.feature_def_id == fid,
                            )
                            .one_or_none()
                        )
                        if selected_row and bool(selected_row[3]):
                            selected_label = str(selected_row[1] or "").strip() or str(selected_row[2] or "").strip()
                            selected_opt = {
                                "value": str(int(selected_row[0])),
                                "label": selected_label,
                                "disabled": False,
                                "option_id": int(selected_row[0]),
                            }
                            filter_row["options"] = [selected_opt] + options_for_ui
                    if selected_opt and not bool(selected_opt.get("disabled")):
                        filter_row["value"] = str(int(raw_option_id))
        filters.append(filter_row)
    return filters


def _mobile_catalog_apply_feature_filters(query, feature_filters: list[dict[str, object]]):
    for filter_row in feature_filters:
        fid = int(filter_row.get("id") or 0)
        if fid <= 0:
            continue
        data_type = str(filter_row.get("data_type") or "text")
        if data_type == "number":
            min_value_raw = filter_row.get("min_value")
            max_value_raw = filter_row.get("max_value")
            min_value = float(min_value_raw) if min_value_raw is not None else None
            max_value = float(max_value_raw) if max_value_raw is not None else None
            if min_value is not None:
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_num.isnot(None),
                            FeatureValue.value_num >= min_value,
                        )
                    )
                )
            if max_value is not None:
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_num.isnot(None),
                            FeatureValue.value_num <= max_value,
                        )
                    )
                )
            continue
        if data_type == "bool":
            value = str(filter_row.get("value") or "").strip()
            if value == "1":
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_bool == True,
                        )
                    )
                )
            elif value == "0":
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_bool == False,
                        )
                    )
                )
            continue
        text_mode = str(filter_row.get("text_mode") or "canonical").strip().lower()
        if text_mode == "legacy_text":
            selected_legacy_value = str(filter_row.get("value") or "").strip()
            if selected_legacy_value:
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_text.isnot(None),
                            func.lower(func.trim(FeatureValue.value_text)) == selected_legacy_value.casefold(),
                        )
                    )
                )
            continue
        selected_option_id = _to_int(filter_row.get("value"), 0)
        if selected_option_id > 0:
            query = query.filter(_feature_text_option_filter_exists(fid, int(selected_option_id)))
    return query


def _mobile_catalog_filter_payload(feature_filters: list[dict[str, object]]) -> list[dict[str, object]]:
    payload: list[dict[str, object]] = []
    for row in feature_filters:
        payload.append(
            {
                "id": int(row.get("id") or 0),
                "label": str(row.get("label") or ""),
                "data_type": str(row.get("data_type") or "text"),
                "text_mode": str(row.get("text_mode") or "canonical"),
                "value": str(row.get("value") or ""),
                "min": str(row.get("min") or ""),
                "max": str(row.get("max") or ""),
                "options": row.get("options") or [],
                "min_options": row.get("min_options") or [],
                "max_options": row.get("max_options") or [],
                "bool_options": row.get("bool_options") or [],
            }
        )
    return payload


def _mobile_default_warehouse_id(db: Session) -> int:
    defaults = _receipt_defaults(db)
    warehouse_id = int(defaults.get("warehouse_id") or 0)
    if warehouse_id and db.get(Warehouse, warehouse_id):
        return warehouse_id
    first = db.query(Warehouse).order_by(Warehouse.name.asc(), Warehouse.id.asc()).first()
    return int(first.id) if first else 0


def _mobile_spare_default_owner_id(request: Request, owners: list[Owner]) -> int:
    by_id = {int(row.id): row for row in owners}
    raw_cookie = str(request.cookies.get(LAST_SPARE_OWNER_COOKIE) or "").strip()
    cookie_owner_id = _to_int(raw_cookie, 0)
    if cookie_owner_id > 0:
        owner = by_id.get(cookie_owner_id)
        if owner and bool(owner.active):
            return int(owner.id)
    if len(owners) == 1:
        return int(owners[0].id)
    return 0


def _mobile_spare_default_condition(db: Session) -> str:
    defaults = _receipt_defaults(db)
    condition = _condition_code_from_input(str(defaults.get("condition") or _default_condition_code()))
    if _condition_exists(db, condition, active_only=True):
        return condition
    fallback_defs = _get_condition_defs(db, active_only=True, include_fallback=True)
    if fallback_defs:
        return str(fallback_defs[0].code or _default_condition_code())
    return _default_condition_code()


def _mobile_first_other_warehouse_id(warehouses: list[Warehouse], from_warehouse_id: int) -> int:
    if not warehouses:
        return 0
    first_id = int(warehouses[0].id)
    for row in warehouses:
        row_id = int(row.id)
        if row_id != int(from_warehouse_id or 0):
            return row_id
    return first_id


def _mobile_cost_param_from_cents(cents: int | None) -> str:
    if cents is None:
        return ""
    value = int(cents)
    euro_value = float(value) / 100.0
    return f"{euro_value:.2f}".rstrip("0").rstrip(".")


def _delivery_scan_normalize_source(raw_source: str | None) -> str:
    value = str(raw_source or "").strip().lower()
    if value in DELIVERY_SCAN_SOURCES:
        return value
    return DELIVERY_SCAN_SOURCE_LIEFERSCHEIN


def _delivery_scan_source_label(source: str) -> str:
    normalized = _delivery_scan_normalize_source(source)
    if normalized == DELIVERY_SCAN_SOURCE_PRODUKTSCHILD:
        return "Produktschild"
    return "Lieferschein"


def _delivery_scan_page_href(source: str) -> str:
    normalized = _delivery_scan_normalize_source(source)
    if normalized == DELIVERY_SCAN_SOURCE_PRODUKTSCHILD:
        return "/m/lieferschein?scan_source=produktschild"
    return "/m/lieferschein"


def _delivery_scan_tesseract_available() -> bool:
    return bool(shutil.which("tesseract"))


def _delivery_scan_compact_token(raw: str | None) -> str:
    return "".join(ch for ch in str(raw or "").upper() if ch.isalnum())


def _delivery_scan_extract_text(filename: str, payload: bytes) -> str:
    if not payload:
        raise ValueError("Datei ist leer.")
    if len(payload) > DELIVERY_SCAN_MAX_BYTES:
        raise ValueError("Datei ist zu groß (max. 12 MB).")
    if not _delivery_scan_tesseract_available():
        raise ValueError("OCR ist nicht verfügbar. Bitte Tesseract installieren.")

    suffix = str(Path(filename or "").suffix or "").lower().strip()
    if suffix not in DELIVERY_SCAN_ALLOWED_SUFFIXES:
        raise ValueError("Nur Bilddateien (JPG/PNG/WEBP/BMP/TIFF) sind erlaubt.")

    dirs = ensure_dirs()
    scan_dir = dirs["tmp"] / "delivery_scan"
    scan_dir.mkdir(parents=True, exist_ok=True)
    tmp_file = tempfile.NamedTemporaryFile(
        dir=str(scan_dir),
        prefix="scan_",
        suffix=suffix,
        delete=False,
    )
    tmp_path = Path(tmp_file.name)
    try:
        tmp_file.write(payload)
        tmp_file.flush()
        tmp_file.close()

        text_parts: list[str] = []
        for psm in ("6", "11"):
            cmd = ["tesseract", str(tmp_path), "stdout", "-l", "deu+eng", "--psm", psm]
            run = subprocess.run(
                cmd,
                check=False,
                capture_output=True,
                text=True,
                timeout=35,
            )
            if run.returncode != 0:
                err = (run.stderr or "").strip() or "OCR fehlgeschlagen."
                raise ValueError(err)
            chunk = str(run.stdout or "").strip()
            if chunk and chunk not in text_parts:
                text_parts.append(chunk)
        text = "\n\n".join(text_parts).strip()
        if not text:
            raise ValueError("Kein lesbarer Text gefunden. Bitte klareres Foto aufnehmen.")
        return text
    finally:
        try:
            tmp_path.unlink(missing_ok=True)
        except Exception:
            pass


def _delivery_scan_extract_references(raw_text: str) -> list[str]:
    text = str(raw_text or "")
    out: list[str] = []

    def _append(value: str):
        token = str(value or "").strip().upper()
        if not token:
            return
        if len(token) < 3 or len(token) > 40:
            return
        if token not in out:
            out.append(token)

    for po in _extract_po_numbers(text):
        _append(po)

    pattern = re.compile(
        r"(?:kommission|auftrag|auftragsnr|auftragsnummer|ref|referenz|lieferschein|ls)\s*[:#-]?\s*([A-Za-z0-9][A-Za-z0-9\-/]{2,})",
        re.IGNORECASE,
    )
    for match in pattern.findall(text):
        _append(match)

    return out[:8]


def _delivery_scan_detect_mode(raw_text: str, has_reservation_hint: bool) -> str:
    text = _normalize_search_text(raw_text)
    if any(word in text for word in ("umlagerung", "umlagern", "transfer", "von lager", "nach lager")):
        return "transfer"
    if any(word in text for word in ("kommission", "kunde", "ausgang", "versand", "auslieferung", "warenausgang")):
        return "issue"
    if any(word in text for word in ("wareneingang", "lieferschein", "anlieferung", "lieferung", "eingang")):
        return "receipt"
    if has_reservation_hint:
        return "issue"
    return "receipt"


def _delivery_scan_guess_qty_from_line(line_text: str) -> int:
    text = str(line_text or "")
    patterns = [
        r"\b(?:menge|anzahl|qty)\s*[:=]?\s*(\d{1,4})\b",
        r"\b(\d{1,4})\s*(?:x|stk|st\.?|stueck|stück|pcs)\b",
        r"\b(\d{1,4})\b\s*$",
    ]
    for pattern in patterns:
        m = re.search(pattern, text, re.IGNORECASE)
        if not m:
            continue
        try:
            qty = int(m.group(1))
        except Exception:
            qty = 0
        if 0 < qty <= 1000:
            return qty
    return 1


def _delivery_scan_build_suggestions(
    db: Session,
    recognized_text: str,
    mode_hint: str,
    scan_source: str = DELIVERY_SCAN_SOURCE_LIEFERSCHEIN,
) -> dict[str, object]:
    source = _delivery_scan_normalize_source(scan_source)
    is_label_scan = source == DELIVERY_SCAN_SOURCE_PRODUKTSCHILD
    lines = [str(line).strip() for line in str(recognized_text or "").splitlines() if str(line).strip()]
    line_rows = [
        {
            "raw": line,
            "norm": _normalize_search_text(line),
            "compact": _delivery_scan_compact_token(line),
        }
        for line in lines
    ]
    doc_norm = _normalize_search_text(recognized_text)
    doc_compact = _delivery_scan_compact_token(recognized_text)
    reference_candidates = _delivery_scan_extract_references(recognized_text)

    products = (
        db.query(Product)
        .filter(Product.active == True)
        .order_by(Product.id.desc())
        .limit(5000)
        .all()
    )

    matched_rows: list[dict[str, object]] = []
    for product in products:
        best_score = 0
        best_line_idx = -1
        best_by = ""

        ean = str(product.ean or "").strip()
        if len(ean) >= 8:
            token = _delivery_scan_compact_token(ean)
            if token and token in doc_compact:
                for idx, line_row in enumerate(line_rows):
                    if token in str(line_row["compact"]):
                        best_score = 180
                        best_line_idx = idx
                        best_by = "EAN"
                        break

        material_no = str(product.material_no or "").strip()
        if len(material_no) >= 4:
            token = _delivery_scan_compact_token(material_no)
            if token and token in doc_compact and best_score < 160:
                for idx, line_row in enumerate(line_rows):
                    if token in str(line_row["compact"]):
                        best_score = 160
                        best_line_idx = idx
                        best_by = "Materialnummer"
                        break

        sku = str(product.sku or "").strip()
        if len(sku) >= 3:
            token = _delivery_scan_compact_token(sku)
            if token and token in doc_compact and best_score < 150:
                for idx, line_row in enumerate(line_rows):
                    if token in str(line_row["compact"]):
                        best_score = 150
                        best_line_idx = idx
                        best_by = "Artikelnummer"
                        break

        title_1 = _normalize_search_text(product.product_title_1 or "")
        title_1_min = 6 if is_label_scan else 10
        if len(title_1) >= title_1_min and title_1 in doc_norm and best_score < 100:
            for idx, line_row in enumerate(line_rows):
                if title_1 in str(line_row["norm"]):
                    best_score = 100
                    best_line_idx = idx
                    best_by = "Produkttitel 1"
                    break

        title_2 = _normalize_search_text(product.product_title_2 or "")
        title_2_min = 6 if is_label_scan else 10
        if len(title_2) >= title_2_min and title_2 in doc_norm and best_score < 97:
            for idx, line_row in enumerate(line_rows):
                if title_2 in str(line_row["norm"]):
                    best_score = 97
                    best_line_idx = idx
                    best_by = "Produkttitel 2"
                    break

        sales_name = _normalize_search_text(product.sales_name or "")
        sales_name_min = 6 if is_label_scan else 10
        if len(sales_name) >= sales_name_min and sales_name in doc_norm and best_score < 95:
            for idx, line_row in enumerate(line_rows):
                if sales_name in str(line_row["norm"]):
                    best_score = 95
                    best_line_idx = idx
                    best_by = "Verkaufsname"
                    break

        name = _normalize_search_text(product.name or "")
        needs_two_words = not is_label_scan
        if len(name) >= (6 if is_label_scan else 10) and (not needs_two_words or len(name.split()) >= 2) and name in doc_norm and best_score < 85:
            for idx, line_row in enumerate(line_rows):
                if name in str(line_row["norm"]):
                    best_score = 85
                    best_line_idx = idx
                    best_by = "Produktname"
                    break

        if best_score <= 0:
            continue
        line_text = ""
        if 0 <= best_line_idx < len(line_rows):
            line_text = str(line_rows[best_line_idx]["raw"])
        qty_guess = _delivery_scan_guess_qty_from_line(line_text)
        matched_rows.append(
            {
                "product": product,
                "score": best_score,
                "line_index": best_line_idx,
                "line_text": line_text,
                "qty_guess": qty_guess,
                "matched_by": best_by,
            }
        )

    matched_rows.sort(key=lambda row: (-int(row["score"]), int(row["line_index"] if int(row["line_index"]) >= 0 else 999999)))
    matched_rows = matched_rows[:40]
    if not matched_rows:
        return {
            "recognized_text": recognized_text,
            "mode": "receipt" if mode_hint == "auto" else mode_hint,
            "references": reference_candidates,
            "scan_source": source,
            "lines": [],
        }

    product_ids = [int(row["product"].id) for row in matched_rows]
    active_reservations = (
        db.query(Reservation)
        .filter(
            Reservation.status == "active",
            Reservation.product_id.in_(product_ids),
        )
        .order_by(Reservation.id.desc())
        .all()
    )
    reservations_by_product: dict[int, list[Reservation]] = {}
    for row in active_reservations:
        reservations_by_product.setdefault(int(row.product_id), []).append(row)

    has_reservation_hint = any(bool(rows) for rows in reservations_by_product.values())
    if mode_hint in ("receipt", "issue", "transfer"):
        detected_mode = mode_hint
    else:
        detected_mode = _delivery_scan_detect_mode(recognized_text, has_reservation_hint)

    receipt_defaults = _receipt_defaults(db)
    default_condition = str(receipt_defaults.get("condition") or _default_condition_code())
    default_to_warehouse_id = int(receipt_defaults.get("warehouse_id") or 0)
    if default_to_warehouse_id and not db.get(Warehouse, default_to_warehouse_id):
        default_to_warehouse_id = 0
    warehouses = db.query(Warehouse).order_by(Warehouse.name.asc(), Warehouse.id.asc()).all()
    if default_to_warehouse_id <= 0 and warehouses:
        default_to_warehouse_id = int(warehouses[0].id)
    default_from_warehouse_id = _mobile_default_warehouse_id(db)
    default_transfer_to = _mobile_first_other_warehouse_id(warehouses, default_from_warehouse_id)

    out_lines: list[dict[str, object]] = []
    seen_product_ids: set[int] = set()
    for idx, match_row in enumerate(matched_rows, start=1):
        product: Product = match_row["product"]
        product_id = int(product.id)
        if product_id in seen_product_ids:
            continue
        seen_product_ids.add(product_id)

        reservation_rows = reservations_by_product.get(product_id, [])
        matched_reservation: Reservation | None = None
        if reservation_rows:
            if reference_candidates:
                lowered_refs = [ref.casefold() for ref in reference_candidates]
                for res in reservation_rows:
                    ref_text = str(res.reference or "").strip().casefold()
                    if ref_text and any(ref in ref_text for ref in lowered_refs):
                        matched_reservation = res
                        break
            if matched_reservation is None and len(reservation_rows) == 1:
                matched_reservation = reservation_rows[0]

        qty = int(match_row["qty_guess"] or 1)
        if matched_reservation and int(matched_reservation.qty or 0) > 0:
            qty = int(matched_reservation.qty)
        qty = max(1, min(1000, int(qty)))

        tx_type = detected_mode
        if matched_reservation:
            tx_type = "issue"

        line_reference = ""
        if matched_reservation and str(matched_reservation.reference or "").strip():
            line_reference = str(matched_reservation.reference or "").strip()
        elif reference_candidates:
            line_reference = str(reference_candidates[0])

        warehouse_from_id = int(matched_reservation.warehouse_id) if matched_reservation else int(default_from_warehouse_id or 0)
        warehouse_to_id = int(default_to_warehouse_id or 0)
        if tx_type == "transfer":
            warehouse_from_id = int(default_from_warehouse_id or 0)
            warehouse_to_id = int(default_transfer_to or 0)
        if matched_reservation and tx_type == "issue":
            warehouse_to_id = 0
        if tx_type == "issue":
            warehouse_to_id = 0
        if tx_type == "receipt":
            warehouse_from_id = 0

        condition = str(matched_reservation.condition or default_condition) if matched_reservation else default_condition
        if not _condition_exists(db, condition, active_only=True):
            condition = default_condition

        out_lines.append(
            {
                "idx": idx,
                "product_id": product_id,
                "product_name": _mobile_display_name(product),
                "material_no": str(product.material_no or "").strip(),
                "matched_by": str(match_row["matched_by"] or ""),
                "line_text": str(match_row["line_text"] or ""),
                "score": int(match_row["score"] or 0),
                "qty": qty,
                "tx_type": tx_type,
                "warehouse_from_id": int(warehouse_from_id or 0),
                "warehouse_to_id": int(warehouse_to_id or 0),
                "condition": condition,
                "reference": line_reference,
                "reservation_id": int(matched_reservation.id) if matched_reservation else 0,
                "reservation_qty": int(matched_reservation.qty or 0) if matched_reservation else 0,
                "reservation_ref": str(matched_reservation.reference or "").strip() if matched_reservation else "",
            }
        )

    return {
        "recognized_text": recognized_text,
        "mode": detected_mode,
        "references": reference_candidates,
        "scan_source": source,
        "lines": out_lines,
    }


_po_re = re.compile(r"PO-\d{4}-\d{4}", re.IGNORECASE)


def _extract_po_numbers(text: str | None) -> list[str]:
    raw = str(text or "")
    found = _po_re.findall(raw)
    out: list[str] = []
    for f in found:
        key = str(f).upper()
        if key not in out:
            out.append(key)
    return out


def _seed_item_type_field_rules(db: Session) -> None:
    for item_type in ITEM_TYPE_CHOICES:
        defaults = DEFAULT_ITEM_TYPE_RULES.get(item_type, {})
        existing_rows = (
            db.query(ItemTypeFieldRule)
            .filter(ItemTypeFieldRule.item_type == item_type)
            .order_by(ItemTypeFieldRule.sort_order.asc(), ItemTypeFieldRule.id.asc())
            .all()
        )
        existing_keys = {str(row.field_key) for row in existing_rows}
        max_sort_order = 0
        for row in existing_rows:
            try:
                max_sort_order = max(max_sort_order, int(row.sort_order or 0))
            except Exception:
                continue
        for idx, field in enumerate(FORM_FIELDS, start=1):
            key = str(field["key"])
            if key in existing_keys:
                continue
            cfg = defaults.get(key, {})
            max_sort_order += 10
            db.add(
                ItemTypeFieldRule(
                    item_type=item_type,
                    field_key=key,
                    visible=bool(cfg.get("visible", False)),
                    required=bool(cfg.get("required", False)),
                    sort_order=max_sort_order if max_sort_order > 0 else idx * 10,
                    section=str(field.get("section_default") or "Identifikation"),
                    help_text_de=None,
                )
            )


CATALOG_DEPRECATED_FORM_FIELDS = {"manufacturer_name"}


def _item_type_field_rules(db: Session, item_type: str) -> list[ItemTypeFieldRule]:
    normalized = _normalize_item_type(item_type, fallback="material")
    rows = (
        db.query(ItemTypeFieldRule)
        .filter(ItemTypeFieldRule.item_type == normalized)
        .order_by(ItemTypeFieldRule.sort_order.asc(), ItemTypeFieldRule.id.asc())
        .all()
    )
    if rows:
        return rows
    _seed_item_type_field_rules(db)
    db.commit()
    return (
        db.query(ItemTypeFieldRule)
        .filter(ItemTypeFieldRule.item_type == normalized)
        .order_by(ItemTypeFieldRule.sort_order.asc(), ItemTypeFieldRule.id.asc())
        .all()
    )


def _product_form_schema(db: Session, item_type: str) -> list[dict]:
    rows = _item_type_field_rules(db, item_type)
    schema: list[dict] = []
    for row in rows:
        spec = FORM_FIELDS_BY_KEY.get(str(row.field_key))
        if not spec or not row.visible or str(row.field_key) in CATALOG_DEPRECATED_FORM_FIELDS:
            continue
        schema.append(
            {
                "key": str(row.field_key),
                "label": str(spec["label_de"]),
                "input_type": str(spec["input_type"]),
                "placeholder": str(spec.get("placeholder_de") or ""),
                "required": bool(row.required),
                "section": str(row.section or spec.get("section_default") or "Identifikation"),
                "help_text": (row.help_text_de or "").strip(),
                "sort_order": int(row.sort_order or 0),
            }
        )
    schema.sort(key=lambda s: (str(s["section"]).lower(), int(s["sort_order"]), str(s["label"]).lower()))
    return schema


def _product_form_key_sets(db: Session, item_type: str) -> tuple[set[str], set[str]]:
    rows = _item_type_field_rules(db, item_type)
    visible = {str(r.field_key) for r in rows if r.visible and str(r.field_key) not in CATALOG_DEPRECATED_FORM_FIELDS}
    required = {
        str(r.field_key)
        for r in rows
        if r.visible and r.required and str(r.field_key) not in CATALOG_DEPRECATED_FORM_FIELDS
    }
    return visible, required


def _product_field_label(field_key: str) -> str:
    spec = FORM_FIELDS_BY_KEY.get(field_key)
    if spec:
        return str(spec["label_de"])
    return field_key


def _parse_product_select_id(db: Session, field_key: str, raw_value) -> tuple[int | None, bool]:
    try:
        value = int(raw_value or 0) or None
    except Exception:
        value = None
    if not value:
        return None, False
    model = None
    if field_key == "manufacturer_id":
        model = Manufacturer
    elif field_key == "area_id":
        model = Area
    elif field_key == "device_kind_id":
        model = DeviceKind
    elif field_key == "device_type_id":
        model = DeviceType
    if model is None:
        return value, True
    row = db.get(model, value)
    return value, bool(row)


def _parse_product_image_urls(form, add_error) -> dict[str, str | None]:
    out: dict[str, str | None] = {}
    for key in _product_image_url_keys():
        raw = (form.get(key) or "").strip()
        if not raw:
            out[key] = None
            continue
        normalized = _normalize_product_image_url(raw)
        if not normalized:
            add_error(key, f"Bild-Link in '{key}' muss mit http://, https:// oder /uploads/ beginnen.")
            out[key] = None
            continue
        out[key] = normalized
    return out


def _catalog_asset_image_field_keys() -> list[str]:
    return [f"asset_image_url_{idx}" for idx in range(1, PRODUCT_IMAGE_ASSET_SLOT_MAX + 1)]


def _catalog_asset_form_defaults(
    db: Session,
    product: Product | None,
    form_data: dict[str, str | list[str]] | None = None,
) -> dict[str, str]:
    data = dict(form_data or {})
    defaults: dict[str, str] = {}
    image_rows_by_slot: dict[int, ProductAsset] = {}
    document_rows_by_type: dict[str, ProductAsset] = {}
    if product and int(getattr(product, "id", 0) or 0) > 0:
        for row in _catalog_product_asset_rows(db, int(product.id)):
            asset_type = str(getattr(row, "asset_type", "") or "").strip().lower()
            if asset_type == "image":
                slot_no = int(getattr(row, "slot_no", 0) or 0)
                if slot_no > 0 and slot_no not in image_rows_by_slot:
                    image_rows_by_slot[slot_no] = row
                continue
            if asset_type and asset_type not in document_rows_by_type:
                document_rows_by_type[asset_type] = row
    for idx in range(1, PRODUCT_IMAGE_ASSET_SLOT_MAX + 1):
        key = f"asset_image_url_{idx}"
        if key in data:
            defaults[key] = _form_scalar(data, key, "")
            continue
        slot_asset = image_rows_by_slot.get(int(idx))
        if slot_asset is not None and str(slot_asset.source_url_raw or "").strip():
            defaults[key] = str(slot_asset.source_url_raw or "").strip()
        else:
            defaults[key] = ""
    for key, asset_type in (
        ("asset_datasheet_url", "datasheet_pdf"),
        ("asset_manual_url", "manual_pdf"),
        ("asset_energy_label_url", "energy_label"),
    ):
        if key in data:
            defaults[key] = _form_scalar(data, key, "")
            continue
        row = document_rows_by_type.get(asset_type)
        defaults[key] = str(row.source_url_raw or "") if row else ""
    return defaults


def _parse_product_asset_urls(form, add_error) -> dict[str, object]:
    out: dict[str, object] = {
        "images": {},
        "documents": {},
    }
    for idx in range(1, PRODUCT_IMAGE_ASSET_SLOT_MAX + 1):
        key = f"asset_image_url_{idx}"
        raw = str(form.get(key) or "").strip()
        if not raw:
            continue
        normalized = _normalize_product_image_url(raw) or _normalize_absolute_url(raw)
        if not normalized:
            add_error(key, "Bild-Link muss mit http://, https://, /uploads/ oder einem lokalen Asset-Link beginnen.")
            continue
        out["images"][int(idx)] = normalized
    for key, asset_type in (
        ("asset_datasheet_url", "datasheet_pdf"),
        ("asset_manual_url", "manual_pdf"),
        ("asset_energy_label_url", "energy_label"),
    ):
        raw = str(form.get(key) or "").strip()
        if not raw:
            continue
        normalized = _normalize_absolute_url(raw)
        if not normalized:
            add_error(key, "Dokument-Link muss mit http:// oder https:// beginnen.")
            continue
        out["documents"][asset_type] = normalized
    return out


def _catalog_apply_learned_asset_features(db: Session, *, product: Product) -> int:
    if int(product.device_kind_id or 0) <= 0:
        return 0
    feature_defs = _feature_defs_for_kind(db, int(product.device_kind_id))
    if not feature_defs:
        return 0
    direct_defs: dict[str, FeatureDef] = {}
    for feature_def in feature_defs:
        for candidate_key in (
            normalize_candidate_name(str(feature_def.label_de or "")),
            normalize_candidate_name(str(feature_def.key or "").replace("_", " ")),
        ):
            if candidate_key and candidate_key not in direct_defs:
                direct_defs[candidate_key] = feature_def
    accepted_candidates = (
        db.query(FeatureCandidate)
        .filter(
            FeatureCandidate.device_kind_id == int(product.device_kind_id),
            FeatureCandidate.status == "accepted",
            FeatureCandidate.feature_def_id.isnot(None),
            or_(
                FeatureCandidate.manufacturer_id.is_(None),
                FeatureCandidate.manufacturer_id == (int(product.manufacturer_id or 0) or None),
            ),
        )
        .all()
    )
    accepted_defs = {
        str(row.normalized_name or "").strip(): db.get(FeatureDef, int(row.feature_def_id or 0))
        for row in accepted_candidates
        if int(row.feature_def_id or 0) > 0
    }
    updates = 0
    assets = (
        db.query(ProductAsset)
        .filter(
            ProductAsset.product_id == int(product.id),
            ProductAsset.extracted_text.isnot(None),
        )
        .all()
    )
    for asset in assets:
        for raw_name, raw_value in parse_pdf_feature_pairs(asset.extracted_text):
            normalized_name = normalize_candidate_name(raw_name)
            feature_def = accepted_defs.get(normalized_name) or direct_defs.get(normalized_name)
            if feature_def is None:
                continue
            try:
                _set_feature_value(
                    db,
                    product_id=int(product.id),
                    feature_def=feature_def,
                    raw_value=str(raw_value or ""),
                    manufacturer_id=int(product.manufacturer_id or 0) or None,
                    apply_rules=True,
                )
                updates += 1
            except Exception:
                continue
    return updates


def _catalog_apply_learned_snapshot_features(
    db: Session,
    *,
    product: Product,
    unknown_columns: dict[str, str],
) -> int:
    if int(product.device_kind_id or 0) <= 0 or not unknown_columns:
        return 0
    accepted_candidates = (
        db.query(FeatureCandidate)
        .filter(
            FeatureCandidate.device_kind_id == int(product.device_kind_id),
            FeatureCandidate.status == "accepted",
            FeatureCandidate.feature_def_id.isnot(None),
            or_(
                FeatureCandidate.manufacturer_id.is_(None),
                FeatureCandidate.manufacturer_id == (int(product.manufacturer_id or 0) or None),
            ),
        )
        .all()
    )
    accepted_defs = {
        str(row.normalized_name or "").strip(): db.get(FeatureDef, int(row.feature_def_id or 0))
        for row in accepted_candidates
        if int(row.feature_def_id or 0) > 0
    }
    updates = 0
    for raw_name, raw_value in unknown_columns.items():
        feature_def = accepted_defs.get(normalize_candidate_name(raw_name))
        if feature_def is None:
            continue
        try:
            _set_feature_value(
                db,
                product_id=int(product.id),
                feature_def=feature_def,
                raw_value=str(raw_value or ""),
                manufacturer_id=int(product.manufacturer_id or 0) or None,
                apply_rules=True,
            )
            updates += 1
        except Exception:
            continue
    return updates


def _catalog_sync_product_assets(
    db: Session,
    *,
    product: Product,
    asset_inputs: dict[str, object],
    manufacturer_row: Manufacturer | None = None,
    datasheet_upload: UploadFile | None = None,
    manual_upload: UploadFile | None = None,
    energy_label_upload: UploadFile | None = None,
    source_kind: str,
    eager_remote_image_download: bool = True,
    eager_remote_asset_types: set[str] | None = None,
) -> dict[str, object]:
    summary: dict[str, object] = {"images": 0, "documents": 0, "candidate_updates": 0, "failures": []}
    documents_touched = False
    eager_document_types = {
        str(item or "").strip().lower()
        for item in (eager_remote_asset_types or {"datasheet_pdf", "manual_pdf", "energy_label", "other"})
        if str(item or "").strip()
    }
    effective_documents = {str(key): str(value) for key, value in dict(asset_inputs.get("documents") or {}).items() if str(value or "").strip()}
    if "datasheet_pdf" not in effective_documents and (datasheet_upload is None or not str(getattr(datasheet_upload, "filename", "") or "").strip()):
        if not _catalog_has_product_asset(db, product_id=int(product.id), asset_type="datasheet_pdf"):
            auto_datasheet_url = _build_product_datasheet_url(
                db,
                manufacturer_row if manufacturer_row is not None else (db.get(Manufacturer, int(product.manufacturer_id)) if int(product.manufacturer_id or 0) > 0 else None),
                product,
            )
            if auto_datasheet_url:
                effective_documents["datasheet_pdf"] = auto_datasheet_url
                summary["auto_datasheet_url"] = auto_datasheet_url
    for slot_no, url in dict(asset_inputs.get("images") or {}).items():
        if not str(url or "").strip():
            continue
        try:
            sync_remote_product_asset(
                db,
                product=product,
                asset_type="image",
                slot_no=int(slot_no),
                source_url_raw=str(url),
                source_kind=source_kind,
                download_binary=bool(eager_remote_image_download),
            )
            summary["images"] = int(summary.get("images") or 0) + 1
        except Exception as exc:
            failures = list(summary.get("failures") or [])
            failures.append(f"Bild {int(slot_no)}: {exc}")
            summary["failures"] = failures
    for asset_type, url in effective_documents.items():
        if not str(url or "").strip():
            continue
        try:
            eager_download = str(asset_type or "").strip().lower() in eager_document_types
            sync_remote_product_asset(
                db,
                product=product,
                asset_type=str(asset_type),
                slot_no=None,
                source_url_raw=str(url),
                source_kind=source_kind,
                download_binary=eager_download,
                extract_text_enabled=eager_download and str(asset_type or "").strip().lower() == "datasheet_pdf",
            )
            summary["documents"] = int(summary.get("documents") or 0) + 1
            documents_touched = documents_touched or eager_download
        except Exception as exc:
            failures = list(summary.get("failures") or [])
            failures.append(f"{asset_type}: {exc}")
            summary["failures"] = failures
    for upload, asset_type in (
        (datasheet_upload, "datasheet_pdf"),
        (manual_upload, "manual_pdf"),
        (energy_label_upload, "energy_label"),
    ):
        if upload is None or not str(getattr(upload, "filename", "") or "").strip():
            continue
        try:
            sync_uploaded_product_asset(
                db,
                product=product,
                asset_type=asset_type,
                upload=upload,
                source_kind=source_kind,
                extract_text_enabled=True,
            )
            summary["documents"] = int(summary.get("documents") or 0) + 1
            documents_touched = True
        except Exception as exc:
            failures = list(summary.get("failures") or [])
            failures.append(f"{asset_type} Upload: {exc}")
            summary["failures"] = failures
    if documents_touched and int(product.device_kind_id or 0) > 0:
        try:
            summary["candidate_updates"] = collect_feature_candidates_from_product_assets(db, product=product)
            summary["applied_feature_updates"] = _catalog_apply_learned_asset_features(db, product=product)
        except Exception as exc:
            failures = list(summary.get("failures") or [])
            failures.append(f"Analyse: {exc}")
            summary["failures"] = failures
    return summary


def _catalog_sync_legacy_image_fields(product: Product, asset_inputs: dict[str, object]) -> None:
    for idx in range(1, PRODUCT_IMAGE_URL_MAX + 1):
        setattr(product, f"image_url_{idx}", None)
    product.image_url = None


def _catalog_prune_manual_image_assets(
    db: Session,
    *,
    product: Product,
    submitted_slots: set[int],
) -> int:
    removed = 0
    for row in _catalog_product_asset_rows(db, int(product.id), asset_type="image"):
        slot_no = int(getattr(row, "slot_no", 0) or 0)
        if slot_no <= 0 or slot_no in submitted_slots:
            continue
        local_path = product_asset_abs_path(str(row.local_path or "").strip())
        if (
            local_path
            and local_path.exists()
            and db.query(ProductAsset.id)
            .filter(
                ProductAsset.local_path == str(row.local_path or "").strip(),
                ProductAsset.id != int(row.id),
            )
            .first()
            is None
        ):
            try:
                local_path.unlink()
            except Exception:
                pass
        db.delete(row)
        removed += 1
    return removed


def _feature_candidate_status_label(value: str | None) -> str:
    key = str(value or "").strip().lower()
    return {
        "proposed": "Offen",
        "accepted": "Übernommen",
        "ignored": "Ignoriert",
        "merged": "Zusammengeführt",
    }.get(key, key or "-")


def _catalog_find_existing_product(
    db: Session,
    *,
    manufacturer_id: int | None,
    device_kind_id: int | None,
    material_no: str | None,
    ean: str | None,
    sales_name: str | None,
    title_1: str | None,
    title_2: str | None,
) -> Product | None:
    ean_value = str(ean or "").strip()
    if ean_value:
        row = db.query(Product).filter(Product.ean == ean_value).one_or_none()
        if row:
            return row
    material = str(material_no or "").strip()
    if material:
        query = db.query(Product).filter(func.lower(Product.material_no) == material.lower())
        if int(manufacturer_id or 0) > 0:
            query = query.filter(or_(Product.manufacturer_id == int(manufacturer_id), Product.manufacturer_id.is_(None)))
        row = query.order_by(Product.id.desc()).first()
        if row:
            return row
    parts = [str(sales_name or "").strip(), str(title_1 or "").strip(), str(title_2 or "").strip()]
    title = " ".join([part for part in parts if part]).strip()
    if title and int(device_kind_id or 0) > 0 and int(manufacturer_id or 0) > 0:
        query = db.query(Product).filter(
            Product.device_kind_id == int(device_kind_id),
            func.lower(func.coalesce(Product.name, "")) == title.lower(),
        )
        query = query.filter(Product.manufacturer_id == int(manufacturer_id))
        return query.order_by(Product.id.desc()).first()
    return None


def _catalog_import_existing_product_maps(
    db: Session,
    *,
    manufacturer_id: int,
    device_kind_id: int,
    rows: list[dict[str, str]],
    product_field_map: dict[str, str],
    ean_column: str,
    description_columns: list[str] | None = None,
) -> dict[str, dict[str, Product]]:
    ean_values: set[str] = set()
    material_values: set[str] = set()
    title_values: set[str] = set()
    for row in rows:
        core_values = _import_core_values_from_row(
            row,
            product_field_map=product_field_map,
            ean_column=ean_column,
            description_columns=list(description_columns or []),
        )
        ean_value = str(core_values.get("ean") or "").strip()
        if ean_value:
            ean_values.add(ean_value)
        material_value = str(core_values.get("material_no") or "").strip().lower()
        if material_value:
            material_values.add(material_value)
        title_value = " ".join(
            [
                str(core_values.get("sales_name") or "").strip(),
                str(core_values.get("product_title_1") or "").strip(),
                str(core_values.get("product_title_2") or "").strip(),
            ]
        ).strip().lower()
        if title_value:
            title_values.add(title_value)

    by_ean: dict[str, Product] = {}
    if ean_values:
        for row in (
            db.query(Product)
            .filter(Product.ean.in_(sorted(ean_values)))
            .order_by(Product.id.desc())
            .all()
        ):
            key = str(row.ean or "").strip()
            if key and key not in by_ean:
                by_ean[key] = row

    by_material: dict[str, Product] = {}
    if material_values:
        material_query = db.query(Product).filter(func.lower(func.coalesce(Product.material_no, "")).in_(sorted(material_values)))
        if int(manufacturer_id or 0) > 0:
            material_query = material_query.filter(
                or_(Product.manufacturer_id == int(manufacturer_id), Product.manufacturer_id.is_(None))
            ).order_by(case((Product.manufacturer_id == int(manufacturer_id), 0), else_=1), Product.id.desc())
        else:
            material_query = material_query.order_by(Product.id.desc())
        for row in material_query.all():
            key = str(row.material_no or "").strip().lower()
            if key and key not in by_material:
                by_material[key] = row

    by_title: dict[str, Product] = {}
    if title_values and int(manufacturer_id or 0) > 0 and int(device_kind_id or 0) > 0:
        for row in (
            db.query(Product)
            .filter(
                Product.manufacturer_id == int(manufacturer_id),
                Product.device_kind_id == int(device_kind_id),
                func.lower(func.coalesce(Product.name, "")).in_(sorted(title_values)),
            )
            .order_by(Product.id.desc())
            .all()
        ):
            key = str(row.name or "").strip().lower()
            if key and key not in by_title:
                by_title[key] = row

    return {
        "ean": by_ean,
        "material": by_material,
        "title": by_title,
    }


def _catalog_import_lookup_existing_product(
    *,
    product_maps: dict[str, dict[str, Product]],
    manufacturer_id: int | None,
    device_kind_id: int | None,
    core_values: dict[str, object],
) -> Product | None:
    ean_value = str(core_values.get("ean") or "").strip()
    if ean_value:
        row = product_maps.get("ean", {}).get(ean_value)
        if row is not None:
            return row
    material_value = str(core_values.get("material_no") or "").strip().lower()
    if material_value:
        row = product_maps.get("material", {}).get(material_value)
        if row is not None:
            return row
    title_value = " ".join(
        [
            str(core_values.get("sales_name") or "").strip(),
            str(core_values.get("product_title_1") or "").strip(),
            str(core_values.get("product_title_2") or "").strip(),
        ]
    ).strip().lower()
    if title_value and int(manufacturer_id or 0) > 0 and int(device_kind_id or 0) > 0:
        row = product_maps.get("title", {}).get(title_value)
        if row is not None:
            return row
    return None


def _catalog_import_register_product_maps(
    product_maps: dict[str, dict[str, Product]],
    *,
    product: Product,
) -> None:
    ean_value = str(getattr(product, "ean", "") or "").strip()
    if ean_value:
        product_maps.setdefault("ean", {})[ean_value] = product
    material_value = str(getattr(product, "material_no", "") or "").strip().lower()
    if material_value:
        product_maps.setdefault("material", {})[material_value] = product
    title_value = str(getattr(product, "name", "") or "").strip().lower()
    if title_value:
        product_maps.setdefault("title", {})[title_value] = product


_CATALOG_PDF_KIND_KEYWORDS = {
    "geschirrspueler": ("geschirrsp", "dishwasher", "maßgedecke", "massgedecke"),
    "waschmaschine": ("waschmaschine", "washing machine", "schleuderdrehzahl"),
    "waeschetrockner": ("waeschetrockner", "wäschetrockner", "dryer", "kondensation"),
    "kuehlschrank": ("kuehlschrank", "kühlschrank", "refrigerator", "kühlen", "kuehlen"),
    "gefrierschrank": ("gefrierschrank", "freezer", "gefrieren"),
    "kuehl_gefrierkombination": ("kühl-gefrier", "kuehl-gefrier", "fridge freezer"),
    "backofen": ("backofen", "oven", "einbaubackofen"),
    "kochfeld": ("kochfeld", "hob", "induktion", "ceranfeld"),
    "herd": ("herd", "cooker"),
}


def _catalog_pdf_text_from_payload(payload: bytes | None, *, file_name: str = "datenblatt.pdf") -> str:
    if not payload:
        return ""
    suffix = Path(str(file_name or "datenblatt.pdf")).suffix or ".pdf"
    try:
        return str(agreement_extract_pdf_text_from_bytes(bytes(payload), suffix=suffix) or "").strip()
    except Exception:
        return ""


def _catalog_pdf_text_from_upload(upload: UploadFile | None) -> str:
    if upload is None or not str(getattr(upload, "filename", "") or "").strip():
        return ""
    try:
        payload = upload.file.read()
        upload.file.seek(0)
    except Exception:
        return ""
    if not payload:
        return ""
    return _catalog_pdf_text_from_payload(payload, file_name=str(getattr(upload, "filename", "") or "datenblatt.pdf"))


def _catalog_guess_device_kind_from_pdf_text(db: Session, text: str) -> DeviceKind | None:
    normalized_text = normalize_candidate_name(text)
    if not normalized_text:
        return None
    kinds = db.query(DeviceKind).order_by(DeviceKind.name.asc(), DeviceKind.id.asc()).all()
    best: tuple[int, DeviceKind] | None = None
    for row in kinds:
        kind_name = str(row.name or "").strip()
        kind_key = normalize_candidate_name(kind_name)
        score = 0
        if kind_key and kind_key in normalized_text:
            score += 10
        for keyword in _CATALOG_PDF_KIND_KEYWORDS.get(kind_key, ()):
            if normalize_candidate_name(keyword) in normalized_text:
                score += 4
        if score <= 0:
            continue
        if best is None or score > best[0]:
            best = (score, row)
    return best[1] if best else None


def _catalog_guess_product_core_from_pdf_text(db: Session, text: str) -> dict[str, object]:
    clean_text = str(text or "").strip()
    if not clean_text:
        return {}
    lines = [str(line).strip() for line in re.split(r"[\r\n]+", clean_text) if str(line).strip()]
    normalized_text = normalize_candidate_name(clean_text)
    manufacturers = db.query(Manufacturer).filter(Manufacturer.active == True).order_by(func.length(Manufacturer.name).desc(), Manufacturer.id.asc()).all()
    manufacturer_row = None
    for row in manufacturers:
        name = str(row.name or "").strip()
        normalized_name = normalize_candidate_name(name)
        if normalized_name and normalized_name in normalized_text:
            manufacturer_row = row
            break

    kind_row = _catalog_guess_device_kind_from_pdf_text(db, clean_text)

    ean_value = ""
    for match in re.finditer(r"\b(\d{13})\b", clean_text):
        try:
            ean_value = normalize_ean(match.group(1))
            break
        except Exception:
            continue

    material_no = ""
    material_patterns = (
        r"(?:material(?:nummer|nr\.?)|artikel(?:nummer|nr\.?)|mat(?:erial)?\.?(?:nr\.?)?)\s*[:#]?\s*([A-Z0-9][A-Z0-9./_-]{3,40})",
        r"(?:e[- ]?nr\.?|modell(?:bezeichnung)?|model(?: no\.?)?)\s*[:#]?\s*([A-Z0-9][A-Z0-9./_-]{3,40})",
    )
    for pattern in material_patterns:
        match = re.search(pattern, clean_text, flags=re.I)
        if match:
            material_no = str(match.group(1) or "").strip()
            break

    title_candidates: list[str] = []
    for line in lines[:30]:
        if len(line) < 5 or len(line) > 120:
            continue
        if ":" in line:
            continue
        lowered = normalize_candidate_name(line)
        if lowered in {"datenblatt", "produktdatenblatt", "energy label"}:
            continue
        if manufacturer_row and normalize_candidate_name(str(manufacturer_row.name or "")) == lowered:
            continue
        title_candidates.append(line)
    sales_name = title_candidates[0] if title_candidates else ""
    title_1 = title_candidates[1] if len(title_candidates) > 1 else sales_name
    title_2 = title_candidates[2] if len(title_candidates) > 2 else ""

    description_lines = [line for line in lines[:20] if line not in {sales_name, title_1, title_2}]
    return {
        "manufacturer_id": int(getattr(manufacturer_row, "id", 0) or 0),
        "manufacturer_name": str(getattr(manufacturer_row, "name", "") or "").strip(),
        "device_kind_id": int(getattr(kind_row, "id", 0) or 0),
        "device_kind_name": str(getattr(kind_row, "name", "") or "").strip(),
        "ean": ean_value,
        "material_no": material_no,
        "sales_name": sales_name,
        "product_title_1": title_1,
        "product_title_2": title_2,
        "description": "\n".join(description_lines[:4]).strip(),
    }


def _catalog_guess_product_core_from_pdf_upload(db: Session, upload: UploadFile | None) -> dict[str, object]:
    text = _catalog_pdf_text_from_upload(upload)
    if not text:
        return {}
    payload = _catalog_guess_product_core_from_pdf_text(db, text)
    payload["pdf_text"] = text
    return payload


def _catalog_attribute_name_variants(attr: AttributeDef) -> set[str]:
    variants: set[str] = set()
    for raw in (
        str(attr.name or "").strip(),
        str(attr.slug or "").replace("_", " ").replace("-", " ").strip(),
    ):
        normalized = normalize_candidate_name(raw)
        if normalized:
            variants.add(normalized)
    return variants


def _catalog_phrase_like_match(left: str, right: str) -> bool:
    left_norm = normalize_candidate_name(left)
    right_norm = normalize_candidate_name(right)
    if not left_norm or not right_norm or left_norm == right_norm:
        return False
    if " " not in left_norm and " " not in right_norm:
        return False
    return f" {left_norm} " in f" {right_norm} " or f" {right_norm} " in f" {left_norm} "


def _catalog_attribute_pdf_alias_lookup(
    db: Session,
    *,
    attrs: list[AttributeDef],
    manufacturer_id: int | None,
    device_kind_id: int | None,
) -> dict[int, list[AttributePdfAlias]]:
    attr_ids = [int(attr.id) for attr in attrs if int(getattr(attr, "id", 0) or 0) > 0]
    if not attr_ids:
        return {}
    query = db.query(AttributePdfAlias).filter(AttributePdfAlias.attribute_id.in_(attr_ids))
    manufacturer_id = int(manufacturer_id or 0) or None
    device_kind_id = int(device_kind_id or 0) or None
    if manufacturer_id is not None:
        query = query.filter(
            or_(
                AttributePdfAlias.manufacturer_id.is_(None),
                AttributePdfAlias.manufacturer_id == manufacturer_id,
            )
        )
    else:
        query = query.filter(AttributePdfAlias.manufacturer_id.is_(None))
    if device_kind_id is not None:
        query = query.filter(
            or_(
                AttributePdfAlias.device_kind_id.is_(None),
                AttributePdfAlias.device_kind_id == device_kind_id,
            )
        )
    else:
        query = query.filter(AttributePdfAlias.device_kind_id.is_(None))
    rows = query.order_by(
        case((AttributePdfAlias.manufacturer_id.isnot(None), 0), else_=1),
        case((AttributePdfAlias.device_kind_id.isnot(None), 0), else_=1),
        AttributePdfAlias.id.asc(),
    ).all()
    out: dict[int, list[AttributePdfAlias]] = {}
    for row in rows:
        out.setdefault(int(row.attribute_id), []).append(row)
    return out


def _catalog_pdf_attribute_match_score(
    normalized_name: str,
    *,
    variants: set[str],
    aliases: list[AttributePdfAlias],
) -> tuple[int, str]:
    best_score = -1
    best_alias = ""
    for alias in aliases:
        alias_norm = normalize_candidate_name(str(alias.alias_norm or alias.alias_text or ""))
        if not alias_norm:
            continue
        score = -1
        if normalized_name == alias_norm:
            score = 220
        elif _catalog_phrase_like_match(normalized_name, alias_norm):
            score = 170
        if score > 0 and int(alias.manufacturer_id or 0) > 0:
            score += 20
        if score > 0 and int(alias.device_kind_id or 0) > 0:
            score += 10
        if score > best_score:
            best_score = score
            best_alias = str(alias.alias_text or "").strip() or alias_norm
    for variant in variants:
        score = -1
        if normalized_name == variant:
            score = 140
        elif _catalog_phrase_like_match(normalized_name, variant):
            score = 90
        if score > best_score:
            best_score = score
            best_alias = variant
    return best_score, best_alias


def _catalog_collect_pdf_attribute_suggestions(
    db: Session,
    attrs: list[AttributeDef],
    *,
    pdf_text: str,
    manufacturer_id: int | None = None,
    device_kind_id: int | None = None,
) -> tuple[dict[int, dict[str, str]], list[str]]:
    pairs = parse_pdf_feature_pairs(pdf_text)
    suggestions: dict[int, dict[str, str]] = {}
    notes: list[str] = []
    alias_lookup = _catalog_attribute_pdf_alias_lookup(
        db,
        attrs=attrs,
        manufacturer_id=manufacturer_id,
        device_kind_id=device_kind_id,
    )
    for attr in attrs:
        variants = _catalog_attribute_name_variants(attr)
        if not variants and not alias_lookup.get(int(attr.id)):
            continue
        best_score = -1
        best_item: dict[str, str] | None = None
        for raw_name, raw_value in pairs:
            normalized_name = normalize_candidate_name(raw_name)
            if not normalized_name:
                continue
            score, matched_alias = _catalog_pdf_attribute_match_score(
                normalized_name,
                variants=variants,
                aliases=list(alias_lookup.get(int(attr.id)) or []),
            )
            if score <= best_score:
                continue
            try:
                parsed_value = _catalog_parse_pdf_attribute_value(attr, raw_value)
            except Exception:
                continue
            if not parsed_value:
                continue
            best_score = score
            best_item = {
                "source_label": str(raw_name or "").strip(),
                "source_value": str(raw_value or "").strip(),
                "value": parsed_value,
                "matched_alias": matched_alias,
                "match_score": str(score),
                "search_query": str(raw_name or raw_value or "").strip(),
            }
        if best_item is not None:
            suggestions[int(attr.id)] = best_item
        elif bool(attr.is_required):
            notes.append(f"Pflichtattribut ohne sicheren PDF-Treffer: {str(attr.name or '').strip()}")
    return suggestions, notes


def _catalog_upsert_attribute_pdf_alias(
    db: Session,
    *,
    attribute_id: int,
    alias_text: str,
    manufacturer_id: int | None = None,
    device_kind_id: int | None = None,
) -> None:
    alias_clean = str(alias_text or "").strip()
    alias_norm = normalize_candidate_name(alias_clean)
    if not alias_norm or int(attribute_id or 0) <= 0:
        return
    manufacturer_id = int(manufacturer_id or 0) or None
    device_kind_id = int(device_kind_id or 0) or None
    row = (
        db.query(AttributePdfAlias)
        .filter(
            AttributePdfAlias.attribute_id == int(attribute_id),
            AttributePdfAlias.alias_norm == alias_norm,
            AttributePdfAlias.manufacturer_id == manufacturer_id,
            AttributePdfAlias.device_kind_id == device_kind_id,
        )
        .one_or_none()
    )
    if row is None:
        row = AttributePdfAlias(
            attribute_id=int(attribute_id),
            manufacturer_id=manufacturer_id,
            device_kind_id=device_kind_id,
            alias_text=alias_clean[:220],
            alias_norm=alias_norm[:220],
            created_at=_utcnow_naive(),
        )
    row.alias_text = alias_clean[:220]
    row.alias_norm = alias_norm[:220]
    row.updated_at = _utcnow_naive()
    db.add(row)


def _catalog_match_pdf_option(raw_value: str, options: list[str]) -> str | None:
    normalized_raw = normalize_candidate_name(raw_value)
    if not normalized_raw:
        return None
    for option in options:
        normalized_option = normalize_candidate_name(option)
        if normalized_raw == normalized_option:
            return option
    for option in options:
        normalized_option = normalize_candidate_name(option)
        if not normalized_option:
            continue
        if normalized_option in normalized_raw or normalized_raw in normalized_option:
            return option
    return None


def _catalog_parse_pdf_attribute_value(attr: AttributeDef, raw_value: str) -> str:
    raw = str(raw_value or "").strip()
    if not raw:
        return ""
    label = str(attr.name or f"Attribut {int(attr.id)}")
    if attr.value_type == "bool":
        normalized = normalize_candidate_name(raw)
        if any(token in normalized for token in ("nicht", "nein", "without", "ohne", "false", "0")):
            return "false"
        if any(token in normalized for token in ("ja", "mit", "vorhanden", "true", "1", "yes")):
            return "true"
        raise ValueError(f"Bool-Wert nicht erkannt: {label}")
    if attr.value_type == "number":
        match = re.search(r"-?\d+(?:[.,]\d+)?", raw)
        if not match:
            raise ValueError(f"Zahl nicht erkannt: {label}")
        numeric = float(str(match.group(0)).replace(",", "."))
        return str(int(numeric)) if numeric.is_integer() else str(numeric)
    if attr.value_type == "enum":
        options = _enum_options_from_json(attr.enum_options_json)
        if not options:
            return raw[:500]
        if bool(attr.is_multi):
            selected: list[str] = []
            for token in re.split(r"[,\n;|/]+", raw):
                token_clean = str(token or "").strip()
                if not token_clean:
                    continue
                matched = _catalog_match_pdf_option(token_clean, options)
                if matched and matched not in selected:
                    selected.append(matched)
            if selected:
                return json.dumps(selected, ensure_ascii=False)
            raise ValueError(f"Enum-Wert nicht erkannt: {label}")
        matched = _catalog_match_pdf_option(raw, options)
        if not matched:
            raise ValueError(f"Enum-Wert nicht erkannt: {label}")
        return matched
    return raw[:1000]


def _catalog_collect_pdf_attribute_values(
    attrs: list[AttributeDef],
    *,
    db: Session,
    pdf_text: str,
    manufacturer_id: int | None = None,
    device_kind_id: int | None = None,
) -> tuple[dict[int, str], list[str]]:
    suggestions, notes = _catalog_collect_pdf_attribute_suggestions(
        db,
        attrs,
        pdf_text=pdf_text,
        manufacturer_id=manufacturer_id,
        device_kind_id=device_kind_id,
    )
    return {
        int(attr_id): str(item.get("value") or "").strip()
        for attr_id, item in suggestions.items()
        if str(item.get("value") or "").strip()
    }, notes


_CATALOG_PDF_CORE_LABEL_HINTS = {
    "ean",
    "ean nummer",
    "gtin",
    "artikelnummer",
    "artikel nr",
    "materialnummer",
    "material nr",
    "modell",
    "modellbezeichnung",
    "modell nummer",
    "modellnummer",
    "produkt",
    "produktname",
    "produkt titel",
    "produkttitel",
    "produkttitel 1",
    "produkttitel 2",
    "verkaufsbezeichnung",
    "verkausbezeichnung",
    "marke",
    "hersteller",
    "geraeteart",
    "geraetetyp",
    "geraete typ",
    "device type",
    "device kind",
    "modellreihe",
}

_CATALOG_PDF_ATTRIBUTE_GROUP_HINTS: tuple[tuple[tuple[str, ...], str], ...] = (
    (("energie", "verbrauch", "effizienz", "geraeusch", "geraeusch", "lautstaerke", "wasser", "strom"), "Energie & Verbrauch"),
    (("hoehe", "breite", "tiefe", "masse", "mae", "nische", "gewicht", "abmess"), "Maße & Einbau"),
    (("programm", "funktion", "komfort", "connect", "autodos", "display", "steuer", "bedien"), "Komfort"),
    (("leistung", "spannung", "anschluss", "technik", "motor", "volumen", "kapazitaet", "kapazität", "trommel"), "Technik"),
)


def _catalog_is_core_pdf_label(raw_name: str | None) -> bool:
    normalized = normalize_candidate_name(raw_name)
    if not normalized:
        return True
    if normalized in _CATALOG_PDF_CORE_LABEL_HINTS:
        return True
    if any(token in normalized for token in ("ean", "material", "modell", "produkt", "verkaufs", "hersteller", "geraeteart", "geraetetyp", "device type", "device kind")):
        return True
    return False


def _catalog_guess_attribute_group_from_pdf_label(raw_name: str | None) -> str:
    normalized = normalize_candidate_name(raw_name)
    if not normalized:
        return ""
    for keywords, group_name in _CATALOG_PDF_ATTRIBUTE_GROUP_HINTS:
        if any(keyword in normalized for keyword in keywords):
            return group_name
    return "Allgemein"


def _catalog_attribute_choice_rows(attrs: list[AttributeDef]) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    for attr in attrs:
        group_name = str(attr.group_name or "").strip()
        label = str(attr.name or "").strip()
        if group_name:
            label = f"{group_name} / {label}"
        rows.append(
            {
                "id": int(attr.id),
                "label": label,
                "value_type": str(attr.value_type or "text"),
                "group_name": group_name,
                "is_required": bool(attr.is_required),
                "is_multi": bool(attr.is_multi),
                "enum_options": _enum_options_from_json(attr.enum_options_json),
            }
        )
    return rows


def _catalog_collect_pdf_new_attribute_candidates(
    db: Session,
    attrs: list[AttributeDef],
    *,
    pdf_text: str,
    manufacturer_id: int | None = None,
    device_kind_id: int | None = None,
) -> list[dict[str, object]]:
    pairs = parse_pdf_feature_pairs(pdf_text)
    if not pairs:
        return []
    suggestions, _ = _catalog_collect_pdf_attribute_suggestions(
        db,
        attrs,
        pdf_text=pdf_text,
        manufacturer_id=manufacturer_id,
        device_kind_id=device_kind_id,
    )
    matched_pairs: set[tuple[str, str]] = set()
    attr_variant_map: dict[str, int] = {}
    for attr in attrs:
        for variant in _catalog_attribute_name_variants(attr):
            attr_variant_map.setdefault(variant, int(attr.id))
    for item in suggestions.values():
        source_label = normalize_candidate_name(item.get("source_label"))
        source_value = normalize_candidate_name(item.get("source_value"))
        if source_label and source_value:
            matched_pairs.add((source_label, source_value))

    deduped: dict[str, dict[str, object]] = {}
    ordered_keys: list[str] = []
    for raw_name, raw_value in pairs:
        source_label = str(raw_name or "").strip()
        source_value = str(raw_value or "").strip()
        normalized_name = normalize_candidate_name(source_label)
        normalized_value = normalize_candidate_name(source_value)
        if not normalized_name or not source_value:
            continue
        if _catalog_is_core_pdf_label(source_label):
            continue
        if (normalized_name, normalized_value) in matched_pairs:
            continue
        dedupe_key = normalized_name
        existing = deduped.get(dedupe_key)
        existing_attr_id = int(attr_variant_map.get(normalized_name) or 0)
        item = {
            "source_label": source_label,
            "source_value": source_value,
            "attribute_id": existing_attr_id,
            "attribute_name": source_label,
            "value_type": "text" if existing_attr_id else guess_feature_data_type([source_value]),
            "group_name": _catalog_guess_attribute_group_from_pdf_label(source_label),
            "enum_options": "",
            "is_required": False,
            "is_multi": False,
            "search_query": source_label,
        }
        if existing is None:
            deduped[dedupe_key] = item
            ordered_keys.append(dedupe_key)
            continue
        if len(source_value) > len(str(existing.get("source_value") or "")):
            deduped[dedupe_key] = item
    out: list[dict[str, object]] = []
    for index, key in enumerate(ordered_keys, start=1):
        row = dict(deduped.get(key) or {})
        row["id"] = index
        out.append(row)
    return out


def _catalog_prepare_pdf_review_candidates(
    *,
    base_candidates: list[dict[str, object]],
    form_data: dict[str, str | list[str]],
    attrs: list[AttributeDef],
) -> list[dict[str, object]]:
    attr_map = {int(attr.id): attr for attr in attrs}
    prepared: list[dict[str, object]] = []
    for default_index, candidate in enumerate(base_candidates, start=1):
        token = str(candidate.get("id") or default_index)
        selected_attr_id = _to_int(
            _form_scalar(form_data, f"candidate_attribute_id_{token}", str(int(candidate.get('attribute_id') or 0) or "")),
            int(candidate.get("attribute_id") or 0),
        )
        selected_attr = attr_map.get(selected_attr_id)
        if f"candidate_seen_{token}" not in form_data and f"candidate_use_{token}" not in form_data:
            form_data[f"candidate_use_{token}"] = "1"
        if f"candidate_attribute_id_{token}" not in form_data and selected_attr_id > 0:
            form_data[f"candidate_attribute_id_{token}"] = str(selected_attr_id)
        if f"candidate_attribute_name_{token}" not in form_data:
            form_data[f"candidate_attribute_name_{token}"] = str(
                (selected_attr.name if selected_attr else candidate.get("attribute_name")) or candidate.get("source_label") or ""
            ).strip()
        if f"candidate_value_type_{token}" not in form_data:
            form_data[f"candidate_value_type_{token}"] = str(
                (selected_attr.value_type if selected_attr else candidate.get("value_type")) or "text"
            ).strip()
        if f"candidate_group_name_{token}" not in form_data and (selected_attr is None or not str(selected_attr.group_name or "").strip()):
            form_data[f"candidate_group_name_{token}"] = str(candidate.get("group_name") or "").strip()
        if f"candidate_enum_options_{token}" not in form_data and selected_attr is None:
            form_data[f"candidate_enum_options_{token}"] = str(candidate.get("enum_options") or "").strip()
        if f"candidate_confirmed_value_{token}" not in form_data:
            form_data[f"candidate_confirmed_value_{token}"] = str(candidate.get("source_value") or "").strip()
        if f"candidate_source_label_{token}" not in form_data:
            form_data[f"candidate_source_label_{token}"] = str(candidate.get("source_label") or "").strip()
        if f"candidate_source_value_{token}" not in form_data:
            form_data[f"candidate_source_value_{token}"] = str(candidate.get("source_value") or "").strip()
        prepared.append(
            {
                "id": token,
                "marker_attr_id": -int(default_index),
                "selected_attribute_id": selected_attr_id,
                "source_label": str(candidate.get("source_label") or "").strip(),
                "source_value": str(candidate.get("source_value") or "").strip(),
                "search_query": str(candidate.get("search_query") or candidate.get("source_label") or "").strip(),
            }
        )
    return prepared


def _catalog_parse_review_attribute_value(
    *,
    label: str,
    value_type: str,
    raw_value: str,
    is_required: bool = False,
    is_multi: bool = False,
    enum_options: list[str] | None = None,
) -> str:
    clean = str(raw_value or "").strip()
    value_type = str(value_type or "text").strip().lower() or "text"
    options = [str(option).strip() for option in list(enum_options or []) if str(option).strip()]
    if not clean:
        if is_required:
            raise ValueError(f"Pflichtattribut fehlt: {label}")
        return ""
    if value_type == "bool":
        lowered = normalize_candidate_name(clean)
        if lowered in {"ja", "yes", "true", "1", "mit", "vorhanden"}:
            return "true"
        if lowered in {"nein", "no", "false", "0", "ohne", "nicht"}:
            return "false"
        raise ValueError(f"Ungültiger Ja/Nein-Wert bei Attribut: {label}")
    if value_type == "number":
        try:
            numeric = float(clean.replace(",", "."))
        except Exception as exc:
            raise ValueError(f"Ungültige Zahl bei Attribut: {label}") from exc
        return str(int(numeric)) if numeric.is_integer() else str(numeric)
    if value_type == "enum":
        if not options:
            if is_multi:
                options = [token for token in [str(part).strip() for part in re.split(r"[,\n;|/]+", clean)] if token]
            else:
                options = [clean]
        if is_multi:
            selected: list[str] = []
            for token in [str(part).strip() for part in re.split(r"[,\n;|/]+", clean)]:
                if not token:
                    continue
                matched = _catalog_match_pdf_option(token, options)
                if not matched:
                    raise ValueError(f"Ungültige Auswahl bei Attribut: {label}")
                if matched not in selected:
                    selected.append(matched)
            if is_required and not selected:
                raise ValueError(f"Pflichtattribut fehlt: {label}")
            return json.dumps(selected, ensure_ascii=False) if selected else ""
        matched = _catalog_match_pdf_option(clean, options)
        if not matched:
            raise ValueError(f"Ungültige Auswahl bei Attribut: {label}")
        return matched
    return clean[:1000]


def _catalog_create_kind_attribute(
    db: Session,
    *,
    device_kind_id: int,
    name: str,
    value_type: str,
    group_name: str = "",
    enum_options_raw: str = "",
    is_required: bool = False,
    is_multi: bool = False,
) -> AttributeDef:
    name_clean = str(name or "").strip()
    if not name_clean:
        raise ValueError("Attributname fehlt.")
    value_type_clean = str(value_type or "").strip().lower()
    if value_type_clean not in _ALLOWED_ATTRIBUTE_TYPES:
        raise ValueError("Ungültiger Attribut-Typ.")
    options = _parse_enum_options(enum_options_raw)
    enum_json = None
    if value_type_clean == "enum":
        if not options:
            raise ValueError("Auswahlattribute brauchen mindestens eine Option.")
        enum_json = json.dumps(options, ensure_ascii=False)
    else:
        is_multi = False
    slug = slugify(name_clean)
    base_slug = slug
    idx = 2
    while db.query(AttributeDef).filter(AttributeDef.slug == slug).count() > 0:
        slug = f"{base_slug}-{idx}"
        idx += 1
    attr = AttributeDef(
        name=name_clean,
        slug=slug,
        value_type=value_type_clean,
        enum_options_json=enum_json,
        is_multi=bool(is_multi),
        group_name=str(group_name or "").strip() or None,
        is_required=bool(is_required),
    )
    db.add(attr)
    db.flush()
    db.add(AttributeScope(attribute_id=int(attr.id), device_kind_id=int(device_kind_id), device_type_id=None))
    db.flush()
    return attr


def _catalog_upsert_product_attribute_value(db: Session, *, product_id: int, attribute_id: int, value_text: str) -> None:
    pav = (
        db.query(ProductAttributeValue)
        .filter(ProductAttributeValue.product_id == int(product_id), ProductAttributeValue.attribute_id == int(attribute_id))
        .one_or_none()
    )
    if pav is None:
        pav = ProductAttributeValue(product_id=int(product_id), attribute_id=int(attribute_id), value_text=value_text)
    else:
        pav.value_text = value_text
    db.add(pav)


def _catalog_parse_pdf_review_candidate_actions(
    form,
    *,
    attrs: list[AttributeDef],
    device_kind_id: int,
    form_errors: dict[str, str],
) -> list[dict[str, object]]:
    attr_map = {int(attr.id): attr for attr in attrs}

    def add_error(field_key: str, message: str) -> None:
        if field_key not in form_errors:
            form_errors[field_key] = message

    out: list[dict[str, object]] = []
    candidate_ids = [str(item).strip() for item in form.getlist("new_attr_candidate_ids") if str(item).strip()]
    for token in candidate_ids:
        use_row = str(form.get(f"candidate_use_{token}") or "").strip().lower() in {"1", "on", "true", "yes"}
        source_label = str(form.get(f"candidate_source_label_{token}") or "").strip()
        source_value = str(form.get(f"candidate_source_value_{token}") or "").strip()
        confirmed_raw = str(form.get(f"candidate_confirmed_value_{token}") or "").strip()
        marker = _catalog_parse_pdf_marker(form.get(f"marker_new_{token}"))
        if not use_row:
            continue
        target_attr_id = _to_int(form.get(f"candidate_attribute_id_{token}"), 0)
        selected_attr = attr_map.get(target_attr_id)
        if selected_attr is not None:
            try:
                confirmed_value = _catalog_parse_review_attribute_value(
                    label=str(selected_attr.name or f"Attribut {int(selected_attr.id)}"),
                    value_type=str(selected_attr.value_type or "text"),
                    raw_value=confirmed_raw,
                    is_required=bool(selected_attr.is_required),
                    is_multi=bool(selected_attr.is_multi),
                    enum_options=_enum_options_from_json(selected_attr.enum_options_json),
                )
            except ValueError as exc:
                add_error(f"candidate_confirmed_value_{token}", str(exc))
                continue
            out.append(
                {
                    "attribute": selected_attr,
                    "source_label": source_label,
                    "source_value": source_value,
                    "confirmed_value": confirmed_value,
                    "marker": marker,
                    "created_new": False,
                }
            )
            continue

        if int(device_kind_id or 0) <= 0:
            add_error("device_kind_id", "Geräteart fehlt für neue Merkmale.")
            continue
        attribute_name = str(form.get(f"candidate_attribute_name_{token}") or "").strip()
        value_type = str(form.get(f"candidate_value_type_{token}") or "").strip().lower() or "text"
        group_name = str(form.get(f"candidate_group_name_{token}") or "").strip()
        enum_options_raw = str(form.get(f"candidate_enum_options_{token}") or "").strip()
        is_required = str(form.get(f"candidate_is_required_{token}") or "").strip().lower() in {"1", "on", "true", "yes"}
        is_multi = str(form.get(f"candidate_is_multi_{token}") or "").strip().lower() in {"1", "on", "true", "yes"}
        if not attribute_name:
            add_error(f"candidate_attribute_name_{token}", "Name für neues Merkmal fehlt.")
            continue
        if value_type not in _ALLOWED_ATTRIBUTE_TYPES:
            add_error(f"candidate_value_type_{token}", "Ungültiger Attribut-Typ.")
            continue
        if value_type == "enum" and not enum_options_raw and confirmed_raw:
            enum_options_raw = confirmed_raw
        try:
            confirmed_value = _catalog_parse_review_attribute_value(
                label=attribute_name,
                value_type=value_type,
                raw_value=confirmed_raw,
                is_required=is_required,
                is_multi=is_multi,
                enum_options=_parse_enum_options(enum_options_raw),
            )
        except ValueError as exc:
            add_error(f"candidate_confirmed_value_{token}", str(exc))
            continue
        out.append(
            {
                "attribute": None,
                "new_attribute_payload": {
                    "name": attribute_name,
                    "value_type": value_type,
                    "group_name": group_name,
                    "enum_options_raw": enum_options_raw,
                    "is_required": is_required,
                    "is_multi": is_multi,
                },
                "source_label": source_label,
                "source_value": source_value,
                "confirmed_value": confirmed_value,
                "marker": marker,
                "created_new": True,
            }
        )
    return out


def _catalog_pdf_extract_fallback_output(
    *,
    core_guess: dict[str, object],
    attrs: list[AttributeDef],
    attr_values: dict[int, str],
    notes: list[str],
) -> dict[str, object]:
    coverage = 0
    for key in ("manufacturer_name", "device_kind_name", "ean", "material_no", "sales_name", "product_title_1"):
        if str(core_guess.get(key) or "").strip():
            coverage += 1
    confidence = min(0.96, 0.18 + (coverage * 0.11) + (len(attr_values) * 0.04))
    hard_case = coverage < 4 or (bool(attrs) and len(attr_values) == 0) or bool(notes)
    attr_name_map = {int(attr.id): str(attr.name or "").strip() for attr in attrs}
    return {
        "manufacturer_name": str(core_guess.get("manufacturer_name") or "").strip(),
        "device_kind_name": str(core_guess.get("device_kind_name") or "").strip(),
        "ean": str(core_guess.get("ean") or "").strip(),
        "material_no": str(core_guess.get("material_no") or "").strip(),
        "sales_name": str(core_guess.get("sales_name") or "").strip(),
        "product_title_1": str(core_guess.get("product_title_1") or "").strip(),
        "product_title_2": str(core_guess.get("product_title_2") or "").strip(),
        "description": str(core_guess.get("description") or "").strip(),
        "hard_case": bool(hard_case),
        "confidence": round(float(confidence), 3),
        "notes": list(notes)[:12],
        "attributes": [
            {
                "attribute_name": attr_name_map.get(int(attr_id), f"Attribut {int(attr_id)}"),
                "value": str(value or "").strip(),
            }
            for attr_id, value in attr_values.items()
            if str(value or "").strip()
        ],
    }


def _catalog_ai_pdf_extract_review(
    db: Session,
    *,
    pdf_text: str,
    fallback_output: dict[str, object],
    attrs: list[AttributeDef],
) -> dict[str, object]:
    result = ai_run_task(
        db,
        settings=_openai_settings(db, include_secret=True),
        task_name="catalog_pdf_extract",
        input_payload={
            "pdf_text": str(pdf_text or "")[:24000],
            "fallback": fallback_output,
            "attributes": [
                {
                    "name": str(attr.name or "").strip(),
                    "value_type": str(attr.value_type or "text"),
                    "group_name": str(attr.group_name or "").strip(),
                    "options": _enum_options_from_json(attr.enum_options_json) if str(attr.value_type or "") == "enum" else [],
                }
                for attr in attrs
            ],
        },
        fallback_output=fallback_output,
        related_object_type="catalog_pdf_extract",
        related_object_id=None,
        title="Produktdatenblatt-Analyse",
        allow_openai=True,
    )
    output = result.get("output") if isinstance(result.get("output"), dict) else {}
    merged = dict(fallback_output)
    for key, value in output.items():
        if key == "attributes" and not list(value or []):
            continue
        if key == "notes" and not list(value or []):
            continue
        if value in (None, "") and not isinstance(value, bool):
            continue
        merged[key] = value
    merged["ai_model"] = str(getattr(result.get("log"), "model_name", "") or "")
    merged["ai_cached"] = bool(result.get("cached"))
    return merged


def _catalog_pdf_extract_review(
    db: Session,
    *,
    pdf_text: str,
    manufacturer_row: Manufacturer | None = None,
    device_kind_row: DeviceKind | None = None,
) -> dict[str, object]:
    parser_core = _catalog_guess_product_core_from_pdf_text(db, pdf_text)
    if manufacturer_row is not None:
        parser_core["manufacturer_id"] = int(manufacturer_row.id)
        parser_core["manufacturer_name"] = str(manufacturer_row.name or "").strip()
    if device_kind_row is not None:
        parser_core["device_kind_id"] = int(device_kind_row.id)
        parser_core["device_kind_name"] = str(device_kind_row.name or "").strip()

    resolved_kind = device_kind_row
    if resolved_kind is None and int(parser_core.get("device_kind_id") or 0) > 0:
        resolved_kind = db.get(DeviceKind, int(parser_core.get("device_kind_id") or 0))
    attrs = _applicable_attributes(db, int(getattr(resolved_kind, "id", 0) or 0), None) if resolved_kind else []
    attr_values, attr_notes = _catalog_collect_pdf_attribute_values(
        attrs,
        db=db,
        pdf_text=pdf_text,
        manufacturer_id=int(getattr(manufacturer_row, "id", 0) or parser_core.get("manufacturer_id") or 0) or None,
        device_kind_id=int(getattr(resolved_kind, "id", 0) or parser_core.get("device_kind_id") or 0) or None,
    )
    fallback_output = _catalog_pdf_extract_fallback_output(
        core_guess=parser_core,
        attrs=attrs,
        attr_values=attr_values,
        notes=attr_notes,
    )
    reviewed_output = dict(fallback_output)
    if bool(fallback_output.get("hard_case")) and pdf_text.strip():
        reviewed_output = _catalog_ai_pdf_extract_review(
            db,
            pdf_text=pdf_text,
            fallback_output=fallback_output,
            attrs=attrs,
        )

    manufacturers = db.query(Manufacturer).filter(Manufacturer.active == True).order_by(Manufacturer.name.asc(), Manufacturer.id.asc()).all()
    manufacturer_lookup = _catalog_scope_lookup_map(manufacturers)
    resolved_manufacturer = manufacturer_row
    if resolved_manufacturer is None:
        resolved_manufacturer = _catalog_resolve_named_row(str(reviewed_output.get("manufacturer_name") or ""), manufacturer_lookup)
        if resolved_manufacturer is None and int(parser_core.get("manufacturer_id") or 0) > 0:
            resolved_manufacturer = db.get(Manufacturer, int(parser_core.get("manufacturer_id") or 0))

    kinds = db.query(DeviceKind).order_by(DeviceKind.name.asc(), DeviceKind.id.asc()).all()
    kind_lookup = _catalog_scope_lookup_map(kinds)
    resolved_kind = device_kind_row
    if resolved_kind is None:
        resolved_kind = _catalog_resolve_named_row(str(reviewed_output.get("device_kind_name") or ""), kind_lookup)
        if resolved_kind is None and int(parser_core.get("device_kind_id") or 0) > 0:
            resolved_kind = db.get(DeviceKind, int(parser_core.get("device_kind_id") or 0))

    attrs = _applicable_attributes(db, int(getattr(resolved_kind, "id", 0) or 0), None) if resolved_kind else []
    attr_lookup: dict[str, AttributeDef] = {}
    for attr in attrs:
        for variant in _catalog_attribute_name_variants(attr):
            attr_lookup.setdefault(variant, attr)
    final_attr_values: dict[int, str] = {}
    attr_warnings: list[str] = []
    for row in list(reviewed_output.get("attributes") or []):
        if not isinstance(row, dict):
            continue
        attr_name = str(row.get("attribute_name") or "").strip()
        raw_value = str(row.get("value") or "").strip()
        if not attr_name or not raw_value:
            continue
        attr = attr_lookup.get(normalize_candidate_name(attr_name))
        if attr is None:
            continue
        try:
            final_attr_values[int(attr.id)] = _catalog_parse_pdf_attribute_value(attr, raw_value)
        except Exception:
            attr_warnings.append(f"Attribut konnte nicht sicher übernommen werden: {attr_name}")

    final_core = {
        "manufacturer_id": int(getattr(resolved_manufacturer, "id", 0) or 0),
        "manufacturer_name": str(getattr(resolved_manufacturer, "name", "") or reviewed_output.get("manufacturer_name") or "").strip(),
        "device_kind_id": int(getattr(resolved_kind, "id", 0) or 0),
        "device_kind_name": str(getattr(resolved_kind, "name", "") or reviewed_output.get("device_kind_name") or "").strip(),
        "ean": str(reviewed_output.get("ean") or parser_core.get("ean") or "").strip(),
        "material_no": str(reviewed_output.get("material_no") or parser_core.get("material_no") or "").strip(),
        "sales_name": str(reviewed_output.get("sales_name") or parser_core.get("sales_name") or "").strip(),
        "product_title_1": str(reviewed_output.get("product_title_1") or parser_core.get("product_title_1") or "").strip(),
        "product_title_2": str(reviewed_output.get("product_title_2") or parser_core.get("product_title_2") or "").strip(),
        "description": str(reviewed_output.get("description") or parser_core.get("description") or "").strip(),
    }
    notes = [str(note) for note in list(reviewed_output.get("notes") or []) if str(note).strip()]
    notes.extend(attr_warnings)
    return {
        "core": final_core,
        "attrs": attrs,
        "attribute_values": final_attr_values,
        "notes": notes[:16],
        "confidence": float(reviewed_output.get("confidence") or fallback_output.get("confidence") or 0.0),
        "hard_case": bool(reviewed_output.get("hard_case")),
        "ai_model": str(reviewed_output.get("ai_model") or "").strip(),
        "ai_cached": bool(reviewed_output.get("ai_cached")),
    }


def _catalog_apply_pdf_review_to_product(
    db: Session,
    *,
    product: Product,
    pdf_text: str,
    manufacturer_row: Manufacturer | None = None,
    device_kind_row: DeviceKind | None = None,
) -> dict[str, object]:
    review = _catalog_pdf_extract_review(
        db,
        pdf_text=pdf_text,
        manufacturer_row=manufacturer_row,
        device_kind_row=device_kind_row,
    )
    applied = 0
    for attr in review.get("attrs") or []:
        if not isinstance(attr, AttributeDef):
            continue
        value_text = str((review.get("attribute_values") or {}).get(int(attr.id)) or "").strip()
        if not value_text:
            continue
        pav = (
            db.query(ProductAttributeValue)
            .filter(ProductAttributeValue.product_id == int(product.id), ProductAttributeValue.attribute_id == int(attr.id))
            .one_or_none()
        )
        if pav:
            pav.value_text = value_text
            db.add(pav)
        else:
            db.add(ProductAttributeValue(product_id=int(product.id), attribute_id=int(attr.id), value_text=value_text))
        applied += 1
    review["applied_count"] = applied
    return review


def _catalog_product_pdf_review_root() -> Path:
    root = ensure_dirs()["tmp"] / CATALOG_PDF_REVIEW_DIRNAME
    root.mkdir(parents=True, exist_ok=True)
    return root


def _catalog_product_pdf_review_token() -> str:
    return uuid.uuid4().hex


def _catalog_product_pdf_review_dir(token: str) -> Path:
    clean = str(token or "").strip().lower()
    if not re.fullmatch(r"[a-f0-9]{32}", clean):
        raise ValueError("Ungültiger Prüf-Token.")
    path = (_catalog_product_pdf_review_root() / clean).resolve()
    root = _catalog_product_pdf_review_root().resolve()
    path.relative_to(root)
    return path


def _catalog_save_product_pdf_review(
    *,
    file_name: str,
    payload: bytes,
    review_data: dict[str, object],
) -> str:
    token = _catalog_product_pdf_review_token()
    review_dir = _catalog_product_pdf_review_dir(token)
    review_dir.mkdir(parents=True, exist_ok=True)
    suffix = Path(str(file_name or "datenblatt.pdf")).suffix.lower() or ".pdf"
    (review_dir / f"source{suffix}").write_bytes(payload)
    (review_dir / "review.json").write_text(json.dumps(review_data, ensure_ascii=False), encoding="utf-8")
    return token


def _catalog_store_product_pdf_review(token: str, review_data: dict[str, object]) -> None:
    review_dir = _catalog_product_pdf_review_dir(token)
    review_dir.mkdir(parents=True, exist_ok=True)
    (review_dir / "review.json").write_text(json.dumps(review_data, ensure_ascii=False), encoding="utf-8")


def _catalog_load_product_pdf_review(token: str) -> dict[str, object]:
    review_dir = _catalog_product_pdf_review_dir(token)
    review_file = review_dir / "review.json"
    if not review_file.is_file():
        raise FileNotFoundError("Prüfdaten wurden nicht gefunden.")
    loaded = json.loads(review_file.read_text(encoding="utf-8"))
    return loaded if isinstance(loaded, dict) else {}


def _catalog_delete_product_pdf_review(token: str) -> None:
    try:
        review_dir = _catalog_product_pdf_review_dir(token)
    except Exception:
        return
    if review_dir.exists():
        shutil.rmtree(review_dir, ignore_errors=True)


def _catalog_product_pdf_review_source_path(token: str) -> Path:
    review_dir = _catalog_product_pdf_review_dir(token)
    for candidate in review_dir.glob("source.*"):
        if candidate.is_file():
            return candidate
    raise FileNotFoundError("Datenblatt-Datei wurde nicht gefunden.")


def _minimum_visible_fields(item_type: str) -> set[str]:
    normalized = _normalize_item_type(item_type, fallback="material")
    if normalized == "appliance":
        return {"sales_name", "material_no", "manufacturer_id", "device_kind_id"}
    if normalized == "spare_part":
        return {"name", "material_no"}
    if normalized == "accessory":
        return {"name", "material_no"}
    return {"name", "material_no"}


def _catalog_admin_form_fields() -> list[dict]:
    return [field for field in FORM_FIELDS if str(field.get("key") or "") not in CATALOG_DEPRECATED_FORM_FIELDS]


def _fix_existing_product_categories(db: Session) -> None:
    """Korrigiert Kategorisierung bestehender Produkte.

    1. Dampfbacköfen: Produkte in Einbauherd/Backofen die 'Dampf'/'Steam' enthalten
       werden nach Dampfbackofen verschoben
    2. Zubehör: Produkte mit DeviceKind 'Zubehör' bekommen item_type='accessory'
    """
    fixed_count = 0

    # 1. Dampfbacköfen umkategorisieren
    backofen_kind = db.query(DeviceKind).filter(DeviceKind.name == "Einbauherd/Backofen").one_or_none()
    dampf_kind = db.query(DeviceKind).filter(DeviceKind.name == "Dampfbackofen").one_or_none()
    if backofen_kind and dampf_kind:
        candidates = (
            db.query(Product)
            .filter(
                Product.device_kind_id == int(backofen_kind.id),
                Product.active == True,
            )
            .all()
        )
        for product in candidates:
            check_text = " ".join([
                str(product.sales_name or ""),
                str(product.name or ""),
                str(product.product_title_1 or ""),
                str(product.description or "")[:300],
            ]).lower()
            if any(w in check_text for w in ("dampfback", "dampf-back", "mit dampf", "combi steam", "steam oven", "kompaktdampf")):
                product.device_kind_id = int(dampf_kind.id)
                db.add(product)
                fixed_count += 1

    # 2. Zubehör-Produkte: item_type korrigieren
    zubehoer_kinds = (
        db.query(DeviceKind)
        .filter(DeviceKind.name.in_(["Zubehör", "Komplementäre Produkte"]))
        .all()
    )
    for kind in zubehoer_kinds:
        updated = (
            db.query(Product)
            .filter(
                Product.device_kind_id == int(kind.id),
                Product.item_type != "accessory",
            )
            .update({Product.item_type: "accessory"}, synchronize_session=False)
        )
        fixed_count += int(updated or 0)

    # 3. Sets → Herd-Set umkategorisieren
    set_kind = db.query(DeviceKind).filter(DeviceKind.name == "Set").one_or_none()
    herdset_kind = db.query(DeviceKind).filter(DeviceKind.name == "Herd-Set").one_or_none()
    if set_kind and herdset_kind and int(set_kind.id) != int(herdset_kind.id):
        updated = (
            db.query(Product)
            .filter(Product.device_kind_id == int(set_kind.id))
            .update({Product.device_kind_id: int(herdset_kind.id)}, synchronize_session=False)
        )
        fixed_count += int(updated or 0)

    if fixed_count > 0:
        try:
            db.flush()
        except Exception:
            pass
        logger.info("Produktkategorien korrigiert: %d Produkte", fixed_count)


def _seed_manufacturer_datasheet_links(db: Session) -> None:
    """BSH-Marken und weitere Hersteller: Datenblatt-Linklogik konfigurieren.

    BSH-URL-Schema: https://media3.bsh-group.com/Documents/specsheet/de-DE/{sales_name}.pdf
    Gilt für: Siemens, Neff, Bosch, Constructa, Gaggenau, Junker

    Miele, AEG/Electrolux, Liebherr haben individuelle URLs → kein Pattern,
    Datenblatt kommt aus der CSV-Spalte Product_fiche.
    """
    BSH_SPECSHEET_BASE = "https://media3.bsh-group.com/Documents/specsheet/de-DE/"
    BSH_SPECSHEET_SUFFIX = ".pdf"

    # (Name, v1, v4, v2_source) — nur für Hersteller mit berechenbarer URL
    MANUFACTURER_LINKS: list[tuple[str, str, str, str]] = [
        ("Siemens", BSH_SPECSHEET_BASE, BSH_SPECSHEET_SUFFIX, "sales_name"),
        ("Neff", BSH_SPECSHEET_BASE, BSH_SPECSHEET_SUFFIX, "sales_name"),
        ("Bosch", BSH_SPECSHEET_BASE, BSH_SPECSHEET_SUFFIX, "sales_name"),
        ("Constructa", BSH_SPECSHEET_BASE, BSH_SPECSHEET_SUFFIX, "sales_name"),
        ("Gaggenau", BSH_SPECSHEET_BASE, BSH_SPECSHEET_SUFFIX, "sales_name"),
        ("Junker", BSH_SPECSHEET_BASE, BSH_SPECSHEET_SUFFIX, "sales_name"),
    ]

    for name, v1, v4, v2_source in MANUFACTURER_LINKS:
        existing = db.query(Manufacturer).filter(Manufacturer.name == name).one_or_none()
        if not existing:
            existing = db.query(Manufacturer).filter(Manufacturer.name.ilike(name)).first()
        if existing:
            if not str(existing.datasheet_var_1 or "").strip():
                existing.datasheet_var_1 = v1
                existing.datasheet_var_3 = None
                existing.datasheet_var_4 = v4
                existing.datasheet_var2_source = v2_source
                db.add(existing)
        else:
            mfg = Manufacturer(
                name=name,
                datasheet_var_1=v1,
                datasheet_var_3=None,
                datasheet_var_4=v4,
                datasheet_var2_source=v2_source,
                active=True,
            )
            db.add(mfg)
    try:
        db.flush()
    except Exception:
        pass


def _seed_defaults(db: Session):
    changed = False
    # instance
    inst = db.get(InstanceConfig, 1)
    if not inst:
        db.add(InstanceConfig(id=1, initialized_at=None))
        changed = True
    # setup state
    st = db.get(SetupState, 1)
    if not st:
        db.add(SetupState(id=1, current_step=0, completed_steps_json="[]"))
        changed = True
    # company profile row
    cp = db.get(CompanyProfile, 1)
    if not cp:
        db.add(CompanyProfile(id=1))
        changed = True
    # default service port info (does not change docker mapping, just documentation)
    if db.query(ServicePort.id).filter(ServicePort.service_name == "web").first() is None:
        db.add(ServicePort(service_name="web", port=int(os.environ.get("APP_PORT", "8080")), protocol="http", exposed=True))
        changed = True
    # default storage paths
    defaults = {
        "data": str(DATA_DIR),
        "uploads": str(DATA_DIR / "uploads"),
        "backups": str(DATA_DIR / "backups"),
        "secrets": str(DATA_DIR / "secrets"),
    }
    existing_paths = {
        str(row[0])
        for row in db.query(StoragePath.purpose).filter(StoragePath.purpose.in_(tuple(defaults.keys()))).all()
    }
    for purpose, path in defaults.items():
        if purpose not in existing_paths:
            db.add(StoragePath(purpose=purpose, path=path))
            changed = True
    # default areas
    area_names = {str(row[0] or "").strip().lower() for row in db.query(Area.name).all()}
    for name in ["Waschen", "Spülen", "Kälte", "Wärme"]:
        if name.lower() not in area_names:
            db.add(Area(name=name))
            changed = True
    # default stock conditions
    condition_codes = {str(row[0]) for row in db.query(StockConditionDef.code).all()}
    for code, label_de, sort_order, active in DEFAULT_STOCK_CONDITIONS:
        if code not in condition_codes:
            db.add(StockConditionDef(code=code, label_de=label_de, sort_order=sort_order, active=active))
            changed = True
    _seed_item_type_field_rules(db)
    _ensure_repair_warehouse(db)
    _ensure_scrap_warehouse(db)
    if _system_setting_get(db, REPAIR_AUTO_PAPERLESS, None) is None:
        _system_setting_set(db, REPAIR_AUTO_PAPERLESS, "0")
        changed = True
    if _system_setting_get(db, SPARE_AUTO_PAPERLESS, None) is None:
        _system_setting_set(db, SPARE_AUTO_PAPERLESS, "0")
        changed = True
    if _system_setting_get(db, CATALOG_AUTO_IMPORT_MAIL, None) is None:
        _system_setting_set(db, CATALOG_AUTO_IMPORT_MAIL, "1")
        changed = True
    if _system_setting_get(db, CATALOG_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, None) is None:
        _system_setting_set(db, CATALOG_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, "0")
        changed = True
    if db.query(User).filter(User.role == "user").update({User.role: "lesen"}):
        changed = True
    # Gerätearten und Features seeden
    try:
        seed_all_device_kinds_and_features(db)
    except Exception as exc:
        logger.warning("Feature-Seeding fehlgeschlagen: %s", exc)
    # BSH-Marken: Datenblatt-Linklogik konfigurieren
    _seed_manufacturer_datasheet_links(db)
    # Bestehende Daten korrigieren
    _fix_existing_product_categories(db)
    if changed or db.new or db.dirty or db.deleted:
        db.commit()
    else:
        db.rollback()


async def _startup_maintenance_loop() -> None:
    await asyncio.sleep(BACKGROUND_TASK_STARTUP_DELAY_SECONDS)
    start = dt.datetime.now()
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        reindexed = _reindex_missing_search_blobs(db, batch_size=250)
        duration = (dt.datetime.now() - start).total_seconds()
        logger.info("startup_maintenance_complete total=%.3fs reindexed=%s", duration, reindexed)
    except Exception:
        db.rollback()
        logger.exception("startup_maintenance_failed")
    finally:
        db.close()


