def _sevdesk_document_detail_path(kind: str, document_id: str | int | None) -> str:
    raw_id = str(document_id or "").strip()
    if not raw_id:
        return ""
    kind_key = _crm_normalize_key(kind)
    if kind_key in {"offer", "order"}:
        return f"/Order/{raw_id}"
    if kind_key == "invoice":
        return f"/Invoice/{raw_id}"
    return ""


def _sevdesk_fetch_document_payload(
    settings: dict[str, str | bool],
    *,
    kind: str,
    document_id: str | int | None,
) -> dict[str, object]:
    path = _sevdesk_document_detail_path(kind, document_id)
    if not path:
        return {}
    payload = sevdesk_request_json(
        settings,
        method="GET",
        path=path,
        query={"embed": "contact"},
    )
    return _sevdesk_first_object(payload)


def _sevdesk_offer_status_from_payload(payload: dict[str, object]) -> str:
    detail = _crm_sevdesk_live_document_detail_payload("order", payload)
    raw_status = _crm_normalize_key(sevdesk_first_value(payload, ("status", "orderStatus", "statusText")))
    label = _crm_normalize_key(detail.get("status_label"))
    if raw_status in {"rejected", "cancelled", "canceled"} or label == "abgelehnt":
        return "rejected"
    if raw_status in {"500", "1000", "accepted", "completed"} or label in {"angenommen", "bestaetigt", "abgeschlossen"}:
        return "accepted"
    if detail.get("sent_at") is not None or raw_status in {"200", "sent"} or label == "gesendet":
        return "sent"
    return "pushed"


def _sevdesk_invoice_status_from_payload(payload: dict[str, object]) -> str:
    detail = _crm_sevdesk_live_document_detail_payload("invoice", payload)
    raw_status = _crm_normalize_key(sevdesk_first_value(payload, ("status", "invoiceStatus", "statusText")))
    label = _crm_normalize_key(detail.get("status_label"))
    amount_cents = int(detail.get("amount_cents") or 0)
    paid_cents = int(detail.get("paid_cents") or 0)
    if raw_status in {"cancelled", "canceled", "storniert"} or label == "storniert":
        return "cancelled"
    if amount_cents > 0 and paid_cents >= amount_cents:
        return "paid"
    if paid_cents > 0 or raw_status in {"750", "partial", "teilbezahlt"} or label == "teilbezahlt":
        return "partially_paid"
    if detail.get("sent_at") is not None or raw_status in {"100", "200", "offen", "open", "sent"} or label in {"offen", "ueberfaellig"}:
        return "sent"
    return "pushed"


def _sevdesk_offer_status_title(status: str, reference: str) -> str:
    mapping = {
        "pushed": "Angebot in sevDesk angelegt",
        "sent": "Angebot über sevDesk versendet",
        "accepted": "Angebot in sevDesk angenommen",
        "rejected": "Angebot in sevDesk abgelehnt",
    }
    return f"{mapping.get(_crm_normalize_key(status), 'Angebot in sevDesk aktualisiert')}: {reference}"


def _sevdesk_invoice_status_title(status: str, reference: str) -> str:
    mapping = {
        "pushed": "Rechnung in sevDesk angelegt",
        "sent": "Rechnung über sevDesk versendet",
        "partially_paid": "Rechnung in sevDesk teilbezahlt",
        "paid": "Rechnung in sevDesk bezahlt",
        "cancelled": "Rechnung in sevDesk storniert",
    }
    return f"{mapping.get(_crm_normalize_key(status), 'Rechnung in sevDesk aktualisiert')}: {reference}"


def _sevdesk_sync_event_timestamp(status: str, detail: dict[str, object]) -> dt.datetime:
    status_key = _crm_normalize_key(status)
    if status_key == "sent":
        return (
            _crm_coerce_datetime(detail.get("sent_at"))
            or _crm_coerce_datetime(detail.get("event_date"))
            or _crm_coerce_datetime(detail.get("updated_at"))
            or _utcnow_naive()
        )
    return (
        _crm_coerce_datetime(detail.get("updated_at"))
        or _crm_coerce_datetime(detail.get("event_date"))
        or _crm_coerce_datetime(detail.get("sent_at"))
        or _utcnow_naive()
    )


def _sevdesk_offer_status_body(detail: dict[str, object]) -> str | None:
    parts = [
        str(detail.get("status_label") or "").strip(),
        _crm_clean_text(str(detail.get("subject_label") or "")),
    ]
    return " | ".join([part for part in parts if part]) or None


def _sevdesk_invoice_status_body(detail: dict[str, object]) -> str | None:
    parts = [
        str(detail.get("status_label") or "").strip(),
        f"offen {_format_eur(int(detail.get('open_amount_cents') or 0))}",
    ]
    return " | ".join([part for part in parts if part]) or None


def _sevdesk_voucher_status_label(status_code: str | None) -> str:
    mapping = {
        "50": "Entwurf",
        "100": "Offen",
        "150": "Uebertragen",
        "750": "Teilbezahlt",
        "1000": "Bezahlt",
    }
    key = str(status_code or "").strip()
    return mapping.get(key, key or "-")


def _sevdesk_voucher_local_status(payload: dict[str, object]) -> str:
    status_code = str(sevdesk_first_value(payload, ("status", "voucherStatus")) or "").strip()
    if status_code == "1000":
        return "paid"
    if status_code in {"150", "750"}:
        return "booked"
    if status_code in {"50", "100"}:
        return "pushed"
    return "pushed"


def _upsert_sevdesk_voucher_stage(db: Session, payload: dict[str, object]) -> SevdeskVoucherStage | None:
    voucher_id = str(sevdesk_first_value(payload, ("id", "voucherId", "ID")) or "").strip()
    if not voucher_id:
        return None
    row = (
        db.query(SevdeskVoucherStage)
        .filter(SevdeskVoucherStage.sevdesk_voucher_id == voucher_id)
        .one_or_none()
    )
    if row is None:
        row = SevdeskVoucherStage(sevdesk_voucher_id=voucher_id, created_at=_utcnow_naive())
    row.voucher_number = sevdesk_first_value(payload, ("voucherNumber", "number", "documentNumber")) or row.voucher_number
    contact_payload = payload.get("contact") if isinstance(payload.get("contact"), dict) else payload.get("supplier")
    if isinstance(contact_payload, dict):
        row.contact_id = sevdesk_first_value(contact_payload, ("id", "ID")) or row.contact_id
    row.status_code = sevdesk_first_value(payload, ("status", "voucherStatus")) or row.status_code
    row.status = _sevdesk_voucher_status_label(row.status_code)
    row.voucher_type = sevdesk_first_value(payload, ("voucherType",)) or row.voucher_type
    row.credit_debit = sevdesk_first_value(payload, ("creditDebit",)) or row.credit_debit
    row.voucher_date = _crm_coerce_datetime(sevdesk_first_value(payload, ("voucherDate", "invoiceDate"))) or row.voucher_date
    row.pay_date = _crm_coerce_datetime(sevdesk_first_value(payload, ("payDate",))) or row.pay_date
    row.payment_deadline = _crm_coerce_datetime(sevdesk_first_value(payload, ("paymentDeadline", "dueDate"))) or row.payment_deadline
    raw_amount = sevdesk_first_value(payload, ("sumGross", "totalGross", "amount"))
    try:
        row.amount_cents = int(round(float(str(raw_amount or "0").replace(",", ".")) * 100)) if raw_amount not in (None, "") else row.amount_cents
    except Exception:
        pass
    row.enshrined_at = _crm_coerce_datetime(sevdesk_first_value(payload, ("enshrined",))) or row.enshrined_at
    row.raw_json = json.dumps(payload, ensure_ascii=False)
    row.imported_at = _utcnow_naive()
    row.updated_at = _utcnow_naive()
    db.add(row)
    db.flush()
    return row


def _sevdesk_sync_voucher_drafts(db: Session, settings: dict[str, str | bool], limit: int = 120) -> dict[str, int]:
    rows = (
        db.query(IncomingVoucherDraft)
        .filter(IncomingVoucherDraft.sevdesk_voucher_id.isnot(None))
        .order_by(
            case((IncomingVoucherDraft.status.in_(("pushed", "booked")), 0), else_=1),
            func.coalesce(IncomingVoucherDraft.updated_at, IncomingVoucherDraft.created_at).desc(),
            IncomingVoucherDraft.id.desc(),
        )
        .limit(max(1, int(limit)))
        .all()
    )
    summary = {"checked": 0, "updated": 0, "errors": 0}
    public_settings = _sevdesk_settings(db, include_secret=False)
    for row in rows:
        voucher_id = str(row.sevdesk_voucher_id or "").strip()
        if not voucher_id:
            continue
        summary["checked"] += 1
        try:
            payload = sevdesk_request_json(settings, method="GET", path=f"/Voucher/{voucher_id}", query={"embed": "contact"})
            if isinstance(payload, dict):
                objects = payload.get("objects")
                if isinstance(objects, list) and objects and isinstance(objects[0], dict):
                    payload_row = objects[0]
                else:
                    payload_row = payload if isinstance(payload, dict) else {}
            else:
                payload_row = {}
            if not payload_row:
                continue
            stage = _upsert_sevdesk_voucher_stage(db, payload_row)
            next_status = _sevdesk_voucher_local_status(payload_row)
            next_status_label = str(getattr(stage, "status", "") or _sevdesk_voucher_status_label(sevdesk_first_value(payload_row, ("status", "voucherStatus")))).strip()
            changed = False
            if _crm_normalize_key(row.status) != _crm_normalize_key(next_status):
                row.status = next_status
                changed = True
            if str(row.sevdesk_voucher_status or "") != next_status_label:
                row.sevdesk_voucher_status = next_status_label or None
                changed = True
            next_due_date = _crm_coerce_datetime(sevdesk_first_value(payload_row, ("paymentDeadline", "dueDate"))) or row.due_date
            if _crm_coerce_datetime(row.due_date) != _crm_coerce_datetime(next_due_date):
                row.due_date = next_due_date
                changed = True
            next_voucher_date = _crm_coerce_datetime(sevdesk_first_value(payload_row, ("voucherDate", "invoiceDate"))) or row.voucher_date
            if _crm_coerce_datetime(row.voucher_date) != _crm_coerce_datetime(next_voucher_date):
                row.voucher_date = next_voucher_date
                changed = True
            _upsert_external_link(
                db,
                system_name="sevdesk",
                object_type="incoming_voucher_draft",
                object_id=int(row.id),
                external_key=str(getattr(stage, "voucher_number", "") or voucher_id),
                external_row_id=voucher_id,
                deep_link_url=sevdesk_build_api_url(public_settings, f"/Voucher/{voucher_id}") or None,
            )
            if changed:
                row.updated_at = _utcnow_naive()
                db.add(row)
                summary["updated"] += 1
        except Exception:
            summary["errors"] += 1
    return summary


def _sevdesk_sync_offer_drafts(db: Session, settings: dict[str, str | bool], limit: int = 80) -> dict[str, int]:
    public_settings = _sevdesk_settings(db, include_secret=False)
    rows = (
        db.query(OfferDraft)
        .filter(OfferDraft.sevdesk_order_id.isnot(None))
        .order_by(
            case((OfferDraft.status.in_(("pushed", "sent")), 0), else_=1),
            func.coalesce(OfferDraft.updated_at, OfferDraft.created_at).desc(),
            OfferDraft.id.desc(),
        )
        .limit(max(1, int(limit)))
        .all()
    )
    order_ids = [str(row.sevdesk_order_id or "").strip() for row in rows if str(row.sevdesk_order_id or "").strip()]
    stage_rows = (
        db.query(SevdeskOrderStage)
        .filter(SevdeskOrderStage.sevdesk_order_id.in_(order_ids or [""]))
        .all()
    ) if order_ids else []
    stage_map = {str(row.sevdesk_order_id or "").strip(): row for row in stage_rows if str(row.sevdesk_order_id or "").strip()}
    summary = {"checked": 0, "updated": 0, "events": 0, "errors": 0}
    for row in rows:
        order_id = str(row.sevdesk_order_id or "").strip()
        if not order_id:
            continue
        summary["checked"] += 1
        current_status = _crm_normalize_key(row.status)
        stage_payload = _json_dict(getattr(stage_map.get(order_id), "raw_json", ""))
        needs_live_fetch = current_status in {"pushed", "sent"} or not stage_payload
        try:
            payload = _sevdesk_fetch_document_payload(settings, kind="order", document_id=order_id) if needs_live_fetch else stage_payload
            if not payload:
                continue
            detail = _crm_sevdesk_live_document_detail_payload("order", payload)
            next_status = _sevdesk_offer_status_from_payload(payload)
            next_number = sevdesk_first_value(payload, ("orderNumber", "number", "documentNumber")) or row.sevdesk_order_number or order_id
            next_sevdesk_status = sevdesk_first_value(payload, ("status", "orderStatus", "statusText")) or row.sevdesk_status or ""
            next_pdf_url = str(detail.get("pdf_url") or row.pdf_url_local or "").strip()
            next_sent_at = _crm_coerce_datetime(detail.get("sent_at")) or row.sent_at
            status_changed = _crm_normalize_key(row.status) != _crm_normalize_key(next_status)
            sent_changed = _crm_coerce_datetime(row.sent_at) != _crm_coerce_datetime(next_sent_at)
            changed = False
            if str(row.sevdesk_order_number or "") != str(next_number or ""):
                row.sevdesk_order_number = str(next_number or "").strip() or None
                changed = True
            if str(row.sevdesk_status or "") != str(next_sevdesk_status or ""):
                row.sevdesk_status = str(next_sevdesk_status or "").strip() or None
                changed = True
            if _crm_normalize_key(row.status) != _crm_normalize_key(next_status):
                row.status = next_status
                changed = True
            if str(row.pdf_url_local or "") != next_pdf_url:
                row.pdf_url_local = next_pdf_url or None
                changed = True
            if _crm_coerce_datetime(row.sent_at) != _crm_coerce_datetime(next_sent_at):
                row.sent_at = next_sent_at
                changed = True
            if changed:
                row.updated_at = _utcnow_naive()
                db.add(row)
                summary["updated"] += 1
            _upsert_external_link(
                db,
                system_name="sevdesk",
                object_type="offer_draft",
                object_id=int(row.id),
                external_key=str(row.sevdesk_order_number or order_id),
                external_row_id=order_id,
                deep_link_url=_sevdesk_document_external_url(
                    public_settings,
                    kind="order",
                    document_id=order_id,
                    payload=payload,
                ) or None,
            )
            if status_changed or (next_status == "sent" and sent_changed):
                _crm_add_timeline_event(
                    db,
                    case_id=int(row.case_id or 0) or None,
                    master_customer_id=int(row.master_customer_id or 0) or None,
                    source_system="sevdesk",
                    event_type=f"offer_{next_status}",
                    title=_sevdesk_offer_status_title(next_status, str(row.sevdesk_order_number or order_id)),
                    body=_sevdesk_offer_status_body(detail),
                    external_ref=f"sevdesk_order:{order_id}",
                    event_ts=_sevdesk_sync_event_timestamp(next_status, detail),
                )
                summary["events"] += 1
        except Exception:
            summary["errors"] += 1
    return summary


def _sevdesk_sync_invoice_drafts(db: Session, settings: dict[str, str | bool], limit: int = 120) -> dict[str, int]:
    public_settings = _sevdesk_settings(db, include_secret=False)
    rows = (
        db.query(InvoiceDraft)
        .filter(InvoiceDraft.sevdesk_invoice_id.isnot(None))
        .order_by(
            case((InvoiceDraft.status.in_(("pushed", "sent", "partially_paid")), 0), else_=1),
            func.coalesce(InvoiceDraft.updated_at, InvoiceDraft.created_at).desc(),
            InvoiceDraft.id.desc(),
        )
        .limit(max(1, int(limit)))
        .all()
    )
    invoice_ids = [str(row.sevdesk_invoice_id or "").strip() for row in rows if str(row.sevdesk_invoice_id or "").strip()]
    stage_rows = (
        db.query(SevdeskInvoiceStage)
        .filter(SevdeskInvoiceStage.sevdesk_invoice_id.in_(invoice_ids or [""]))
        .all()
    ) if invoice_ids else []
    stage_map = {str(row.sevdesk_invoice_id or "").strip(): row for row in stage_rows if str(row.sevdesk_invoice_id or "").strip()}
    summary = {"checked": 0, "updated": 0, "events": 0, "errors": 0}
    for row in rows:
        invoice_id = str(row.sevdesk_invoice_id or "").strip()
        if not invoice_id:
            continue
        summary["checked"] += 1
        current_status = _crm_normalize_key(row.status)
        stage_payload = _json_dict(getattr(stage_map.get(invoice_id), "raw_json", ""))
        needs_live_fetch = current_status in {"pushed", "sent", "partially_paid"} or not stage_payload
        try:
            payload = _sevdesk_fetch_document_payload(settings, kind="invoice", document_id=invoice_id) if needs_live_fetch else stage_payload
            if not payload:
                continue
            detail = _crm_sevdesk_live_document_detail_payload("invoice", payload)
            next_status = _sevdesk_invoice_status_from_payload(payload)
            next_number = sevdesk_first_value(payload, ("invoiceNumber", "number", "documentNumber")) or row.sevdesk_invoice_number or invoice_id
            next_sevdesk_status = sevdesk_first_value(payload, ("status", "invoiceStatus", "statusText")) or row.sevdesk_status or ""
            next_pdf_url = str(detail.get("pdf_url") or row.pdf_url_local or "").strip()
            next_sent_at = _crm_coerce_datetime(detail.get("sent_at")) or row.sent_at
            next_invoice_date = _crm_coerce_datetime(sevdesk_first_value(payload, ("invoiceDate",))) or row.invoice_date
            next_due_date = _crm_coerce_datetime(sevdesk_first_value(payload, ("dueDate", "dueDateUntil", "timeToPay"))) or row.due_date
            status_changed = _crm_normalize_key(row.status) != _crm_normalize_key(next_status)
            sent_changed = _crm_coerce_datetime(row.sent_at) != _crm_coerce_datetime(next_sent_at)
            changed = False
            if str(row.sevdesk_invoice_number or "") != str(next_number or ""):
                row.sevdesk_invoice_number = str(next_number or "").strip() or None
                changed = True
            if str(row.sevdesk_status or "") != str(next_sevdesk_status or ""):
                row.sevdesk_status = str(next_sevdesk_status or "").strip() or None
                changed = True
            if _crm_normalize_key(row.status) != _crm_normalize_key(next_status):
                row.status = next_status
                changed = True
            if str(row.pdf_url_local or "") != next_pdf_url:
                row.pdf_url_local = next_pdf_url or None
                changed = True
            if _crm_coerce_datetime(row.sent_at) != _crm_coerce_datetime(next_sent_at):
                row.sent_at = next_sent_at
                changed = True
            if _crm_coerce_datetime(row.invoice_date) != _crm_coerce_datetime(next_invoice_date):
                row.invoice_date = next_invoice_date
                changed = True
            if _crm_coerce_datetime(row.due_date) != _crm_coerce_datetime(next_due_date):
                row.due_date = next_due_date
                changed = True
            if changed:
                row.updated_at = _utcnow_naive()
                db.add(row)
                summary["updated"] += 1
            _upsert_external_link(
                db,
                system_name="sevdesk",
                object_type="invoice_draft",
                object_id=int(row.id),
                external_key=str(row.sevdesk_invoice_number or invoice_id),
                external_row_id=invoice_id,
                deep_link_url=_sevdesk_document_external_url(
                    public_settings,
                    kind="invoice",
                    document_id=invoice_id,
                    payload=payload,
                ) or None,
            )
            if changed:
                _ensure_dunning_case_for_invoice(db, row)
            if status_changed or (next_status == "sent" and sent_changed):
                _crm_add_timeline_event(
                    db,
                    case_id=int(row.case_id or 0) or None,
                    master_customer_id=int(row.master_customer_id or 0) or None,
                    source_system="sevdesk",
                    event_type=f"invoice_{next_status}",
                    title=_sevdesk_invoice_status_title(next_status, str(row.sevdesk_invoice_number or invoice_id)),
                    body=_sevdesk_invoice_status_body(detail),
                    external_ref=f"sevdesk_invoice:{invoice_id}",
                    event_ts=_sevdesk_sync_event_timestamp(next_status, detail),
                )
                summary["events"] += 1
        except Exception:
            summary["errors"] += 1
    return summary


def _sevdesk_sync_sales_backchannel(db: Session, settings: dict[str, str | bool]) -> dict[str, int]:
    offer_summary = _sevdesk_sync_offer_drafts(db, settings)
    invoice_summary = _sevdesk_sync_invoice_drafts(db, settings)
    voucher_summary = _sevdesk_sync_voucher_drafts(db, settings)
    return {
        "checked": int(offer_summary.get("checked") or 0) + int(invoice_summary.get("checked") or 0) + int(voucher_summary.get("checked") or 0),
        "updated": int(offer_summary.get("updated") or 0) + int(invoice_summary.get("updated") or 0) + int(voucher_summary.get("updated") or 0),
        "events": int(offer_summary.get("events") or 0) + int(invoice_summary.get("events") or 0),
        "errors": int(offer_summary.get("errors") or 0) + int(invoice_summary.get("errors") or 0) + int(voucher_summary.get("errors") or 0),
    }


def _sevdesk_sync_once_background() -> None:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        settings = _sevdesk_settings(db, include_secret=True)
        if bool(settings.get("enabled")) and bool(settings.get("api_token")):
            _customer_init_import_sevdesk(db)
            _sevdesk_sync_sales_backchannel(db, settings)
            _sevdesk_set_last_sync_at(db)
            db.commit()
    except Exception:
        db.rollback()
        raise
    finally:
        db.close()


async def _sevdesk_sync_loop() -> None:
    await asyncio.sleep(BACKGROUND_TASK_STARTUP_DELAY_SECONDS + 4)
    while True:
        try:
            await asyncio.to_thread(_sevdesk_sync_once_background)
        except asyncio.CancelledError:
            raise
        except Exception:
            logger.exception("sevdesk_sync_loop_failed")
        await asyncio.sleep(SEVDESK_SYNC_INTERVAL)


def _paperless_sync_once_background() -> None:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        settings = _paperless_settings(db, include_secret=True)
        if bool(settings.get("enabled")) and bool(settings.get("token")) and str(settings.get("mode") or "poll_api").strip() == "poll_api":
            _paperless_sync_inbox_once(db)
            db.commit()
    except Exception:
        db.rollback()
        raise
    finally:
        db.close()


async def _paperless_sync_loop() -> None:
    await asyncio.sleep(BACKGROUND_TASK_STARTUP_DELAY_SECONDS + 6)
    while True:
        try:
            await asyncio.to_thread(_paperless_sync_once_background)
        except asyncio.CancelledError:
            raise
        except Exception:
            logger.exception("paperless_sync_loop_failed")
        await asyncio.sleep(PAPERLESS_SYNC_INTERVAL)


def _current_qty_for_min_scope(db: Session, product: Product, warehouse_id: int, bin_id: int | None) -> int:
    cond = _default_min_stock_condition(db)
    q = db.query(func.coalesce(func.sum(StockBalance.quantity), 0)).filter(
        StockBalance.product_id == product.id,
        StockBalance.warehouse_id == warehouse_id,
        StockBalance.condition == cond,
    )
    if bin_id is not None:
        q = q.filter(StockBalance.bin_id == bin_id)
    return int(q.scalar() or 0)


def _collect_min_stock_warnings(
    db: Session,
    warehouse_id: int | None = None,
    bin_id: int | None = None,
    limit: int = 200,
) -> list[dict]:
    q = db.query(MinStock).order_by(MinStock.id.asc())
    if warehouse_id:
        q = q.filter(MinStock.warehouse_id == warehouse_id)
    if bin_id is not None:
        q = q.filter(MinStock.bin_id == bin_id)
    rows = q.limit(limit).all()
    if not rows:
        return []
    products = {p.id: p for p in db.query(Product).all()}
    warehouses = {w.id: w for w in db.query(Warehouse).all()}
    bins = {b.id: b for b in db.query(WarehouseBin).all()}
    out: list[dict] = []
    for row in rows:
        product = products.get(row.product_id)
        if not product:
            continue
        current = _current_qty_for_min_scope(db, product, row.warehouse_id, row.bin_id)
        minimum = int(row.min_qty or 0)
        if current >= minimum:
            continue
        out.append(
            {
                "product_id": row.product_id,
                "product_name": product.name,
                "warehouse_id": row.warehouse_id,
                "warehouse_name": warehouses.get(row.warehouse_id).name if warehouses.get(row.warehouse_id) else str(row.warehouse_id),
                "bin_id": row.bin_id,
                "bin_name": bins.get(row.bin_id).code if row.bin_id and bins.get(row.bin_id) else "",
                "current_qty": current,
                "min_qty": minimum,
                "missing_qty": minimum - current,
            }
        )
    return out


ALLOWED_ROLES = ("admin", "lagerist", "techniker", "lesen")


@app.middleware("http")
async def setup_and_auth_gate(request: Request, call_next):
    # attach user + enforce first-run setup
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        request.state.user = get_current_user(request, db)
        if request.state.user is not None:
            now = dt.datetime.utcnow().replace(tzinfo=None)
            if "customer_view" not in request.session:
                request.session["customer_view"] = True
            if bool(request.session.get("customer_view", True)):
                request.session.pop("customer_view_until", None)
            else:
                until_raw = (request.session.get("customer_view_until") or "").strip()
                until_dt = None
                if until_raw:
                    try:
                        until_dt = dt.datetime.fromisoformat(until_raw)
                    except Exception:
                        until_dt = None
                if until_dt is None:
                    until_dt = now + dt.timedelta(seconds=CUSTOMER_VIEW_TIMEOUT_SECONDS)
                    request.session["customer_view_until"] = until_dt.isoformat()
                elif now >= until_dt:
                    request.session["customer_view"] = True
                    request.session.pop("customer_view_until", None)
        else:
            request.session.pop("customer_view", None)
            request.session.pop("customer_view_until", None)

        path = request.url.path
        allow_setup_paths = (
            path.startswith("/setup")
            or path.startswith("/static")
            or path.startswith("/meta")
            or path.startswith("/health")
        )

        if not is_initialized(db) and not allow_setup_paths:
            return RedirectResponse(url="/setup", status_code=302)

        # If initialized: keep /setup reachable (admin can use it later). We do not hard-block here.
    finally:
        db.close()

    response = await call_next(request)
    return response


# IMPORTANT: SessionMiddleware must run *before* our custom middleware accesses request.session.
# Starlette/FastAPI middleware ordering means the last added middleware runs first (outermost).
# Therefore we add SessionMiddleware *after* defining @app.middleware handlers.
app.add_middleware(SessionMiddleware, secret_key=get_session_secret(), max_age=60 * 60 * 24 * 7)


@app.exception_handler(HTTPException)
@app.exception_handler(StarletteHTTPException)
async def http_exception_redirect_handler(request: Request, exc: HTTPException | StarletteHTTPException):
    status_code = int(getattr(exc, "status_code", 500))
    detail = getattr(exc, "detail", "Fehler")
    headers = getattr(exc, "headers", None) or {}

    if not _wants_json(request):
        accept = (request.headers.get("accept") or "").lower()
        wants_html = "text/html" in accept or accept == "" or "*/*" in accept
        if wants_html and not request.url.path.startswith("/api"):
            if status_code == 401:
                try:
                    _flash(request, "Bitte anmelden.", "warn")
                except Exception:
                    pass
                return RedirectResponse("/login", status_code=302)
            if status_code == 403:
                return templates.TemplateResponse(
                    "error.html",
                    _ctx(
                        request,
                        title="Zugriff verweigert",
                        error_title="Zugriff verweigert",
                        error_message="Für diese Seite fehlen die erforderlichen Rechte.",
                        error_code=403,
                    ),
                    status_code=403,
                )
            if status_code == 404:
                return templates.TemplateResponse(
                    "error.html",
                    _ctx(
                        request,
                        title="Seite nicht gefunden",
                        error_title="Seite nicht gefunden",
                        error_message="Die angeforderte Seite wurde nicht gefunden.",
                        error_code=404,
                    ),
                    status_code=404,
                )

    return JSONResponse(status_code=status_code, content={"detail": detail}, headers=headers)


@app.exception_handler(Exception)
async def unhandled_exception_handler(request: Request, exc: Exception):
    logger.error("Unhandled exception on %s %s: %s", request.method, request.url.path, exc, exc_info=True)
    if _wants_json(request) or request.url.path.startswith("/api"):
        return JSONResponse(status_code=500, content={"detail": "Interner Serverfehler"})
    return templates.TemplateResponse(
        "error.html",
        _ctx(
            request,
            title="Interner Fehler",
            error_title="Interner Fehler",
            error_message="Ein unerwarteter Fehler ist aufgetreten. Bitte versuchen Sie es erneut.",
            error_code=500,
        ),
        status_code=500,
    )


