def _decode_csv_bytes(raw: bytes, encoding: str | None = None) -> str:
    preferred = (encoding or "").strip().lower()
    if preferred:
        tried = [preferred, preferred.replace("-", "_")]
    else:
        tried = []
    for enc in tried + ["utf-8-sig", "utf-8", "cp1252", "latin-1"]:
        try:
            return raw.decode(enc)
        except UnicodeDecodeError:
            continue
        except LookupError:
            continue
    return raw.decode("utf-8", errors="replace")


def _detect_csv_upload_settings(raw: bytes) -> dict[str, object]:
    best_choice: dict[str, object] | None = None
    encodings = ["utf-8-sig", "utf-8", "cp1252", "latin-1"]
    for encoding in encodings:
        try:
            text = raw.decode(encoding)
        except Exception:
            continue
        lines = [line for line in text.splitlines() if line.strip()]
        if not lines:
            continue
        sample = "\n".join(lines[:20])
        try:
            dialect = csv.Sniffer().sniff(sample, delimiters=";,")
            delimiter = str(getattr(dialect, "delimiter", ";") or ";")
        except Exception:
            delimiter = ";" if sample.count(";") >= sample.count(",") else ","
        try:
            has_header = bool(csv.Sniffer().has_header(sample))
        except Exception:
            has_header = True
        preview_rows = list(csv.reader(io.StringIO(sample), delimiter=delimiter))
        row_lengths = [len([cell for cell in row if str(cell or "").strip() or len(row) > 1]) for row in preview_rows[:10] if row]
        width_score = sum(1 for length in row_lengths if length > 1)
        consistency_score = -abs(len(set(row_lengths)) - 1) if row_lengths else -10
        delimiter_score = sample.count(delimiter)
        score = (width_score, consistency_score, delimiter_score)
        candidate = {
            "encoding": encoding,
            "delimiter": delimiter if delimiter in (";", ",") else ";",
            "has_header": has_header,
            "score": score,
        }
        if best_choice is None or tuple(candidate["score"]) > tuple(best_choice["score"]):
            best_choice = candidate
    if best_choice is None:
        return {"encoding": "utf-8", "delimiter": ";", "has_header": True}
    return {
        "encoding": str(best_choice.get("encoding") or "utf-8"),
        "delimiter": str(best_choice.get("delimiter") or ";"),
        "has_header": bool(best_choice.get("has_header")),
    }


def _read_csv_rows(path: Path, delimiter: str, has_header: bool, encoding: str = "utf-8") -> tuple[list[str], list[dict[str, str]]]:
    text = _decode_csv_bytes(path.read_bytes(), encoding=encoding)

    if has_header:
        reader = csv.DictReader(io.StringIO(text), delimiter=delimiter)
        columns = [c.strip() for c in (reader.fieldnames or []) if c and c.strip()]
        rows: list[dict[str, str]] = []
        for row in reader:
            out: dict[str, str] = {}
            for col in columns:
                out[col] = (row.get(col) or "").strip()
            if any(v for v in out.values()):
                rows.append(out)
        return columns, rows

    raw_rows = list(csv.reader(io.StringIO(text), delimiter=delimiter))
    if not raw_rows:
        return [], []
    max_cols = max(len(r) for r in raw_rows)
    columns = [f"Spalte {i+1}" for i in range(max_cols)]
    rows = []
    for rr in raw_rows:
        out = {}
        for i, col in enumerate(columns):
            out[col] = (rr[i] if i < len(rr) else "").strip()
        if any(v for v in out.values()):
            rows.append(out)
    return columns, rows


def _csv_value(row: dict[str, str], column: str | None) -> str:
    if not column:
        return ""
    return (row.get(column) or "").strip()


def _guess_column(columns: list[str], candidates: tuple[str, ...]) -> str:
    norm_map = {c.strip().lower(): c for c in columns}
    for c in candidates:
        if c in norm_map:
            return norm_map[c]
    return ""


def _normalize_import_header(raw: str) -> str:
    return _normalize_search_text(raw).replace(" ", "_")


