def _pick_import_profile(db: Session, profile_id: int) -> ImportProfile | None:
    if int(profile_id or 0) <= 0:
        return None
    return db.get(ImportProfile, int(profile_id))


def _import_profile_matches_scope(
    profile: ImportProfile | None,
    *,
    manufacturer_id: int,
    device_kind_id: int,
) -> bool:
    if profile is None:
        return True
    if int(manufacturer_id or 0) <= 0 or int(device_kind_id or 0) <= 0:
        return True
    return (
        int(profile.manufacturer_id or 0) == int(manufacturer_id)
        and int(profile.device_kind_id or 0) == int(device_kind_id)
    )


def _import_drop_mismatched_profile(
    mapping_data: dict,
    *,
    profile: ImportProfile | None,
    manufacturer: Manufacturer | None,
    device_kind: DeviceKind | None,
    profile_name_default: str,
) -> tuple[dict, bool]:
    if profile is None:
        return mapping_data, False
    manufacturer_id = int(getattr(manufacturer, "id", 0) or 0)
    device_kind_id = int(getattr(device_kind, "id", 0) or 0)
    if _import_profile_matches_scope(
        profile,
        manufacturer_id=manufacturer_id,
        device_kind_id=device_kind_id,
    ):
        return mapping_data, False
    cleaned = dict(mapping_data)
    cleaned["profile_id"] = 0
    current_profile_name = str(cleaned.get("profile_name") or "").strip()
    selected_profile_name = str(getattr(profile, "name", "") or "").strip()
    if not current_profile_name or current_profile_name == selected_profile_name:
        cleaned["profile_name"] = str(profile_name_default or current_profile_name or "CSV-Katalogimport").strip()
    return cleaned, True


def _touch_import_profile(db: Session, profile: ImportProfile) -> None:
    profile.updated_at = dt.datetime.utcnow().replace(tzinfo=None)
    profile.last_used_at = dt.datetime.utcnow().replace(tzinfo=None)
    db.add(profile)


def _save_import_profile_maps(
    db: Session,
    *,
    profile: ImportProfile,
    product_field_map: dict[str, str],
    feature_maps: list[dict[str, str]],
    accessory_map: dict[str, str] | None = None,
) -> None:
    _ = feature_maps, accessory_map
    db.query(ImportProfileMap).filter(ImportProfileMap.profile_id == int(profile.id)).delete(synchronize_session=False)
    for target_key, source_column in product_field_map.items():
        if not source_column:
            continue
        db.add(
            ImportProfileMap(
                profile_id=int(profile.id),
                map_type="product_field",
                target_key=str(target_key),
                source_column=str(source_column),
                data_type=None,
            )
        )


