def _catalog_csv_is_miele_dishwasher_scope(
    manufacturer_name: str | None = None,
    device_kind_name: str | None = None,
) -> bool:
    manufacturer_key = normalize_candidate_name(str(manufacturer_name or ""))
    kind_key = normalize_candidate_name(str(device_kind_name or ""))
    return "miele" in manufacturer_key and "geschirrsp" in kind_key


def _catalog_csv_ignored_columns_for_scope(
    *,
    manufacturer_name: str | None = None,
    device_kind_name: str | None = None,
) -> set[str]:
    ignored: set[str] = set()
    if _catalog_csv_is_miele_dishwasher_scope(
        manufacturer_name=manufacturer_name,
        device_kind_name=device_kind_name,
    ):
        ignored.update(
            {
                _import_compact_key("Brand"),
                _import_compact_key("RecommendedPrice_CURR"),
                _import_compact_key("InternalArticleNumber"),
                _import_compact_key("ProductFamily"),
                _import_compact_key("ProductFamily_Name"),
                _import_compact_key("PRODUCT_GROUP"),
            }
        )
    return ignored


def _catalog_csv_is_ignored_column(
    column: str | None,
    *,
    manufacturer_name: str | None = None,
    device_kind_name: str | None = None,
) -> bool:
    return _import_compact_key(column) in _catalog_csv_ignored_columns_for_scope(
        manufacturer_name=manufacturer_name,
        device_kind_name=device_kind_name,
    )


def _catalog_csv_extra_recognized_columns(
    row: dict[str, str],
    *,
    manufacturer_name: str | None = None,
    device_kind_name: str | None = None,
) -> set[str]:
    recognized_keys = {
        _import_compact_key("COL_MAIN"),
        _import_compact_key("RecommendedPrice"),
        _import_compact_key("RecommendedPrice_CURR"),
        _import_compact_key("LowResolutionPictureName"),
        _import_compact_key("PRODUCT_IMAGE"),
        _import_compact_key("HighResolutionPictureName"),
    }
    for idx in range(1, PRODUCT_IMAGE_URL_MAX + 1):
        recognized_keys.add(_import_compact_key(f"ADD_IMAGE{idx}_ID"))
        recognized_keys.add(_import_compact_key(f"ADD_IMAGE{idx}"))
    recognized_keys.update(
        _catalog_csv_ignored_columns_for_scope(
            manufacturer_name=manufacturer_name,
            device_kind_name=device_kind_name,
        )
    )
    out: set[str] = set()
    for key in row.keys():
        clean_key = str(key or "").strip()
        if clean_key and _import_compact_key(clean_key) in recognized_keys:
            out.add(clean_key)
    return out


def _catalog_csv_image_fallback_urls(row: dict[str, str]) -> list[str]:
    fallback_keys: list[str] = [
        _import_compact_key("LowResolutionPictureName"),
        _import_compact_key("PRODUCT_IMAGE"),
        _import_compact_key("HighResolutionPictureName"),
    ]
    for idx in range(1, PRODUCT_IMAGE_URL_MAX + 1):
        fallback_keys.append(_import_compact_key(f"ADD_IMAGE{idx}_ID"))
        fallback_keys.append(_import_compact_key(f"ADD_IMAGE{idx}"))
    ordered_columns: list[str] = []
    seen_columns: set[str] = set()
    for fallback_key in fallback_keys:
        for column in row.keys():
            clean_column = str(column or "").strip()
            if not clean_column or clean_column in seen_columns:
                continue
            if _import_compact_key(clean_column) != fallback_key:
                continue
            ordered_columns.append(clean_column)
            seen_columns.add(clean_column)
    out: list[str] = []
    seen_values: set[str] = set()
    for column in ordered_columns:
        raw_value = _csv_value(row, column)
        normalized = _normalize_product_image_url(raw_value) or _normalize_absolute_url(raw_value) or raw_value.strip()
        if not normalized:
            continue
        dedupe_key = normalized.strip().casefold()
        if dedupe_key in seen_values:
            continue
        seen_values.add(dedupe_key)
        out.append(normalized)
    return out


def _catalog_csv_sale_price_cents_from_row(row: dict[str, str]) -> int | None:
    price_columns: list[str] = []
    currency_columns: list[str] = []
    for column in row.keys():
        key = _import_compact_key(column)
        if key in {_import_compact_key("RecommendedPrice"), _import_compact_key("SalePrice"), _import_compact_key("ListPrice")}:
            price_columns.append(str(column))
        if key in {_import_compact_key("RecommendedPrice_CURR"), _import_compact_key("Currency"), _import_compact_key("CURR")}:
            currency_columns.append(str(column))
    currency_value = _catalog_csv_pick_row_value(row, currency_columns).strip().upper()
    if currency_value and currency_value not in {"EUR", "€"}:
        return None
    price_value = _catalog_csv_pick_row_value(row, price_columns)
    if not price_value:
        return None
    try:
        return _parse_eur_to_cents(price_value, "Verkaufspreis")
    except Exception:
        return None


def _import_compact_key(raw: str | None) -> str:
    return normalize_candidate_name(raw).replace(" ", "")


def _import_clean_text(raw: str | None) -> str:
    text = str(raw or "").replace("\r\n", "\n").replace("\r", "\n")
    lines = [re.sub(r"\s+", " ", line).strip(" \t|;,") for line in text.split("\n")]
    return "\n".join([line for line in lines if line]).strip()


def _import_preserve_structured_text(raw: str | None) -> str:
    text = str(raw or "").replace("\r\n", "\n").replace("\r", "\n")
    lines = [str(line or "").strip(" \t") for line in text.split("\n")]
    return "\n".join([line for line in lines if line.strip()]).strip()


def _import_text_is_duplicate(candidate: str, existing: list[str]) -> bool:
    normalized = normalize_candidate_name(candidate)
    if not normalized:
        return True
    compact = normalized.replace(" ", "")
    for row in existing:
        existing_norm = normalize_candidate_name(row)
        if not existing_norm:
            continue
        existing_compact = existing_norm.replace(" ", "")
        if compact == existing_compact:
            return True
        if len(compact) >= 12 and compact in existing_compact:
            return True
        if len(existing_compact) >= 12 and existing_compact in compact:
            return True
    return False


def _import_unique_texts(values: list[str]) -> list[str]:
    out: list[str] = []
    for raw_value in values:
        clean = _import_clean_text(raw_value)
        if not clean or _import_text_is_duplicate(clean, out):
            continue
        out.append(clean)
    return out


def _import_description_label(column: str | None) -> str:
    normalized = _import_compact_key(column)
    if not normalized:
        return "Beschreibung"
    if normalized == "colmain":
        return "Gerätefarbe / Blendenfarbe"
    if normalized == "recommendedprice":
        return "Verkaufspreis Brutto"
    if "shortdescription" in normalized:
        return "Kurzbeschreibung"
    if "longdescription" in normalized or normalized == "description":
        return "Beschreibung"
    if "shorttextinvoice" in normalized or "invoice" in normalized:
        return "Rechnungstext"
    if normalized.startswith("usp") or "highlight" in normalized or "benefit" in normalized:
        return "Highlights"
    if "program" in normalized:
        return "Programme"
    if "feature" in normalized:
        return "Merkmale"
    return _import_human_label(column)


def _catalog_csv_column_sample_values(rows: list[dict[str, str]], column: str, *, limit: int = 8) -> list[str]:
    out: list[str] = []
    seen: set[str] = set()
    for row in rows:
        value = _import_clean_text(_csv_value(row, column))
        if not value:
            continue
        key = normalize_candidate_name(value)
        if key in seen:
            continue
        seen.add(key)
        out.append(value[:600])
        if len(out) >= max(1, int(limit)):
            break
    return out


def _catalog_csv_attribute_key(attr: AttributeDef) -> str:
    slug = str(attr.slug or "").strip()
    if slug:
        return slug
    return _sanitize_feature_key(str(attr.name or "merkmal"))


def _catalog_csv_attribute_variants(attr: AttributeDef) -> set[str]:
    variants = set(_catalog_attribute_name_variants(attr))
    name_compact = _import_compact_key(str(attr.name or ""))
    slug_compact = _import_compact_key(str(attr.slug or ""))
    attr_key = _catalog_csv_attribute_key(attr)
    if name_compact:
        variants.add(name_compact)
    if slug_compact:
        variants.add(slug_compact)
    if attr_key:
        variants.add(_import_compact_key(attr_key))
    combined = " ".join([str(attr.name or ""), str(attr.slug or ""), str(attr.group_name or "")]).strip()
    combined_compact = _import_compact_key(combined)
    if combined_compact:
        variants.add(combined_compact)
    for match_tokens, hint_tokens in _CATALOG_CSV_ATTRIBUTE_HINTS:
        if any(token in combined_compact for token in match_tokens):
            for token in hint_tokens:
                variants.add(_import_compact_key(token))
    return {variant for variant in variants if variant}


def _catalog_csv_is_text_rich_column(column: str) -> bool:
    normalized = _import_compact_key(column)
    return any(
        key in normalized
        for key in ("description", "usp", "highlight", "benefit", "feature", "program", "invoice", "title", "text")
    )


def _catalog_csv_attribute_value_score(attr: AttributeDef, column: str, values: list[str]) -> float:
    if not values:
        return 0.0
    normalized_attr = normalize_candidate_name(" ".join([str(attr.name or ""), str(attr.slug or ""), str(attr.group_name or "")]))
    column_key = _import_compact_key(column)
    score = 0.0
    numeric_hits = 0
    energy_hits = 0
    noise_hits = 0
    capacity_hits = 0
    type_hits = 0
    dimension_hits = 0
    connection_hits = 0
    for raw_value in values:
        lowered = normalize_candidate_name(raw_value)
        if re.search(r"\d", raw_value):
            numeric_hits += 1
        if re.search(r"\b[a-g](?:\+{1,3})?\b", raw_value.strip(), flags=re.I):
            energy_hits += 1
        if "db" in lowered or re.search(r"\b([3-7]\d)\b", lowered):
            noise_hits += 1
        if "kg" in lowered or "massgedeck" in lowered or "maßgedeck" in lowered or re.search(r"\b([1-2]?\d)(?:[.,]\d+)?\b", lowered):
            capacity_hits += 1
        if any(token in lowered for token in ("unterbau", "integrier", "einbau", "freistehend", "stand")):
            type_hits += 1
        if any(token in lowered for token in (" cm", " mm", " x ", "hoehe", "höhe", "breite", "tiefe")) or column_key in {"height", "width", "depth"}:
            dimension_hits += 1
        if any(token in lowered for token in ("volt", "watt", "ampere", "hz")):
            connection_hits += 1
    total = max(1, len(values))
    if str(attr.value_type or "").strip() == "number":
        score += (numeric_hits / total) * 2.5
    if any(token in normalized_attr for token in ("energie", "effizienz")):
        score += (energy_hits / total) * 4.0
    if any(token in normalized_attr for token in ("geraeusch", "laut")):
        score += (noise_hits / total) * 3.5
    if any(token in normalized_attr for token in ("fuell", "belad", "kapaz", "fassungs", "massgedeck", "maßgedeck")):
        score += (capacity_hits / total) * 3.0
    if any(token in normalized_attr for token in ("geraetetyp", "bauart", "bauform", "aufstell")):
        score += (type_hits / total) * 2.8
    if any(token in normalized_attr for token in ("nische", "mass", "maß", "hoehe", "höhe", "breite", "tiefe")):
        score += (dimension_hits / total) * 2.4
    if any(token in normalized_attr for token in ("anschluss", "spannung", "strom", "leistung")):
        score += (connection_hits / total) * 2.2
    return score


def _catalog_csv_attribute_column_score(attr: AttributeDef, column: str, values: list[str]) -> float:
    column_key = _import_compact_key(column)
    if not column_key:
        return 0.0
    score = 0.0
    for variant in _catalog_csv_attribute_variants(attr):
        if not variant:
            continue
        if column_key == variant:
            score = max(score, 10.0)
            continue
        if variant in column_key or column_key in variant:
            score = max(score, 7.0)
            continue
        shared = len(set(variant.split()) & set(normalize_candidate_name(column).split()))
        if shared > 0:
            score = max(score, 4.0 + (shared * 0.8))
    if _catalog_csv_is_text_rich_column(column):
        score += 1.2
    score += _catalog_csv_attribute_value_score(attr, column, values)
    return score


def _catalog_csv_core_fallback_candidates(
    columns: list[str],
    field: str,
    selected_column: str = "",
    *,
    manufacturer_name: str | None = None,
    device_kind_name: str | None = None,
) -> list[str]:
    hint_map = {
        "manufacturer_name": ("brand", "manufacturer", "marke", "hersteller", "brandcodeconcat"),
        "device_kind_name": ("productfamily_name", "productfamily", "geraeteart", "gerätetyp", "productgroup", "category"),
        "sales_name": ("code", "salesname", "short_description", "shorttext_invoice", "name", "producttitle"),
        "material_no": ("productcode", "internalarticlenumber", "materialnummer", "art_num", "code", "model"),
        "product_title_1": ("short_description", "producttitle", "name", "code"),
        "product_title_2": ("producttitle", "long_description", "shorttext_invoice", "short_description"),
    }
    selected_norm = _import_compact_key(selected_column)
    out: list[str] = []
    for column in columns:
        if _import_compact_key(column) == selected_norm:
            continue
        if _catalog_csv_is_ignored_column(
            column,
            manufacturer_name=manufacturer_name,
            device_kind_name=device_kind_name,
        ):
            continue
        key = _import_compact_key(column)
        if any(hint in key for hint in hint_map.get(field, ())):
            out.append(column)
    return out[:6]


def _catalog_csv_description_columns(
    columns: list[str],
    selected_columns: list[str] | None = None,
    *,
    manufacturer_name: str | None = None,
    device_kind_name: str | None = None,
) -> list[str]:
    if selected_columns:
        selected = [
            str(col).strip()
            for col in selected_columns
            if str(col).strip()
            and not _catalog_csv_is_ignored_column(
                str(col).strip(),
                manufacturer_name=manufacturer_name,
                device_kind_name=device_kind_name,
            )
        ]
        if selected:
            return selected
    ranked: list[tuple[float, str]] = []
    for column in columns:
        if _catalog_csv_is_ignored_column(
            column,
            manufacturer_name=manufacturer_name,
            device_kind_name=device_kind_name,
        ):
            continue
        key = _import_compact_key(column)
        score = 0.0
        if "longdescription" in key or key == "description":
            score += 9.0
        if "shortdescription" in key:
            score += 7.0
        if key == "colmain" or "colour" in key or "color" in key:
            score += 5.0
        if key.startswith("usp") or "highlight" in key or "benefit" in key:
            score += 5.5
        if "shorttextinvoice" in key or "invoice" in key:
            score += 4.0
        if "producttitle" in key:
            score += 3.5
        if "feature" in key or "program" in key:
            score += 3.0
        if score > 0:
            ranked.append((score, column))
    ranked.sort(key=lambda item: (-item[0], item[1].lower()))
    out: list[str] = []
    for _score, column in ranked:
        if column not in out:
            out.append(column)
        if len(out) >= 8:
            break
    return out


def _catalog_csv_import_plan_fallback(
    *,
    manufacturer: Manufacturer,
    device_kind: DeviceKind,
    columns: list[str],
    rows: list[dict[str, str]],
    attrs: list[AttributeDef],
    mapping_data: dict[str, object],
) -> dict[str, object]:
    product_field_map = dict(mapping_data.get("product_field_map") or {})
    manufacturer_name = str(getattr(manufacturer, "name", "") or "").strip()
    device_kind_name = str(getattr(device_kind, "name", "") or "").strip()
    description_columns = _catalog_csv_description_columns(
        columns,
        selected_columns=list(mapping_data.get("description_columns") or []),
        manufacturer_name=manufacturer_name,
        device_kind_name=device_kind_name,
    )
    core_fallback_map: dict[str, list[str]] = {}
    for field in ("manufacturer_name", "device_kind_name", "sales_name", "material_no", "product_title_1", "product_title_2"):
        core_fallback_map[field] = _catalog_csv_core_fallback_candidates(
            columns,
            field=field,
            selected_column=str(product_field_map.get(field) or ""),
            manufacturer_name=manufacturer_name,
            device_kind_name=device_kind_name,
        )

    attribute_maps: dict[int, dict[str, object]] = {}
    for attr in attrs:
        scored: list[tuple[float, str]] = []
        for column in columns:
            if _catalog_csv_is_ignored_column(
                column,
                manufacturer_name=manufacturer_name,
                device_kind_name=device_kind_name,
            ):
                continue
            values = _catalog_csv_column_sample_values(rows, column)
            score = _catalog_csv_attribute_column_score(attr, column, values)
            if score <= 0:
                continue
            scored.append((score, column))
        scored.sort(key=lambda item: (-item[0], item[1].lower()))
        if not scored:
            continue
        best_score, primary = scored[0]
        fallback_columns = [column for _score, column in scored[1:4] if column != primary]
        if best_score < 4.0 and not _catalog_csv_is_text_rich_column(primary):
            continue
        attribute_maps[int(attr.id)] = {
            "attribute_id": int(attr.id),
            "feature_key": _catalog_csv_attribute_key(attr),
            "primary_column": primary,
            "fallback_columns": fallback_columns,
            "confidence": round(min(0.99, 0.42 + (best_score / 14.0)), 3),
            "reason": f"Header- und Wertmuster passen zu '{str(attr.name or '').strip()}'",
        }

    notes = []
    if description_columns:
        notes.append(f"Beschreibung wird aus {len(description_columns)} CSV-Spalten aufgebaut.")
    if attribute_maps:
        notes.append(f"{len(attribute_maps)} definierte Merkmale werden direkt aus der CSV bzw. aus Beschreibungsspalten abgeleitet.")
    return {
        "description_columns": description_columns,
        "core_fallback_map": core_fallback_map,
        "attribute_maps": attribute_maps,
        "notes": notes,
        "confidence": 0.35 if attribute_maps else 0.2,
    }


def _catalog_csv_resolve_attribute_by_key(attrs: list[AttributeDef], feature_key: str | None) -> AttributeDef | None:
    lookup: dict[str, AttributeDef] = {}
    for attr in attrs:
        for key in (
            _catalog_csv_attribute_key(attr),
            str(attr.slug or "").strip(),
            normalize_candidate_name(str(attr.name or "")),
        ):
            compact = _import_compact_key(key)
            if compact:
                lookup.setdefault(compact, attr)
    return lookup.get(_import_compact_key(feature_key))


def _catalog_csv_import_plan_ai(
    db: Session,
    *,
    manufacturer: Manufacturer,
    device_kind: DeviceKind,
    columns: list[str],
    rows: list[dict[str, str]],
    attrs: list[AttributeDef],
    mapping_data: dict[str, object],
) -> dict[str, object]:
    fallback_plan = _catalog_csv_import_plan_fallback(
        manufacturer=manufacturer,
        device_kind=device_kind,
        columns=columns,
        rows=rows,
        attrs=attrs,
        mapping_data=mapping_data,
    )
    sample_rows: list[dict[str, str]] = []
    ignored_columns = {
        str(column)
        for column in columns
        if _catalog_csv_is_ignored_column(
            column,
            manufacturer_name=str(manufacturer.name or "").strip(),
            device_kind_name=str(device_kind.name or "").strip(),
        )
    }
    for row in rows[:8]:
        prepared = {
            str(column): str(_csv_value(row, column))[:400]
            for column in columns
            if str(column) not in ignored_columns and str(_csv_value(row, column)).strip()
        }
        if prepared:
            sample_rows.append(prepared)
    if not sample_rows:
        return fallback_plan

    fallback_output = {
        "description_columns": list(fallback_plan.get("description_columns") or []),
        "core_fallbacks": [
            {"field": str(field), "columns": list(cols)}
            for field, cols in dict(fallback_plan.get("core_fallback_map") or {}).items()
            if cols
        ],
        "feature_column_map": [
            {
                "feature_key": str(item.get("feature_key") or ""),
                "primary_column": str(item.get("primary_column") or ""),
                "fallback_columns": list(item.get("fallback_columns") or []),
                "confidence": float(item.get("confidence") or 0.0),
                "reason": str(item.get("reason") or ""),
            }
            for item in dict(fallback_plan.get("attribute_maps") or {}).values()
            if str(item.get("primary_column") or "").strip()
        ],
        "notes": list(fallback_plan.get("notes") or []),
        "confidence": float(fallback_plan.get("confidence") or 0.0),
    }
    result = ai_run_task(
        db,
        settings=_openai_settings(db, include_secret=True),
        task_name="catalog_csv_import_plan",
        input_payload={
            "manufacturer_name": str(manufacturer.name or "").strip(),
            "device_kind_name": str(device_kind.name or "").strip(),
            "columns": columns,
            "sample_rows": sample_rows,
            "mapped_core_fields": dict(mapping_data.get("product_field_map") or {}),
            "attributes": [
                {
                    "feature_key": _catalog_csv_attribute_key(attr),
                    "attribute_name": str(attr.name or "").strip(),
                    "group_name": str(attr.group_name or "").strip(),
                    "value_type": str(attr.value_type or "text"),
                    "options": _enum_options_from_json(attr.enum_options_json) if str(attr.value_type or "") == "enum" else [],
                }
                for attr in attrs
            ],
            "heuristic_plan": fallback_output,
        },
        fallback_output=fallback_output,
        related_object_type="catalog_csv_import_plan",
        related_object_id=None,
        title="CSV-Spaltenanalyse",
        allow_openai=True,
    )
    output = result.get("output") if isinstance(result.get("output"), dict) else {}
    merged = dict(fallback_plan)
    allowed_columns = {
        str(column): True
        for column in columns
        if str(column) not in ignored_columns
    }

    ai_description_columns = [
        str(column).strip()
        for column in list(output.get("description_columns") or [])
        if str(column).strip() in allowed_columns
    ]
    if ai_description_columns:
        merged["description_columns"] = _catalog_csv_description_columns(
            columns,
            selected_columns=ai_description_columns,
            manufacturer_name=str(manufacturer.name or "").strip(),
            device_kind_name=str(device_kind.name or "").strip(),
        )

    core_fallback_map = dict(merged.get("core_fallback_map") or {})
    for row in list(output.get("core_fallbacks") or []):
        if not isinstance(row, dict):
            continue
        field = str(row.get("field") or "").strip()
        if field not in ("manufacturer_name", "device_kind_name", "sales_name", "material_no", "product_title_1", "product_title_2"):
            continue
        cols = [str(column).strip() for column in list(row.get("columns") or []) if str(column).strip() in allowed_columns]
        if cols:
            core_fallback_map[field] = cols[:6]
    merged["core_fallback_map"] = core_fallback_map

    attribute_maps = dict(merged.get("attribute_maps") or {})
    for row in list(output.get("feature_column_map") or []):
        if not isinstance(row, dict):
            continue
        attr = _catalog_csv_resolve_attribute_by_key(attrs, row.get("feature_key"))
        if attr is None:
            continue
        primary_column = str(row.get("primary_column") or "").strip()
        fallback_columns = [
            str(column).strip()
            for column in list(row.get("fallback_columns") or [])
            if str(column).strip() in allowed_columns and str(column).strip() != primary_column
        ]
        if primary_column not in allowed_columns and not fallback_columns:
            continue
        if primary_column not in allowed_columns:
            primary_column = fallback_columns[0]
            fallback_columns = fallback_columns[1:]
        attribute_maps[int(attr.id)] = {
            "attribute_id": int(attr.id),
            "feature_key": _catalog_csv_attribute_key(attr),
            "primary_column": primary_column,
            "fallback_columns": fallback_columns[:4],
            "confidence": round(float(row.get("confidence") or 0.0), 3),
            "reason": str(row.get("reason") or "").strip() or "KI-Spaltenanalyse",
        }
    merged["attribute_maps"] = attribute_maps
    merged["notes"] = _import_unique_texts(list(fallback_plan.get("notes") or []) + [str(note) for note in list(output.get("notes") or []) if str(note).strip()])[:12]
    merged["confidence"] = max(float(fallback_plan.get("confidence") or 0.0), float(output.get("confidence") or 0.0))
    return merged


def _catalog_csv_pick_row_value(row: dict[str, str], columns: list[str]) -> str:
    for column in columns:
        value = _csv_value(row, column)
        if value:
            return value
    return ""


def _catalog_csv_text_blob(
    row: dict[str, str],
    *,
    description_columns: list[str],
    attribute_plan: dict[int, dict[str, object]],
) -> str:
    columns: list[str] = []
    for column in description_columns:
        if column not in columns:
            columns.append(column)
    for plan_row in attribute_plan.values():
        for column in [str(plan_row.get("primary_column") or "")] + [str(col) for col in list(plan_row.get("fallback_columns") or [])]:
            if column and column not in columns:
                columns.append(column)
    blocks: list[str] = []
    for column in columns:
        value = _csv_value(row, column)
        if not value:
            continue
        blocks.append(f"{_import_description_label(column)}: {value}")
    return "\n".join(blocks).strip()


def _catalog_csv_derived_attribute_value(attr: AttributeDef, row: dict[str, str], text_blob: str) -> str:
    normalized_attr = normalize_candidate_name(" ".join([str(attr.name or ""), str(attr.slug or ""), str(attr.group_name or "")]))
    if not normalized_attr:
        return ""
    combined = " ".join([_csv_value(row, key) for key in row.keys() if _csv_value(row, key)] + [text_blob]).strip()
    if not combined:
        return ""
    if any(token in normalized_attr for token in ("energie", "effizienz")):
        match = re.search(r"\b([A-G](?:\+{1,3})?)\b", combined, flags=re.I)
        if match:
            return str(match.group(1) or "").upper()
    if any(token in normalized_attr for token in ("geraeusch", "laut")):
        match = re.search(r"(\d+(?:[.,]\d+)?)\s*dB", combined, flags=re.I)
        if match:
            return f"{match.group(1)} dB"
    if any(token in normalized_attr for token in ("fuell", "belad", "kapaz")):
        match = re.search(r"(\d+(?:[.,]\d+)?)\s*kg", combined, flags=re.I)
        if match:
            return f"{match.group(1)} kg"
    if any(token in normalized_attr for token in ("fassungs", "massgedeck", "maßgedeck")):
        match = re.search(r"(\d+(?:[.,]\d+)?)\s*(?:maßgedecke|massgedecke)", combined, flags=re.I)
        if match:
            return f"{match.group(1)} Maßgedecke"
    if any(token in normalized_attr for token in ("geraetetyp", "bauart", "bauform", "aufstell")):
        for token in ("integrierbar", "vollintegrierbar", "unterbau", "einbau", "freistehend", "stand"):
            if token in normalize_candidate_name(combined):
                return token.capitalize()
    if any(token in normalized_attr for token in ("nische", "mass", "maß", "hoehe", "höhe", "breite", "tiefe")):
        values = {
            "H": _catalog_csv_pick_row_value(row, ["HEIGHT", "HEIGHT_MM", "NICHE_HEIGHT", "NICHE_HEIGHT_MIN", "NICHE_HEIGHT_MAX"]),
            "B": _catalog_csv_pick_row_value(row, ["WIDTH", "WIDTH_MM", "NICHE_WIDTH", "NICHE_WIDTH_MIN", "NICHE_WIDTH_MAX"]),
            "T": _catalog_csv_pick_row_value(row, ["DEPTH", "DEPTH_MM", "NICHE_DEPTH", "NICHE_DEPTH_MIN", "NICHE_DEPTH_MAX"]),
        }
        dimension_values = [str(value).strip() for value in values.values() if str(value).strip()]
        if dimension_values:
            if all(str(value).strip() for value in values.values()):
                return f"{values['H']} x {values['B']} x {values['T']} mm"
            return " / ".join(dimension_values)
    if any(token in normalized_attr for token in ("anschluss", "spannung", "strom", "leistung")):
        parts = []
        for label, candidates in (
            ("Anschluss", ["CONNECTION", "CONNECTED_LOAD"]),
            ("Strom", ["CURRENT"]),
            ("Spannung", ["VOLTAGE", "VOLTAGE_MIN", "VOLTAGE_MAX"]),
            ("Frequenz", ["FREQUENCY"]),
            ("Leistung", ["POWER", "WATTAGE"]),
        ):
            value = _catalog_csv_pick_row_value(row, candidates)
            if value:
                parts.append(f"{label}: {value}")
        if parts:
            return " | ".join(parts)
    return ""




def _import_guess_accessory_source_column(columns: list[str]) -> str:
    return _guess_column(
        columns,
        (
            "zubehoer",
            "zubehör",
            "zubehoerliste",
            "zubehörliste",
            "accessories",
            "accessory_list",
        ),
    )


def _catalog_import_profile_name_default(
    *,
    manufacturer: Manufacturer | None = None,
    device_kind: DeviceKind | None = None,
    filename: str | None = None,
) -> str:
    if manufacturer and device_kind:
        return f"{str(manufacturer.name or '').strip()} {str(device_kind.name or '').strip()}".strip()
    file_stem = Path(str(filename or "").strip()).stem.strip()
    return file_stem or "CSV-Katalogimport"


def _catalog_import_scope_lookups(db: Session) -> tuple[dict[str, list[Manufacturer]], dict[str, list[DeviceKind]]]:
    manufacturers = db.query(Manufacturer).filter(Manufacturer.active == True).order_by(Manufacturer.name.asc(), Manufacturer.id.asc()).all()
    kinds = db.query(DeviceKind).order_by(DeviceKind.name.asc(), DeviceKind.id.asc()).all()
    return _catalog_scope_lookup_map(manufacturers), _catalog_scope_lookup_map(kinds)


def _import_resolve_scope_from_row(
    row: dict[str, str],
    *,
    product_field_map: dict[str, str],
    manufacturer_lookup: dict[str, list[Manufacturer]],
    kind_lookup: dict[str, list[DeviceKind]],
    fallback_manufacturer: Manufacturer | None = None,
    fallback_kind: DeviceKind | None = None,
    db: Session | None = None,
    auto_create: bool = False,
) -> tuple[Manufacturer | None, DeviceKind | None, list[str], dict[str, str]]:
    manufacturer_column = str(product_field_map.get("manufacturer_name") or "").strip()
    kind_column = str(product_field_map.get("device_kind_name") or "").strip()
    raw_manufacturer = _csv_value(row, manufacturer_column)
    raw_kind = _csv_value(row, kind_column)

    manufacturer_row = fallback_manufacturer if not raw_manufacturer else _catalog_resolve_named_row(raw_manufacturer, manufacturer_lookup)
    kind_row = fallback_kind if not raw_kind else _catalog_resolve_named_row(raw_kind, kind_lookup)

    issues: list[str] = []

    # Auto-Create: Hersteller automatisch anlegen wenn nicht gefunden
    if raw_manufacturer and manufacturer_row is None and auto_create and db is not None:
        clean_name = str(raw_manufacturer).strip()
        if clean_name:
            manufacturer_row = db.query(Manufacturer).filter(Manufacturer.name.ilike(clean_name)).first()
            if not manufacturer_row:
                manufacturer_row = Manufacturer(name=clean_name, active=True)
                db.add(manufacturer_row)
                db.flush()
            # In Lookup eintragen für nächste Zeilen
            _catalog_scope_register(manufacturer_lookup, manufacturer_row)

    # Auto-Create: Geräteart automatisch anlegen wenn nicht gefunden
    if raw_kind and kind_row is None and auto_create and db is not None:
        clean_name = str(raw_kind).strip()
        if clean_name:
            kind_row = db.query(DeviceKind).filter(DeviceKind.name.ilike(clean_name)).first()
            if not kind_row:
                kind_row = ensure_device_kind(db, clean_name)
                seed_features_for_kind(db, kind_row)
                db.flush()
            # In Lookup eintragen für nächste Zeilen
            _catalog_scope_register(kind_lookup, kind_row)

    if raw_manufacturer and manufacturer_row is None:
        issues.append(f"Hersteller '{raw_manufacturer}' ist nicht bekannt.")
    if raw_kind and kind_row is None:
        issues.append(f"Geräteart '{raw_kind}' ist nicht bekannt.")
    if not raw_manufacturer and fallback_manufacturer is None:
        issues.append("Hersteller fehlt.")
    if not raw_kind and fallback_kind is None:
        issues.append("Geräteart fehlt.")
    return manufacturer_row, kind_row, issues, {
        "manufacturer_name": raw_manufacturer,
        "device_kind_name": raw_kind,
    }


def _catalog_scope_register(lookup: dict[str, list], entity) -> None:
    """Registriert eine neu erstellte Entität in der Scope-Lookup-Map."""
    name = str(getattr(entity, "name", "") or "").strip()
    if not name:
        return
    for key in (_catalog_scope_label_key(name), _catalog_scope_compact_key(name)):
        if key:
            lookup.setdefault(key, []).append(entity)


def _import_resolve_scope_from_rows(
    db: Session,
    *,
    rows: list[dict[str, str]],
    product_field_map: dict[str, str],
    fallback_manufacturer_id: int = 0,
    fallback_kind_id: int = 0,
    sample_limit: int = 200,
) -> dict[str, object]:
    fallback_manufacturer = db.get(Manufacturer, int(fallback_manufacturer_id)) if int(fallback_manufacturer_id or 0) > 0 else None
    fallback_kind = db.get(DeviceKind, int(fallback_kind_id)) if int(fallback_kind_id or 0) > 0 else None
    manufacturer_lookup, kind_lookup = _catalog_import_scope_lookups(db)

    errors: list[str] = []
    manufacturer_ids: set[int] = set()
    kind_ids: set[int] = set()
    manufacturer_samples: set[str] = set()
    kind_samples: set[str] = set()
    manufacturer_row: Manufacturer | None = fallback_manufacturer
    kind_row: DeviceKind | None = fallback_kind

    for row in rows[: max(1, int(sample_limit))]:
        resolved_manufacturer, resolved_kind, issues, raw_values = _import_resolve_scope_from_row(
            row,
            product_field_map=product_field_map,
            manufacturer_lookup=manufacturer_lookup,
            kind_lookup=kind_lookup,
            fallback_manufacturer=fallback_manufacturer,
            fallback_kind=fallback_kind,
            db=db,
            auto_create=True,
        )
        if raw_values.get("manufacturer_name"):
            manufacturer_samples.add(str(raw_values["manufacturer_name"]))
        if raw_values.get("device_kind_name"):
            kind_samples.add(str(raw_values["device_kind_name"]))
        if issues:
            errors.extend(issues[:2])
            if len(errors) >= 6:
                break
            continue
        if resolved_manufacturer is not None:
            manufacturer_ids.add(int(resolved_manufacturer.id))
            manufacturer_row = resolved_manufacturer
        if resolved_kind is not None:
            kind_ids.add(int(resolved_kind.id))
            kind_row = resolved_kind
        if len(manufacturer_ids) > 1 or len(kind_ids) > 1:
            break

    if len(manufacturer_ids) > 1:
        errors.append("Die CSV enthält mehrere Hersteller. Bitte pro Import nur einen Hersteller verwenden.")
    if len(kind_ids) > 1:
        errors.append("Die CSV enthält mehrere Gerätearten. Bitte pro Import nur eine Geräteart verwenden.")
    if not manufacturer_row:
        errors.append("Hersteller konnte aus der CSV nicht eindeutig erkannt werden.")
    if not kind_row:
        errors.append("Geräteart konnte aus der CSV nicht eindeutig erkannt werden.")
    return {
        "manufacturer": manufacturer_row,
        "device_kind": kind_row,
        "manufacturer_values": sorted(manufacturer_samples)[:8],
        "device_kind_values": sorted(kind_samples)[:8],
        "errors": errors[:8],
    }


def _import_mapping_from_profile(
    db: Session,
    *,
    profile_id: int,
    feature_defs_by_key: dict[str, FeatureDef],
) -> dict:
    profile = _pick_import_profile(db, profile_id)
    if not profile:
        return {}
    profile_maps = db.query(ImportProfileMap).filter(ImportProfileMap.profile_id == int(profile.id)).all()
    product_field_map: dict[str, str] = {}
    for map_row in profile_maps:
        map_type = str(map_row.map_type or "").strip()
        target_key = str(map_row.target_key or "").strip()
        source_column = str(map_row.source_column or "").strip()
        if not source_column:
            continue
        if map_type == "product_field":
            product_field_map[target_key] = source_column
    return {
        "profile_id": int(profile.id),
        "profile_name": str(profile.name or ""),
        "product_field_map": product_field_map,
        "description_columns": list(_json_load_list(getattr(profile, "description_columns_json", None))),
        "feature_maps": [],
        "accessory_map": {"source_column": "", "separator_mode": "auto"},
        "ean_column": str(profile.ean_column or ""),
    }


def _import_default_mapping_data(
    db: Session,
    *,
    columns: list[str],
    feature_defs_by_key: dict[str, FeatureDef],
    profile_id: int = 0,
    profile_name_default: str = "",
) -> dict:
    product_field_map = _import_guess_product_field_map(columns)
    ean_column = _guess_column(columns, ("ean", "gtin", "gtin13", "barcode"))
    base = {
        "profile_id": int(profile_id or 0),
        "profile_name": profile_name_default or "CSV-Katalogimport",
        "update_profile": True,
        "ean_column": str(ean_column or ""),
        "product_field_map": product_field_map,
        "description_columns": _import_guess_description_columns(columns),
        "feature_maps": [],
        "accessory_map": {"source_column": "", "separator_mode": "auto"},
        "resolved_manufacturer_id": 0,
        "resolved_device_kind_id": 0,
        "resolved_manufacturer_name": "",
        "resolved_device_kind_name": "",
    }
    if int(profile_id or 0) > 0:
        from_profile = _import_mapping_from_profile(db, profile_id=int(profile_id), feature_defs_by_key=feature_defs_by_key)
        if from_profile:
            base["profile_id"] = int(from_profile.get("profile_id") or profile_id)
            if str(from_profile.get("profile_name") or "").strip():
                base["profile_name"] = str(from_profile.get("profile_name") or "").strip()
            base["ean_column"] = str(from_profile.get("ean_column") or base["ean_column"] or "").strip()
            for key in _import_product_field_keys():
                mapped = str((from_profile.get("product_field_map") or {}).get(key) or "").strip()
                if mapped:
                    base["product_field_map"][key] = mapped
            description_columns = from_profile.get("description_columns")
            if isinstance(description_columns, list):
                base["description_columns"] = [str(col).strip() for col in description_columns if str(col).strip()]
    return base


def _import_normalize_mapping_data(
    mapping_data: dict,
    *,
    columns: list[str],
    profile_name_default: str,
) -> dict:
    product_field_map_raw = mapping_data.get("product_field_map")
    if not isinstance(product_field_map_raw, dict):
        product_field_map_raw = {}
    product_field_map: dict[str, str] = {}
    for key in _import_product_field_keys():
        value = str(product_field_map_raw.get(key) or "").strip()
        product_field_map[key] = value if value in columns else ""
    description_columns_raw = mapping_data.get("description_columns")
    if not isinstance(description_columns_raw, list):
        description_columns_raw = [description_columns_raw] if description_columns_raw else []
    description_columns: list[str] = []
    for raw_value in description_columns_raw:
        value = str(raw_value or "").strip()
        if value and value in columns and value not in description_columns:
            description_columns.append(value)
    ean_column = str(mapping_data.get("ean_column") or product_field_map.get("ean") or "").strip()
    if ean_column and ean_column not in columns:
        ean_column = ""

    profile_name = str(mapping_data.get("profile_name") or profile_name_default or "").strip()
    return {
        "profile_id": _to_int(mapping_data.get("profile_id"), 0),
        "profile_name": profile_name or "CSV-Katalogimport",
        "update_profile": bool(mapping_data.get("update_profile", True)),
        "ean_column": ean_column,
        "product_field_map": product_field_map,
        "description_columns": description_columns,
        "feature_maps": [],
        "accessory_map": {"source_column": "", "separator_mode": "auto"},
        "resolved_manufacturer_id": _to_int(mapping_data.get("resolved_manufacturer_id"), 0),
        "resolved_device_kind_id": _to_int(mapping_data.get("resolved_device_kind_id"), 0),
        "resolved_manufacturer_name": str(mapping_data.get("resolved_manufacturer_name") or "").strip(),
        "resolved_device_kind_name": str(mapping_data.get("resolved_device_kind_name") or "").strip(),
    }


def _import_parse_mapping_form(form, *, columns: list[str], feature_defs_by_key: dict[str, FeatureDef], profile_name_default: str) -> dict:
    _ = feature_defs_by_key
    product_field_map = {}
    for key in _import_product_field_keys():
        value = str(form.get(f"map_{key}") or "").strip()
        product_field_map[key] = value if value in columns else ""
    description_columns = []
    for raw_value in list(form.getlist("description_columns") or []):
        value = str(raw_value or "").strip()
        if value and value in columns and value not in description_columns:
            description_columns.append(value)
    ean_column = str(form.get("ean_column") or "").strip()
    if ean_column not in columns:
        ean_column = ""

    return _import_normalize_mapping_data(
        {
            "profile_id": _to_int(form.get("profile_id"), 0),
            "profile_name": str(form.get("profile_name") or "").strip() or profile_name_default,
            "update_profile": form.get("update_profile") == "on",
            "ean_column": ean_column,
            "product_field_map": product_field_map,
            "description_columns": description_columns,
            "feature_maps": [],
            "accessory_map": {"source_column": "", "separator_mode": "auto"},
        },
        columns=columns,
        profile_name_default=profile_name_default,
    )


def _import_ensure_feature_row_names(mapping_data: dict, columns: list[str]) -> None:
    idx_by_column = {col: idx for idx, col in enumerate(columns)}
    for row in mapping_data.get("feature_maps", []):
        if not isinstance(row, dict):
            continue
        if str(row.get("row_name") or "").strip():
            continue
        col = str(row.get("source_column") or "").strip()
        idx = idx_by_column.get(col)
        if idx is None:
            continue
        row["row_name"] = f"feature_row_{idx}"


def _import_validate_mapping(
    mapping_data: dict,
    *,
    db: Session | None = None,
    columns: list[str],
    rows: list[dict[str, str]] | None = None,
    feature_defs_by_key: dict[str, FeatureDef],
    fallback_manufacturer_id: int = 0,
    fallback_kind_id: int = 0,
) -> tuple[dict, dict]:
    errors = {
        "global_errors": [],
        "field_errors": {},
    }
    normalized = _import_normalize_mapping_data(mapping_data, columns=columns, profile_name_default=str(mapping_data.get("profile_name") or ""))
    _import_ensure_feature_row_names(normalized, columns)

    ean_column = str(normalized.get("ean_column") or "").strip()
    product_field_map = normalized.get("product_field_map") or {}
    core_mapping_present = any(
        str(product_field_map.get(key) or "").strip()
        for key in ("material_no", "sales_name", "product_title_1", "product_title_2")
    )
    if not ean_column:
        errors["field_errors"]["ean_column"] = "EAN ist Pflicht und dient als eindeutige Geräte-ID."
        errors["global_errors"].append("Bitte eine EAN-/GTIN-Spalte zuordnen.")
    if not str(product_field_map.get("manufacturer_name") or "").strip() and int(fallback_manufacturer_id or 0) <= 0:
        errors["field_errors"]["map_manufacturer_name"] = "Bitte Hersteller zuordnen."
        errors["global_errors"].append("Hersteller fehlt im Mapping.")
    if not str(product_field_map.get("device_kind_name") or "").strip() and int(fallback_kind_id or 0) <= 0:
        errors["field_errors"]["map_device_kind_name"] = "Bitte Geräteart zuordnen."
        errors["global_errors"].append("Geräteart fehlt im Mapping.")
    if not core_mapping_present:
        errors["field_errors"]["map_sales_name"] = "Bitte mindestens Verkaufsbezeichnung, Materialnummer oder Produkttitel 1 zuordnen."
        errors["global_errors"].append("Mindestens Verkaufsbezeichnung, Materialnummer oder Produkttitel 1 ist erforderlich.")
    for key in _import_product_field_keys():
        if key == "ean":
            continue
        source_column = str(product_field_map.get(key) or "").strip()
        if source_column and source_column not in columns:
            errors["field_errors"][f"map_{key}"] = f"Ungültige Spaltenzuordnung für '{key}'."
            errors["global_errors"].append(f"Ungültige Spaltenzuordnung für '{key}'.")

    resolved_scope = {
        "manufacturer": None,
        "device_kind": None,
        "errors": [],
    }
    if db is not None and rows is not None and not errors["global_errors"]:
        resolved_scope = _import_resolve_scope_from_rows(
            db,
            rows=rows,
            product_field_map=product_field_map,
            fallback_manufacturer_id=int(fallback_manufacturer_id or 0),
            fallback_kind_id=int(fallback_kind_id or 0),
        )
        for msg in list(resolved_scope.get("errors") or []):
            errors["global_errors"].append(str(msg))
        if resolved_scope.get("manufacturer") is None:
            errors["field_errors"]["map_manufacturer_name"] = "Hersteller konnte nicht eindeutig erkannt werden."
        if resolved_scope.get("device_kind") is None:
            errors["field_errors"]["map_device_kind_name"] = "Geräteart konnte nicht eindeutig erkannt werden."

    validated = {
        "profile_id": _to_int(normalized.get("profile_id"), 0),
        "profile_name": str(normalized.get("profile_name") or "").strip(),
        "update_profile": bool(normalized.get("update_profile", True)),
        "ean_column": ean_column,
        "product_field_map": product_field_map,
        "description_columns": list(normalized.get("description_columns") or []),
        "feature_maps": [],
        "accessory_map": {"source_column": "", "separator_mode": "auto"},
        "resolved_manufacturer_id": int(getattr(resolved_scope.get("manufacturer"), "id", 0) or 0),
        "resolved_device_kind_id": int(getattr(resolved_scope.get("device_kind"), "id", 0) or 0),
        "resolved_manufacturer_name": str(getattr(resolved_scope.get("manufacturer"), "name", "") or ""),
        "resolved_device_kind_name": str(getattr(resolved_scope.get("device_kind"), "name", "") or ""),
    }
    return validated, errors


def _import_feature_prefill_by_column(mapping_data: dict, feature_defs_by_key: dict[str, FeatureDef]) -> dict[str, dict[str, str]]:
    out: dict[str, dict[str, str]] = {}
    for row in mapping_data.get("feature_maps", []):
        if not isinstance(row, dict):
            continue
        source_column = str(row.get("source_column") or "").strip()
        if not source_column:
            continue
        feature_key = str(row.get("feature_key") or "").strip()
        if not feature_key:
            continue
        fdef = feature_defs_by_key.get(feature_key)
        is_existing = str(row.get("is_existing") or "")
        if is_existing not in ("0", "1"):
            is_existing = "1" if fdef else "0"
        out[source_column] = {
            "feature_key": feature_key,
            "feature_label": str(row.get("feature_label") or row.get("label_de") or (fdef.label_de if fdef else feature_key)),
            "data_type": str(row.get("data_type") or (fdef.data_type if fdef else "text")),
            "is_existing": is_existing,
            "existing_key": str(row.get("existing_key") or (feature_key if is_existing == "1" else "__neu__")),
            "new_label": str(row.get("new_label") or ""),
            "row_name": str(row.get("row_name") or ""),
    }
    return out


def _import_human_label(raw: str | None) -> str:
    text = str(raw or "").strip()
    if not text:
        return "Beschreibung"
    text = re.sub(r"[_\-]+", " ", text)
    text = re.sub(r"\s+", " ", text).strip()
    return text[:120]


def _import_build_description_from_row(
    row: dict[str, str],
    *,
    description_columns: list[str],
    core_values: dict[str, str] | None = None,
) -> str | None:
    if not description_columns:
        return None
    core_texts = _import_unique_texts(
        [
            str((core_values or {}).get("sales_name") or ""),
            str((core_values or {}).get("material_no") or ""),
            str((core_values or {}).get("product_title_1") or ""),
            str((core_values or {}).get("product_title_2") or ""),
        ]
    )
    intro_parts: list[str] = []
    blocks: list[str] = []
    highlight_items: list[str] = []
    kv_lines: list[str] = []
    for column in description_columns:
        raw_value = _csv_value(row, column)
        clean_value = _import_clean_text(raw_value)
        if not clean_value:
            continue
        if _import_text_is_duplicate(clean_value, core_texts + intro_parts):
            continue
        label = _import_description_label(column)
        normalized_label = _import_compact_key(column)
        structured_value = _import_preserve_structured_text(raw_value) or clean_value
        if label == "Kurzbeschreibung":
            intro_parts.extend(_import_unique_texts([clean_value]))
            continue
        if label == "Highlights" or normalized_label.startswith("usp"):
            highlight_items.extend(_import_unique_texts([clean_value]))
            continue
        if "\n" in structured_value or len(structured_value) > 140 or label in {"Beschreibung", "Programme", "Merkmale"}:
            if kv_lines:
                blocks.extend(kv_lines)
                kv_lines = []
            include_heading = label not in {"Beschreibung"} and normalized_label not in {"description", "longdescription"}
            if include_heading:
                blocks.append(label)
            blocks.extend([line.rstrip() for line in structured_value.splitlines() if line.strip()])
            blocks.append("")
            continue
        kv_lines.append(f"{label}: {clean_value}")
    intro_parts = _import_unique_texts(intro_parts)
    if intro_parts:
        blocks.extend(intro_parts)
        blocks.append("")
    highlight_items = _import_unique_texts(highlight_items)
    if highlight_items:
        blocks.append("Highlights")
        blocks.extend([f"- {item}" for item in highlight_items])
        blocks.append("")
    if kv_lines:
        blocks.extend(kv_lines)
    text = "\n".join([line for line in blocks if line is not None]).strip()
    return text or None


def _import_parse_accessory_tokens(raw_value: str, separator_mode: str) -> list[str]:
    raw = str(raw_value or "").strip()
    if not raw:
        return []
    mode = str(separator_mode or "auto").strip().lower()
    if mode not in ACCESSORY_SEPARATOR_MODES:
        mode = "auto"
    if mode == "semicolon":
        tokens = raw.split(";")
    elif mode == "comma":
        tokens = raw.split(",")
    else:
        tokens = re.split(r"[;,]+", raw)
    out: list[str] = []
    seen: set[str] = set()
    for token in tokens:
        clean = str(token or "").strip()
        if not clean:
            continue
        key = clean.casefold()
        if key in seen:
            continue
        seen.add(key)
        out.append(clean)
    return out


def _import_match_accessory_candidates(
    db: Session,
    *,
    token: str,
    product_id: int,
    manufacturer_id: int | None,
    device_kind_id: int | None,
) -> list[Product]:
    token_clean = str(token or "").strip()
    if not token_clean:
        return []
    token_lower = token_clean.casefold()
    token_norm = _normalize_search_text(token_clean)
    token_digits = re.sub(r"\D+", "", token_clean)

    def _prefer_context(rows: list[Product]) -> list[Product]:
        if len(rows) <= 1:
            return rows
        if manufacturer_id:
            rows_mfg = [row for row in rows if int(row.manufacturer_id or 0) == int(manufacturer_id)]
            if len(rows_mfg) == 1:
                return rows_mfg
            if rows_mfg:
                rows = rows_mfg
        if device_kind_id:
            rows_kind = [row for row in rows if int(row.device_kind_id or 0) == int(device_kind_id)]
            if len(rows_kind) == 1:
                return rows_kind
            if rows_kind:
                rows = rows_kind
        return rows

    candidates = (
        db.query(Product)
        .filter(
            Product.id != int(product_id),
            Product.active == True,
            Product.material_no.isnot(None),
            func.lower(func.trim(Product.material_no)) == token_lower,
        )
        .order_by(Product.id.asc())
        .all()
    )
    if candidates:
        return _prefer_context(candidates)

    if token_digits:
        candidates = (
            db.query(Product)
            .filter(
                Product.id != int(product_id),
                Product.active == True,
                Product.ean == token_digits,
            )
            .order_by(Product.id.asc())
            .all()
        )
        if candidates:
            return _prefer_context(candidates)

    candidates = (
        db.query(Product)
        .filter(
            Product.id != int(product_id),
            Product.active == True,
            Product.sales_name.isnot(None),
            func.lower(func.trim(Product.sales_name)) == token_lower,
        )
        .order_by(Product.id.asc())
        .all()
    )
    if candidates:
        return _prefer_context(candidates)

    candidates = (
        db.query(Product)
        .filter(
            Product.id != int(product_id),
            Product.active == True,
            Product.name.isnot(None),
            func.lower(func.trim(Product.name)) == token_lower,
        )
        .order_by(Product.id.asc())
        .all()
    )
    if candidates:
        return _prefer_context(candidates)

    if token_norm:
        candidates = (
            db.query(Product)
            .filter(
                Product.id != int(product_id),
                Product.active == True,
                Product.search_blob.isnot(None),
                func.instr(func.lower(Product.search_blob), token_norm.casefold()) > 0,
            )
            .order_by(Product.id.asc())
            .limit(5)
            .all()
        )
        if candidates:
            return _prefer_context(candidates)
    return []


def _import_ensure_accessory_link(
    db: Session,
    *,
    product_id: int,
    accessory_product_id: int,
    source: str,
    import_run_id: int | None,
) -> bool:
    exists_row = (
        db.query(ProductAccessoryLink.id)
        .filter(
            ProductAccessoryLink.product_id == int(product_id),
            ProductAccessoryLink.accessory_product_id == int(accessory_product_id),
        )
        .first()
    )
    if exists_row:
        return False
    db.add(
        ProductAccessoryLink(
            product_id=int(product_id),
            accessory_product_id=int(accessory_product_id),
            source=str(source or "csv"),
            import_run_id=int(import_run_id) if int(import_run_id or 0) > 0 else None,
            created_at=_utcnow_naive(),
        )
    )
    return True


def _import_resolve_open_accessory_references(db: Session) -> int:
    refs = (
        db.query(ProductAccessoryReference)
        .filter(ProductAccessoryReference.status.in_(("pending", "not_found", "ambiguous")))
        .order_by(ProductAccessoryReference.id.asc())
        .limit(2000)
        .all()
    )
    resolved_count = 0
    for ref in refs:
        candidates = _import_match_accessory_candidates(
            db,
            token=str(ref.raw_value or ""),
            product_id=int(ref.product_id),
            manufacturer_id=int(ref.manufacturer_id) if ref.manufacturer_id else None,
            device_kind_id=int(ref.device_kind_id) if ref.device_kind_id else None,
        )
        if len(candidates) != 1:
            continue
        matched = candidates[0]
        _import_ensure_accessory_link(
            db,
            product_id=int(ref.product_id),
            accessory_product_id=int(matched.id),
            source="csv",
            import_run_id=int(ref.import_run_id) if ref.import_run_id else None,
        )
        ref.status = "linked"
        ref.matched_product_id = int(matched.id)
        db.add(ref)
        resolved_count += 1
    return resolved_count


def _import_profile_unmapped_columns(
    db: Session,
    *,
    profile_id: int,
    columns: list[str],
) -> list[str]:
    profile = _pick_import_profile(db, int(profile_id))
    if not profile:
        return []
    map_rows = db.query(ImportProfileMap).filter(ImportProfileMap.profile_id == int(profile.id)).all()
    mapped_columns = {str(row.source_column or "").strip() for row in map_rows if str(row.source_column or "").strip()}
    mapped_columns.add(str(profile.ean_column or "").strip())
    for column in _json_load_list(getattr(profile, "description_columns_json", None)):
        clean = str(column or "").strip()
        if clean:
            mapped_columns.add(clean)
    return [column for column in columns if column not in mapped_columns]


def _import_draft_open_url(draft: ImportDraft) -> str:
    step = str(draft.current_step or "").strip()
    if step == "run":
        return f"/catalog/import/{int(draft.id)}/run"
    return f"/catalog/import/{int(draft.id)}/map"


def _import_read_draft_csv(draft: ImportDraft) -> tuple[list[str], list[dict[str, str]], str]:
    file_path = Path(str(draft.file_path_tmp or "")).resolve()
    if not file_path.exists():
        return [], [], "Importdatei nicht mehr vorhanden."
    dirs = ensure_dirs()
    allowed_root = (dirs["tmp"] / "imports").resolve()
    try:
        file_path.relative_to(allowed_root)
    except Exception:
        return [], [], "Importdatei liegt außerhalb des erlaubten Importordners."
    delimiter = str(draft.delimiter or ";").strip() or ";"
    if delimiter not in (";", ","):
        delimiter = ";"
    encoding = str(draft.encoding or "utf-8").strip() or "utf-8"
    has_header = bool(draft.has_header)
    try:
        columns, rows = _read_csv_rows(file_path, delimiter=delimiter, has_header=has_header, encoding=encoding)
    except Exception as exc:
        return [], [], f"CSV konnte nicht gelesen werden: {exc}"
    if not columns:
        return [], [], "Keine Spalten erkannt. Bitte Trennzeichen prüfen."
    return columns, rows, ""


def _import_upload_page_ctx(
    request: Request,
    *,
    db: Session,
    user,
    form_data: dict | None = None,
    global_errors: list[str] | None = None,
) -> dict:
    form_data = form_data or {}
    selected_manufacturer_id = _to_int(form_data.get("manufacturer_id"), _to_int(request.query_params.get("manufacturer_id"), 0))
    selected_kind_id = _to_int(form_data.get("kind_id"), _to_int(request.query_params.get("kind_id"), 0))
    selected_profile_id = _to_int(form_data.get("profile_id"), 0)
    manufacturers = db.query(Manufacturer).filter(Manufacturer.active == True).order_by(Manufacturer.name.asc(), Manufacturer.id.asc()).all()
    kinds = db.query(DeviceKind).order_by(DeviceKind.name.asc(), DeviceKind.id.asc()).all()
    available_profiles: list[ImportProfile] = []
    if selected_manufacturer_id and selected_kind_id:
        available_profiles = (
            db.query(ImportProfile)
            .filter(
                ImportProfile.manufacturer_id == int(selected_manufacturer_id),
                ImportProfile.device_kind_id == int(selected_kind_id),
            )
            .order_by(ImportProfile.last_used_at.desc(), ImportProfile.id.desc())
            .all()
        )
    recent_drafts = db.query(ImportDraft).order_by(ImportDraft.updated_at.desc(), ImportDraft.id.desc()).limit(5).all()
    manufacturer_ids = {int(d.manufacturer_id) for d in recent_drafts if d.manufacturer_id}
    kind_ids = {int(d.device_kind_id) for d in recent_drafts if d.device_kind_id}
    manufacturer_map = {}
    if manufacturer_ids:
        for row in db.query(Manufacturer).filter(Manufacturer.id.in_(manufacturer_ids)).all():
            manufacturer_map[int(row.id)] = str(row.name or "")
    kind_map = {}
    if kind_ids:
        for row in db.query(DeviceKind).filter(DeviceKind.id.in_(kind_ids)).all():
            kind_map[int(row.id)] = str(row.name or "")

    return _ctx(
        request,
        user=user,
        manufacturers=manufacturers,
        kinds=kinds,
        selected_manufacturer_id=selected_manufacturer_id,
        selected_kind_id=selected_kind_id,
        selected_profile_id=selected_profile_id,
        available_profiles=available_profiles,
        recent_drafts=recent_drafts,
        manufacturer_map=manufacturer_map,
        kind_map=kind_map,
        upload_form_data={
            "delimiter": str(form_data.get("delimiter") or ";"),
            "encoding": str(form_data.get("encoding") or "utf-8"),
            "has_header": bool(form_data.get("has_header", True)),
        },
        global_errors=global_errors or [],
        draft_open_url=_import_draft_open_url,
    )


def _import_map_page_response(
    request: Request,
    *,
    db: Session,
    user,
    draft: ImportDraft,
    columns: list[str],
    rows: list[dict[str, str]],
    mapping_data: dict,
    errors: dict | None = None,
):
    fallback_manufacturer = db.get(Manufacturer, int(draft.manufacturer_id or 0)) if draft.manufacturer_id else None
    fallback_kind = db.get(DeviceKind, int(draft.device_kind_id or 0)) if draft.device_kind_id else None
    profile_name_default = _catalog_import_profile_name_default(
        manufacturer=fallback_manufacturer,
        device_kind=fallback_kind,
        filename=draft.filename_original,
    )
    normalized_mapping = _import_normalize_mapping_data(mapping_data, columns=columns, profile_name_default=profile_name_default)
    _import_ensure_feature_row_names(normalized_mapping, columns)
    validated_mapping, resolved_errors = _import_validate_mapping(
        normalized_mapping,
        db=db,
        columns=columns,
        rows=rows,
        feature_defs_by_key={},
        fallback_manufacturer_id=int(draft.manufacturer_id or 0),
        fallback_kind_id=int(draft.device_kind_id or 0),
    )
    manufacturer = db.get(Manufacturer, int(validated_mapping.get("resolved_manufacturer_id") or 0)) if int(validated_mapping.get("resolved_manufacturer_id") or 0) > 0 else fallback_manufacturer
    selected_kind = db.get(DeviceKind, int(validated_mapping.get("resolved_device_kind_id") or 0)) if int(validated_mapping.get("resolved_device_kind_id") or 0) > 0 else fallback_kind
    feature_defs = _feature_defs_for_kind(db, int(selected_kind.id)) if selected_kind else []
    feature_defs_by_key = {str(row.key or "").strip(): row for row in feature_defs}
    attrs = _applicable_attributes(db, int(selected_kind.id), None) if selected_kind else []
    analysis_plan = (
        _catalog_csv_import_plan_fallback(
            manufacturer=manufacturer,
            device_kind=selected_kind,
            columns=columns,
            rows=rows,
            attrs=attrs,
            mapping_data=normalized_mapping,
        )
        if selected_kind and manufacturer
        else {"description_columns": [], "notes": []}
    )
    if not list(normalized_mapping.get("description_columns") or []) and list(analysis_plan.get("description_columns") or []):
        normalized_mapping["description_columns"] = list(analysis_plan.get("description_columns") or [])
    matched_profiles = (
        _detect_matching_profiles(
            db,
            manufacturer_id=int(manufacturer.id),
            device_kind_id=int(selected_kind.id),
            columns=columns,
        )
        if manufacturer and selected_kind
        else []
    )
    profile_id = _to_int(normalized_mapping.get("profile_id"), _to_int(draft.import_profile_id, 0))
    active_profile = _pick_import_profile(db, profile_id)
    unmapped_columns = _import_profile_unmapped_columns(db, profile_id=profile_id, columns=columns) if active_profile else []

    product_field_map = normalized_mapping.get("product_field_map") or {}
    feature_prefill_by_column = _import_feature_prefill_by_column(normalized_mapping, feature_defs_by_key)
    accessory_map = normalized_mapping.get("accessory_map") or {}
    validation_errors = errors if isinstance(errors, dict) else resolved_errors
    if "global_errors" not in validation_errors or not isinstance(validation_errors.get("global_errors"), list):
        validation_errors["global_errors"] = []
    if "field_errors" not in validation_errors or not isinstance(validation_errors.get("field_errors"), dict):
        validation_errors["field_errors"] = {}

    return templates.TemplateResponse(
        "catalog/import_map.html",
        _ctx(
            request,
            user=user,
            draft=draft,
            columns=columns,
            preview_rows=rows[:10],
            total_rows=len(rows),
            delimiter=draft.delimiter,
            encoding=draft.encoding,
            has_header=bool(draft.has_header),
            manufacturer=manufacturer,
            selected_kind=selected_kind,
            matched_profiles=matched_profiles,
            auto_profile_id=int(active_profile.id) if active_profile else 0,
            active_profile=active_profile,
            profile_name_default=profile_name_default,
            profile_update_default=bool(normalized_mapping.get("update_profile", True)),
            product_field_map=product_field_map,
            description_columns=list(normalized_mapping.get("description_columns") or []),
            image_field_indices=list(range(1, PRODUCT_IMAGE_URL_MAX + 1)),
            ean_column=str(normalized_mapping.get("ean_column") or ""),
            resolved_manufacturer_name=str(getattr(manufacturer, "name", "") or normalized_mapping.get("resolved_manufacturer_name") or ""),
            resolved_device_kind_name=str(getattr(selected_kind, "name", "") or normalized_mapping.get("resolved_device_kind_name") or ""),
            feature_defs=feature_defs,
            feature_prefill_by_column=feature_prefill_by_column,
            selected_profile_id=profile_id,
            profile_name_value=str(normalized_mapping.get("profile_name") or profile_name_default),
            accessory_source_column=str(accessory_map.get("source_column") or ""),
            accessory_separator_mode=str(accessory_map.get("separator_mode") or "auto"),
            validation_errors=validation_errors,
            unmapped_columns=unmapped_columns,
            analysis_notes=[str(note) for note in list(analysis_plan.get("notes") or []) if str(note).strip()],
        ),
    )


def _catalog_import_run_job_key(draft_id: int) -> str:
    return f"catalog_import_run:{int(draft_id)}"


def _catalog_import_result_payload(import_run: ImportRun | None) -> dict[str, object]:
    if import_run is None:
        return {}
    payload = _json_load_dict(import_run.log_text)
    if payload:
        return payload
    raw = str(import_run.log_text or "").strip()
    return {"raw_log": raw} if raw else {}


def _catalog_import_result_context(*, draft: ImportDraft, import_run: ImportRun) -> dict[str, object]:
    payload = _catalog_import_result_payload(import_run)
    warnings_preview = payload.get("warnings") if isinstance(payload.get("warnings"), list) else []
    errors_preview = payload.get("errors") if isinstance(payload.get("errors"), list) else []
    open_accessory_preview = payload.get("open_accessory_preview") if isinstance(payload.get("open_accessory_preview"), list) else []
    new_profile_columns = payload.get("new_profile_columns") if isinstance(payload.get("new_profile_columns"), list) else []
    snapshot_count = int(payload.get("snapshot_count") or 0)
    attribute_update_count = int(payload.get("attribute_update_count") or 0)
    description_columns_used = payload.get("description_columns_used") if isinstance(payload.get("description_columns_used"), list) else []
    analysis_notes = payload.get("analysis_notes") if isinstance(payload.get("analysis_notes"), list) else []
    return {
        "draft": draft,
        "created_count": int(import_run.inserted_count or 0),
        "updated_count": int(import_run.updated_count or 0),
        "skipped_count": int(payload.get("skipped_count") or 0),
        "error_count": int(import_run.error_count or 0),
        "errors_preview": errors_preview[:50],
        "warning_count": len(warnings_preview),
        "warnings_preview": warnings_preview[:50],
        "accessory_linked_count": int(payload.get("accessory_linked_count") or 0),
        "accessory_open_count": int(payload.get("accessory_open_count") or 0),
        "resolved_accessory_count": int(payload.get("resolved_accessory_count") or 0),
        "open_accessory_preview": open_accessory_preview[:50],
        "profile_updated": bool(payload.get("profile_updated")),
        "new_profile_columns": [str(value) for value in new_profile_columns[:50]],
        "snapshot_count": snapshot_count,
        "attribute_update_count": attribute_update_count,
        "description_columns_used": [str(value) for value in description_columns_used[:12]],
        "analysis_notes": [str(value) for value in analysis_notes[:12]],
        "reopen_url": f"/catalog/import/{int(draft.id)}/map" if draft.status == IMPORT_DRAFT_STATUS_FAILED else _import_draft_open_url(draft),
        "import_run": import_run,
    }


def _detect_matching_profiles_global(
    db: Session,
    *,
    columns: list[str],
) -> list[dict[str, object]]:
    normalized = {_normalize_import_header(c): c for c in columns}
    profiles = db.query(ImportProfile).order_by(ImportProfile.last_used_at.desc(), ImportProfile.id.desc()).all()
    ranked: list[dict[str, object]] = []
    for profile in profiles:
        maps = db.query(ImportProfileMap).filter(ImportProfileMap.profile_id == int(profile.id)).all()
        map_dict = _profile_map_dict(maps)
        required_ok = False
        score = 0
        manufacturer_row = map_dict.get(("product_field", "manufacturer_name"))
        if manufacturer_row and _normalize_import_header(str(manufacturer_row.source_column or "")) in normalized:
            score += 4
        kind_row = map_dict.get(("product_field", "device_kind_name"))
        if kind_row and _normalize_import_header(str(kind_row.source_column or "")) in normalized:
            score += 4
        for map_key in (
            ("product_field", "material_no"),
            ("product_field", "sales_name"),
            ("product_field", "product_title_1"),
            ("product_field", "product_title_2"),
        ):
            row = map_dict.get(map_key)
            if row and _normalize_import_header(str(row.source_column or "")) in normalized:
                required_ok = True
                score += 10
        if str(profile.ean_column or "").strip() and _normalize_import_header(str(profile.ean_column or "")) in normalized:
            required_ok = True
            score += 12
        if not required_ok:
            continue
        for map_row in maps:
            if _normalize_import_header(str(map_row.source_column or "")) in normalized:
                score += 1
        ranked.append(
            {
                "profile": profile,
                "score": score,
                "maps": maps,
            }
        )
    ranked.sort(key=lambda row: (int(row["score"]), int(getattr(row["profile"], "id", 0))), reverse=True)
    return ranked


def _catalog_auto_import_report_error(
    db: Session,
    *,
    attachment: MailAttachment,
    message: EmailMessage | None,
    error_text: str,
) -> None:
    existing = (
        db.query(SupervisorFinding)
        .filter(
            SupervisorFinding.finding_type == "catalog_auto_import",
            SupervisorFinding.related_object_type == "mail_attachment",
            SupervisorFinding.related_object_id == int(attachment.id),
            SupervisorFinding.status != "resolved",
        )
        .order_by(SupervisorFinding.id.desc())
        .first()
    )
    title = f"CSV-Autoimport fehlgeschlagen: {str(attachment.filename or 'Anhang').strip() or attachment.id}"
    description = error_text.strip()
    if message is not None and str(message.subject or "").strip():
        description = f"Mail: {str(message.subject or '').strip()}\n\n{description}"
    if existing is None:
        db.add(
            SupervisorFinding(
                finding_type="catalog_auto_import",
                severity="mittel",
                title=title[:240],
                description=description[:4000],
                suggested_action="Importprofil prüfen oder CSV-Mapping korrigieren.",
                related_object_type="mail_attachment",
                related_object_id=int(attachment.id),
                status="open",
                created_at=_utcnow_naive(),
                updated_at=_utcnow_naive(),
            )
        )
        return
    existing.title = title[:240]
    existing.description = description[:4000]
    existing.updated_at = _utcnow_naive()
    db.add(existing)


def _catalog_auto_import_resolve_error(db: Session, *, attachment_id: int) -> None:
    rows = (
        db.query(SupervisorFinding)
        .filter(
            SupervisorFinding.finding_type == "catalog_auto_import",
            SupervisorFinding.related_object_type == "mail_attachment",
            SupervisorFinding.related_object_id == int(attachment_id),
            SupervisorFinding.status != "resolved",
        )
        .all()
    )
    for row in rows:
        row.status = "resolved"
        row.updated_at = _utcnow_naive()
        db.add(row)


def _catalog_auto_import_detect_profile(
    db: Session,
    *,
    csv_path: Path,
) -> dict[str, object]:
    attempts: list[tuple[str, str]] = []
    best: dict[str, object] = {}
    for delimiter in (";", ","):
        for encoding in ("utf-8", "utf-8-sig", "cp1252", "latin-1"):
            attempts.append((delimiter, encoding))
    for delimiter, encoding in attempts:
        try:
            columns, rows = _read_csv_rows(csv_path, delimiter=delimiter, has_header=True, encoding=encoding)
        except Exception:
            continue
        if not columns or not rows:
            continue
        matches = _detect_matching_profiles_global(db, columns=columns)
        if not matches:
            continue
        top_score = int(matches[0]["score"] or 0)
        top_matches = [row for row in matches if int(row["score"] or 0) == top_score]
        if len(top_matches) != 1:
            continue
        if not best or int(best.get("score") or 0) < top_score:
            best = {
                "delimiter": delimiter,
                "encoding": encoding,
                "has_header": True,
                "columns": columns,
                "rows": rows,
                "profile": top_matches[0]["profile"],
                "score": top_score,
            }
    return best


def _catalog_enqueue_auto_import_from_attachment(
    db: Session,
    *,
    attachment: MailAttachment,
    message: EmailMessage | None,
) -> dict[str, object]:
    abs_path = _mail_attachment_abs_path(str(attachment.file_path or "").strip())
    if not abs_path or not abs_path.is_file():
        raise ValueError("Datei des Mail-Anhangs wurde nicht gefunden.")
    if abs_path.stat().st_size > CATALOG_AUTO_IMPORT_MAX_ATTACHMENT_BYTES:
        raise ValueError("CSV-Anhang ist größer als das erlaubte Limit.")
    detected = _catalog_auto_import_detect_profile(db, csv_path=abs_path)
    profile = detected.get("profile")
    if profile is None:
        raise ValueError("Es konnte kein eindeutiges Importprofil zugeordnet werden.")
    profile = profile  # type: ignore[assignment]
    manufacturer = db.get(Manufacturer, int(profile.manufacturer_id or 0))
    selected_kind = db.get(DeviceKind, int(profile.device_kind_id or 0))
    if manufacturer is None or selected_kind is None:
        raise ValueError("Importprofil verweist auf keinen gültigen Hersteller oder keine gültige Geräteart.")
    columns = list(detected.get("columns") or [])
    rows = list(detected.get("rows") or [])
    mapping_data = _import_default_mapping_data(
        db,
        columns=columns,
        feature_defs_by_key={},
        profile_id=int(profile.id),
        profile_name_default=_catalog_import_profile_name_default(
            manufacturer=manufacturer,
            device_kind=selected_kind,
            filename=attachment.filename,
        ),
    )
    mapping_data["profile_id"] = int(profile.id)
    validated_mapping, errors = _import_validate_mapping(
        mapping_data,
        db=db,
        columns=columns,
        rows=rows,
        feature_defs_by_key={},
        fallback_manufacturer_id=int(profile.manufacturer_id or 0),
        fallback_kind_id=int(profile.device_kind_id or 0),
    )
    if errors["global_errors"] or errors["field_errors"]:
        raise ValueError("; ".join([str(msg) for msg in list(errors["global_errors"])[:4]]) or "Importprofil ist für den Autoimport nicht gültig.")
    draft = ImportDraft(
        created_at=_utcnow_naive(),
        updated_at=_utcnow_naive(),
        status=IMPORT_DRAFT_STATUS_VALIDATED,
        filename_original=str(attachment.filename or "").strip() or Path(str(attachment.file_path or "")).name,
        file_path_tmp="",
        delimiter=str(detected.get("delimiter") or profile.delimiter or ";"),
        encoding=str(detected.get("encoding") or profile.encoding or "utf-8"),
        has_header=True,
        manufacturer_id=int(manufacturer.id),
        device_kind_id=int(selected_kind.id),
        import_profile_id=int(profile.id),
        current_step="run",
        mapping_json=_json_dump(validated_mapping),
        validation_errors_json=None,
        last_preview_json=_json_dump({"columns": columns, "rows": rows[:10], "total_rows": len(rows)}),
        created_by_user_id=None,
    )
    db.add(draft)
    db.commit()
    db.refresh(draft)
    tmp_root = (ensure_dirs()["tmp"] / "imports" / str(int(draft.id))).resolve()
    tmp_root.mkdir(parents=True, exist_ok=True)
    csv_path = tmp_root / "source.csv"
    shutil.copy2(abs_path, csv_path)
    draft.file_path_tmp = str(csv_path)
    draft.updated_at = _utcnow_naive()
    db.add(draft)
    db.commit()

    job_key = _catalog_import_run_job_key(int(draft.id))
    if _sync_job_existing_active(db, lock_key="catalog_import") is not None:
        raise RuntimeError("defer:Ein anderer Katalogimport läuft bereits.")
    import_run = ImportRun(
        profile_id=int(profile.id),
        filename=str(draft.filename_original or csv_path.name),
        started_at=_utcnow_naive(),
    )
    db.add(import_run)
    db.commit()
    db.refresh(import_run)
    job, created_job = _enqueue_sync_job(
        db,
        system_name="catalog",
        direction="pull",
        entity_type="catalog_import_run",
        title="CSV-Katalogimport (Mail)",
        job_key=job_key,
        lock_key="catalog_import",
        log_text=f"CSV-Katalogimport aus Mail-Anhang #{int(attachment.id)}",
        progress={
            "draft_id": int(draft.id),
            "import_run_id": int(import_run.id),
            "phase": "Automatisch aus Mail übernommen",
            "phase_detail": f"{len(rows)} Zeilen sind vorbereitet.",
            "total_count": len(rows),
            "processed_count": 0,
            "success_count": 0,
            "error_count": 0,
            "current_item_label": str(draft.filename_original or import_run.filename or "CSV-Datei"),
            "current_item_ref": f"Mail-Anhang #{int(attachment.id)}",
        },
        result_url=f"/catalog/import/runs/{int(import_run.id)}",
    )
    if not created_job:
        db.delete(import_run)
        db.commit()
        raise RuntimeError("defer:Katalogimport konnte nicht in die Warteschlange gestellt werden.")
    return {
        "draft_id": int(draft.id),
        "import_run_id": int(import_run.id),
        "job_id": int(job.id),
        "attachment_id": int(attachment.id),
        "message_id": int(message.id) if message is not None else None,
    }


def _catalog_auto_import_zip_from_attachment(
    db: Session,
    *,
    attachment: MailAttachment,
    message: EmailMessage | None,
) -> int:
    """Verarbeitet einen ZIP-Anhang aus einer E-Mail: extrahiert CSVs und importiert jede einzeln."""
    abs_path = _mail_attachment_abs_path(str(attachment.file_path or "").strip())
    if not abs_path or not abs_path.is_file():
        raise ValueError("ZIP-Anhang wurde nicht gefunden.")
    if abs_path.stat().st_size > CATALOG_AUTO_IMPORT_MAX_ATTACHMENT_BYTES * 5:
        raise ValueError("ZIP-Anhang ist größer als das erlaubte Limit.")

    zip_data = abs_path.read_bytes()
    zip_result = prepare_zip_import(db, zip_data, zip_filename=str(attachment.filename or ""))
    csv_files = zip_result["csv_files"]
    if not csv_files:
        raise ValueError(f"Keine importierbaren CSVs im ZIP: {'; '.join(zip_result['errors'][:3])}")

    imported_count = 0
    for csv_entry in csv_files:
        try:
            csv_data = csv_entry["data"]
            csv_filename = csv_entry["filename"]
            manufacturer = csv_entry["manufacturer"]
            device_kind = csv_entry["device_kind"]
            if not manufacturer or not device_kind:
                continue

            detected_settings = _detect_csv_upload_settings(csv_data)
            delimiter = str(detected_settings.get("delimiter") or ";").strip()
            encoding = str(detected_settings.get("encoding") or "utf-8").strip() or "utf-8"

            draft = ImportDraft(
                created_at=_utcnow_naive(),
                updated_at=_utcnow_naive(),
                status=IMPORT_DRAFT_STATUS_VALIDATED,
                filename_original=csv_filename,
                file_path_tmp="",
                delimiter=delimiter,
                encoding=encoding,
                has_header=True,
                manufacturer_id=int(manufacturer.id),
                device_kind_id=int(device_kind.id),
                import_profile_id=None,
                current_step="run",
                mapping_json=None,
                validation_errors_json=None,
                last_preview_json=None,
                created_by_user_id=None,
            )
            db.add(draft)
            db.commit()
            db.refresh(draft)

            tmp_root = (ensure_dirs()["tmp"] / "imports" / str(int(draft.id))).resolve()
            tmp_root.mkdir(parents=True, exist_ok=True)
            csv_path = tmp_root / "source.csv"
            csv_path.write_bytes(csv_data)
            draft.file_path_tmp = str(csv_path)

            columns, rows, csv_error = _import_read_draft_csv(draft)
            if csv_error or not rows:
                draft.status = IMPORT_DRAFT_STATUS_FAILED
                draft.validation_errors_json = _json_dump({"global_errors": [csv_error or "Keine Daten"], "field_errors": {}})
                db.add(draft)
                db.commit()
                continue

            feature_defs_by_key: dict[str, FeatureDef] = {}
            feature_defs_for_kind = _feature_defs_for_kind(db, int(device_kind.id))
            feature_defs_by_key = {str(row.key or "").strip(): row for row in feature_defs_for_kind}

            mapping_data = _import_default_mapping_data(
                db, columns=columns, feature_defs_by_key=feature_defs_by_key,
                profile_id=0, profile_name_default=_catalog_import_profile_name_default(
                    manufacturer=manufacturer, device_kind=device_kind, filename=csv_filename),
            )
            mapping_data["manufacturer_name"] = str(manufacturer.name or "")
            mapping_data["resolved_manufacturer_id"] = int(manufacturer.id)
            mapping_data["device_kind_name"] = str(device_kind.name or "")
            mapping_data["resolved_device_kind_id"] = int(device_kind.id)

            validated_mapping, errors = _import_validate_mapping(
                mapping_data, db=db, columns=columns, rows=rows,
                feature_defs_by_key=feature_defs_by_key,
                fallback_manufacturer_id=int(manufacturer.id),
                fallback_kind_id=int(device_kind.id),
            )
            if errors["global_errors"] or errors["field_errors"]:
                draft.status = IMPORT_DRAFT_STATUS_FAILED
                draft.validation_errors_json = _json_dump(errors)
                db.add(draft)
                db.commit()
                continue

            draft.mapping_json = _json_dump(validated_mapping)
            draft.last_preview_json = _json_dump({"columns": columns, "rows": rows[:10], "total_rows": len(rows)})
            draft.updated_at = _utcnow_naive()
            db.add(draft)
            db.commit()

            import_run = ImportRun(
                profile_id=None,
                filename=csv_filename,
                started_at=_utcnow_naive(),
            )
            db.add(import_run)
            db.commit()
            db.refresh(import_run)

            job, created_job = _enqueue_sync_job(
                db,
                system_name="catalog",
                direction="pull",
                entity_type="catalog_import_run",
                title=f"ZIP-Import: {csv_filename}",
                job_key=_catalog_import_run_job_key(int(draft.id)),
                lock_key=f"catalog_import_{int(draft.id)}",
                log_text=f"ZIP-Import aus Mail-Anhang #{int(attachment.id)}: {csv_filename}",
                progress={
                    "draft_id": int(draft.id),
                    "import_run_id": int(import_run.id),
                    "phase": "ZIP-Import wird vorbereitet",
                    "total_count": len(rows),
                },
                result_url=f"/catalog/import/runs/{int(import_run.id)}",
            )
            db.commit()
            imported_count += 1

        except Exception as exc:
            logger.warning("ZIP-Import: %s fehlgeschlagen: %s", csv_entry.get("filename", "?"), exc)

    return imported_count


def _catalog_auto_import_mail_attachments(db: Session, *, limit: int = 3) -> dict[str, int]:
    enabled = _bool_from_setting(_system_setting_get(db, CATALOG_AUTO_IMPORT_MAIL, "1"), default=True)
    if not enabled:
        return {"processed": 0, "imported": 0, "errors": 0}
    last_attachment_id = _to_int(_system_setting_get(db, CATALOG_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, "0"), 0)
    rows = (
        db.query(MailAttachment, EmailMessage)
        .join(EmailMessage, EmailMessage.id == MailAttachment.mail_message_id)
        .filter(MailAttachment.id > int(last_attachment_id))
        .order_by(MailAttachment.id.asc())
        .limit(max(1, int(limit)))
        .all()
    )
    processed = 0
    imported = 0
    errors = 0
    current_last_id = int(last_attachment_id)
    for attachment, message in rows:
        attachment_id = int(attachment.id)
        current_last_id = max(current_last_id, attachment_id)
        filename = str(attachment.filename or "").strip().lower()
        mime_type = str(attachment.mime_type or "").strip().lower()
        is_csv = filename.endswith(".csv") or mime_type in {"text/csv", "application/csv", "application/vnd.ms-excel"}
        is_zip = filename.endswith(".zip") or mime_type in {"application/zip", "application/x-zip-compressed"}
        if not (is_csv or is_zip):
            processed += 1
            _system_setting_set(db, CATALOG_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, str(current_last_id))
            db.commit()
            continue
        try:
            if is_zip:
                zip_imported = _catalog_auto_import_zip_from_attachment(db, attachment=attachment, message=message)
                imported += zip_imported
            else:
                _catalog_enqueue_auto_import_from_attachment(db, attachment=attachment, message=message)
                imported += 1
            _catalog_auto_import_resolve_error(db, attachment_id=attachment_id)
        except RuntimeError as exc:
            if str(exc).startswith("defer:"):
                break
            errors += 1
            _catalog_auto_import_report_error(db, attachment=attachment, message=message, error_text=str(exc))
        except Exception as exc:
            errors += 1
            _catalog_auto_import_report_error(db, attachment=attachment, message=message, error_text=str(exc))
        processed += 1
        _system_setting_set(db, CATALOG_AUTO_IMPORT_MAIL_LAST_ATTACHMENT_ID, str(current_last_id))
        db.commit()
    return {"processed": processed, "imported": imported, "errors": errors}


def _import_core_values_from_row(
    row: dict[str, str],
    *,
    product_field_map: dict[str, str],
    ean_column: str,
    description_columns: list[str] | None = None,
    import_plan: dict[str, object] | None = None,
) -> dict[str, object]:
    core_fallback_map = dict((import_plan or {}).get("core_fallback_map") or {})

    def pick_value(field: str) -> str:
        columns = []
        primary = str(product_field_map.get(field) or "").strip()
        if primary:
            columns.append(primary)
        for column in list(core_fallback_map.get(field) or []):
            clean = str(column or "").strip()
            if clean and clean not in columns:
                columns.append(clean)
        return _catalog_csv_pick_row_value(row, columns)

    manufacturer_name = pick_value("manufacturer_name")
    device_kind_name = pick_value("device_kind_name")
    sales_name = pick_value("sales_name")
    material_no = pick_value("material_no")
    product_title_1 = pick_value("product_title_1")
    product_title_2 = pick_value("product_title_2")
    ean_raw = _csv_value(row, ean_column)
    ean_digits = re.sub(r"\D+", "", ean_raw)
    try:
        normalized_ean = normalize_ean(ean_digits) if ean_digits else None
    except Exception:
        normalized_ean = ean_digits or None
    unique_titles = _import_unique_texts([sales_name, product_title_1, product_title_2])
    sales_name = unique_titles[0] if unique_titles else sales_name
    product_title_1 = unique_titles[1] if len(unique_titles) > 1 else ""
    product_title_2 = unique_titles[2] if len(unique_titles) > 2 else ""
    description = _import_build_description_from_row(
        row,
        description_columns=list(description_columns or list((import_plan or {}).get("description_columns") or [])),
        core_values={
            "sales_name": sales_name,
            "material_no": material_no,
            "product_title_1": product_title_1,
            "product_title_2": product_title_2,
        },
    )
    return {
        "manufacturer_name": manufacturer_name or None,
        "device_kind_name": device_kind_name or None,
        "sales_name": sales_name or None,
        "material_no": material_no or None,
        "product_title_1": product_title_1 or None,
        "product_title_2": product_title_2 or None,
        "ean": normalized_ean or None,
        "description": description,
    }


def _import_asset_inputs_from_row(
    row: dict[str, str],
    *,
    product_field_map: dict[str, str],
) -> dict[str, object]:
    images: dict[int, str] = {}
    seen_urls: set[str] = set()
    for idx in range(1, PRODUCT_IMAGE_URL_MAX + 1):
        image_value = _csv_value(row, product_field_map.get(f"image_url_{idx}")).strip()
        if not image_value:
            continue
        normalized = _normalize_product_image_url(image_value) or _normalize_absolute_url(image_value) or image_value
        dedupe_key = str(normalized).strip().casefold()
        if not dedupe_key or dedupe_key in seen_urls:
            continue
        seen_urls.add(dedupe_key)
        images[idx] = normalized
    next_slot = 1
    for fallback_url in _catalog_csv_image_fallback_urls(row):
        dedupe_key = str(fallback_url).strip().casefold()
        if not dedupe_key or dedupe_key in seen_urls:
            continue
        while next_slot in images and next_slot <= PRODUCT_IMAGE_URL_MAX:
            next_slot += 1
        if next_slot > PRODUCT_IMAGE_URL_MAX:
            break
        images[next_slot] = fallback_url
        seen_urls.add(dedupe_key)
        next_slot += 1
    # Dokumente: Energielabel aus CSV (Datenblatt wird über die
    # Hersteller-Linklogik in _catalog_sync_product_assets gebaut)
    documents: dict[str, str] = {}
    for col in ("Energy_label", "ENERGY_LABEL"):
        raw_url = str(row.get(col) or "").strip()
        if raw_url and raw_url.lower().startswith("http"):
            normalized = _normalize_absolute_url(raw_url)
            if normalized:
                documents["energy_label"] = normalized
                break

    return {
        "images": images,
        "documents": documents,
    }


def _import_unknown_columns_from_row(
    row: dict[str, str],
    *,
    validated_mapping: dict[str, object],
    manufacturer_name: str | None = None,
    device_kind_name: str | None = None,
) -> dict[str, str]:
    mapped_columns: set[str] = set()
    product_field_map = dict(validated_mapping.get("product_field_map") or {})
    for source_column in product_field_map.values():
        clean = str(source_column or "").strip()
        if clean:
            mapped_columns.add(clean)
    ean_column = str(validated_mapping.get("ean_column") or "").strip()
    if ean_column:
        mapped_columns.add(ean_column)
    for source_column in list(validated_mapping.get("description_columns") or []):
        clean = str(source_column or "").strip()
        if clean:
            mapped_columns.add(clean)
    mapped_columns.update(
        _catalog_csv_extra_recognized_columns(
            row,
            manufacturer_name=manufacturer_name,
            device_kind_name=device_kind_name,
        )
    )
    out: dict[str, str] = {}
    for key, value in row.items():
        clean_key = str(key or "").strip()
        if not clean_key or clean_key in mapped_columns:
            continue
        clean_value = str(value or "").strip()
        if not clean_value:
            continue
        out[clean_key] = clean_value[:1000]
    return out


def _import_external_key_from_core(core: dict[str, object], *, line_no: int) -> str:
    for key in ("material_no", "ean", "sales_name", "product_title_1", "product_title_2"):
        value = str(core.get(key) or "").strip()
        if value:
            return value[:220]
    return f"Zeile {int(line_no)}"


def _catalog_import_execute_job(db: Session, job: ExternalSyncJob) -> dict[str, object]:
    progress = _sync_job_progress_payload(job.progress_json)
    draft_id = _to_int(progress.get("draft_id"), 0)
    import_run_id = _to_int(progress.get("import_run_id"), 0)
    if draft_id <= 0 or import_run_id <= 0:
        raise ValueError("Katalog-Importjob enthält keine gültigen Referenzen.")
    draft = db.get(ImportDraft, int(draft_id))
    import_run = db.get(ImportRun, int(import_run_id))
    if not draft or not import_run:
        raise ValueError("Importentwurf oder Importlauf wurde nicht gefunden.")

    columns, rows, csv_error = _import_read_draft_csv(draft)
    if csv_error:
        raise ValueError(csv_error)

    fallback_manufacturer = db.get(Manufacturer, int(draft.manufacturer_id or 0)) if draft.manufacturer_id else None
    fallback_kind = db.get(DeviceKind, int(draft.device_kind_id or 0)) if draft.device_kind_id else None
    mapping_data = _json_load_dict(draft.mapping_json)
    validated_mapping, errors = _import_validate_mapping(
        mapping_data,
        db=db,
        columns=columns,
        rows=rows,
        feature_defs_by_key={},
        fallback_manufacturer_id=int(draft.manufacturer_id or 0),
        fallback_kind_id=int(draft.device_kind_id or 0),
    )
    if errors["global_errors"] or errors["field_errors"]:
        draft.validation_errors_json = _json_dump(errors)
        draft.status = IMPORT_DRAFT_STATUS_FAILED
        draft.current_step = "map"
        draft.updated_at = _utcnow_naive()
        db.add(draft)
        db.flush()
        raise ValueError("Import-Mapping ist nicht mehr gültig. Bitte Zuordnung prüfen.")

    manufacturer = db.get(Manufacturer, int(validated_mapping.get("resolved_manufacturer_id") or 0)) if int(validated_mapping.get("resolved_manufacturer_id") or 0) > 0 else fallback_manufacturer
    selected_kind = db.get(DeviceKind, int(validated_mapping.get("resolved_device_kind_id") or 0)) if int(validated_mapping.get("resolved_device_kind_id") or 0) > 0 else fallback_kind
    if not manufacturer or not selected_kind:
        raise ValueError("Hersteller oder Geräteart konnten aus der CSV nicht eindeutig erkannt werden.")
    draft.manufacturer_id = int(manufacturer.id)
    draft.device_kind_id = int(selected_kind.id)
    # Feature-Definitionen seeden (legt fehlende automatisch an)
    try:
        seed_features_for_kind(db, selected_kind)
        db.flush()
    except Exception:
        pass
    feature_defs = _feature_defs_for_kind(db, int(selected_kind.id))
    feature_defs_by_key = {str(row.key or "").strip(): row for row in feature_defs}

    profile = _pick_import_profile(db, _to_int(validated_mapping.get("profile_id"), 0))
    validated_mapping, profile_dropped = _import_drop_mismatched_profile(
        validated_mapping,
        profile=profile,
        manufacturer=manufacturer,
        device_kind=selected_kind,
        profile_name_default=_catalog_import_profile_name_default(
            manufacturer=manufacturer,
            device_kind=selected_kind,
            filename=draft.filename_original,
        ),
    )
    if profile_dropped:
        draft.import_profile_id = None
        profile = None

    profile_created = False
    profile_name_default = _catalog_import_profile_name_default(
        manufacturer=manufacturer,
        device_kind=selected_kind,
        filename=draft.filename_original,
    )
    profile_name = str(validated_mapping.get("profile_name") or "").strip() or profile_name_default
    if not profile:
        profile = (
            db.query(ImportProfile)
            .filter(
                ImportProfile.manufacturer_id == int(manufacturer.id),
                ImportProfile.device_kind_id == int(selected_kind.id),
                func.lower(ImportProfile.name) == profile_name.lower(),
            )
            .one_or_none()
        )
    if not profile:
        profile = ImportProfile(
            manufacturer_id=int(manufacturer.id),
            device_kind_id=int(selected_kind.id),
            name=profile_name,
            delimiter=str(draft.delimiter or ";"),
            encoding=str(draft.encoding or "utf-8"),
            has_header=bool(draft.has_header),
            ean_column=str(validated_mapping.get("ean_column") or ""),
            description_columns_json=_json_dump(list(validated_mapping.get("description_columns") or [])),
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
        db.add(profile)
        db.flush()
        profile_created = True

    if int(import_run.profile_id or 0) != int(profile.id):
        import_run.profile_id = int(profile.id)
    if not import_run.started_at:
        import_run.started_at = _utcnow_naive()
    db.add(import_run)
    db.flush()

    product_field_map = validated_mapping.get("product_field_map") or {}
    ean_column = str(validated_mapping.get("ean_column") or "")
    description_columns = list(validated_mapping.get("description_columns") or [])
    import_plan = _catalog_csv_import_plan_ai(
        db,
        manufacturer=manufacturer,
        device_kind=selected_kind,
        columns=columns,
        rows=rows,
        attrs=[],
        mapping_data=validated_mapping,
    )
    planned_description_columns = [str(column).strip() for column in list(import_plan.get("description_columns") or []) if str(column).strip()]
    if planned_description_columns and not description_columns:
        description_columns = planned_description_columns
        validated_mapping["description_columns"] = description_columns
    manufacturer_lookup, kind_lookup = _catalog_import_scope_lookups(db)
    existing_product_maps = _catalog_import_existing_product_maps(
        db,
        manufacturer_id=int(manufacturer.id),
        device_kind_id=int(selected_kind.id),
        rows=rows,
        product_field_map=product_field_map,
        ean_column=ean_column,
        description_columns=description_columns,
    )
    selected_kind_name = str(selected_kind.name or "").strip()

    created = 0
    updated = 0
    skipped = 0
    errors_list: list[str] = []
    warnings_list: list[str] = []
    snapshot_count = 0
    attribute_update_count = 0
    commit_interval = max(1, int(CATALOG_IMPORT_PROGRESS_COMMIT_INTERVAL or 10))
    start_line = 2 if bool(draft.has_header) else 1
    total_rows = len(rows)
    _sync_job_update_progress(
        db,
        job,
        phase="CSV-Daten werden verarbeitet",
        phase_detail=f"{total_rows} Zeilen werden importiert.",
        total_count=total_rows,
        processed_count=0,
        success_count=0,
        error_count=0,
        current_item_label=str(draft.filename_original or import_run.filename or "CSV-Datei"),
        current_item_ref=f"Entwurf #{int(draft.id)}",
        result_url=f"/catalog/import/runs/{int(import_run.id)}",
        commit=True,
    )

    for line_no, row in enumerate(rows, start=start_line):
        try:
            core_values = _import_core_values_from_row(
                row,
                product_field_map=product_field_map,
                ean_column=ean_column,
                description_columns=description_columns,
                import_plan=import_plan,
            )
            external_key = _import_external_key_from_core(core_values, line_no=line_no)
            if not str(core_values.get("ean") or "").strip():
                skipped += 1
                errors_list.append(f"Zeile {line_no}: EAN fehlt oder ist ungültig.")
                continue
            if not any(str(core_values.get(key) or "").strip() for key in ("material_no", "sales_name", "product_title_1", "product_title_2")):
                skipped += 1
                errors_list.append(f"Zeile {line_no}: Kein Kernfeld für die Produktidentifikation vorhanden.")
                continue
            row_manufacturer, row_kind, scope_issues, _ = _import_resolve_scope_from_row(
                row,
                product_field_map=product_field_map,
                manufacturer_lookup=manufacturer_lookup,
                kind_lookup=kind_lookup,
                fallback_manufacturer=manufacturer,
                fallback_kind=selected_kind,
                db=db,
                auto_create=True,
            )
            if scope_issues:
                skipped += 1
                errors_list.append(f"Zeile {line_no}: {' '.join(scope_issues)}")
                continue
            if row_manufacturer is None or row_kind is None:
                skipped += 1
                errors_list.append(f"Zeile {line_no}: Hersteller oder Geräteart konnten nicht erkannt werden.")
                continue

            product: Product | None = None
            row_created = 0
            row_updated = 0
            row_snapshot_count = 0
            row_attribute_updates = 0
            row_warnings: list[str] = []
            with db.begin_nested():
                product = _catalog_import_lookup_existing_product(
                    product_maps=existing_product_maps,
                    manufacturer_id=int(row_manufacturer.id),
                    device_kind_id=int(row_kind.id),
                    core_values=core_values,
                )
                if product:
                    row_updated = 1
                else:
                    product = Product(active=True, track_mode="quantity", item_type="appliance")
                    row_created = 1

                product.ean = str(core_values.get("ean") or "").strip() or product.ean
                product.sales_name = str(core_values.get("sales_name") or "").strip() or product.sales_name
                product.material_no = str(core_values.get("material_no") or "").strip() or product.material_no
                product.manufacturer_name = None
                product.product_title_1 = str(core_values.get("product_title_1") or "").strip() or product.product_title_1
                product.product_title_2 = str(core_values.get("product_title_2") or "").strip() or product.product_title_2
                product.description = str(core_values.get("description") or "").strip() or product.description
                product.name = (
                    str(core_values.get("sales_name") or "").strip()
                    or str(core_values.get("product_title_1") or "").strip()
                    or str(core_values.get("product_title_2") or "").strip()
                    or product.name
                    or f"Produkt {external_key}"
                )
                kind_name_lower = str(row_kind.name or "").strip().lower()
                if kind_name_lower in ("zubehör", "zubehoer", "accessory", "accessories", "komplementäre produkte"):
                    product.item_type = "accessory"
                else:
                    product.item_type = "appliance"

                # Sub-Kategorie-Erkennung: Dampfbackofen aus Einbauherd/Backofen-CSV
                actual_kind = row_kind
                if kind_name_lower in ("einbauherd/backofen", "einbauherd", "backofen", "ovens"):
                    short_desc = str(core_values.get("sales_name") or "").lower()
                    long_desc_start = str(core_values.get("product_title_1") or str(core_values.get("description") or ""))[:300].lower()
                    combined_check = f"{short_desc} {long_desc_start}"
                    if any(w in combined_check for w in ("dampf", "steam", "combi steam")):
                        dampf_kind = db.query(DeviceKind).filter(DeviceKind.name == "Dampfbackofen").one_or_none()
                        if dampf_kind:
                            actual_kind = dampf_kind
                            seed_features_for_kind(db, dampf_kind)

                product.track_mode = "quantity"
                product.manufacturer_id = int(row_manufacturer.id)
                product.manufacturer = str(row_manufacturer.name or "").strip() or product.manufacturer
                product.device_kind_id = int(actual_kind.id)
                product.device_type_id = None
                product.area_id = None
                product.active = True
                product.source_kind = "csv"
                sale_price_cents = _catalog_csv_sale_price_cents_from_row(row)
                if sale_price_cents is not None:
                    product.sale_price_cents = int(sale_price_cents)
                    product.price_source = "csv"
                product.import_profile_id = int(profile.id) if profile else None
                product.last_import_run_id = int(import_run.id)
                product.last_imported_at = _utcnow_naive()

                asset_inputs = _import_asset_inputs_from_row(row, product_field_map=product_field_map)

                db.add(product)
                db.flush()

                try:
                    asset_summary = _catalog_sync_product_assets(
                        db,
                        product=product,
                        asset_inputs=asset_inputs,
                        manufacturer_row=row_manufacturer,
                        source_kind="csv",
                        eager_remote_image_download=False,
                        eager_remote_asset_types={"datasheet_pdf"},
                    )
                    for asset_failure in list(asset_summary.get("failures") or [])[:8]:
                        row_warnings.append(f"Zeile {line_no}: {asset_failure}")
                except Exception as asset_exc:
                    row_warnings.append(f"Zeile {line_no}: Assets konnten nicht vollständig verarbeitet werden ({asset_exc}).")
                _catalog_sync_legacy_image_fields(product, asset_inputs)

                # --- Feature-Extraktion aus CSV-Spalten ---
                try:
                    row_kind_name = str(actual_kind.name or selected_kind_name).strip()
                    row_feature_defs = feature_defs_by_key
                    if int(actual_kind.id) != int(selected_kind.id):
                        row_fds = _feature_defs_for_kind(db, int(actual_kind.id))
                        row_feature_defs = {str(fd.key or "").strip(): fd for fd in row_fds}
                    csv_feature_values = extract_features_from_csv_row(
                        row,
                        device_kind_name=row_kind_name,
                        feature_defs=row_feature_defs,
                    )
                    for fkey, fval in csv_feature_values.items():
                        fdef = row_feature_defs.get(fkey)
                        if fdef and fval:
                            try:
                                with db.begin_nested():
                                    _set_feature_value(
                                        db,
                                        product_id=int(product.id),
                                        feature_def=fdef,
                                        raw_value=str(fval),
                                        manufacturer_id=int(row_manufacturer.id),
                                        apply_rules=True,
                                        source_kind="csv",
                                    )
                            except Exception:
                                pass
                except Exception as feat_exc:
                    row_warnings.append(f"Zeile {line_no}: Feature-Extraktion: {feat_exc}")

                # --- Zubehör-Verlinkung aus ACCESSORIES-Spalte ---
                try:
                    acc_raw = str(row.get("ACCESSORIES") or "").strip()
                    if acc_raw and product:
                        for acc_code in acc_raw.split(","):
                            acc_code = acc_code.strip()
                            if not acc_code:
                                continue
                            acc_product = (
                                db.query(Product)
                                .filter(
                                    or_(
                                        Product.material_no == acc_code,
                                        Product.name == acc_code,
                                        Product.sales_name == acc_code,
                                    ),
                                    Product.active == True,
                                )
                                .first()
                            )
                            if acc_product and int(acc_product.id) != int(product.id):
                                existing_link = (
                                    db.query(ProductAccessoryLink.id)
                                    .filter(
                                        ProductAccessoryLink.product_id == int(product.id),
                                        ProductAccessoryLink.accessory_product_id == int(acc_product.id),
                                    )
                                    .first()
                                )
                                if not existing_link:
                                    db.add(ProductAccessoryLink(
                                        product_id=int(product.id),
                                        accessory_product_id=int(acc_product.id),
                                        source="csv",
                                        import_run_id=int(import_run.id),
                                    ))
                except Exception:
                    pass

                unknown_columns = _import_unknown_columns_from_row(
                    row,
                    validated_mapping=validated_mapping,
                    manufacturer_name=str(row_manufacturer.name or "").strip(),
                    device_kind_name=str(row_kind.name or "").strip(),
                )
                save_import_row_snapshot(
                    db,
                    import_run_id=int(import_run.id),
                    product_id=int(product.id),
                    manufacturer_id=int(row_manufacturer.id),
                    device_kind_id=int(row_kind.id),
                    external_key=external_key,
                    raw_row={str(key): str(value or "") for key, value in row.items()},
                    normalized_core={
                        key: value
                        for key, value in core_values.items()
                        if value not in (None, "")
                    },
                    detected_asset_urls={
                        "images": {str(key): str(value) for key, value in dict(asset_inputs.get("images") or {}).items()},
                        "documents": {str(key): str(value) for key, value in dict(asset_inputs.get("documents") or {}).items()},
                    },
                    unknown_columns=unknown_columns,
                )
                row_snapshot_count += 1

                _refresh_product_search_blob(db, product, kind_name=selected_kind_name)

            if product is not None:
                created += row_created
                updated += row_updated
                snapshot_count += row_snapshot_count
                attribute_update_count += row_attribute_updates
                warnings_list.extend(row_warnings)
                _catalog_import_register_product_maps(existing_product_maps, product=product)
        except Exception as exc:
            skipped += 1
            errors_list.append(f"Zeile {line_no}: {exc}")

        processed_count = line_no - start_line + 1
        if processed_count == 1 or processed_count % commit_interval == 0 or processed_count == total_rows:
            row_label = (
                _csv_value(row, product_field_map.get("sales_name"))
                or _csv_value(row, product_field_map.get("product_title_1"))
                or _csv_value(row, product_field_map.get("product_title_2"))
                or re.sub(r"\D+", "", _csv_value(row, ean_column))
                or f"Zeile {line_no}"
            )
            row_ref = re.sub(r"\D+", "", _csv_value(row, ean_column)) or f"Zeile {line_no}"
            _sync_job_update_progress(
                db,
                job,
                current_item_label=row_label,
                current_item_ref=row_ref,
                processed_count=processed_count,
                success_count=created + updated,
                error_count=len(errors_list),
                result_url=f"/catalog/import/runs/{int(import_run.id)}",
                commit=False,
            )
            db.commit()

    should_update_profile = bool(validated_mapping.get("update_profile", True)) or profile_created
    profile_updated = False
    new_profile_columns: list[str] = []
    if profile:
        existing_map_rows = db.query(ImportProfileMap).filter(ImportProfileMap.profile_id == int(profile.id)).all()
        existing_cols = {str(profile.ean_column or "").strip()}
        for existing_map in existing_map_rows:
            src = str(existing_map.source_column or "").strip()
            if src:
                existing_cols.add(src)
        selected_cols = {str(validated_mapping.get("ean_column") or "").strip()}
        for src in (validated_mapping.get("product_field_map") or {}).values():
            src_clean = str(src or "").strip()
            if src_clean:
                selected_cols.add(src_clean)
        new_profile_columns = sorted([col for col in selected_cols if col and col not in existing_cols])

        if should_update_profile:
            profile.delimiter = str(draft.delimiter or ";")
            profile.encoding = str(draft.encoding or "utf-8")
            profile.has_header = bool(draft.has_header)
            profile.ean_column = str(validated_mapping.get("ean_column") or profile.ean_column or "")
            profile.description_columns_json = _json_dump(list(validated_mapping.get("description_columns") or []))
            _touch_import_profile(db, profile)
            _save_import_profile_maps(
                db,
                profile=profile,
                product_field_map=validated_mapping.get("product_field_map") or {},
                feature_maps=validated_mapping.get("feature_maps") or [],
                accessory_map=validated_mapping.get("accessory_map") or {},
            )
            db.commit()
            profile_updated = True

    import_run.finished_at = _utcnow_naive()
    import_run.inserted_count = int(created)
    import_run.updated_count = int(updated)
    import_run.error_count = int(len(errors_list))
    import_run.log_text = _json_dump(
        {
            "draft_id": int(draft.id),
            "errors": errors_list[:120],
            "warnings": warnings_list[:120],
            "skipped_count": skipped,
            "profile_updated": profile_updated,
            "new_profile_columns": new_profile_columns,
            "snapshot_count": snapshot_count,
            "attribute_update_count": attribute_update_count,
            "description_columns_used": description_columns,
            "analysis_notes": list(import_plan.get("notes") or []),
        }
    )
    db.add(import_run)
    db.commit()

    has_warnings = bool(warnings_list)
    if len(errors_list) == 0 and not has_warnings:
        draft.status = IMPORT_DRAFT_STATUS_IMPORTED
    elif len(errors_list) == 0:
        draft.status = IMPORT_DRAFT_STATUS_WARNINGS
    else:
        draft.status = IMPORT_DRAFT_STATUS_FAILED
    draft.current_step = "run"
    draft.mapping_json = _json_dump(validated_mapping)
    draft.validation_errors_json = _json_dump({"global_errors": errors_list[:50], "field_errors": {}}) if errors_list else None
    draft.import_profile_id = int(profile.id) if profile else None
    draft.updated_at = _utcnow_naive()
    db.add(draft)
    _sync_job_update_progress(
        db,
        job,
        phase="CSV-Import abgeschlossen",
        phase_detail=f"Neu {created} | aktualisiert {updated} | Fehler {len(errors_list)}",
        total_count=total_rows,
        processed_count=total_rows,
        success_count=created + updated,
        error_count=len(errors_list),
        current_item_label="Fertig",
        current_item_ref=f"Importlauf #{int(import_run.id)}",
        result_url=f"/catalog/import/runs/{int(import_run.id)}",
        commit=False,
    )
    _finish_sync_job(
        db,
        job,
        status="done",
        log_text=f"CSV-Import abgeschlossen: neu={created}, aktualisiert={updated}, fehler={len(errors_list)}",
        result_url=f"/catalog/import/runs/{int(import_run.id)}",
    )
    return {
        "created": created,
        "updated": updated,
        "skipped": skipped,
        "errors": len(errors_list),
        "warnings": len(warnings_list),
        "attribute_updates": attribute_update_count,
        "import_run_id": int(import_run.id),
    }

def _guess_attribute_column(columns: list[str], attr: AttributeDef) -> str:
    candidates: list[str] = []
    name = str(attr.name or "").strip().lower()
    slug = str(attr.slug or "").strip().lower()
    if name:
        candidates.extend(
            [
                name,
                name.replace(" ", "_"),
                name.replace(" ", "-"),
                name.replace("ä", "ae").replace("ö", "oe").replace("ü", "ue").replace("ß", "ss"),
            ]
        )
    if slug:
        candidates.extend([slug, slug.replace("_", " "), slug.replace("-", " ")])
    ordered: list[str] = []
    seen: set[str] = set()
    for candidate in candidates:
        key = str(candidate or "").strip().lower()
        if not key or key in seen:
            continue
        seen.add(key)
        ordered.append(key)
    return _guess_column(columns, tuple(ordered))


def _enum_match_option(raw_value: str, options: list[str]) -> str | None:
    raw = str(raw_value or "").strip()
    if not raw:
        return None
    for option in options:
        if raw == option:
            return option
    lowered = raw.lower()
    for option in options:
        if lowered == str(option or "").strip().lower():
            return option
    return None


def _parse_import_attribute_value(attr: AttributeDef, raw_value: str) -> str:
    raw = str(raw_value or "").strip()
    if not raw:
        return ""
    label = str(attr.name or f"Attribut {int(attr.id)}")

    if attr.value_type == "bool":
        lowered = raw.lower()
        if lowered in ("1", "true", "ja", "j", "on", "x"):
            return "true"
        if lowered in ("0", "false", "nein", "n", "off"):
            return "false"
        raise ValueError(f"Ungültiger Ja/Nein-Wert bei Attribut '{label}': {raw}")

    if attr.value_type == "number":
        try:
            parsed = float(raw.replace(",", "."))
            return str(int(parsed)) if parsed.is_integer() else str(parsed)
        except Exception as exc:
            raise ValueError(f"Ungültige Zahl bei Attribut '{label}': {raw}") from exc

    if attr.value_type == "enum":
        options = _enum_options_from_json(attr.enum_options_json)
        if not options:
            return raw
        if bool(attr.is_multi):
            selected: list[str] = []
            for token in re.split(r"[,\n;|]+", raw):
                token_clean = str(token or "").strip()
                if not token_clean:
                    continue
                matched = _enum_match_option(token_clean, options)
                if not matched:
                    raise ValueError(f"Ungültiger Optionswert bei Attribut '{label}': {token_clean}")
                if matched not in selected:
                    selected.append(matched)
            return json.dumps(selected, ensure_ascii=False) if selected else ""
        matched = _enum_match_option(raw, options)
        if not matched:
            raise ValueError(f"Ungültiger Optionswert bei Attribut '{label}': {raw}")
        return matched

    return raw


