def _resolve_number_filter_selection(raw_value: str | None, available_values: list[float]) -> tuple[str, float] | None:
    raw = str(raw_value or "").strip()
    if not raw:
        return None
    try:
        parsed = float(raw.replace(",", "."))
    except Exception:
        return None
    for value in available_values:
        if abs(float(value) - parsed) < 1e-9:
            return (_format_feature_number_option(value), float(value))
    return None


def _products_list_attribute_rows(
    db: Session,
    *,
    kind_id: int,
    product_ids: list[int],
) -> dict[int, list[str]]:
    if not product_ids:
        return {}
    attrs = _applicable_attributes(db, int(kind_id), None)
    if not attrs:
        return {}
    out: dict[int, list[str]] = {}
    for attr in attrs:
        for product_id, value_text in (
            db.query(ProductAttributeValue.product_id, ProductAttributeValue.value_text)
            .filter(
                ProductAttributeValue.product_id.in_(product_ids),
                ProductAttributeValue.attribute_id == int(attr.id),
            )
            .all()
        ):
            value = _format_list_attribute_value(attr, str(value_text or "").strip())
            if not value:
                continue
            bucket = out.setdefault(int(product_id), [])
            label = str(attr.name or "Attribut").strip()
            entry = f"{label}: {value}"
            if entry not in bucket and len(bucket) < 3:
                bucket.append(entry)
    return out


def _parse_feature_raw_value(
    data_type: str,
    raw_value: str,
    feature_key: str | None = None,
) -> tuple[str | None, float | None, bool | None, str]:
    raw = str(raw_value or "").strip()
    if not raw:
        return None, None, None, ""
    dtype = str(data_type or "text").strip().lower()
    if dtype == "number":
        value_num = _parse_feature_number_value(raw, feature_key=feature_key)
        display = str(int(value_num)) if value_num.is_integer() else str(value_num)
        return None, value_num, None, _normalize_search_text(display)
    if dtype == "bool":
        lowered = raw.lower()
        if lowered in ("ja", "j", "true", "1", "x", "yes"):
            return None, None, True, "ja true 1"
        if lowered in ("nein", "n", "false", "0", "no"):
            return None, None, False, "nein false 0"
        raise ValueError(f"Ungültiger Bool-Wert: {raw}")
    value_text = raw
    return value_text, None, None, _normalize_search_text(value_text)


def _sanitize_feature_key(label: str) -> str:
    base = slugify(label or "")
    cleaned = re.sub(r"[^a-z0-9_-]+", "", base.replace(" ", "-").lower()).strip("-_")
    return cleaned or "merkmal"


def _sanitize_feature_canonical_key(value: str) -> str:
    base = slugify(value or "")
    cleaned = re.sub(r"[^a-z0-9_-]+", "", base.replace(" ", "-").lower()).strip("-_")
    return cleaned or "option"


def _normalize_feature_alias_text(value: str | None) -> str:
    return _normalize_search_text(value)


def _is_text_like_feature(data_type: str | None) -> bool:
    dtype = str(data_type or "text").strip().lower()
    return dtype not in ("number", "bool")


def _ensure_feature_option(
    db: Session,
    *,
    feature_def_id: int,
    canonical_key: str,
    label_de: str,
    sort_order: int = 0,
    active: bool = True,
) -> FeatureOption:
    key_clean = _sanitize_feature_canonical_key(canonical_key)
    row = (
        db.query(FeatureOption)
        .filter(
            FeatureOption.feature_def_id == int(feature_def_id),
            func.lower(FeatureOption.canonical_key) == key_clean.lower(),
        )
        .one_or_none()
    )
    if row:
        row.label_de = str(label_de or row.label_de or key_clean).strip() or key_clean
        row.sort_order = int(sort_order or 0)
        if active:
            row.active = True
        db.add(row)
        db.flush()
        return row

    row = FeatureOption(
        feature_def_id=int(feature_def_id),
        canonical_key=key_clean,
        label_de=str(label_de or key_clean).strip() or key_clean,
        active=bool(active),
        sort_order=int(sort_order or 0),
    )
    db.add(row)
    db.flush()
    return row


def _resolve_feature_option_for_raw(
    db: Session,
    *,
    feature_def: FeatureDef,
    raw_value: str,
    manufacturer_id: int | None = None,
) -> FeatureOption | None:
    raw_norm = _normalize_feature_alias_text(raw_value)
    if not raw_norm:
        return None
    fdef_id = int(feature_def.id or 0)
    if fdef_id <= 0:
        return None
    manufacturer_id_int = int(manufacturer_id or 0)

    alias_q = (
        db.query(FeatureOptionAlias, FeatureOption)
        .join(FeatureOption, FeatureOption.id == FeatureOptionAlias.option_id)
        .filter(
            FeatureOption.feature_def_id == fdef_id,
            FeatureOption.active == True,
            FeatureOptionAlias.alias_norm == raw_norm,
        )
    )
    if manufacturer_id_int > 0:
        alias_q = alias_q.filter(
            or_(
                FeatureOptionAlias.manufacturer_id == manufacturer_id_int,
                FeatureOptionAlias.manufacturer_id.is_(None),
            )
        ).order_by(
            case((FeatureOptionAlias.manufacturer_id == manufacturer_id_int, 0), else_=1),
            FeatureOptionAlias.priority.asc(),
            FeatureOption.sort_order.asc(),
            FeatureOption.id.asc(),
            FeatureOptionAlias.id.asc(),
        )
    else:
        alias_q = alias_q.filter(FeatureOptionAlias.manufacturer_id.is_(None)).order_by(
            FeatureOptionAlias.priority.asc(),
            FeatureOption.sort_order.asc(),
            FeatureOption.id.asc(),
            FeatureOptionAlias.id.asc(),
        )

    alias_match = alias_q.first()
    if alias_match:
        return alias_match[1]

    option_rows = (
        db.query(FeatureOption)
        .filter(FeatureOption.feature_def_id == fdef_id, FeatureOption.active == True)
        .order_by(FeatureOption.sort_order.asc(), FeatureOption.id.asc())
        .all()
    )
    for option in option_rows:
        if _normalize_feature_alias_text(option.label_de) == raw_norm:
            return option
        if _normalize_feature_alias_text(option.canonical_key) == raw_norm:
            return option
    return None


def _feature_value_row_has_payload(row: FeatureValue | None, data_type: str | None) -> bool:
    if not row:
        return False
    dtype = str(data_type or "text").strip().lower()
    if dtype == "number":
        return row.value_num is not None
    if dtype == "bool":
        return row.value_bool is not None
    if row.option_id:
        return True
    return bool(str(row.value_text or "").strip())


def _set_feature_row_option_value(
    row: FeatureValue,
    *,
    option: FeatureOption,
    raw_text: str | None = None,
) -> None:
    if raw_text is not None:
        row.raw_text = str(raw_text or "").strip() or None
    label = str(option.label_de or option.canonical_key or "").strip() or str(option.canonical_key or "").strip()
    row.option_id = int(option.id)
    row.value_text = label or None
    row.value_num = None
    row.value_bool = None
    row.value_norm = _normalize_search_text(label)


def _set_feature_row_bool_value(row: FeatureValue, *, value_bool: bool, raw_text: str | None = None) -> None:
    if raw_text is not None:
        row.raw_text = str(raw_text or "").strip() or None
    row.option_id = None
    row.value_text = None
    row.value_num = None
    row.value_bool = bool(value_bool)
    row.value_norm = "ja true 1" if bool(value_bool) else "nein false 0"


def _find_feature_def_by_key(db: Session, *, device_kind_id: int, key: str) -> FeatureDef | None:
    key_clean = _sanitize_feature_key(key)
    return (
        db.query(FeatureDef)
        .filter(
            FeatureDef.device_kind_id == int(device_kind_id),
            func.lower(FeatureDef.key) == key_clean.lower(),
        )
        .one_or_none()
    )


def _set_composite_feature_rules(
    db: Session,
    *,
    product_id: int,
    source_feature_def: FeatureDef,
    raw_value: str,
) -> None:
    raw_clean = str(raw_value or "").strip()
    raw_norm = _normalize_feature_alias_text(raw_clean)
    if not raw_norm:
        return
    device_kind_id = int(source_feature_def.device_kind_id or 0)
    if device_kind_id <= 0:
        return

    has_unterbau = "unterbau" in raw_norm
    has_freistehend = ("freisteh" in raw_norm) or ("stand" in raw_norm)

    if has_unterbau:
        underbau_def = _find_feature_def_by_key(db, device_kind_id=device_kind_id, key="unterbaufaehig")
        if not underbau_def:
            underbau_def = _upsert_feature_def(
                db,
                device_kind_id=device_kind_id,
                key="unterbaufaehig",
                label_de="Unterbaufähig",
                data_type="bool",
                filterable=True,
            )
        if str(underbau_def.data_type or "").strip().lower() == "bool":
            current = (
                db.query(FeatureValue)
                .filter(
                    FeatureValue.product_id == int(product_id),
                    FeatureValue.feature_def_id == int(underbau_def.id),
                )
                .one_or_none()
            )
            if int(underbau_def.id) == int(source_feature_def.id) or not _feature_value_row_has_payload(
                current, underbau_def.data_type
            ):
                target_row = current or FeatureValue(product_id=int(product_id), feature_def_id=int(underbau_def.id))
                _set_feature_row_bool_value(target_row, value_bool=True, raw_text=raw_clean)
                db.add(target_row)

    if has_freistehend:
        aufstellart_def = _find_feature_def_by_key(db, device_kind_id=device_kind_id, key="aufstellart")
        if not aufstellart_def:
            aufstellart_def = _upsert_feature_def(
                db,
                device_kind_id=device_kind_id,
                key="aufstellart",
                label_de="Aufstellart",
                data_type="text",
                filterable=True,
            )
        if _is_text_like_feature(aufstellart_def.data_type):
            freistehend_option = _ensure_feature_option(
                db,
                feature_def_id=int(aufstellart_def.id),
                canonical_key="freistehend",
                label_de="freistehend",
                sort_order=10,
                active=True,
            )
            current = (
                db.query(FeatureValue)
                .filter(
                    FeatureValue.product_id == int(product_id),
                    FeatureValue.feature_def_id == int(aufstellart_def.id),
                )
                .one_or_none()
            )
            if int(aufstellart_def.id) == int(source_feature_def.id) or not _feature_value_row_has_payload(
                current, aufstellart_def.data_type
            ):
                target_row = current or FeatureValue(product_id=int(product_id), feature_def_id=int(aufstellart_def.id))
                _set_feature_row_option_value(target_row, option=freistehend_option, raw_text=raw_clean)
                db.add(target_row)


def _apply_alias_to_existing_feature_values(
    db: Session,
    *,
    feature_def: FeatureDef,
    option: FeatureOption,
    alias_norm: str,
    manufacturer_id: int | None = None,
    only_unmapped: bool = True,
) -> int:
    normalized_alias = _normalize_feature_alias_text(alias_norm)
    if not normalized_alias:
        return 0
    query = (
        db.query(FeatureValue)
        .join(Product, Product.id == FeatureValue.product_id)
        .filter(
            Product.device_kind_id == int(feature_def.device_kind_id or 0),
            FeatureValue.feature_def_id == int(feature_def.id),
            FeatureValue.raw_text.isnot(None),
            func.length(func.trim(FeatureValue.raw_text)) > 0,
        )
    )
    if only_unmapped:
        query = query.filter(FeatureValue.option_id.is_(None))
    manufacturer_id_int = int(manufacturer_id or 0)
    if manufacturer_id_int > 0:
        query = query.filter(Product.manufacturer_id == manufacturer_id_int)

    updated = 0
    for row in query.all():
        if _normalize_feature_alias_text(row.raw_text) != normalized_alias:
            continue
        _set_feature_row_option_value(row, option=option)
        db.add(row)
        updated += 1
    return updated


def _upsert_feature_def(
    db: Session,
    *,
    device_kind_id: int,
    key: str,
    label_de: str,
    data_type: str,
    filterable: bool = True,
) -> FeatureDef:
    key_clean = _sanitize_feature_key(key)
    row = (
        db.query(FeatureDef)
        .filter(FeatureDef.device_kind_id == int(device_kind_id), func.lower(FeatureDef.key) == key_clean.lower())
        .one_or_none()
    )
    if row:
        row.label_de = str(label_de or row.label_de or key_clean).strip() or key_clean
        if data_type in ALLOWED_FEATURE_DATA_TYPES:
            row.data_type = data_type
        row.filterable = bool(filterable)
        db.add(row)
        db.flush()
        return row
    row = FeatureDef(
        device_kind_id=int(device_kind_id),
        key=key_clean,
        label_de=str(label_de or key_clean).strip() or key_clean,
        data_type=data_type if data_type in ALLOWED_FEATURE_DATA_TYPES else "text",
        filterable=bool(filterable),
    )
    db.add(row)
    db.flush()
    return row


def _set_feature_value(
    db: Session,
    *,
    product_id: int,
    feature_def: FeatureDef,
    raw_value: str,
    manufacturer_id: int | None = None,
    apply_rules: bool = True,
    source_kind: str | None = None,
) -> None:
    existing = (
        db.query(FeatureValue)
        .filter(FeatureValue.product_id == int(product_id), FeatureValue.feature_def_id == int(feature_def.id))
        .one_or_none()
    )

    # Quellen-Priorität: CSV > PDF. PDF darf CSV-Werte nicht überschreiben.
    if existing and source_kind == "pdf" and getattr(existing, "source_kind", None) == "csv":
        return

    data_type = str(feature_def.data_type or "text").strip().lower()
    raw_clean = str(raw_value or "").strip()
    try:
        value_text, value_num, value_bool, value_norm = _parse_feature_raw_value(
            data_type,
            raw_clean,
            feature_key=str(feature_def.key or ""),
        )
    except ValueError:
        if existing:
            db.delete(existing)
        raise

    has_value = bool(value_norm)
    if not has_value:
        if existing:
            db.delete(existing)
        return

    row = existing or FeatureValue(product_id=int(product_id), feature_def_id=int(feature_def.id))
    row.raw_text = raw_clean or None
    if source_kind:
        row.source_kind = source_kind

    if _is_text_like_feature(data_type):
        option = _resolve_feature_option_for_raw(
            db,
            feature_def=feature_def,
            raw_value=raw_clean,
            manufacturer_id=manufacturer_id,
        )
        if option:
            _set_feature_row_option_value(row, option=option, raw_text=raw_clean)
        else:
            row.option_id = None
            row.value_text = value_text
            row.value_num = None
            row.value_bool = None
            row.value_norm = value_norm
    else:
        row.option_id = None
        row.value_text = value_text
        row.value_num = value_num
        row.value_bool = value_bool
        row.value_norm = value_norm
    db.add(row)
    if apply_rules and raw_clean and _is_text_like_feature(data_type):
        _set_composite_feature_rules(
            db,
            product_id=int(product_id),
            source_feature_def=feature_def,
            raw_value=raw_clean,
        )


def _refresh_product_search_blob(db: Session, product: Product, *, kind_name: str = "") -> None:
    kind_label = str(kind_name or "").strip()
    if not kind_label and product.device_kind_id:
        kind_row = db.get(DeviceKind, int(product.device_kind_id))
        if kind_row:
            kind_label = str(kind_row.name or "").strip()

    raw_parts = [
        product.name,
        product.sales_name,
        product.product_title_1,
        product.product_title_2,
        product.ean,
        product.material_no,
        product.description,
        product.manufacturer,
        product.manufacturer_name,
        kind_label,
    ]

    feature_rows = (
        db.query(
            FeatureDef.data_type,
            func.coalesce(FeatureOption.label_de, FeatureValue.value_text),
            FeatureValue.value_num,
            FeatureValue.value_bool,
        )
        .join(FeatureValue, FeatureValue.feature_def_id == FeatureDef.id)
        .outerjoin(FeatureOption, FeatureOption.id == FeatureValue.option_id)
        .filter(FeatureValue.product_id == int(product.id))
        .all()
    )
    for data_type, value_text, value_num, value_bool in feature_rows:
        display_value = _feature_value_display_value(str(data_type or "text"), value_text, value_num, value_bool)
        if display_value:
            raw_parts.append(display_value)

    legacy_attr_rows = (
        db.query(AttributeDef.name, ProductAttributeValue.value_text)
        .join(ProductAttributeValue, ProductAttributeValue.attribute_id == AttributeDef.id)
        .filter(ProductAttributeValue.product_id == int(product.id))
        .all()
    )
    for attr_name, value_text in legacy_attr_rows:
        if value_text:
            raw_parts.append(f"{str(attr_name or '').strip()} {str(value_text)}")
            raw_parts.append(str(value_text))

    latest_snapshot = (
        db.query(ImportRowSnapshot)
        .filter(ImportRowSnapshot.product_id == int(product.id))
        .order_by(ImportRowSnapshot.id.desc())
        .first()
    )
    if latest_snapshot is not None:
        unknown_columns = _json_load_dict(latest_snapshot.unknown_columns_json)
        for key, value in unknown_columns.items():
            if not str(value or "").strip():
                continue
            raw_parts.append(f"{str(key or '').strip()} {str(value or '').strip()}")

    normalized_parts: list[str] = []
    for part in _import_unique_texts([str(value or "") for value in raw_parts if str(value or "").strip()]):
        normalized = _normalize_search_text(part)
        if normalized:
            normalized_parts.append(normalized)
    blob = " ".join(normalized_parts).strip()
    product.search_blob = blob or None
    db.add(product)


def _reindex_search_blobs(db: Session) -> None:
    products = db.query(Product).all()
    if not products:
        return
    for product in products:
        _refresh_product_search_blob(db, product)
    db.commit()


def _reindex_missing_search_blobs(db: Session, batch_size: int = 500) -> int:
    total = 0
    limit = max(1, int(batch_size or 500))
    while True:
        products = (
            db.query(Product)
            .filter(
                or_(
                    Product.search_blob.is_(None),
                    func.trim(func.coalesce(Product.search_blob, "")) == "",
                )
            )
            .limit(limit)
            .all()
        )
        if not products:
            break
        for product in products:
            _refresh_product_search_blob(db, product)
        db.commit()
        total += len(products)
        if len(products) < limit:
            break
    return total


def build_product_search_filter(q: str, include_attribute_values: bool = False):
    _ = include_attribute_values
    q = (q or "").strip()
    if not q:
        return None

    q_norm = _normalize_search_text(q)
    q_compact = _compact_search_text(q)
    conds = []
    if q_norm:
        conds.append(func.lower(func.coalesce(Product.search_blob, "")).like(f"%{q_norm}%"))
    if q_compact:
        conds.append(func.replace(func.lower(func.coalesce(Product.search_blob, "")), " ", "").like(f"%{q_compact}%"))
    if not conds:
        return None
    return or_(*conds)


def _parse_active(
    raw: str,
    default_value: bool = True,
    true_values: set[str] | None = None,
    false_values: set[str] | None = None,
) -> bool:
    v = (raw or "").strip().lower()
    if not v:
        return default_value
    if true_values and v in true_values:
        return True
    if false_values and v in false_values:
        return False
    if v in ("ja", "j", "true", "1", "aktiv", "x"):
        return True
    if v in ("nein", "n", "false", "0", "inaktiv"):
        return False
    return default_value


def _find_product_by_sku_or_ean(db: Session, sku: str | None, ean: str | None) -> Product | None:
    if sku:
        p = db.query(Product).filter(func.lower(Product.sku) == sku.lower()).one_or_none()
        if p:
            return p
    if ean:
        p = db.query(Product).filter(Product.ean == ean).one_or_none()
        if p:
            return p
    return None


def _resolve_catalog_refs(
    db: Session,
    area_name: str,
    kind_name: str,
    type_name: str,
    auto_create: bool,
    fallback_area: Area | None = None,
    fallback_kind: DeviceKind | None = None,
    fallback_type: DeviceType | None = None,
) -> tuple[Area | None, DeviceKind | None, DeviceType | None]:
    area_name = area_name.strip()
    kind_name = kind_name.strip()
    type_name = type_name.strip()

    area: Area | None = None
    kind: DeviceKind | None = None
    dtype: DeviceType | None = None

    def _find_area(name: str) -> Area | None:
        return db.query(Area).filter(func.lower(Area.name) == name.lower()).one_or_none()

    def _find_kind(area_id: int, name: str) -> DeviceKind | None:
        return db.query(DeviceKind).filter(DeviceKind.area_id == area_id, func.lower(DeviceKind.name) == name.lower()).one_or_none()

    def _find_type(kind_id: int, name: str) -> DeviceType | None:
        return db.query(DeviceType).filter(DeviceType.device_kind_id == kind_id, func.lower(DeviceType.name) == name.lower()).one_or_none()

    if area_name:
        area = _find_area(area_name)
        if not area and fallback_area:
            area = fallback_area
        if not area and auto_create:
            area = Area(name=area_name)
            db.add(area)
            db.flush()
        if not area:
            raise ValueError(f"Bereich nicht gefunden: {area_name}")
    elif fallback_area:
        area = fallback_area

    if kind_name:
        if not area:
            if fallback_kind:
                area = db.get(Area, int(fallback_kind.area_id or 0))
            if not area:
                if not auto_create:
                    raise ValueError("Geräteart ohne gültigen Bereich.")
                area = _find_area("Unbekannt")
                if not area:
                    area = Area(name="Unbekannt")
                    db.add(area)
                    db.flush()
        kind = _find_kind(area.id, kind_name)
        if not kind and fallback_kind:
            kind = fallback_kind
            area = db.get(Area, int(kind.area_id or 0)) if kind and kind.area_id else area
        if not kind and auto_create:
            kind = DeviceKind(area_id=area.id, name=kind_name)
            db.add(kind)
            db.flush()
        if not kind:
            raise ValueError(f"Geräteart nicht gefunden: {kind_name}")
    elif fallback_kind:
        kind = fallback_kind
        if not area:
            area = db.get(Area, int(kind.area_id or 0))

    if type_name:
        if not kind:
            if fallback_type:
                kind = db.get(DeviceKind, int(fallback_type.device_kind_id or 0))
                if kind and not area:
                    area = db.get(Area, int(kind.area_id or 0))
            if not kind:
                if not auto_create:
                    raise ValueError("Gerätetyp ohne gültige Geräteart.")
                if not area:
                    area = _find_area("Unbekannt")
                    if not area:
                        area = Area(name="Unbekannt")
                        db.add(area)
                        db.flush()
                kind = _find_kind(area.id, "Unbekannt")
                if not kind:
                    kind = DeviceKind(area_id=area.id, name="Unbekannt")
                    db.add(kind)
                    db.flush()
        dtype = _find_type(kind.id, type_name)
        if not dtype and fallback_type:
            dtype = fallback_type
            kind = db.get(DeviceKind, int(dtype.device_kind_id or 0)) if dtype and dtype.device_kind_id else kind
            if kind and not area:
                area = db.get(Area, int(kind.area_id or 0))
        if not dtype and auto_create:
            dtype = DeviceType(device_kind_id=kind.id, name=type_name)
            db.add(dtype)
            db.flush()
        if not dtype:
            raise ValueError(f"Gerätetyp nicht gefunden: {type_name}")
    elif fallback_type:
        dtype = fallback_type
        if not kind:
            kind = db.get(DeviceKind, int(dtype.device_kind_id or 0))
        if kind and not area:
            area = db.get(Area, int(kind.area_id or 0))

    if kind and area and int(kind.area_id or 0) != int(area.id):
        raise ValueError("Geräteart passt nicht zum Bereich.")
    if dtype and kind and int(dtype.device_kind_id or 0) != int(kind.id):
        raise ValueError("Gerätetyp passt nicht zur Geräteart.")

    return area, kind, dtype


def _applicable_attributes(db: Session, device_kind_id: int | None, device_type_id: int | None) -> list[AttributeDef]:
    if not device_kind_id and not device_type_id:
        return []
    q = db.query(AttributeDef).join(AttributeScope, AttributeScope.attribute_id == AttributeDef.id)
    conds = []
    if device_type_id:
        conds.append(AttributeScope.device_type_id == device_type_id)
    if device_kind_id:
        conds.append(AttributeScope.device_kind_id == device_kind_id)
    if not conds:
        return []
    return q.filter(or_(*conds)).distinct().order_by(AttributeDef.group_name.asc(), AttributeDef.name.asc()).all()


def _parse_product_attribute_values(form, attrs: list[AttributeDef]) -> tuple[dict[int, str], list[str]]:
    values: dict[int, str] = {}
    errors: list[str] = []

    for attr in attrs:
        key = f"attr_{attr.id}"
        label = attr.name
        value_text = ""

        if attr.value_type == "bool":
            raw_bool = (form.get(key) or "").strip().lower()
            if raw_bool in ("on", "true", "1", "ja", "j"):
                value_text = "true"
            elif raw_bool in ("false", "0", "nein", "n"):
                value_text = "false"
            else:
                if attr.is_required:
                    errors.append(f"Pflichtattribut fehlt: {label}")
                value_text = ""
        elif attr.value_type == "number":
            raw = (form.get(key) or "").strip()
            if not raw:
                if attr.is_required:
                    errors.append(f"Pflichtattribut fehlt: {label}")
                value_text = ""
            else:
                try:
                    val = float(raw.replace(",", "."))
                    value_text = str(int(val)) if val.is_integer() else str(val)
                except Exception:
                    errors.append(f"Ungültige Zahl bei Attribut: {label}")
                    value_text = ""
        elif attr.value_type == "enum":
            options = _enum_options_from_json(attr.enum_options_json)
            if attr.is_multi:
                raw_values = [str(v).strip() for v in form.getlist(key)]
                selected = [v for v in raw_values if v]
                invalid = [v for v in selected if v not in options]
                if invalid:
                    errors.append(f"Ungültige Auswahl bei Attribut: {label}")
                if attr.is_required and not selected:
                    errors.append(f"Pflichtattribut fehlt: {label}")
                value_text = json.dumps(selected, ensure_ascii=False) if selected else ""
            else:
                raw = (form.get(key) or "").strip()
                if attr.is_required and not raw:
                    errors.append(f"Pflichtattribut fehlt: {label}")
                if raw and raw not in options:
                    errors.append(f"Ungültige Auswahl bei Attribut: {label}")
                value_text = raw
        else:
            raw = (form.get(key) or "").strip()
            if attr.is_required and not raw:
                errors.append(f"Pflichtattribut fehlt: {label}")
            value_text = raw

        values[attr.id] = value_text

    return values, errors


def _format_list_attribute_value(attr: AttributeDef, raw_value: str | None) -> str:
    raw = str(raw_value or "").strip()
    if not raw:
        return ""
    if attr.value_type == "bool":
        lowered = raw.lower()
        if lowered == "true":
            return "Ja"
        if lowered == "false":
            return "Nein"
    if attr.value_type == "enum" and bool(attr.is_multi):
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, list):
                items = [str(v).strip() for v in parsed if str(v).strip()]
                return ", ".join(items)
        except Exception:
            return raw
    return raw


def _flush_description_text_block(out: list[dict[str, object]], lines: list[str]) -> None:
    if not lines:
        return
    text = " ".join(str(line or "").strip() for line in lines if str(line or "").strip()).strip()
    lines.clear()
    if text:
        out.append({"kind": "text", "text": text})


def _flush_description_list_block(out: list[dict[str, object]], items: list[str]) -> None:
    if not items:
        return
    cleaned = [str(item or "").strip() for item in items if str(item or "").strip()]
    items.clear()
    if cleaned:
        out.append({"kind": "list", "items": cleaned})


def _flush_description_kv_block(out: list[dict[str, object]], rows: list[dict[str, str]]) -> None:
    if not rows:
        return
    cleaned: list[dict[str, str]] = []
    for row in rows:
        label = str(row.get("label") or "").strip()
        value = str(row.get("value") or "").strip()
        if not label or not value:
            continue
        cleaned.append({"label": label, "value": value})
    rows.clear()
    if cleaned:
        out.append({"kind": "kv", "rows": cleaned})


