def _catalog_guess_asset_rule_template(
    source_url: str | None,
    *,
    product: Product,
) -> tuple[str, list[str]]:
    template = str(source_url or "").strip()
    if not template:
        return "", []
    replacements: list[tuple[str, str]] = []
    for field_name, raw_value in (
        ("ean", product.ean),
        ("material_no", product.material_no),
        ("sales_name", product.sales_name),
        ("title_1", product.product_title_1),
        ("title_2", product.product_title_2),
    ):
        clean = str(raw_value or "").strip()
        if len(clean) < 4:
            continue
        variants = [quote(clean, safe=""), clean]
        variants = sorted({value for value in variants if value}, key=len, reverse=True)
        for variant in variants:
            if variant in template:
                replacements.append((field_name, variant))
                break
    replacements.sort(key=lambda row: len(row[1]), reverse=True)
    used_fields: list[str] = []
    for field_name, variant in replacements:
        placeholder = "{{ " + field_name + " }}"
        if variant not in template:
            continue
        template = template.replace(variant, placeholder)
        if field_name not in used_fields:
            used_fields.append(field_name)
    if "{{ " not in template:
        return "", []
    return template, used_fields


def _catalog_observed_asset_rule_candidates(
    db: Session,
    *,
    manufacturer_id: int = 0,
    sample_limit: int = 4000,
    result_limit: int = 24,
) -> list[dict[str, object]]:
    query = (
        db.query(ProductAsset, Product, Manufacturer.name)
        .join(Product, Product.id == ProductAsset.product_id)
        .outerjoin(Manufacturer, Manufacturer.id == Product.manufacturer_id)
        .filter(
            ProductAsset.source_url_raw.isnot(None),
            func.length(func.trim(func.coalesce(ProductAsset.source_url_raw, ""))) > 0,
        )
        .order_by(ProductAsset.updated_at.desc(), ProductAsset.id.desc())
    )
    if int(manufacturer_id or 0) > 0:
        query = query.filter(Product.manufacturer_id == int(manufacturer_id))
    rows = query.limit(int(sample_limit)).all()
    grouped: dict[tuple[int, str, str], dict[str, object]] = {}
    for asset, product, manufacturer_name in rows:
        template, source_fields = _catalog_guess_asset_rule_template(
            str(getattr(asset, "source_url_raw", "") or ""),
            product=product,
        )
        if not template or not source_fields:
            continue
        manufacturer_key = int(getattr(product, "manufacturer_id", 0) or 0)
        asset_type = str(getattr(asset, "asset_type", "") or "").strip().lower() or "other"
        group_key = (manufacturer_key, asset_type, template)
        row = grouped.get(group_key)
        if row is None:
            row = {
                "manufacturer_id": manufacturer_key,
                "manufacturer_name": str(manufacturer_name or "").strip() or "Global",
                "asset_type": asset_type,
                "url_template": template,
                "source_fields": list(source_fields),
                "count": 0,
                "example_url": str(getattr(asset, "source_url_raw", "") or "").strip(),
            }
            grouped[group_key] = row
        row["count"] = int(row.get("count") or 0) + 1
    candidates = [row for row in grouped.values() if int(row.get("count") or 0) >= 2]
    candidates.sort(
        key=lambda row: (
            -int(row.get("count") or 0),
            str(row.get("manufacturer_name") or "").lower(),
            str(row.get("asset_type") or "").lower(),
            str(row.get("url_template") or "").lower(),
        )
    )
    return candidates[: int(result_limit)]


