@app.post("/catalog/import/{draft_id}/map", response_class=HTMLResponse)
async def catalog_import_map_post(draft_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    draft = db.get(ImportDraft, int(draft_id))
    if not draft:
        raise HTTPException(status_code=404)
    columns, rows, csv_error = _import_read_draft_csv(draft)
    if csv_error:
        _flash(request, csv_error, "error")
        return RedirectResponse("/catalog/import", status_code=302)

    manufacturer = db.get(Manufacturer, int(draft.manufacturer_id or 0)) if draft.manufacturer_id else None
    selected_kind = db.get(DeviceKind, int(draft.device_kind_id or 0)) if draft.device_kind_id else None
    feature_defs_by_key: dict[str, FeatureDef] = {}
    profile_name_default = _catalog_import_profile_name_default(
        manufacturer=manufacturer,
        device_kind=selected_kind,
        filename=draft.filename_original,
    )
    form = await request.form()
    mapping_from_form = _import_parse_mapping_form(
        form,
        columns=columns,
        feature_defs_by_key=feature_defs_by_key,
        profile_name_default=profile_name_default,
    )

    draft.mapping_json = _json_dump(mapping_from_form)
    draft.import_profile_id = int(mapping_from_form.get("profile_id") or 0) or None
    draft.current_step = "map"
    draft.status = IMPORT_DRAFT_STATUS_MAPPING
    draft.updated_at = _utcnow_naive()
    db.add(draft)
    db.commit()

    validated_mapping, errors = _import_validate_mapping(
        mapping_from_form,
        db=db,
        columns=columns,
        rows=rows,
        feature_defs_by_key=feature_defs_by_key,
        fallback_manufacturer_id=int(draft.manufacturer_id or 0),
        fallback_kind_id=int(draft.device_kind_id or 0),
    )
    if errors["global_errors"] or errors["field_errors"]:
        draft.mapping_json = _json_dump(validated_mapping)
        draft.validation_errors_json = _json_dump(errors)
        draft.status = IMPORT_DRAFT_STATUS_FAILED
        draft.current_step = "map"
        draft.updated_at = _utcnow_naive()
        draft.manufacturer_id = int(validated_mapping.get("resolved_manufacturer_id") or 0) or None
        draft.device_kind_id = int(validated_mapping.get("resolved_device_kind_id") or 0) or None
        db.add(draft)
        db.commit()
        return _import_map_page_response(
            request,
            db=db,
            user=user,
            draft=draft,
            columns=columns,
            rows=rows,
            mapping_data=validated_mapping,
            errors=errors,
        )

    resolved_manufacturer = db.get(Manufacturer, int(validated_mapping.get("resolved_manufacturer_id") or 0)) if int(validated_mapping.get("resolved_manufacturer_id") or 0) > 0 else None
    resolved_kind = db.get(DeviceKind, int(validated_mapping.get("resolved_device_kind_id") or 0)) if int(validated_mapping.get("resolved_device_kind_id") or 0) > 0 else None
    resolved_profile_name_default = _catalog_import_profile_name_default(
        manufacturer=resolved_manufacturer,
        device_kind=resolved_kind,
        filename=draft.filename_original,
    )
    validated_mapping, profile_dropped = _import_drop_mismatched_profile(
        validated_mapping,
        profile=_pick_import_profile(db, _to_int(validated_mapping.get("profile_id"), 0)),
        manufacturer=resolved_manufacturer,
        device_kind=resolved_kind,
        profile_name_default=resolved_profile_name_default,
    )
    if profile_dropped:
        _flash(request, "Ein unpassendes Altprofil wurde verworfen. Der Import läuft mit deinem aktuellen Mapping weiter.", "warn")

    draft.mapping_json = _json_dump(validated_mapping)
    draft.validation_errors_json = None
    draft.status = IMPORT_DRAFT_STATUS_VALIDATED
    draft.current_step = "run"
    draft.updated_at = _utcnow_naive()
    draft.import_profile_id = int(validated_mapping.get("profile_id") or 0) or None
    draft.manufacturer_id = int(validated_mapping.get("resolved_manufacturer_id") or 0) or None
    draft.device_kind_id = int(validated_mapping.get("resolved_device_kind_id") or 0) or None
    db.add(draft)
    db.commit()
    return RedirectResponse(f"/catalog/import/{int(draft.id)}/run", status_code=302)


@app.get("/catalog/import/{draft_id}/run", response_class=HTMLResponse)
def catalog_import_run_get(draft_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    draft = db.get(ImportDraft, int(draft_id))
    if not draft:
        raise HTTPException(status_code=404)
    job_key = _catalog_import_run_job_key(int(draft.id))
    active_job = _sync_job_existing_active(db, job_key=job_key)
    columns, rows, csv_error = _import_read_draft_csv(draft)
    if csv_error:
        _flash(request, csv_error, "error")
        return RedirectResponse("/catalog/import", status_code=302)

    manufacturer = db.get(Manufacturer, int(draft.manufacturer_id or 0)) if draft.manufacturer_id else None
    selected_kind = db.get(DeviceKind, int(draft.device_kind_id or 0)) if draft.device_kind_id else None
    feature_defs_by_key: dict[str, FeatureDef] = {}
    profile_name_default = _catalog_import_profile_name_default(
        manufacturer=manufacturer,
        device_kind=selected_kind,
        filename=draft.filename_original,
    )
    mapping_data = _json_load_dict(draft.mapping_json)
    validated_mapping, errors = _import_validate_mapping(
        mapping_data,
        db=db,
        columns=columns,
        rows=rows,
        feature_defs_by_key=feature_defs_by_key,
        fallback_manufacturer_id=int(draft.manufacturer_id or 0),
        fallback_kind_id=int(draft.device_kind_id or 0),
    )
    if errors["global_errors"] or errors["field_errors"]:
        if active_job is None:
            draft.validation_errors_json = _json_dump(errors)
            draft.status = IMPORT_DRAFT_STATUS_FAILED
            draft.current_step = "map"
            draft.updated_at = _utcnow_naive()
            draft.manufacturer_id = int(validated_mapping.get("resolved_manufacturer_id") or 0) or None
            draft.device_kind_id = int(validated_mapping.get("resolved_device_kind_id") or 0) or None
            db.add(draft)
            db.commit()
        return _import_map_page_response(
            request,
            db=db,
            user=user,
            draft=draft,
            columns=columns,
            rows=rows,
            mapping_data=validated_mapping,
            errors=errors,
        )

    resolved_manufacturer = db.get(Manufacturer, int(validated_mapping.get("resolved_manufacturer_id") or 0)) if int(validated_mapping.get("resolved_manufacturer_id") or 0) > 0 else None
    resolved_kind = db.get(DeviceKind, int(validated_mapping.get("resolved_device_kind_id") or 0)) if int(validated_mapping.get("resolved_device_kind_id") or 0) > 0 else None
    resolved_profile_name_default = _catalog_import_profile_name_default(
        manufacturer=resolved_manufacturer,
        device_kind=resolved_kind,
        filename=draft.filename_original,
    )
    validated_mapping, profile_dropped = _import_drop_mismatched_profile(
        validated_mapping,
        profile=_pick_import_profile(db, _to_int(validated_mapping.get("profile_id"), _to_int(draft.import_profile_id, 0))),
        manufacturer=resolved_manufacturer,
        device_kind=resolved_kind,
        profile_name_default=resolved_profile_name_default,
    )
    if profile_dropped:
        if active_job is None:
            draft.import_profile_id = None

    if active_job is None:
        draft.mapping_json = _json_dump(validated_mapping)
        draft.validation_errors_json = None
        draft.status = IMPORT_DRAFT_STATUS_VALIDATED
        draft.current_step = "run"
        draft.updated_at = _utcnow_naive()
        draft.manufacturer_id = int(validated_mapping.get("resolved_manufacturer_id") or 0) or None
        draft.device_kind_id = int(validated_mapping.get("resolved_device_kind_id") or 0) or None
        db.add(draft)
        db.commit()
    manufacturer = db.get(Manufacturer, int(validated_mapping.get("resolved_manufacturer_id") or 0)) if int(validated_mapping.get("resolved_manufacturer_id") or 0) > 0 else manufacturer
    selected_kind = db.get(DeviceKind, int(validated_mapping.get("resolved_device_kind_id") or 0)) if int(validated_mapping.get("resolved_device_kind_id") or 0) > 0 else selected_kind

    profile_id = _to_int(validated_mapping.get("profile_id"), _to_int(draft.import_profile_id, 0))
    active_profile = _pick_import_profile(db, profile_id)
    unmapped_columns = _import_profile_unmapped_columns(db, profile_id=profile_id, columns=columns) if active_profile else []
    product_labels = {
        "manufacturer_name": "Hersteller",
        "device_kind_name": "Geräteart",
        "sales_name": "Verkaufsbezeichnung",
        "material_no": "Materialnummer",
        "product_title_1": "Produkttitel 1",
        "product_title_2": "Produkttitel 2",
    }
    for idx in range(1, PRODUCT_IMAGE_URL_MAX + 1):
        product_labels[f"image_url_{idx}"] = f"Bild {idx}"
    mapped_product_fields = []
    product_field_map = validated_mapping.get("product_field_map") or {}
    for key, label in product_labels.items():
        src = str(product_field_map.get(key) or "").strip()
        if src:
            mapped_product_fields.append({"target": label, "source": src})
    ean_source = str(validated_mapping.get("ean_column") or "").strip()
    if ean_source:
        mapped_product_fields.insert(0, {"target": "EAN/GTIN", "source": ean_source})
    description_columns = [str(col).strip() for col in list(validated_mapping.get("description_columns") or []) if str(col).strip()]
    if description_columns:
        mapped_product_fields.append({"target": "Beschreibung", "source": ", ".join(description_columns)})
    latest_job = _latest_sync_job_for_key(db, job_key)
    latest_result_run = None
    if latest_job and str(latest_job.result_url or "").strip():
        match = re.search(r"/catalog/import/runs/(\d+)$", str(latest_job.result_url or "").strip())
        if match:
            latest_result_run = db.get(ImportRun, int(match.group(1)))
    if active_job is None and latest_job and str(latest_job.status or "").strip() == "done" and latest_result_run is not None:
        return RedirectResponse(f"/catalog/import/runs/{int(latest_result_run.id)}", status_code=302)

    return templates.TemplateResponse(
        "catalog/import_run.html",
        _ctx(
            request,
            user=user,
            draft=draft,
            manufacturer=manufacturer,
            selected_kind=selected_kind,
            active_profile=active_profile,
            profile_name_value=str(validated_mapping.get("profile_name") or profile_name_default),
            update_profile=bool(validated_mapping.get("update_profile", True)),
            mapped_product_fields=mapped_product_fields,
            total_rows=len(rows),
            unmapped_columns=unmapped_columns,
            active_job=_sync_job_view(active_job) if active_job else None,
            latest_job=_sync_job_view(latest_job) if latest_job else None,
            latest_result_run=latest_result_run,
        ),
    )


@app.post("/catalog/import/{draft_id}/run", response_class=HTMLResponse)
async def catalog_import_run_post(draft_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    draft = db.get(ImportDraft, int(draft_id))
    if not draft:
        raise HTTPException(status_code=404)
    columns, rows, csv_error = _import_read_draft_csv(draft)
    if csv_error:
        _flash(request, csv_error, "error")
        return RedirectResponse("/catalog/import", status_code=302)

    manufacturer = db.get(Manufacturer, int(draft.manufacturer_id or 0)) if draft.manufacturer_id else None
    selected_kind = db.get(DeviceKind, int(draft.device_kind_id or 0)) if draft.device_kind_id else None
    feature_defs_by_key: dict[str, FeatureDef] = {}
    mapping_data = _json_load_dict(draft.mapping_json)
    validated_mapping, errors = _import_validate_mapping(
        mapping_data,
        db=db,
        columns=columns,
        rows=rows,
        feature_defs_by_key=feature_defs_by_key,
        fallback_manufacturer_id=int(draft.manufacturer_id or 0),
        fallback_kind_id=int(draft.device_kind_id or 0),
    )
    if errors["global_errors"] or errors["field_errors"]:
        draft.validation_errors_json = _json_dump(errors)
        draft.status = IMPORT_DRAFT_STATUS_FAILED
        draft.current_step = "map"
        draft.updated_at = _utcnow_naive()
        draft.manufacturer_id = int(validated_mapping.get("resolved_manufacturer_id") or 0) or None
        draft.device_kind_id = int(validated_mapping.get("resolved_device_kind_id") or 0) or None
        db.add(draft)
        db.commit()
        return _import_map_page_response(
            request,
            db=db,
            user=user,
            draft=draft,
            columns=columns,
            rows=rows,
            mapping_data=validated_mapping,
            errors=errors,
        )

    resolved_manufacturer = db.get(Manufacturer, int(validated_mapping.get("resolved_manufacturer_id") or 0)) if int(validated_mapping.get("resolved_manufacturer_id") or 0) > 0 else None
    resolved_kind = db.get(DeviceKind, int(validated_mapping.get("resolved_device_kind_id") or 0)) if int(validated_mapping.get("resolved_device_kind_id") or 0) > 0 else None
    resolved_profile_name_default = _catalog_import_profile_name_default(
        manufacturer=resolved_manufacturer,
        device_kind=resolved_kind,
        filename=draft.filename_original,
    )
    validated_mapping, profile_dropped = _import_drop_mismatched_profile(
        validated_mapping,
        profile=_pick_import_profile(db, _to_int(validated_mapping.get("profile_id"), _to_int(draft.import_profile_id, 0))),
        manufacturer=resolved_manufacturer,
        device_kind=resolved_kind,
        profile_name_default=resolved_profile_name_default,
    )
    if profile_dropped:
        draft.import_profile_id = None

    job_key = _catalog_import_run_job_key(int(draft.id))
    active_job = _sync_job_existing_active(db, lock_key="catalog_import", job_key=job_key)
    if active_job is not None:
        if str(active_job.job_key or "").strip() == job_key:
            _flash(request, "Für diesen Entwurf läuft bereits ein Hintergrundimport.", "warn")
        else:
            _flash(request, "Ein anderer Katalogimport läuft bereits. Bitte warten, bis dieser Lauf beendet ist.", "warn")
        return RedirectResponse(f"/catalog/import/{int(draft.id)}/run", status_code=302)

    draft.mapping_json = _json_dump(validated_mapping)
    draft.validation_errors_json = None
    draft.status = IMPORT_DRAFT_STATUS_VALIDATED
    draft.current_step = "run"
    draft.updated_at = _utcnow_naive()
    draft.import_profile_id = int(validated_mapping.get("profile_id") or 0) or None
    draft.manufacturer_id = int(validated_mapping.get("resolved_manufacturer_id") or 0) or None
    draft.device_kind_id = int(validated_mapping.get("resolved_device_kind_id") or 0) or None
    db.add(draft)
    db.commit()

    profile_id = _to_int(validated_mapping.get("profile_id"), 0)
    profile = _pick_import_profile(db, profile_id)
    manufacturer = db.get(Manufacturer, int(validated_mapping.get("resolved_manufacturer_id") or 0)) if int(validated_mapping.get("resolved_manufacturer_id") or 0) > 0 else manufacturer
    selected_kind = db.get(DeviceKind, int(validated_mapping.get("resolved_device_kind_id") or 0)) if int(validated_mapping.get("resolved_device_kind_id") or 0) > 0 else selected_kind
    if not manufacturer or not selected_kind:
        errors = {
            "global_errors": ["Hersteller oder Geräteart konnten nicht eindeutig erkannt werden."],
            "field_errors": {
                "map_manufacturer_name": "Hersteller fehlt.",
                "map_device_kind_name": "Geräteart fehlt.",
            },
        }
        draft.validation_errors_json = _json_dump(errors)
        draft.status = IMPORT_DRAFT_STATUS_FAILED
        draft.current_step = "map"
        draft.updated_at = _utcnow_naive()
        db.add(draft)
        db.commit()
        return _import_map_page_response(
            request,
            db=db,
            user=user,
            draft=draft,
            columns=columns,
            rows=rows,
            mapping_data=validated_mapping,
            errors=errors,
        )
    validated_mapping, profile_dropped = _import_drop_mismatched_profile(
        validated_mapping,
        profile=profile,
        manufacturer=manufacturer,
        device_kind=selected_kind,
        profile_name_default=_catalog_import_profile_name_default(
            manufacturer=manufacturer,
            device_kind=selected_kind,
            filename=draft.filename_original,
        ),
    )
    if profile_dropped:
        draft.import_profile_id = None
        profile = None

    profile_created = False
    profile_name_default = _catalog_import_profile_name_default(
        manufacturer=manufacturer,
        device_kind=selected_kind,
        filename=draft.filename_original,
    )
    profile_name = str(validated_mapping.get("profile_name") or "").strip() or profile_name_default
    if not profile:
        profile = (
            db.query(ImportProfile)
            .filter(
                ImportProfile.manufacturer_id == int(manufacturer.id),
                ImportProfile.device_kind_id == int(selected_kind.id),
                func.lower(ImportProfile.name) == profile_name.lower(),
            )
            .one_or_none()
        )
    if not profile:
        profile = ImportProfile(
            manufacturer_id=int(manufacturer.id),
            device_kind_id=int(selected_kind.id),
            name=profile_name,
            delimiter=str(draft.delimiter or ";"),
            encoding=str(draft.encoding or "utf-8"),
            has_header=bool(draft.has_header),
            ean_column=str(validated_mapping.get("ean_column") or ""),
            description_columns_json=_json_dump(list(validated_mapping.get("description_columns") or [])),
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
        db.add(profile)
        db.flush()
        profile_created = True

    for row in validated_mapping.get("feature_maps", []):
        feature_key = str(row.get("feature_key") or "").strip()
        if not feature_key:
            continue
        fdef = feature_defs_by_key.get(feature_key)
        if not fdef:
            fdef = _upsert_feature_def(
                db,
                device_kind_id=int(selected_kind.id),
                key=feature_key,
                label_de=str(row.get("label_de") or row.get("feature_label") or feature_key),
                data_type=str(row.get("data_type") or "text"),
            )
            feature_defs_by_key[feature_key] = fdef
    db.commit()

    import_run = ImportRun(
        profile_id=int(profile.id) if profile else None,
        filename=str(draft.filename_original or Path(str(draft.file_path_tmp or "")).name),
        started_at=_utcnow_naive(),
    )
    db.add(import_run)
    db.commit()
    db.refresh(import_run)
    job, created_job = _enqueue_sync_job(
        db,
        system_name="catalog",
        direction="pull",
        entity_type="catalog_import_run",
        title="CSV-Katalogimport",
        job_key=job_key,
        lock_key="catalog_import",
        log_text="CSV-Katalogimport",
        progress={
            "draft_id": int(draft.id),
            "import_run_id": int(import_run.id),
            "phase": "Wartet auf Start",
            "phase_detail": f"{len(rows)} Zeilen sind vorbereitet.",
            "total_count": len(rows),
            "processed_count": 0,
            "success_count": 0,
            "error_count": 0,
            "current_item_label": str(draft.filename_original or import_run.filename or "CSV-Datei"),
            "current_item_ref": f"Entwurf #{int(draft.id)}",
        },
        result_url=f"/catalog/import/runs/{int(import_run.id)}",
    )
    if not created_job:
        db.delete(import_run)
    db.commit()
    if created_job:
        _flash(
            request,
            f"CSV-Import wurde als Hintergrundjob gestartet. {len(rows)} Zeilen werden verarbeitet, du kannst in anderen Bereichen weiterarbeiten.",
            "info",
        )
    else:
        _flash(request, "Für diesen Entwurf läuft bereits ein Hintergrundimport.", "warn")
    return RedirectResponse(f"/catalog/import/{int(draft.id)}/run", status_code=302)


@app.get("/catalog/import/runs/{import_run_id}", response_class=HTMLResponse)
def catalog_import_result_get(import_run_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    import_run = db.get(ImportRun, int(import_run_id))
    if not import_run:
        raise HTTPException(status_code=404)
    payload = _catalog_import_result_payload(import_run)
    draft = db.get(ImportDraft, _to_int(payload.get("draft_id"), 0))
    if not draft:
        raise HTTPException(status_code=404)
    return templates.TemplateResponse(
        "catalog/import_result.html",
        _ctx(
            request,
            user=user,
            **_catalog_import_result_context(draft=draft, import_run=import_run),
        ),
    )


def _catalog_import_pdf_review_response(
    request: Request,
    *,
    user,
    db: Session,
    import_run: ImportRun,
    review: ImportPdfReview,
    form_data: dict[str, str | list[str]] | None = None,
    form_errors: dict[str, str] | None = None,
):
    product = db.get(Product, int(review.product_id or 0))
    asset = db.get(ProductAsset, int(review.product_asset_id or 0))
    if product is None or asset is None or int(asset.product_id or 0) != int(product.id):
        raise HTTPException(status_code=404)
    pdf_path = _catalog_product_asset_pdf_path(db, product=product, asset=asset)
    manufacturer_row = db.get(Manufacturer, int(product.manufacturer_id or 0)) if int(product.manufacturer_id or 0) > 0 else None
    device_kind_row = db.get(DeviceKind, int(product.device_kind_id or 0)) if int(product.device_kind_id or 0) > 0 else None
    attrs = _applicable_attributes(db, int(product.device_kind_id or 0), None)
    attribute_choice_rows = _catalog_attribute_choice_rows(attrs)
    options_map: dict[int, list[str]] = {int(attr.id): _enum_options_from_json(attr.enum_options_json) for attr in attrs}
    grouped: dict[str, list[AttributeDef]] = {}
    for attr in attrs:
        grouped.setdefault((attr.group_name or "").strip() or "Ohne Gruppe", []).append(attr)
    attrs_grouped = sorted(grouped.items(), key=lambda item: (item[0] != "Ohne Gruppe", item[0].lower()))
    suggestions, notes = _catalog_collect_pdf_attribute_suggestions(
        db,
        attrs,
        pdf_text=str(asset.extracted_text or "").strip(),
        manufacturer_id=int(product.manufacturer_id or 0) or None,
        device_kind_id=int(product.device_kind_id or 0) or None,
    )
    new_attr_candidates = _catalog_collect_pdf_new_attribute_candidates(
        db,
        attrs,
        pdf_text=str(asset.extracted_text or "").strip(),
        manufacturer_id=int(product.manufacturer_id or 0) or None,
        device_kind_id=int(product.device_kind_id or 0) or None,
    )
    stored_review = _json_load_dict(review.review_json)
    stored_items = {}
    for row in list(stored_review.get("items") or []):
        if not isinstance(row, dict):
            continue
        attr_id = _to_int(row.get("attribute_id"), 0)
        if attr_id > 0:
            stored_items[attr_id] = row
    current_value_rows = (
        db.query(ProductAttributeValue.attribute_id, ProductAttributeValue.value_text)
        .filter(ProductAttributeValue.product_id == int(product.id))
        .all()
    )
    current_value_map = {int(attr_id): str(value_text or "").strip() for attr_id, value_text in current_value_rows}
    form_data = dict(form_data or {})
    form_errors = dict(form_errors or {})
    suggestion_map: dict[int, dict[str, str]] = {}
    val_map: dict[int, str] = {}
    val_multi_map: dict[int, list[str]] = {}
    for attr in attrs:
        attr_id = int(attr.id)
        suggestion = dict(suggestions.get(attr_id) or {})
        stored = dict(stored_items.get(attr_id) or {})
        effective_value = (
            str(_form_scalar(form_data, f"attr_{attr_id}") or "").strip()
            or str(stored.get("confirmed_value") or "").strip()
            or str(suggestion.get("value") or "").strip()
            or str(current_value_map.get(attr_id) or "").strip()
        )
        effective_source_label = (
            str(form_data.get(f"source_label_{attr_id}") or "").strip()
            or str(stored.get("source_label") or "").strip()
            or str(suggestion.get("source_label") or "").strip()
        )
        effective_source_value = (
            str(form_data.get(f"source_value_{attr_id}") or "").strip()
            or str(stored.get("source_value") or "").strip()
            or str(suggestion.get("source_value") or "").strip()
        )
        effective_marker = (
            str(form_data.get(f"marker_{attr_id}") or "").strip()
            or (_json_dump(stored.get("marker")) if isinstance(stored.get("marker"), dict) else "")
        )
        form_data.setdefault(f"attr_{attr_id}", effective_value)
        form_data.setdefault(f"source_label_{attr_id}", effective_source_label)
        form_data.setdefault(f"source_value_{attr_id}", effective_source_value)
        form_data.setdefault(f"marker_{attr_id}", effective_marker)
        if attr.value_type == "enum" and bool(attr.is_multi):
            selected_values: list[str] = []
            raw_multi = form_data.get(f"attr_{attr_id}")
            if isinstance(raw_multi, list):
                selected_values = [str(item).strip() for item in raw_multi if str(item).strip()]
            elif effective_value:
                try:
                    parsed = json.loads(effective_value)
                    if isinstance(parsed, list):
                        selected_values = [str(item).strip() for item in parsed if str(item).strip()]
                except Exception:
                    selected_values = []
            val_multi_map[attr_id] = selected_values
        else:
            val_map[attr_id] = effective_value
        search_query = str(suggestion.get("search_query") or effective_source_label or effective_source_value or attr.name or "").strip()
        suggestion_map[attr_id] = {
            "source_label": effective_source_label,
            "source_value": effective_source_value,
            "value": effective_value,
            "matched_alias": str(suggestion.get("matched_alias") or "").strip(),
            "match_score": str(suggestion.get("match_score") or "").strip(),
            "search_url": f"{_catalog_product_asset_url(int(product.id), asset)}#search={quote(search_query)}" if search_query else _catalog_product_asset_url(int(product.id), asset),
        }
    prepared_new_attr_candidates = _catalog_prepare_pdf_review_candidates(
        base_candidates=new_attr_candidates,
        form_data=form_data,
        attrs=attrs,
    )
    review_rows = _catalog_import_pdf_review_query(db, import_run_id=int(import_run.id)).all()
    learning_rows = _catalog_learning_pdf_reviews(db, import_run_id=int(import_run.id), limit=2)
    learning_ids = [int(row.id) for row in learning_rows]
    try:
        queue_position = learning_ids.index(int(review.id)) + 1
    except ValueError:
        review_ids = [int(row.id) for row in review_rows]
        try:
            queue_position = review_ids.index(int(review.id)) + 1
        except ValueError:
            queue_position = 1
    queue_total = len(learning_rows) if learning_rows and int(review.id) in learning_ids else len(review_rows)
    next_learning_review, _learning_position, _learning_total = _catalog_next_learning_pdf_review(
        db,
        import_run_id=int(import_run.id),
        after_review_id=int(review.id),
        limit=2,
    )
    next_review = next_learning_review if int(review.id) in learning_ids else _catalog_next_import_pdf_review(db, import_run_id=int(import_run.id), after_review_id=int(review.id))
    pdf_url = _catalog_product_asset_url(int(product.id), asset)
    return templates.TemplateResponse(
        "catalog/import_pdf_review.html",
        _ctx(
            request,
            user=user,
            import_run=import_run,
            review=review,
            product=product,
            manufacturer_row=manufacturer_row,
            device_kind_row=device_kind_row,
            attrs=attrs,
            attrs_grouped=attrs_grouped,
            attribute_choice_rows=attribute_choice_rows,
            options_map=options_map,
            val_map=val_map,
            val_multi_map=val_multi_map,
            form_data=form_data,
            form_errors=form_errors,
            suggestions=suggestion_map,
            new_attr_candidates=prepared_new_attr_candidates,
            current_value_map=current_value_map,
            review_notes=[str(item) for item in notes if str(item).strip()],
            pdf_url=pdf_url,
            pdf_preview_base_url=f"/catalog/products/{int(product.id)}/assets/{int(asset.id)}/preview",
            pdf_page_count=_catalog_pdf_page_count(pdf_path),
            queue_position=queue_position,
            queue_total=queue_total,
            learning_mode=bool(learning_rows and int(review.id) in learning_ids),
            auto_apply_after_review=bool(learning_rows and int(review.id) in learning_ids and queue_position >= len(learning_rows)),
            auto_apply_pending_count=max(
                0,
                len([row for row in review_rows if str(row.status or "").strip().lower() == "pending" and int(row.id) not in set(learning_ids)])
            ),
            next_review_url=f"/catalog/import/runs/{int(import_run.id)}/reviews/{int(next_review.id)}" if next_review else "",
            result_url=f"/catalog/import/runs/{int(import_run.id)}",
        ),
    )


@app.get("/catalog/import/runs/{import_run_id}/reviews")
def catalog_import_reviews_redirect(import_run_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    _ = user
    import_run = db.get(ImportRun, int(import_run_id))
    if not import_run:
        raise HTTPException(status_code=404)
    _flash(request, "Die alte CSV-PDF-Review ist deaktiviert. Merkmale werden jetzt direkt beim CSV-Import zugeordnet.", "info")
    return RedirectResponse(f"/catalog/import/runs/{int(import_run.id)}", status_code=302)


@app.get("/catalog/import/runs/{import_run_id}/reviews/{review_id}", response_class=HTMLResponse)
def catalog_import_review_get(import_run_id: int, review_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    _ = review_id, user
    import_run = db.get(ImportRun, int(import_run_id))
    if not import_run:
        raise HTTPException(status_code=404)
    _flash(request, "Die alte CSV-PDF-Review ist deaktiviert. Merkmale werden jetzt direkt beim CSV-Import zugeordnet.", "info")
    return RedirectResponse(f"/catalog/import/runs/{int(import_run.id)}", status_code=302)


