def _catalog_product_pdf_review_response(
    request: Request,
    *,
    user,
    db: Session,
    review_token: str,
    review_data: dict[str, object] | None = None,
    form_data: dict[str, str | list[str]] | None = None,
    form_errors: dict[str, str] | None = None,
):
    payload = review_data or _catalog_load_product_pdf_review(review_token)
    pdf_source_path = _catalog_product_pdf_review_source_path(review_token)
    core = dict(payload.get("core") or {})
    form_data = dict(form_data or {})
    form_errors = dict(form_errors or {})
    if "manufacturer_id" not in form_data:
        form_data["manufacturer_id"] = str(int(core.get("manufacturer_id") or 0) or "")
    if "device_kind_id" not in form_data:
        form_data["device_kind_id"] = str(int(core.get("device_kind_id") or 0) or "")
    for key in ("ean", "material_no", "sales_name", "product_title_1", "product_title_2", "description"):
        if key not in form_data and str(core.get(key) or "").strip():
            form_data[key] = str(core.get(key) or "").strip()
    stored_markers = payload.get("markers") if isinstance(payload.get("markers"), dict) else {}

    manufacturers = db.query(Manufacturer).filter(Manufacturer.active == True).order_by(Manufacturer.name.asc(), Manufacturer.id.asc()).all()
    kinds = db.query(DeviceKind).order_by(DeviceKind.name.asc(), DeviceKind.id.asc()).all()
    selected_kind_id = _to_int(_form_scalar(form_data, "device_kind_id"), int(core.get("device_kind_id") or 0))
    selected_manufacturer_id = _to_int(_form_scalar(form_data, "manufacturer_id"), int(core.get("manufacturer_id") or 0))
    attrs = _applicable_attributes(db, selected_kind_id, None)
    attribute_choice_rows = _catalog_attribute_choice_rows(attrs)
    options_map: dict[int, list[str]] = {}
    grouped: dict[str, list[AttributeDef]] = {}
    val_map: dict[int, str] = {}
    val_multi_map: dict[int, list[str]] = {}
    stored_attr_values = payload.get("attribute_values") if isinstance(payload.get("attribute_values"), dict) else {}
    for attr in attrs:
        options_map[int(attr.id)] = _enum_options_from_json(attr.enum_options_json)
        raw_value = str(stored_attr_values.get(str(attr.id)) or stored_attr_values.get(int(attr.id)) or "").strip()
        marker_value = stored_markers.get(str(attr.id)) if isinstance(stored_markers, dict) else None
        if f"marker_{int(attr.id)}" not in form_data and isinstance(marker_value, dict):
            form_data[f"marker_{int(attr.id)}"] = _json_dump(marker_value)
        if raw_value:
            val_map[int(attr.id)] = raw_value
            if attr.value_type == "enum" and bool(attr.is_multi):
                try:
                    parsed = json.loads(raw_value)
                    if isinstance(parsed, list):
                        val_multi_map[int(attr.id)] = [str(item).strip() for item in parsed if str(item).strip()]
                except Exception:
                    val_multi_map[int(attr.id)] = []
        grouped.setdefault((attr.group_name or "").strip() or "Ohne Gruppe", []).append(attr)
    _apply_product_attribute_form_values(attrs, val_map, val_multi_map, form_data)
    attrs_grouped = sorted(grouped.items(), key=lambda item: (item[0] != "Ohne Gruppe", item[0].lower()))
    pdf_text = str(payload.get("pdf_text") or "").strip()
    if not pdf_text:
        pdf_text = _catalog_pdf_text_from_payload(pdf_source_path.read_bytes(), file_name=pdf_source_path.name)
    new_attr_candidates = _catalog_collect_pdf_new_attribute_candidates(
        db,
        attrs,
        pdf_text=pdf_text,
        manufacturer_id=selected_manufacturer_id or None,
        device_kind_id=selected_kind_id or None,
    )
    prepared_new_attr_candidates = _catalog_prepare_pdf_review_candidates(
        base_candidates=new_attr_candidates,
        form_data=form_data,
        attrs=attrs,
    )
    existing_product = _catalog_find_existing_product(
        db,
        manufacturer_id=selected_manufacturer_id,
        device_kind_id=selected_kind_id,
        material_no=str(_form_scalar(form_data, "material_no", "") or "").strip() or None,
        ean=str(_form_scalar(form_data, "ean", "") or "").strip() or None,
        sales_name=str(_form_scalar(form_data, "sales_name", "") or "").strip() or None,
        title_1=str(_form_scalar(form_data, "product_title_1", "") or "").strip() or None,
        title_2=str(_form_scalar(form_data, "product_title_2", "") or "").strip() or None,
    )
    if existing_product is None and int(payload.get("existing_product_id") or 0) > 0:
        existing_product = db.get(Product, int(payload.get("existing_product_id") or 0))
    return templates.TemplateResponse(
        "catalog/product_pdf_review.html",
        _ctx(
            request,
            user=user,
            review_token=review_token,
            form_data=form_data,
            form_errors=form_errors,
            manufacturers=manufacturers,
            kinds=kinds,
            attrs=attrs,
            attrs_grouped=attrs_grouped,
            attribute_choice_rows=attribute_choice_rows,
            options_map=options_map,
            val_map=val_map,
            val_multi_map=val_multi_map,
            new_attr_candidates=prepared_new_attr_candidates,
            review_meta={
                "source_filename": str(payload.get("source_filename") or "").strip(),
                "confidence": float(payload.get("confidence") or 0.0),
                "hard_case": bool(payload.get("hard_case")),
                "ai_model": str(payload.get("ai_model") or "").strip(),
                "notes": [str(item) for item in list(payload.get("notes") or []) if str(item).strip()],
                "existing_product_id": int(getattr(existing_product, "id", 0) or 0),
            },
            existing_product=existing_product,
            pdf_download_url=f"/catalog/pdf-reviews/{review_token}/source",
            pdf_preview_base_url=f"/catalog/pdf-reviews/{review_token}/preview",
            pdf_page_count=_catalog_pdf_page_count(pdf_source_path),
        ),
    )


@app.get("/catalog/products/new", response_class=HTMLResponse)
def products_new_get(
    request: Request,
    user=Depends(require_admin),
    item_type: str = "",
    area_id: int = 0,
    device_kind_id: int = 0,
    device_type_id: int = 0,
    db: Session = Depends(db_session),
):
    manual_mode = (request.query_params.get("mode") or "").strip().lower() == "manual"
    selected_item_type = _normalize_item_type(item_type, fallback="")
    if not manual_mode and selected_item_type in ("", "appliance"):
        return _catalog_product_pdf_import_response(request, user=user)
    if not selected_item_type:
        return templates.TemplateResponse(
            "catalog/product_new_choose_type.html",
            _ctx(
                request,
                user=user,
                item_types=ITEM_TYPE_CHOICES,
                item_type_labels=ITEM_TYPE_LABELS,
            ),
        )

    draft_key = f"draft:/catalog/products/new:{selected_item_type}"
    prefill_form_data: dict[str, str | list[str]] = {}
    query_keys = {str(k) for k in request.query_params.keys()}
    if query_keys.issubset({"item_type"}):
        loaded = _draft_get(request, draft_key)
        if isinstance(loaded, dict):
            prefill_form_data = dict(loaded)

    selected_area_id = int(area_id or _to_int(_form_scalar(prefill_form_data, "area_id"), 0) or 0)
    selected_kind_id = int(device_kind_id or _to_int(_form_scalar(prefill_form_data, "device_kind_id"), 0) or 0)
    selected_type_id = int(device_type_id or _to_int(_form_scalar(prefill_form_data, "device_type_id"), 0) or 0)
    areas, kinds, types, selected_area_id, selected_kind_id, selected_type_id = _catalog_cascade_state(
        db,
        selected_area_id=selected_area_id,
        selected_kind_id=selected_kind_id,
        selected_type_id=selected_type_id,
    )
    manufacturers = db.query(Manufacturer).filter(Manufacturer.active == True).order_by(Manufacturer.name.asc()).all()
    warehouses = db.query(Warehouse).order_by(Warehouse.name.asc()).all()
    suppliers = db.query(Supplier).filter(Supplier.active == True).order_by(Supplier.name.asc()).all()
    owners = db.query(Owner).filter(Owner.active == True).order_by(Owner.name.asc()).all()
    condition_defs = _get_condition_defs(db, active_only=True, include_fallback=True)
    receipt_defaults = _receipt_defaults(db)
    attrs: list[AttributeDef] = []
    options_map: dict[int, list[str]] = {}
    grouped: dict[str, list[AttributeDef]] = {}
    val_map: dict[int, str] = {}
    val_multi_map: dict[int, list[str]] = {}
    for a in attrs:
        options_map[a.id] = _enum_options_from_json(a.enum_options_json)
        group_name = (a.group_name or "").strip() or "Ohne Gruppe"
        grouped.setdefault(group_name, []).append(a)
    _apply_product_attribute_form_values(attrs, val_map, val_multi_map, prefill_form_data)
    attrs_grouped = sorted(grouped.items(), key=lambda item: (item[0] != "Ohne Gruppe", item[0].lower()))
    form_schema = _product_form_schema(db, selected_item_type)
    return templates.TemplateResponse(
        "catalog/product_form.html",
        _ctx(
            request,
            user=user,
            product=None,
            areas=areas,
            kinds=kinds,
            types=types,
            manufacturers=manufacturers,
            warehouses=warehouses,
            suppliers=suppliers,
            owners=owners,
            condition_defs=condition_defs,
            receipt_defaults=receipt_defaults,
            item_types=ITEM_TYPE_CHOICES,
            item_type_labels=ITEM_TYPE_LABELS,
            selected_item_type=selected_item_type,
            item_type_locked=True,
            selected_area_id=selected_area_id,
            selected_kind_id=selected_kind_id,
            selected_type_id=selected_type_id,
            attrs=attrs,
            attrs_grouped=attrs_grouped,
            val_map=val_map,
            val_multi_map=val_multi_map,
            options_map=options_map,
            form_schema=form_schema,
            form_data=prefill_form_data,
            asset_form_defaults=_catalog_asset_form_defaults(db, None, prefill_form_data),
            form_errors={},
            first_error_field_id="",
            draft_key=draft_key,
            show_receipt_block=True,
            receipt_form_data={},
            receipt_form_errors={},
        ),
    )


@app.post("/catalog/products/new/analyze", response_class=HTMLResponse)
async def products_new_pdf_analyze(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    """PDF-Datenblatt hochladen → Produkt direkt anlegen über den neuen PDF-Import-Service."""
    form = await request.form()
    upload: UploadFile = form.get("datasheet_upload")  # type: ignore
    if not upload or not str(getattr(upload, "filename", "") or "").strip():
        return _catalog_product_pdf_import_response(request, user=user, global_errors=["Bitte ein Produktdatenblatt auswählen."])
    payload = await upload.read()
    if not payload:
        return _catalog_product_pdf_import_response(request, user=user, global_errors=["Das Produktdatenblatt ist leer."])

    # Neuer Weg: direkt über import_product_from_pdf
    tmp_root = ensure_dirs()["tmp"] / "imports"
    tmp_root.mkdir(parents=True, exist_ok=True)
    tmp_path = tmp_root / f"pdf_new_{uuid.uuid4().hex[:12]}.pdf"
    tmp_path.write_bytes(payload)
    try:
        result = import_product_from_pdf(db, tmp_path)
        db.commit()
        product_id = result["product_id"]
        action = "angelegt" if result.get("created") else "aktualisiert"
        _flash(
            request,
            f"Produkt '{result['product_name']}' aus Datenblatt {action}. "
            f"Hersteller: {result['manufacturer']}, Geräteart: {result['device_kind']}, "
            f"Merkmale: {result['features_set']}, Bilder: {result['images_saved']}"
            + (f", EAN: {result['ean']}" if result.get("ean") else ""),
            "info",
        )
        return RedirectResponse(f"/catalog/products/{product_id}", status_code=302)
    except Exception as exc:
        db.rollback()
        return _catalog_product_pdf_import_response(request, user=user, global_errors=[f"PDF-Import fehlgeschlagen: {exc}"])
    finally:
        try:
            tmp_path.unlink(missing_ok=True)
        except Exception:
            pass


@app.post("/catalog/products/new/analyze-legacy", response_class=HTMLResponse)
async def products_new_pdf_analyze_legacy(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    """Legacy PDF-Analyse (alter Weg mit Review-Zwischenschritt)."""
    form = await request.form()
    upload: UploadFile = form.get("datasheet_upload")  # type: ignore
    if not upload or not str(getattr(upload, "filename", "") or "").strip():
        return _catalog_product_pdf_import_response(request, user=user, global_errors=["Bitte ein Produktdatenblatt auswählen."])
    payload = await upload.read()
    try:
        upload.file.seek(0)
    except Exception:
        pass
    if not payload:
        return _catalog_product_pdf_import_response(request, user=user, global_errors=["Das Produktdatenblatt ist leer."])
    pdf_text = _catalog_pdf_text_from_payload(payload, file_name=str(getattr(upload, "filename", "") or "datenblatt.pdf"))
    if not pdf_text:
        return _catalog_product_pdf_import_response(
            request,
            user=user,
            global_errors=["Das PDF konnte nicht gelesen werden. Bitte ein textbasiertes Datenblatt verwenden."],
        )
    review = _catalog_pdf_extract_review(db, pdf_text=pdf_text)
    core = dict(review.get("core") or {})
    existing_product = _catalog_find_existing_product(
        db,
        manufacturer_id=int(core.get("manufacturer_id") or 0) or None,
        device_kind_id=int(core.get("device_kind_id") or 0) or None,
        material_no=str(core.get("material_no") or "").strip() or None,
        ean=str(core.get("ean") or "").strip() or None,
        sales_name=str(core.get("sales_name") or "").strip() or None,
        title_1=str(core.get("product_title_1") or "").strip() or None,
        title_2=str(core.get("product_title_2") or "").strip() or None,
    )
    review_data = {
        "source_filename": str(getattr(upload, "filename", "") or "").strip(),
        "core": core,
        "attribute_values": {str(key): str(value) for key, value in dict(review.get("attribute_values") or {}).items()},
        "confidence": float(review.get("confidence") or 0.0),
        "hard_case": bool(review.get("hard_case")),
        "ai_model": str(review.get("ai_model") or "").strip(),
        "notes": [str(item) for item in list(review.get("notes") or []) if str(item).strip()],
        "existing_product_id": int(getattr(existing_product, "id", 0) or 0),
    }
    review_token = _catalog_save_product_pdf_review(
        file_name=str(getattr(upload, "filename", "") or "datenblatt.pdf"),
        payload=payload,
        review_data=review_data,
    )
    return _catalog_product_pdf_review_response(
        request,
        user=user,
        db=db,
        review_token=review_token,
        review_data=review_data,
    )


@app.post("/catalog/products/new/confirm", response_class=HTMLResponse)
async def products_new_pdf_confirm(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    form = await request.form()
    review_token = str(form.get("review_token") or "").strip()
    form_data = _extract_form_data(form)
    if not review_token:
        return _catalog_product_pdf_import_response(request, user=user, global_errors=["Die Prüfdaten fehlen. Bitte Datenblatt erneut analysieren."])
    try:
        review_payload = _catalog_load_product_pdf_review(review_token)
        source_path = _catalog_product_pdf_review_source_path(review_token)
    except Exception:
        return _catalog_product_pdf_import_response(request, user=user, global_errors=["Die Prüfdaten sind abgelaufen. Bitte Datenblatt erneut hochladen."])

    form_errors: dict[str, str] = {}

    def add_error(field_key: str, message: str) -> None:
        if field_key not in form_errors:
            form_errors[field_key] = message

    manufacturer_id = _to_int(form.get("manufacturer_id"), 0)
    manufacturer_row = db.get(Manufacturer, manufacturer_id) if manufacturer_id > 0 else None
    if manufacturer_row is None:
        add_error("manufacturer_id", "Hersteller konnte nicht erkannt werden.")

    device_kind_id = _to_int(form.get("device_kind_id"), 0)
    device_kind_row = db.get(DeviceKind, device_kind_id) if device_kind_id > 0 else None
    if device_kind_row is None:
        add_error("device_kind_id", "Geräteart konnte nicht erkannt werden.")

    ean = None
    ean_raw = str(form.get("ean") or "").strip()
    if not ean_raw:
        add_error("ean", "EAN ist für den Produktimport Pflicht.")
    else:
        try:
            ean = normalize_ean(ean_raw)
        except Exception as exc:
            add_error("ean", f"EAN ist ungültig: {exc}")

    material_no = str(form.get("material_no") or "").strip() or None
    sales_name = str(form.get("sales_name") or "").strip() or None
    product_title_1 = str(form.get("product_title_1") or "").strip() or None
    product_title_2 = str(form.get("product_title_2") or "").strip() or None
    description = str(form.get("description") or "").strip() or None
    if not any([sales_name, material_no, product_title_1, product_title_2]):
        add_error("sales_name", "Mindestens Verkaufsbezeichnung, Materialnummer oder Produkttitel muss gefüllt sein.")

    attrs = _applicable_attributes(db, int(device_kind_id or 0), None) if device_kind_row else []
    parsed_attr_values, parse_errors = _parse_product_attribute_values(form, attrs)
    for msg in parse_errors:
        add_error("__all__", msg)
    candidate_actions = _catalog_parse_pdf_review_candidate_actions(
        form,
        attrs=attrs,
        device_kind_id=int(device_kind_id or 0),
        form_errors=form_errors,
    )
    marker_map: dict[str, dict[str, object]] = {}
    for attr in attrs:
        marker = _catalog_parse_pdf_marker(form.get(f"marker_{int(attr.id)}"))
        if marker is not None:
            marker_map[str(int(attr.id))] = marker

    if form_errors:
        review_payload["markers"] = marker_map
        _catalog_store_product_pdf_review(review_token, review_payload)
        return _catalog_product_pdf_review_response(
            request,
            user=user,
            db=db,
            review_token=review_token,
            form_data=form_data,
            form_errors=form_errors,
        )

    existing_product = _catalog_find_existing_product(
        db,
        manufacturer_id=int(manufacturer_id or 0) or None,
        device_kind_id=int(device_kind_id or 0) or None,
        material_no=material_no,
        ean=ean,
        sales_name=sales_name,
        title_1=product_title_1,
        title_2=product_title_2,
    )
    created_new_product = existing_product is None
    product = existing_product or Product(active=True, track_mode="quantity", item_type="appliance")
    product.name = sales_name or product_title_1 or material_no or product.name or "Produktdatenblatt"
    product.item_type = "appliance"
    product.track_mode = "quantity"
    product.manufacturer_id = int(manufacturer_row.id)
    product.manufacturer = str(manufacturer_row.name or "").strip()
    product.manufacturer_name = None
    product.device_kind_id = int(device_kind_row.id)
    product.device_type_id = None
    product.area_id = None
    product.material_no = material_no
    product.sales_name = sales_name
    product.product_title_1 = product_title_1
    product.product_title_2 = product_title_2
    product.description = description
    product.ean = ean
    product.active = True
    product.source_kind = "manual"
    db.add(product)
    db.flush()

    payload = source_path.read_bytes()
    upsert_product_asset(
        db,
        product=product,
        asset_type="datasheet_pdf",
        source_kind="manual",
        source_url_raw=None,
        payload=payload,
        mime_type="application/pdf",
        original_name=str(review_payload.get("source_filename") or source_path.name),
        extract_text_enabled=True,
    )
    # Feature-Extraktion aus dem Datenblatt-Text
    if device_kind_row:
        try:
            from .services.pdf_product_import_service import extract_technical_data
            seed_features_for_kind(db, device_kind_row)
            db.flush()
            datasheet_text = _catalog_product_datasheet_text(db, product)
            if datasheet_text:
                tech_data = extract_technical_data(datasheet_text)
                feature_defs = _feature_defs_for_kind(db, int(device_kind_row.id))
                feature_defs_by_key = {str(fd.key or "").strip(): fd for fd in feature_defs}
                for feature_key, raw_value in tech_data.items():
                    if feature_key.startswith("_"):
                        continue
                    fdef = feature_defs_by_key.get(feature_key)
                    if fdef and raw_value:
                        try:
                            _set_feature_value(
                                db,
                                product_id=int(product.id),
                                feature_def=fdef,
                                raw_value=str(raw_value),
                                manufacturer_id=int(manufacturer_row.id) if manufacturer_row else None,
                                apply_rules=True,
                                source_kind="pdf",
                            )
                        except Exception:
                            pass
        except Exception:
            pass

    _refresh_product_search_blob(db, product, kind_name=str(device_kind_row.name or "").strip())
    write_product_outbox_event(db, product, event_type="ProductCreated" if created_new_product else "ProductUpdated")
    db.commit()
    _catalog_delete_product_pdf_review(review_token)
    _flash(request, "Produkt aus Datenblatt angelegt." if created_new_product else "Vorhandenes Produkt aus Datenblatt aktualisiert.", "info")
    return RedirectResponse(f"/catalog/products/{int(product.id)}/edit", status_code=302)


@app.post("/catalog/products/new")
async def products_new_post(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    form = await request.form()
    item_type = _normalize_item_type(form.get("item_type"), fallback="")
    if not item_type:
        _flash(request, "Bitte zuerst eine Artikelart wählen.", "error")
        return RedirectResponse("/catalog/products/new", status_code=302)
    draft_key = f"draft:/catalog/products/new:{item_type}"
    form_data = _extract_form_data(form)
    form_data["item_type"] = item_type
    action = (form.get("action") or "save").strip().lower()
    wants_receipt = action == "save_and_receipt"
    _draft_set(request, draft_key, form_data)
    visible_fields, required_fields = _product_form_key_sets(db, item_type)

    text_values: dict[str, str] = {}
    select_values: dict[str, int | None] = {}
    form_errors: dict[str, str] = {}

    def add_error(field_key: str, message: str) -> None:
        if field_key not in form_errors:
            form_errors[field_key] = message

    for key in visible_fields:
        if key in SELECT_FIELD_KEYS:
            value, exists = _parse_product_select_id(db, key, form.get(key))
            select_values[key] = value if exists else None
            if key in required_fields and not value:
                add_error(key, f"Feld '{_product_field_label(key)}' ist erforderlich.")
            elif value and not exists:
                add_error(key, f"Ungültiger Wert für Feld '{_product_field_label(key)}'.")
            continue
        text_values[key] = (form.get(key) or "").strip()
        if key in required_fields and not text_values[key]:
            add_error(key, f"Feld '{_product_field_label(key)}' ist erforderlich.")

    datasheet_upload = form.get("datasheet_upload")
    manual_upload = form.get("manual_upload")
    energy_label_upload = form.get("energy_label_upload")
    pdf_guess = _catalog_guess_product_core_from_pdf_upload(db, datasheet_upload) if item_type == "appliance" else {}
    if item_type == "appliance" and pdf_guess:
        if "manufacturer_id" in visible_fields and not select_values.get("manufacturer_id") and int(pdf_guess.get("manufacturer_id") or 0) > 0:
            select_values["manufacturer_id"] = int(pdf_guess.get("manufacturer_id") or 0)
            form_errors.pop("manufacturer_id", None)
        if "device_kind_id" in visible_fields and not select_values.get("device_kind_id") and int(pdf_guess.get("device_kind_id") or 0) > 0:
            select_values["device_kind_id"] = int(pdf_guess.get("device_kind_id") or 0)
            form_errors.pop("device_kind_id", None)
        for key in ("sales_name", "material_no", "product_title_1", "product_title_2", "description", "ean", "name"):
            if key in visible_fields and not text_values.get(key) and str(pdf_guess.get(key) or "").strip():
                text_values[key] = str(pdf_guess.get(key) or "").strip()
                form_errors.pop(key, None)

    name = text_values.get("name", "") if "name" in visible_fields else ""
    if item_type == "appliance" and (("name" not in visible_fields) or not name):
        name = text_values.get("sales_name", "") or text_values.get("product_title_1", "") or text_values.get("material_no", "") or name
    if not name:
        add_error("name", "Feld 'Bezeichnung' ist erforderlich.")

    manufacturer_id = select_values.get("manufacturer_id") if "manufacturer_id" in visible_fields else None
    manufacturer_row = db.get(Manufacturer, manufacturer_id) if manufacturer_id else None
    if item_type == "appliance" and "manufacturer_id" in visible_fields and not manufacturer_id:
        add_error("manufacturer_id", "Für Großgeräte ist ein Hersteller Pflicht oder muss aus dem Datenblatt erkannt werden.")

    ean = None
    try:
        if "ean" in visible_fields:
            ean = normalize_ean(text_values.get("ean"))
    except ValueError as e:
        add_error("ean", f"Ungültige EAN: {e}")
    material_no = text_values.get("material_no") or None if "material_no" in visible_fields else None
    asset_inputs = _parse_product_asset_urls(form, add_error)

    device_kind_id = select_values.get("device_kind_id") if "device_kind_id" in visible_fields else None
    if item_type == "appliance" and not device_kind_id:
        add_error("device_kind_id", "Für Großgeräte ist eine Geräteart Pflicht oder muss aus dem Datenblatt erkannt werden.")
    existing_product = (
        _catalog_find_existing_product(
            db,
            manufacturer_id=manufacturer_id,
            device_kind_id=device_kind_id,
            material_no=material_no,
            ean=ean,
            sales_name=text_values.get("sales_name"),
            title_1=text_values.get("product_title_1"),
            title_2=text_values.get("product_title_2"),
        )
        if item_type == "appliance"
        else None
    )
    if material_no:
        existing_material = (
            db.query(Product)
            .filter(func.lower(Product.material_no) == material_no.lower())
            .one_or_none()
        )
        if existing_material and (existing_product is None or int(existing_material.id) != int(existing_product.id)):
            add_error("material_no", "Materialnummer existiert bereits.")
    area_id = None
    device_type_id = None

    attrs: list[AttributeDef] = []
    parsed_values, parse_errors = _parse_product_attribute_values(form, attrs)
    if parse_errors:
        attrs_by_name = {str(a.name or "").strip().lower(): a for a in attrs}
        for msg in parse_errors:
            after_colon = str(msg).split(":", 1)[1].strip().lower() if ":" in str(msg) else ""
            attr = attrs_by_name.get(after_colon)
            if attr:
                add_error(f"attr_{int(attr.id)}", msg)
            else:
                add_error("__all__", msg)

    if form_errors:
        for msg in list(form_errors.values())[:5]:
            _flash(request, msg, "error")
        selected_kind_id = _to_int(_form_scalar(form_data, "device_kind_id"), 0)
        selected_type_id = _to_int(_form_scalar(form_data, "device_type_id"), 0)
        response = products_new_get(
            request,
            user=user,
            item_type=item_type,
            area_id=_to_int(_form_scalar(form_data, "area_id"), 0),
            device_kind_id=selected_kind_id,
            device_type_id=selected_type_id,
            db=db,
        )
        response.context["form_data"] = form_data
        response.context["form_errors"] = form_errors
        response.context["first_error_field_id"] = _first_error_field_id(form_errors, PRODUCT_FORM_FIELD_IDS)
        _apply_product_attribute_form_values(
            response.context.get("attrs", []),
            response.context.get("val_map", {}),
            response.context.get("val_multi_map", {}),
            form_data,
        )
        return _rerender_template_response(response)

    sales_name = text_values.get("sales_name") or None if "sales_name" in visible_fields else None
    product_title_1 = text_values.get("product_title_1") or None if "product_title_1" in visible_fields else None
    product_title_2 = text_values.get("product_title_2") or None if "product_title_2" in visible_fields else None
    sku = text_values.get("sku") or None if "sku" in visible_fields else None
    description = text_values.get("description") or None if "description" in visible_fields else None
    created_new_product = existing_product is None
    p = existing_product or Product(active=True, track_mode="quantity", item_type=item_type)
    p.name = name
    p.item_type = item_type
    p.manufacturer = manufacturer_row.name if manufacturer_row else p.manufacturer
    p.manufacturer_id = manufacturer_id
    p.material_no = material_no
    p.sales_name = sales_name
    p.manufacturer_name = None
    p.product_title_1 = product_title_1
    p.product_title_2 = product_title_2
    p.sku = sku
    p.ean = ean
    p.track_mode = "quantity"
    p.description = description
    p.area_id = area_id
    p.device_kind_id = device_kind_id
    p.device_type_id = device_type_id
    p.active = True
    p.source_kind = "manual"
    db.add(p)
    db.flush()
    try:
        asset_summary = _catalog_sync_product_assets(
            db,
            product=p,
            asset_inputs=asset_inputs,
            manufacturer_row=manufacturer_row,
            datasheet_upload=datasheet_upload,
            manual_upload=manual_upload,
            energy_label_upload=energy_label_upload,
            source_kind="manual",
        )
        if int(asset_summary.get("candidate_updates") or 0) > 0:
            _flash(request, f"Analyse hat {int(asset_summary.get('candidate_updates') or 0)} Merkmalskandidat(en) erkannt.", "info")
        datasheet_text = _catalog_product_datasheet_text(db, p)
        if datasheet_text:
            pdf_review = _catalog_apply_pdf_review_to_product(
                db,
                product=p,
                pdf_text=datasheet_text,
                manufacturer_row=manufacturer_row,
                device_kind_row=db.get(DeviceKind, int(device_kind_id)) if int(device_kind_id or 0) > 0 else None,
            )
            if int(pdf_review.get("applied_count") or 0) > 0:
                _flash(request, f"Datenblatt hat {int(pdf_review.get('applied_count') or 0)} Attributwerte übernommen.", "info")
        asset_failures = list(asset_summary.get("failures") or [])
        if asset_failures:
            _flash(request, f"Einige Assets konnten nicht verarbeitet werden: {asset_failures[0]}", "warn")
    except Exception as exc:
        _flash(request, f"Produkt wurde gespeichert, Asset-/PDF-Verarbeitung war nur teilweise erfolgreich: {exc}", "warn")
    _catalog_sync_legacy_image_fields(p, asset_inputs)
    for a in attrs:
        value_text = parsed_values.get(a.id, "")
        pav = (
            db.query(ProductAttributeValue)
            .filter(ProductAttributeValue.product_id == p.id, ProductAttributeValue.attribute_id == a.id)
            .one_or_none()
        )
        if value_text != "":
            if pav:
                pav.value_text = value_text
                db.add(pav)
            else:
                db.add(ProductAttributeValue(product_id=p.id, attribute_id=a.id, value_text=value_text))
        elif pav:
            db.delete(pav)
    _refresh_product_search_blob(db, p)
    write_product_outbox_event(db, p, event_type="ProductCreated" if created_new_product else "ProductUpdated")
    db.commit()
    _draft_clear(request, draft_key)

    if wants_receipt:
        payload, receipt_errors = _direct_receipt_payload_from_form(db, form)

        if receipt_errors:
            _flash(request, "Produkt wurde gespeichert. Einbuchung konnte nicht abgeschlossen werden.", "warn")
            for msg in list(receipt_errors.values())[:5]:
                _flash(request, msg, "error")
            response = products_edit_get(product_id=int(p.id), request=request, user=user, db=db)
            response.context["show_receipt_block"] = True
            response.context["receipt_form_data"] = form_data
            response.context["receipt_form_errors"] = receipt_errors
            response.context["first_error_field_id"] = _first_error_field_id(receipt_errors, PRODUCT_RECEIPT_FIELD_IDS)
            return _rerender_template_response(response)
        try:
            _apply_direct_receipt(
                db=db,
                product_id=int(p.id),
                actor_user_id=user.id,
                payload=payload,
                reference=f"PRODUKT-{int(p.id)}",
                note="Direkt-Einbuchung bei Produktanlage",
            )
            db.commit()
        except Exception as exc:
            db.rollback()
            _flash(request, "Produkt wurde gespeichert. Einbuchung konnte nicht abgeschlossen werden.", "warn")
            receipt_errors = {"__all__": f"Einbuchung fehlgeschlagen: {exc}"}
            response = products_edit_get(product_id=int(p.id), request=request, user=user, db=db)
            response.context["show_receipt_block"] = True
            response.context["receipt_form_data"] = form_data
            response.context["receipt_form_errors"] = receipt_errors
            response.context["first_error_field_id"] = _first_error_field_id(receipt_errors, PRODUCT_RECEIPT_FIELD_IDS)
            return _rerender_template_response(response)

        _flash(request, "Produkt gespeichert und direkt eingebucht.", "info")
        return RedirectResponse(f"/catalog/products/{p.id}?receipt_saved=1", status_code=302)

    _flash(request, "Produkt angelegt." if created_new_product else "Vorhandenes Produkt über Datenblatt aktualisiert.", "info")
    return RedirectResponse(f"/catalog/products/{p.id}/edit", status_code=302)


@app.get("/catalog/products/{product_id}/edit", response_class=HTMLResponse)
def products_edit_get(product_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    p = db.get(Product, product_id)
    if not p:
        raise HTTPException(status_code=404)
    draft_key = f"draft:/catalog/products/edit:{int(product_id)}"
    prefill_form_data: dict[str, str | list[str]] = {}
    if not request.query_params:
        loaded = _draft_get(request, draft_key)
        if isinstance(loaded, dict):
            prefill_form_data = dict(loaded)

    selected_area_id = _to_int(_form_scalar(prefill_form_data, "area_id"), int(p.area_id or 0))
    selected_kind_id = _to_int(_form_scalar(prefill_form_data, "device_kind_id"), int(p.device_kind_id or 0))
    selected_type_id = _to_int(_form_scalar(prefill_form_data, "device_type_id"), int(p.device_type_id or 0))
    areas, kinds, types, selected_area_id, selected_kind_id, selected_type_id = _catalog_cascade_state(
        db,
        selected_area_id=selected_area_id,
        selected_kind_id=selected_kind_id,
        selected_type_id=selected_type_id,
    )
    manufacturers = db.query(Manufacturer).filter(Manufacturer.active == True).order_by(Manufacturer.name.asc()).all()
    if p.manufacturer_id and all(int(m.id) != int(p.manufacturer_id) for m in manufacturers):
        selected_manufacturer = db.get(Manufacturer, p.manufacturer_id)
        if selected_manufacturer:
            manufacturers.append(selected_manufacturer)
            manufacturers = sorted(manufacturers, key=lambda m: (str(m.name or "").lower(), m.id))
    warehouses = db.query(Warehouse).order_by(Warehouse.name.asc()).all()
    suppliers = db.query(Supplier).filter(Supplier.active == True).order_by(Supplier.name.asc()).all()
    owners = db.query(Owner).filter(Owner.active == True).order_by(Owner.name.asc()).all()
    condition_defs = _get_condition_defs(db, active_only=True, include_fallback=True)
    receipt_defaults = _receipt_defaults(db)

    attrs: list[AttributeDef] = []
    val_map = {v.attribute_id: v.value_text for v in p.attribute_values}
    val_multi_map: dict[int, list[str]] = {}
    options_map: dict[int, list[str]] = {}
    grouped: dict[str, list[AttributeDef]] = {}
    for a in attrs:
        options = _enum_options_from_json(a.enum_options_json)
        options_map[a.id] = options
        if a.value_type == "enum" and a.is_multi:
            try:
                parsed = json.loads(val_map.get(a.id, "") or "[]")
                if isinstance(parsed, list):
                    val_multi_map[a.id] = [str(v) for v in parsed]
                else:
                    val_multi_map[a.id] = []
            except Exception:
                val_multi_map[a.id] = []
        group_name = (a.group_name or "").strip() or "Ohne Gruppe"
        grouped.setdefault(group_name, []).append(a)
    _apply_product_attribute_form_values(attrs, val_map, val_multi_map, prefill_form_data)
    attrs_grouped = sorted(grouped.items(), key=lambda item: (item[0] != "Ohne Gruppe", item[0].lower()))
    min_rows = (
        db.query(MinStock)
        .filter(MinStock.product_id == p.id)
        .order_by(MinStock.warehouse_id.asc(), MinStock.bin_id.asc())
        .all()
    )
    bins = db.query(WarehouseBin).order_by(WarehouseBin.warehouse_id.asc(), WarehouseBin.code.asc()).all()
    selected_item_type = _normalize_item_type(p.item_type, fallback="material")
    form_schema = _product_form_schema(db, selected_item_type)

    return templates.TemplateResponse(
        "catalog/product_form.html",
        _ctx(
            request,
            user=user,
            product=p,
            areas=areas,
            kinds=kinds,
            types=types,
            manufacturers=manufacturers,
            item_types=ITEM_TYPE_CHOICES,
            item_type_labels=ITEM_TYPE_LABELS,
            warehouses=warehouses,
            suppliers=suppliers,
            owners=owners,
            condition_defs=condition_defs,
            receipt_defaults=receipt_defaults,
            attrs=attrs,
            attrs_grouped=attrs_grouped,
            val_map=val_map,
            val_multi_map=val_multi_map,
            options_map=options_map,
            min_rows=min_rows,
            bins=bins,
            selected_item_type=selected_item_type,
            item_type_locked=True,
            selected_area_id=selected_area_id,
            selected_kind_id=selected_kind_id,
            selected_type_id=selected_type_id,
            form_schema=form_schema,
            form_data=prefill_form_data,
            asset_form_defaults=_catalog_asset_form_defaults(db, p, prefill_form_data),
            document_assets=_catalog_product_document_assets(db, p),
            form_errors={},
            first_error_field_id="",
            draft_key=draft_key,
            show_receipt_block=False,
            receipt_form_data={},
            receipt_form_errors={},
        ),
    )


@app.post("/catalog/products/{product_id}/edit")
async def products_edit_post(product_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    p = db.get(Product, product_id)
    if not p:
        raise HTTPException(status_code=404)
    form = await request.form()
    form_data = _extract_form_data(form)
    action = (form.get("action") or "save").strip().lower()
    wants_receipt = action == "save_and_receipt"
    item_type = _normalize_item_type(p.item_type, fallback="material")
    form_data["item_type"] = item_type
    draft_key = f"draft:/catalog/products/edit:{int(product_id)}"
    _draft_set(request, draft_key, form_data)
    visible_fields, required_fields = _product_form_key_sets(db, item_type)

    text_values: dict[str, str] = {}
    select_values: dict[str, int | None] = {}
    form_errors: dict[str, str] = {}

    def add_error(field_key: str, message: str) -> None:
        if field_key not in form_errors:
            form_errors[field_key] = message

    for key in visible_fields:
        if key in SELECT_FIELD_KEYS:
            value, exists = _parse_product_select_id(db, key, form.get(key))
            select_values[key] = value if exists else None
            if key in required_fields and not value:
                add_error(key, f"Feld '{_product_field_label(key)}' ist erforderlich.")
            elif value and not exists:
                add_error(key, f"Ungültiger Wert für Feld '{_product_field_label(key)}'.")
            continue
        text_values[key] = (form.get(key) or "").strip()
        if key in required_fields and not text_values[key]:
            add_error(key, f"Feld '{_product_field_label(key)}' ist erforderlich.")

    datasheet_upload = form.get("datasheet_upload")
    manual_upload = form.get("manual_upload")
    energy_label_upload = form.get("energy_label_upload")
    pdf_guess = _catalog_guess_product_core_from_pdf_upload(db, datasheet_upload) if item_type == "appliance" else {}
    if item_type == "appliance" and pdf_guess:
        if "manufacturer_id" in visible_fields and not select_values.get("manufacturer_id") and int(pdf_guess.get("manufacturer_id") or 0) > 0:
            select_values["manufacturer_id"] = int(pdf_guess.get("manufacturer_id") or 0)
            form_errors.pop("manufacturer_id", None)
        if "device_kind_id" in visible_fields and not select_values.get("device_kind_id") and int(pdf_guess.get("device_kind_id") or 0) > 0:
            select_values["device_kind_id"] = int(pdf_guess.get("device_kind_id") or 0)
            form_errors.pop("device_kind_id", None)
        for key in ("sales_name", "material_no", "product_title_1", "product_title_2", "description", "ean", "name"):
            if key in visible_fields and not text_values.get(key) and str(pdf_guess.get(key) or "").strip():
                text_values[key] = str(pdf_guess.get(key) or "").strip()
                form_errors.pop(key, None)

    updated_name = text_values.get("name", "") if "name" in visible_fields else p.name
    if item_type == "appliance" and (("name" not in visible_fields) or not updated_name):
        updated_name = text_values.get("sales_name", "") or text_values.get("product_title_1", "") or text_values.get("material_no", "") or (p.name or "")
    if not updated_name:
        add_error("name", "Feld 'Bezeichnung' ist erforderlich.")

    manufacturer_id = select_values.get("manufacturer_id") if "manufacturer_id" in visible_fields else p.manufacturer_id
    manufacturer_row = db.get(Manufacturer, manufacturer_id) if manufacturer_id else None
    if item_type == "appliance" and "manufacturer_id" in visible_fields and not manufacturer_id:
        add_error("manufacturer_id", "Für Großgeräte ist ein Hersteller Pflicht oder muss aus dem Datenblatt erkannt werden.")

    material_no = text_values.get("material_no") or None if "material_no" in visible_fields else p.material_no
    if "material_no" in visible_fields and material_no:
        existing_material = (
            db.query(Product)
            .filter(func.lower(Product.material_no) == material_no.lower(), Product.id != p.id)
            .one_or_none()
        )
        if existing_material:
            add_error("material_no", "Materialnummer existiert bereits.")

    ean = p.ean
    if "ean" in visible_fields:
        try:
            ean = normalize_ean(text_values.get("ean"))
        except ValueError as e:
            add_error("ean", f"Ungültige EAN: {e}")
    asset_inputs = _parse_product_asset_urls(form, add_error)
    if item_type == "appliance":
        selected_kind = select_values.get("device_kind_id") if "device_kind_id" in visible_fields else p.device_kind_id
        if not selected_kind:
            add_error("device_kind_id", "Für Großgeräte ist eine Geräteart Pflicht oder muss aus dem Datenblatt erkannt werden.")

    if form_errors:
        for msg in list(form_errors.values())[:5]:
            _flash(request, msg, "error")
        response = products_edit_get(product_id=product_id, request=request, user=user, db=db)
        response.context["form_data"] = form_data
        response.context["form_errors"] = form_errors
        response.context["first_error_field_id"] = _first_error_field_id(form_errors, PRODUCT_FORM_FIELD_IDS)
        response.context["show_receipt_block"] = wants_receipt
        response.context["receipt_form_data"] = form_data
        response.context["receipt_form_errors"] = {}
        _apply_product_attribute_form_values(
            response.context.get("attrs", []),
            response.context.get("val_map", {}),
            response.context.get("val_multi_map", {}),
            form_data,
        )
        return _rerender_template_response(response)

    p.name = updated_name
    if "manufacturer_id" in visible_fields:
        p.manufacturer_id = manufacturer_id
        p.manufacturer = manufacturer_row.name if manufacturer_row else None
    if "material_no" in visible_fields:
        p.material_no = material_no
    if "sales_name" in visible_fields:
        p.sales_name = text_values.get("sales_name") or None
    p.manufacturer_name = None
    if "product_title_1" in visible_fields:
        p.product_title_1 = text_values.get("product_title_1") or None
    if "product_title_2" in visible_fields:
        p.product_title_2 = text_values.get("product_title_2") or None
    if "sku" in visible_fields:
        p.sku = text_values.get("sku") or None
    if "ean" in visible_fields:
        p.ean = ean
    if "description" in visible_fields:
        p.description = text_values.get("description") or None
    if "device_kind_id" in visible_fields:
        p.device_kind_id = select_values.get("device_kind_id")
    p.area_id = None
    p.device_type_id = None
    p.track_mode = "quantity"

    attrs: list[AttributeDef] = []
    parsed_values, parse_errors = _parse_product_attribute_values(form, attrs)
    if parse_errors:
        attrs_by_name = {str(a.name or "").strip().lower(): a for a in attrs}
        for msg in parse_errors:
            after_colon = str(msg).split(":", 1)[1].strip().lower() if ":" in str(msg) else ""
            attr = attrs_by_name.get(after_colon)
            if attr:
                add_error(f"attr_{int(attr.id)}", msg)
            else:
                add_error("__all__", msg)
        for msg in list(form_errors.values())[:5]:
            _flash(request, msg, "error")
        response = products_edit_get(product_id=product_id, request=request, user=user, db=db)
        response.context["form_data"] = form_data
        response.context["form_errors"] = form_errors
        response.context["first_error_field_id"] = _first_error_field_id(form_errors, PRODUCT_FORM_FIELD_IDS)
        response.context["show_receipt_block"] = wants_receipt
        response.context["receipt_form_data"] = form_data
        response.context["receipt_form_errors"] = {}
        _apply_product_attribute_form_values(
            response.context.get("attrs", []),
            response.context.get("val_map", {}),
            response.context.get("val_multi_map", {}),
            form_data,
        )
        return _rerender_template_response(response)

    # update attribute values for applicable attributes
    for a in attrs:
        value_text = parsed_values.get(a.id, "")
        pav = (
            db.query(ProductAttributeValue)
            .filter(ProductAttributeValue.product_id == p.id, ProductAttributeValue.attribute_id == a.id)
            .one_or_none()
        )
        if value_text != "":
            if pav:
                pav.value_text = value_text
                db.add(pav)
            else:
                db.add(ProductAttributeValue(product_id=p.id, attribute_id=a.id, value_text=value_text))
        elif pav:
            db.delete(pav)

    db.add(p)
    db.flush()
    try:
        _catalog_prune_manual_image_assets(
            db,
            product=p,
            submitted_slots={int(key) for key in dict(asset_inputs.get("images") or {}).keys()},
        )
        asset_summary = _catalog_sync_product_assets(
            db,
            product=p,
            asset_inputs=asset_inputs,
            manufacturer_row=manufacturer_row,
            datasheet_upload=datasheet_upload,
            manual_upload=manual_upload,
            energy_label_upload=energy_label_upload,
            source_kind="manual",
        )
        if int(asset_summary.get("candidate_updates") or 0) > 0:
            _flash(request, f"Analyse hat {int(asset_summary.get('candidate_updates') or 0)} Merkmalskandidat(en) aktualisiert.", "info")
        datasheet_text = _catalog_product_datasheet_text(db, p)
        if datasheet_text:
            pdf_review = _catalog_apply_pdf_review_to_product(
                db,
                product=p,
                pdf_text=datasheet_text,
                manufacturer_row=manufacturer_row,
                device_kind_row=db.get(DeviceKind, int(p.device_kind_id)) if int(p.device_kind_id or 0) > 0 else None,
            )
            if int(pdf_review.get("applied_count") or 0) > 0:
                _flash(request, f"Datenblatt hat {int(pdf_review.get('applied_count') or 0)} Attributwerte aktualisiert.", "info")
        asset_failures = list(asset_summary.get("failures") or [])
        if asset_failures:
            _flash(request, f"Einige Assets konnten nicht verarbeitet werden: {asset_failures[0]}", "warn")
    except Exception as exc:
        _flash(request, f"Produkt wurde gespeichert, Asset-/PDF-Verarbeitung war nur teilweise erfolgreich: {exc}", "warn")
    _catalog_sync_legacy_image_fields(p, asset_inputs)
    _refresh_product_search_blob(db, p)
    write_product_outbox_event(db, p, event_type="ProductUpdated")
    db.commit()
    _draft_clear(request, draft_key)

    if wants_receipt:
        payload, receipt_errors = _direct_receipt_payload_from_form(db, form)
        if receipt_errors:
            _flash(request, "Produkt wurde gespeichert. Einbuchung konnte nicht abgeschlossen werden.", "warn")
            for msg in list(receipt_errors.values())[:5]:
                _flash(request, msg, "error")
            response = products_edit_get(product_id=product_id, request=request, user=user, db=db)
            response.context["show_receipt_block"] = True
            response.context["receipt_form_data"] = form_data
            response.context["receipt_form_errors"] = receipt_errors
            response.context["first_error_field_id"] = _first_error_field_id(receipt_errors, PRODUCT_RECEIPT_FIELD_IDS)
            return _rerender_template_response(response)
        try:
            _apply_direct_receipt(
                db=db,
                product_id=int(p.id),
                actor_user_id=user.id,
                payload=payload,
                reference=f"PRODUKT-{int(p.id)}",
                note="Direkt-Einbuchung beim Produktspeichern",
            )
            db.commit()
        except Exception as exc:
            db.rollback()
            _flash(request, "Produkt wurde gespeichert. Einbuchung konnte nicht abgeschlossen werden.", "warn")
            receipt_errors = {"__all__": f"Einbuchung fehlgeschlagen: {exc}"}
            response = products_edit_get(product_id=product_id, request=request, user=user, db=db)
            response.context["show_receipt_block"] = True
            response.context["receipt_form_data"] = form_data
            response.context["receipt_form_errors"] = receipt_errors
            response.context["first_error_field_id"] = _first_error_field_id(receipt_errors, PRODUCT_RECEIPT_FIELD_IDS)
            return _rerender_template_response(response)
        _flash(request, "Produkt gespeichert und eingebucht.", "info")
        return RedirectResponse(f"/catalog/products/{p.id}?receipt_saved=1", status_code=302)

    _flash(request, "Produkt gespeichert.", "info")
    return RedirectResponse(f"/catalog/products/{p.id}/edit", status_code=302)


def _product_archive_action(product_id: int, request: Request, db: Session):
    product = db.get(Product, product_id)
    if not product:
        raise HTTPException(status_code=404)
    if not bool(product.active):
        product.active = True
        db.add(product)
        db.flush()
        write_product_outbox_event(db, product, event_type="ProductUpdated")
        db.commit()
        _flash(request, "Produkt wurde reaktiviert.", "info")
        return RedirectResponse(f"/catalog/products/{product_id}", status_code=302)

    non_zero_balances = (
        db.query(StockBalance)
        .filter(StockBalance.product_id == product_id, StockBalance.quantity != 0)
        .count()
    )
    serials_in_stock = (
        db.query(StockSerial)
        .filter(StockSerial.product_id == product_id, StockSerial.status.in_(("in_stock", "reserved")))
        .count()
    )
    active_reservations = (
        db.query(Reservation)
        .filter(Reservation.product_id == product_id, Reservation.status == "active")
        .count()
    )
    if non_zero_balances or serials_in_stock or active_reservations:
        _flash(
            request,
            "Produkt kann nicht archiviert werden: Bestand ist nicht 0 oder es gibt aktive Reservierungen.",
            "error",
        )
        return RedirectResponse(f"/catalog/products/{product_id}/edit", status_code=302)

    product.active = False
    db.add(product)
    db.flush()
    write_product_outbox_event(db, product, event_type="ProductDeleted")
    db.commit()
    _flash(request, "Produkt wurde archiviert.", "info")
    return RedirectResponse("/catalog/products", status_code=302)


@app.post("/catalog/products/{product_id}/archive")
def product_archive(product_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    _ = user
    return _product_archive_action(product_id, request, db)


@app.post("/catalog/products/{product_id}/delete")
def product_delete(product_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    _ = user
    return _product_archive_action(product_id, request, db)


@app.post("/catalog/products/{product_id}/min_stock/set")
async def product_min_stock_set(product_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    product = db.get(Product, product_id)
    if not product:
        raise HTTPException(status_code=404)
    form = await request.form()
    warehouse_id = _to_int(form.get("warehouse_id"))
    bin_id = _to_int(form.get("bin_id")) or None
    min_qty = _to_int(form.get("min_qty"))
    if not warehouse_id:
        _flash(request, "Bitte Lager auswählen.", "error")
        return RedirectResponse(f"/catalog/products/{product_id}/edit", status_code=302)
    if bin_id:
        b = db.get(WarehouseBin, bin_id)
        if not b or b.warehouse_id != warehouse_id:
            _flash(request, "Fach passt nicht zum Lager.", "error")
            return RedirectResponse(f"/catalog/products/{product_id}/edit", status_code=302)

    q = db.query(MinStock).filter(MinStock.product_id == product_id, MinStock.warehouse_id == warehouse_id)
    if bin_id is None:
        q = q.filter(MinStock.bin_id.is_(None))
    else:
        q = q.filter(MinStock.bin_id == bin_id)
    row = q.one_or_none()

    if min_qty <= 0:
        if row:
            db.delete(row)
            db.commit()
            _flash(request, "Mindestbestand entfernt.", "info")
        else:
            _flash(request, "Kein Mindestbestand gesetzt.", "info")
        return RedirectResponse(f"/catalog/products/{product_id}/edit", status_code=302)

    if not row:
        row = MinStock(product_id=product_id, warehouse_id=warehouse_id, bin_id=bin_id, min_qty=min_qty)
    else:
        row.min_qty = min_qty
    db.add(row)
    db.commit()
    _flash(request, "Mindestbestand gespeichert.", "info")
    return RedirectResponse(f"/catalog/products/{product_id}/edit", status_code=302)


