def _crm_clean_text(value: str | None) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip())


def _crm_normalize_key(value: str | None) -> str:
    return _crm_clean_text(value).casefold()


def _crm_normalize_email(value: str | None) -> str:
    return _crm_normalize_key(value)


def _crm_normalize_phone(value: str | None) -> str:
    raw = re.sub(r"[^0-9+]", "", str(value or "").strip())
    if raw.startswith("00"):
        raw = f"+{raw[2:]}"
    if raw.startswith("+"):
        return f"+{re.sub(r'[^0-9]', '', raw)}"
    return re.sub(r"[^0-9]", "", raw)


def _crm_known_email_domains(db: Session, limit: int = 160) -> set[str]:
    domain_counts: dict[str, int] = {}

    def add_email(email_value: str | None) -> None:
        email_clean = _crm_clean_text(email_value).lower()
        if "@" not in email_clean:
            return
        domain = email_clean.rsplit("@", 1)[-1].strip()
        if not domain:
            return
        domain_counts[domain] = domain_counts.get(domain, 0) + 1

    for row in db.query(CrmAddress.email).filter(CrmAddress.email.isnot(None)).all():
        add_email(row[0] if isinstance(row, tuple) else getattr(row, "email", None))
    for row in db.query(CustomerContactPerson.email).filter(CustomerContactPerson.email.isnot(None)).all():
        add_email(row[0] if isinstance(row, tuple) else getattr(row, "email", None))
    for row in db.query(ServiceLocation.contact_email).filter(ServiceLocation.contact_email.isnot(None)).all():
        add_email(row[0] if isinstance(row, tuple) else getattr(row, "contact_email", None))
    ordered = sorted(domain_counts.items(), key=lambda item: (-item[1], item[0]))
    return {domain for domain, _ in ordered[: max(20, int(limit or 160))]}


def _crm_party_display_name(display_name: str | None, first_name: str | None, last_name: str | None) -> str:
    cleaned = _crm_clean_text(display_name)
    if cleaned:
        return cleaned
    joined = _crm_clean_text(f"{str(first_name or '').strip()} {str(last_name or '').strip()}")
    return joined


def _crm_pick_default_address(address_rows: list[CrmAddress]) -> CrmAddress | None:
    active_rows = [row for row in address_rows if bool(row.active)]
    rows = active_rows or address_rows
    for row in rows:
        if bool(row.is_default):
            return row
    return rows[0] if rows else None


def _crm_party_address_maps(db: Session, party_ids: list[int]) -> tuple[dict[int, list[CrmAddress]], dict[int, CrmAddress | None]]:
    by_party: dict[int, list[CrmAddress]] = {}
    default_map: dict[int, CrmAddress | None] = {}
    if not party_ids:
        return by_party, default_map
    rows = (
        db.query(CrmAddress)
        .filter(CrmAddress.party_id.in_(party_ids))
        .order_by(CrmAddress.is_default.desc(), CrmAddress.active.desc(), CrmAddress.id.asc())
        .all()
    )
    for row in rows:
        by_party.setdefault(int(row.party_id), []).append(row)
    for party_id in party_ids:
        default_map[int(party_id)] = _crm_pick_default_address(by_party.get(int(party_id), []))
    return by_party, default_map


def _crm_address_summary(address: CrmAddress | None) -> str:
    if not address:
        return ""
    parts = []
    usage_label = _crm_address_usage_label(getattr(address, "usage_type", "") or "")
    street = _crm_clean_text(f"{str(address.street or '').strip()} {str(address.house_no or '').strip()}")
    city = _crm_clean_text(f"{str(address.zip_code or '').strip()} {str(address.city or '').strip()}")
    if usage_label and usage_label != "-":
        parts.append(usage_label)
    if street:
        parts.append(street)
    if city:
        parts.append(city)
    return " | ".join(parts)


def _crm_customer_label(customer: MasterCustomer | None, party: Party | None, address: CrmAddress | None = None) -> str:
    if not customer or not party:
        return "-"
    city = _crm_clean_text(f"{str(address.zip_code or '').strip()} {str(address.city or '').strip()}") if address else ""
    bits = [str(customer.customer_no_internal or "").strip(), str(party.display_name or "").strip()]
    if city:
        bits.append(city)
    return " | ".join([bit for bit in bits if bit])


def _crm_location_label(location: ServiceLocation | None, address: CrmAddress | None = None, customer_label: str = "") -> str:
    if not location:
        return "-"
    bits = [str(location.location_label or "").strip()]
    if customer_label:
        bits.append(customer_label)
    address_text = _crm_address_summary(address)
    if address_text:
        bits.append(address_text)
    return " | ".join([bit for bit in bits if bit])


def _crm_parse_address_payload(form, prefix: str = "") -> dict[str, str | bool | None]:
    usage_type = _crm_normalize_key(form.get(f"{prefix}usage_type")) or "other"
    if usage_type not in CRM_ADDRESS_USAGE_CHOICES:
        usage_type = "other"
    return {
        "label": _crm_clean_text(form.get(f"{prefix}label") or "") or None,
        "usage_type": usage_type,
        "street": _crm_clean_text(form.get(f"{prefix}street") or "") or None,
        "house_no": _crm_clean_text(form.get(f"{prefix}house_no") or "") or None,
        "zip_code": _crm_clean_text(form.get(f"{prefix}zip_code") or "") or None,
        "city": _crm_clean_text(form.get(f"{prefix}city") or "") or None,
        "country_code": _crm_clean_text(form.get(f"{prefix}country_code") or "") or None,
        "email": _crm_clean_text(form.get(f"{prefix}email") or "") or None,
        "phone": _crm_clean_text(form.get(f"{prefix}phone") or "") or None,
    }


def _crm_address_payload_has_content(payload: dict[str, str | bool | None]) -> bool:
    for key in ("label", "street", "house_no", "zip_code", "city", "country_code", "email", "phone"):
        if str(payload.get(key) or "").strip():
            return True
    return False


def _crm_apply_address_payload(address: CrmAddress, payload: dict[str, str | bool | None]) -> None:
    address.label = str(payload.get("label") or "").strip() or None
    address.usage_type = str(payload.get("usage_type") or "other").strip() or "other"
    address.street = str(payload.get("street") or "").strip() or None
    address.house_no = str(payload.get("house_no") or "").strip() or None
    address.zip_code = str(payload.get("zip_code") or "").strip() or None
    address.city = str(payload.get("city") or "").strip() or None
    address.country_code = str(payload.get("country_code") or "").strip() or None
    address.email = str(payload.get("email") or "").strip() or None
    address.phone = str(payload.get("phone") or "").strip() or None


def _crm_clear_address_validation(address: CrmAddress) -> None:
    address.address_validation_status = None
    address.address_validation_message = None
    address.address_validation_source = None
    address.normalized_street = None
    address.normalized_house_no = None
    address.normalized_zip_code = None
    address.normalized_city = None
    address.normalized_country_code = None
    address.address_validated_at = None


def _crm_apply_address_validation_result(address: CrmAddress, result: dict[str, object] | None) -> dict[str, object]:
    payload = dict(result or {})
    status = _crm_clean_text(payload.get("status") or "") or None
    if not status:
        _crm_clear_address_validation(address)
        return {"status": "", "auto_corrected": False}
    address.address_validation_status = status
    address.address_validation_message = _crm_clean_text(payload.get("message") or "") or None
    address.address_validation_source = _crm_clean_text(payload.get("source") or "") or None
    address.normalized_street = _crm_clean_text(payload.get("normalized_street") or "") or None
    address.normalized_house_no = _crm_clean_text(payload.get("normalized_house_no") or "") or None
    address.normalized_zip_code = _crm_clean_text(payload.get("normalized_zip_code") or "") or None
    address.normalized_city = _crm_clean_text(payload.get("normalized_city") or "") or None
    address.normalized_country_code = _crm_clean_text(payload.get("normalized_country_code") or "") or None
    address.address_validated_at = _utcnow_naive()
    auto_corrected = False
    if status == "valid":
        updates = {
            "street": address.normalized_street,
            "house_no": address.normalized_house_no,
            "zip_code": address.normalized_zip_code,
            "city": address.normalized_city,
            "country_code": address.normalized_country_code,
        }
        for attr, normalized in updates.items():
            normalized_clean = _crm_clean_text(normalized or "") or None
            current_clean = _crm_clean_text(getattr(address, attr, None) or "") or None
            if normalized_clean and normalized_clean != current_clean:
                setattr(address, attr, normalized_clean)
                auto_corrected = True
    return {"status": status, "auto_corrected": auto_corrected}


def _crm_clear_email_validation(
    row,
    *,
    status_attr: str,
    message_attr: str,
    suggestion_attr: str,
    checked_attr: str,
) -> None:
    setattr(row, status_attr, None)
    setattr(row, message_attr, None)
    setattr(row, suggestion_attr, None)
    setattr(row, checked_attr, None)


def _crm_apply_email_validation_result(
    row,
    result: dict[str, object] | None,
    *,
    status_attr: str,
    message_attr: str,
    suggestion_attr: str,
    checked_attr: str,
) -> str:
    payload = dict(result or {})
    status = _crm_clean_text(payload.get("status") or "") or None
    if not status:
        _crm_clear_email_validation(
            row,
            status_attr=status_attr,
            message_attr=message_attr,
            suggestion_attr=suggestion_attr,
            checked_attr=checked_attr,
        )
        return ""
    setattr(row, status_attr, status)
    setattr(row, message_attr, _crm_clean_text(payload.get("message") or "") or None)
    setattr(row, suggestion_attr, _crm_clean_text(payload.get("suggestion") or "") or None)
    setattr(row, checked_attr, _utcnow_naive())
    return status


def _crm_validate_address_row(address: CrmAddress, cache: dict[str, dict[str, object]] | None = None) -> dict[str, object]:
    signature = "|".join(
        [
            _crm_normalize_key(address.street),
            _crm_normalize_key(address.house_no),
            _crm_normalize_key(address.zip_code),
            _crm_normalize_key(address.city),
            _crm_normalize_key(address.country_code or "DE"),
        ]
    )
    if cache is not None and signature in cache:
        result = dict(cache[signature])
    else:
        result = quality_validate_address(
            street=address.street,
            house_no=address.house_no,
            zip_code=address.zip_code,
            city=address.city,
            country_code=address.country_code or "DE",
        )
        if cache is not None:
            cache[signature] = dict(result)
    applied = _crm_apply_address_validation_result(address, result)
    result["auto_corrected"] = bool(applied.get("auto_corrected"))
    return result


def _crm_validate_email_value(
    email_value: str | None,
    *,
    known_domains: set[str],
    cache: dict[str, dict[str, object]] | None = None,
) -> dict[str, object]:
    email_clean = _crm_clean_text(email_value).lower()
    if not email_clean:
        return {"status": "", "message": "", "suggestion": ""}
    if cache is not None and email_clean in cache:
        return dict(cache[email_clean])
    result = quality_validate_email_address(email_clean, known_domains=known_domains)
    if cache is not None:
        cache[email_clean] = dict(result)
    return result


def _crm_bank_source_document_id(value: str | None) -> str:
    text = _crm_clean_text(value)
    if not text.startswith("paperless:"):
        return ""
    return text.split(":", 1)[-1].strip()


def _crm_customer_bank_summary(customer: MasterCustomer, paperless_settings: dict[str, str | bool] | None = None) -> dict[str, object]:
    source_document_id = _crm_bank_source_document_id(customer.bank_source)
    source_url = ""
    if source_document_id and paperless_settings:
        source_url = paperless_build_document_url(paperless_settings, source_document_id)
    source_label = ""
    if source_document_id:
        source_label = f"Paperless {source_document_id}"
    elif _crm_clean_text(customer.bank_source):
        source_label = _crm_clean_text(customer.bank_source)
    return {
        "account_holder": _crm_clean_text(customer.bank_account_holder),
        "iban": _crm_clean_text(customer.bank_iban),
        "bic": _crm_clean_text(customer.bank_bic),
        "bank_name": _crm_clean_text(customer.bank_name),
        "confidence": int(customer.bank_confidence or 0),
        "source_label": source_label,
        "source_url": source_url,
    }


def _crm_sync_customer_bank_from_paperless(db: Session, customer: MasterCustomer, party: Party) -> dict[str, object]:
    candidate_items: dict[str, DocumentInboxItem] = {}
    for row in _paperless_customer_candidate_items(db, int(customer.id), limit=24):
        candidate_items[str(row.paperless_document_id or "")] = row
    for link in _paperless_links_for_object(db, "customer", int(customer.id)):
        item = _document_inbox_item_from_paperless_id(db, str(link.paperless_document_id or ""))
        if item is not None:
            candidate_items[str(item.paperless_document_id or "")] = item
    candidates: list[dict[str, object]] = []
    for row in candidate_items.values():
        text = _document_search_blob(row)
        row_candidates = extract_bank_candidates_from_text(
            text,
            title=row.title,
            correspondent=row.correspondent,
            document_type=row.document_type,
            customer_name=party.display_name,
        )
        for candidate in row_candidates:
            candidate["source_document_id"] = str(row.paperless_document_id or "")
            candidates.append(candidate)
    best = pick_best_bank_candidate(candidates)
    if not best:
        return {"updated": 0, "candidate_count": 0, "skipped_conflict": 0}
    new_iban = quality_normalize_iban(str(best.get("iban") or ""))
    if not new_iban:
        return {"updated": 0, "candidate_count": len(candidates), "skipped_conflict": 0}
    current_iban = quality_normalize_iban(customer.bank_iban)
    if current_iban and current_iban != new_iban:
        return {
            "updated": 0,
            "candidate_count": len(candidates),
            "skipped_conflict": 1,
            "iban": new_iban,
        }
    if int(best.get("confidence") or 0) < 6:
        return {
            "updated": 0,
            "candidate_count": len(candidates),
            "skipped_conflict": 0,
            "iban": new_iban,
        }
    changed = False

    def assign(attr: str, value: str | None) -> None:
        nonlocal changed
        cleaned = _crm_clean_text(value) or None
        current = _crm_clean_text(getattr(customer, attr, None) or "") or None
        if cleaned and cleaned != current:
            setattr(customer, attr, cleaned)
            changed = True

    assign("bank_iban", new_iban)
    assign("bank_bic", str(best.get("bic") or ""))
    assign("bank_account_holder", str(best.get("account_holder") or party.display_name or ""))
    assign("bank_name", str(best.get("bank_name") or ""))
    bank_source = f"paperless:{str((best.get('source_document_ids') or [''])[0] or '').strip()}"
    if bank_source.strip(":") and bank_source != _crm_clean_text(customer.bank_source):
        customer.bank_source = bank_source
        changed = True
    confidence = int(best.get("confidence") or 0)
    if int(customer.bank_confidence or 0) != confidence:
        customer.bank_confidence = confidence
        changed = True
    customer.bank_validated_at = _utcnow_naive()
    if not changed:
        return {"updated": 0, "candidate_count": len(candidates), "skipped_conflict": 0, "iban": new_iban}
    customer.updated_at = _utcnow_naive()
    db.add(customer)
    return {"updated": 1, "candidate_count": len(candidates), "skipped_conflict": 0, "iban": new_iban}


def _crm_apply_customer_bank_form(customer: MasterCustomer, form) -> None:
    prev_holder = _crm_clean_text(customer.bank_account_holder) or None
    prev_iban = quality_normalize_iban(customer.bank_iban) or None
    prev_bic = _crm_clean_text(customer.bank_bic).upper() or None
    prev_bank_name = _crm_clean_text(customer.bank_name) or None
    customer.bank_account_holder = _crm_clean_text(form.get("bank_account_holder") or "") or None
    customer.bank_iban = quality_normalize_iban(form.get("bank_iban") or "") or None
    customer.bank_bic = _crm_clean_text(form.get("bank_bic") or "").upper() or None
    customer.bank_name = _crm_clean_text(form.get("bank_name") or "") or None
    has_bank_data = any(
        (
            customer.bank_account_holder,
            customer.bank_iban,
            customer.bank_bic,
            customer.bank_name,
        )
    )
    if has_bank_data:
        changed = any(
            (
                customer.bank_account_holder != prev_holder,
                customer.bank_iban != prev_iban,
                customer.bank_bic != prev_bic,
                customer.bank_name != prev_bank_name,
            )
        )
        if changed or not _crm_clean_text(customer.bank_source):
            customer.bank_source = "manual"
        customer.bank_validated_at = _utcnow_naive()
        customer.bank_confidence = customer.bank_confidence if customer.bank_confidence is not None else 100
    else:
        customer.bank_source = None
        customer.bank_validated_at = None
        customer.bank_confidence = None


def _crm_customer_quality_rows(
    customer: MasterCustomer,
    addresses: list[CrmAddress],
    contact_rows: list[dict[str, object]],
    service_location_cards: list[dict[str, object]],
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    severity = {
        "invalid": 0,
        "undeliverable": 1,
        "review": 2,
        "partial": 3,
        "unknown": 4,
        "": 9,
        "valid": 9,
    }
    for address in addresses:
        status = _crm_clean_text(address.address_validation_status)
        if status and status != "valid":
            rows.append(
                {
                    "scope": "address",
                    "title": address.label or _crm_address_usage_label(address.usage_type),
                    "status": status,
                    "status_label": _crm_quality_status_label(status),
                    "message": _crm_clean_text(address.address_validation_message),
                    "edit_url": f"/crm/kunden/{int(customer.id)}/adressen/{int(address.id)}/bearbeiten",
                }
            )
        email_status = _crm_clean_text(address.email_validation_status)
        if email_status and email_status != "valid":
            rows.append(
                {
                    "scope": "email",
                    "title": address.email or (address.label or "Adresse"),
                    "status": email_status,
                    "status_label": _crm_quality_status_label(email_status),
                    "message": _crm_clean_text(address.email_validation_message),
                    "edit_url": f"/crm/kunden/{int(customer.id)}/adressen/{int(address.id)}/bearbeiten",
                }
            )
    for item in contact_rows:
        row = item.get("row")
        party = item.get("party")
        if not row:
            continue
        status = _crm_clean_text(getattr(row, "email_validation_status", ""))
        if status and status != "valid":
            rows.append(
                {
                    "scope": "email",
                    "title": _crm_clean_text(getattr(row, "email", None)) or _crm_clean_text(getattr(party, "display_name", None)) or "Kontaktperson",
                    "status": status,
                    "status_label": _crm_quality_status_label(status),
                    "message": _crm_clean_text(getattr(row, "email_validation_message", None)),
                    "edit_url": f"/crm/kunden/{int(customer.id)}/kontaktpersonen/{int(row.id)}/bearbeiten",
                }
            )
    for item in service_location_cards:
        row = item.get("row")
        address = item.get("address")
        if row is None:
            continue
        status = _crm_clean_text(getattr(row, "contact_email_validation_status", ""))
        if status and status != "valid":
            rows.append(
                {
                    "scope": "email",
                    "title": _crm_clean_text(getattr(row, "contact_email", None)) or _crm_clean_text(getattr(row, "location_label", None)) or "Leistungsort",
                    "status": status,
                    "status_label": _crm_quality_status_label(status),
                    "message": _crm_clean_text(getattr(row, "contact_email_validation_message", None)),
                    "edit_url": f"/crm/kunden/{int(customer.id)}/standorte/{int(row.id)}/bearbeiten",
                }
            )
        address_status = _crm_clean_text(getattr(address, "address_validation_status", None)) if address else ""
        if address and address_status and address_status != "valid":
            rows.append(
                {
                    "scope": "address",
                    "title": _crm_clean_text(getattr(row, "location_label", None)) or address.label or "Leistungsort-Adresse",
                    "status": address_status,
                    "status_label": _crm_quality_status_label(address_status),
                    "message": _crm_clean_text(getattr(address, "address_validation_message", None)),
                    "edit_url": f"/crm/kunden/{int(customer.id)}/standorte/{int(row.id)}/bearbeiten",
                }
            )
    rows.sort(key=lambda item: (severity.get(str(item.get("status") or ""), 9), str(item.get("title") or "")))
    return rows[:18]


def _crm_clear_default_addresses(db: Session, party_id: int, keep_address_id: int = 0) -> None:
    rows = db.query(CrmAddress).filter(CrmAddress.party_id == int(party_id)).all()
    for row in rows:
        row.is_default = int(row.id) == int(keep_address_id)
        db.add(row)


def _crm_next_customer_no(db: Session) -> str:
    prefix = "MC-"
    rows = (
        db.query(MasterCustomer.customer_no_internal)
        .filter(MasterCustomer.customer_no_internal.like(f"{prefix}%"))
        .order_by(MasterCustomer.customer_no_internal.desc())
        .limit(1)
        .all()
    )
    seq = 1
    if rows and rows[0][0]:
        tail = str(rows[0][0]).replace(prefix, "", 1)
        try:
            seq = int(tail) + 1
        except Exception:
            seq = 1
    return f"{prefix}{seq:06d}"


def _crm_next_case_no(db: Session) -> str:
    year = dt.datetime.utcnow().year
    prefix = f"VG-{year}-"
    rows = (
        db.query(CrmCase.case_no)
        .filter(CrmCase.case_no.like(f"{prefix}%"))
        .order_by(CrmCase.case_no.desc())
        .limit(1)
        .all()
    )
    seq = 1
    if rows and rows[0][0]:
        tail = str(rows[0][0]).replace(prefix, "", 1)
        try:
            seq = int(tail) + 1
        except Exception:
            seq = 1
    return f"{prefix}{seq:04d}"


def _crm_customer_options(
    db: Session,
    *,
    include_ids: list[int] | None = None,
    limit: int = 300,
) -> list[dict[str, object]]:
    include_id_values = [int(value) for value in (include_ids or []) if int(value or 0) > 0]
    base_query = (
        db.query(MasterCustomer)
        .filter(MasterCustomer.status == "active")
        .order_by(MasterCustomer.customer_no_internal.asc())
    )
    rows: list[MasterCustomer] = []
    seen_ids: set[int] = set()
    if include_id_values:
        for row in db.query(MasterCustomer).filter(MasterCustomer.id.in_(include_id_values)).order_by(MasterCustomer.customer_no_internal.asc()).all():
            row_id = int(row.id or 0)
            if row_id > 0 and row_id not in seen_ids:
                seen_ids.add(row_id)
                rows.append(row)
    remaining = max(0, int(limit) - len(rows))
    if remaining > 0:
        query = base_query
        if seen_ids:
            query = query.filter(~MasterCustomer.id.in_(sorted(seen_ids)))
        for row in query.limit(remaining).all():
            row_id = int(row.id or 0)
            if row_id > 0 and row_id not in seen_ids:
                seen_ids.add(row_id)
                rows.append(row)
    party_ids = [int(row.party_id) for row in rows]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids)).all()} if party_ids else {}
    _, default_map = _crm_party_address_maps(db, party_ids)
    options = []
    for row in rows:
        party = parties.get(int(row.party_id))
        address = default_map.get(int(row.party_id))
        options.append({
            "id": int(row.id),
            "label": _crm_customer_label(row, party, address),
            "name": str(party.display_name or "").strip() if party else "",
            "street": str(address.street or "").strip() if address else "",
            "house_no": str(address.house_no or "").strip() if address else "",
            "zip_code": str(address.zip_code or "").strip() if address else "",
            "city": str(address.city or "").strip() if address else "",
            "country_code": str(address.country_code or "DE").strip() if address else "DE",
            "email": str(address.email or "").strip() if address else "",
        })
    return options


def _crm_location_options(
    db: Session,
    *,
    include_ids: list[int] | None = None,
    customer_ids: list[int] | None = None,
    limit: int = 300,
) -> list[dict[str, object]]:
    include_id_values = [int(value) for value in (include_ids or []) if int(value or 0) > 0]
    customer_id_values = [int(value) for value in (customer_ids or []) if int(value or 0) > 0]
    base_query = (
        db.query(ServiceLocation)
        .filter(ServiceLocation.active == True)
        .order_by(ServiceLocation.location_label.asc(), ServiceLocation.id.asc())
    )
    rows: list[ServiceLocation] = []
    seen_ids: set[int] = set()
    if include_id_values:
        for row in db.query(ServiceLocation).filter(ServiceLocation.id.in_(include_id_values)).order_by(ServiceLocation.location_label.asc(), ServiceLocation.id.asc()).all():
            row_id = int(row.id or 0)
            if row_id > 0 and row_id not in seen_ids:
                seen_ids.add(row_id)
                rows.append(row)
    if customer_id_values:
        query = base_query.filter(ServiceLocation.master_customer_id.in_(customer_id_values))
        if seen_ids:
            query = query.filter(~ServiceLocation.id.in_(sorted(seen_ids)))
        for row in query.limit(max(0, int(limit) - len(rows))).all():
            row_id = int(row.id or 0)
            if row_id > 0 and row_id not in seen_ids:
                seen_ids.add(row_id)
                rows.append(row)
    remaining = max(0, int(limit) - len(rows))
    if remaining > 0:
        query = base_query
        if seen_ids:
            query = query.filter(~ServiceLocation.id.in_(sorted(seen_ids)))
        for row in query.limit(remaining).all():
            row_id = int(row.id or 0)
            if row_id > 0 and row_id not in seen_ids:
                seen_ids.add(row_id)
                rows.append(row)
    customer_ids = [int(row.master_customer_id) for row in rows if int(row.master_customer_id or 0) > 0]
    customers = {int(row.id): row for row in db.query(MasterCustomer).filter(MasterCustomer.id.in_(customer_ids)).all()} if customer_ids else {}
    party_ids = [int(row.party_id) for row in customers.values()]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids)).all()} if party_ids else {}
    _, default_map = _crm_party_address_maps(db, party_ids)
    address_ids = [int(row.address_id) for row in rows if int(row.address_id or 0) > 0]
    addresses = {int(row.id): row for row in db.query(CrmAddress).filter(CrmAddress.id.in_(address_ids)).all()} if address_ids else {}
    options = []
    for row in rows:
        customer = customers.get(int(row.master_customer_id or 0)) if int(row.master_customer_id or 0) > 0 else None
        party = parties.get(int(customer.party_id or 0)) if customer else None
        customer_label = _crm_customer_label(customer, party, default_map.get(int(customer.party_id))) if customer and party else ""
        address = addresses.get(int(row.address_id or 0))
        options.append(
            {
                "id": int(row.id),
                "label": _crm_location_label(row, address, customer_label),
                "customer_id": int(row.master_customer_id or 0) or None,
                "street": str(address.street or "").strip() if address else "",
                "house_no": str(address.house_no or "").strip() if address else "",
                "zip_code": str(address.zip_code or "").strip() if address else "",
                "city": str(address.city or "").strip() if address else "",
                "country_code": str(address.country_code or "DE").strip() if address else "DE",
            }
        )
    return options


def _crm_offer_options(
    db: Session,
    *,
    include_ids: list[int] | None = None,
    customer_id: int = 0,
    limit: int = 160,
) -> list[dict[str, object]]:
    include_id_values = [int(value) for value in (include_ids or []) if int(value or 0) > 0]
    rows: list[OfferDraft] = []
    seen_ids: set[int] = set()
    if include_id_values:
        for row in (
            db.query(OfferDraft)
            .filter(OfferDraft.id.in_(include_id_values))
            .order_by(OfferDraft.updated_at.desc(), OfferDraft.id.desc())
            .all()
        ):
            row_id = int(row.id or 0)
            if row_id > 0 and row_id not in seen_ids:
                seen_ids.add(row_id)
                rows.append(row)
    query = db.query(OfferDraft)
    if int(customer_id or 0) > 0:
        query = query.filter(OfferDraft.master_customer_id == int(customer_id))
    if seen_ids:
        query = query.filter(~OfferDraft.id.in_(sorted(seen_ids)))
    for row in query.order_by(OfferDraft.updated_at.desc(), OfferDraft.id.desc()).limit(max(0, int(limit) - len(rows))).all():
        row_id = int(row.id or 0)
        if row_id > 0 and row_id not in seen_ids:
            seen_ids.add(row_id)
            rows.append(row)
    customer_map = _crm_customer_labels_map(db, [int(row.master_customer_id) for row in rows if int(row.master_customer_id or 0) > 0])
    options: list[dict[str, object]] = []
    for row in rows:
        bits = [_offer_reference_label(row)]
        customer_label = customer_map.get(int(row.master_customer_id or 0), "")
        if customer_label:
            bits.append(customer_label)
        if row.created_at:
            bits.append(_format_date_local(row.created_at))
        options.append(
            {
                "id": int(row.id),
                "label": " | ".join([bit for bit in bits if bit]),
                "customer_id": int(row.master_customer_id or 0) or None,
                "service_location_id": int(row.service_location_id or 0) or None,
            }
        )
    return options


def _crm_case_customer_object_options(db: Session, ordering_party_id: int, service_location_id: int) -> list[dict[str, object]]:
    query = db.query(CustomerObject)
    if int(service_location_id or 0) > 0:
        query = query.filter(
            or_(
                CustomerObject.service_location_id == int(service_location_id),
                CustomerObject.master_customer_id == int(ordering_party_id or 0),
            )
        )
    elif int(ordering_party_id or 0) > 0:
        query = query.filter(CustomerObject.master_customer_id == int(ordering_party_id))
    else:
        return []
    rows = query.order_by(CustomerObject.updated_at.desc(), CustomerObject.id.desc()).limit(150).all()
    options: list[dict[str, object]] = []
    for row in rows:
        label_parts = [
            str(row.brand_label or "").strip(),
            str(row.model_label or row.type_label or "").strip(),
        ]
        label = _crm_clean_text(" ".join([part for part in label_parts if part])) or _crm_clean_text(row.external_object_code) or f"Objekt {row.id}"
        meta_parts = [str(row.external_object_code or "").strip(), str(row.serial_no or "").strip()]
        meta = " | ".join([part for part in meta_parts if part])
        options.append({"id": int(row.id), "label": f"{label}{f' | {meta}' if meta else ''}"})
    return options


def _crm_case_role_map(db: Session, case_ids: list[int]) -> dict[int, dict[str, RoleAssignment]]:
    out: dict[int, dict[str, RoleAssignment]] = {}
    if not case_ids:
        return out
    rows = db.query(RoleAssignment).filter(RoleAssignment.case_id.in_(case_ids)).all()
    for row in rows:
        out.setdefault(int(row.case_id), {})[str(row.role_type or "")] = row
    return out


def _crm_recent_case_rows(db: Session, customer_id: int, limit: int = 10) -> list[dict[str, object]]:
    assignment_rows = (
        db.query(RoleAssignment)
        .filter(RoleAssignment.master_customer_id == int(customer_id), RoleAssignment.role_type.in_((CRM_ROLE_ORDERING_PARTY, CRM_ROLE_INVOICE_RECIPIENT)))
        .order_by(RoleAssignment.id.desc())
        .limit(max(20, limit * 2))
        .all()
    )
    case_ids = []
    role_labels: dict[int, str] = {}
    for row in assignment_rows:
        case_id = int(row.case_id or 0)
        if case_id <= 0 or case_id in case_ids:
            continue
        case_ids.append(case_id)
        role_labels[case_id] = _crm_role_label(row.role_type)
    if not case_ids:
        return []
    cases = (
        db.query(CrmCase)
        .filter(CrmCase.id.in_(case_ids))
        .order_by(CrmCase.updated_at.desc(), CrmCase.id.desc())
        .limit(limit)
        .all()
    )
    return [{"row": row, "role_label": role_labels.get(int(row.id), "Kunde")} for row in cases]


def _crm_merge_pair_key(a: int, b: int) -> str:
    left, right = sorted((int(a), int(b)))
    return f"{left}:{right}"


def _crm_merge_rejections(db: Session) -> set[str]:
    row = db.get(SystemSetting, CRM_MERGE_REJECTIONS_SETTING)
    if not row or not row.value:
        return set()
    try:
        payload = json.loads(row.value)
    except Exception:
        return set()
    if not isinstance(payload, list):
        return set()
    out = set()
    for item in payload:
        text = _crm_clean_text(item)
        if text:
            out.add(text)
    return out


def _crm_save_merge_rejections(db: Session, values: set[str]) -> None:
    row = db.get(SystemSetting, CRM_MERGE_REJECTIONS_SETTING)
    if row is None:
        row = SystemSetting(key=CRM_MERGE_REJECTIONS_SETTING)
    row.value = json.dumps(sorted(values), ensure_ascii=False)
    db.add(row)


def _crm_canonical_identifier(value) -> str:
    raw = re.sub(r"\s+", "", _crm_clean_text(value).lower())
    if not raw:
        return ""
    match = re.match(r"^([a-z]+)(\d+)$", raw)
    if match:
        prefix, digits = match.groups()
        return f"{prefix}{int(digits)}"
    if raw.isdigit():
        return str(int(raw))
    return raw


def _crm_customer_stage_profile(party: Party | None, default_address: CrmAddress | None) -> dict[str, str]:
    return {
        "display_name": _crm_clean_text(getattr(party, "display_name", "") if party else ""),
        "name_key": _crm_normalize_key(getattr(party, "display_name", "") if party else ""),
        "street": _crm_clean_text(getattr(default_address, "street", "") if default_address else ""),
        "street_key": _crm_normalize_key(getattr(default_address, "street", "") if default_address else ""),
        "zip_code": _crm_clean_text(getattr(default_address, "zip_code", "") if default_address else ""),
        "zip_key": _crm_normalize_key(getattr(default_address, "zip_code", "") if default_address else ""),
        "city": _crm_clean_text(getattr(default_address, "city", "") if default_address else ""),
        "city_key": _crm_normalize_key(getattr(default_address, "city", "") if default_address else ""),
        "email_key": _crm_normalize_email(getattr(default_address, "email", "") if default_address else ""),
        "phone_key": _crm_normalize_phone(getattr(default_address, "phone", "") if default_address else ""),
    }


def _crm_select_unique_outsmart_relation_rows(
    rows: list[OutsmartRelationStage],
    *,
    street_key: str = "",
    city_key: str = "",
) -> list[OutsmartRelationStage]:
    if not rows:
        return []
    selected = list(rows)
    if street_key:
        exact_street = [row for row in selected if _crm_normalize_key(row.street_norm or row.street or "") == street_key]
        if exact_street:
            selected = exact_street
    if city_key:
        exact_city = [row for row in selected if _crm_normalize_key(row.city_norm or row.city or "") == city_key]
        if exact_city:
            selected = exact_city
    canonical_keys = {
        _crm_canonical_identifier(row.debtor_no or row.relation_no)
        for row in selected
        if _crm_canonical_identifier(row.debtor_no or row.relation_no)
    }
    if len(canonical_keys) == 1:
        return selected
    if len(selected) == 1:
        return selected
    return []


def _crm_match_outsmart_relation_stage(
    db: Session,
    *,
    profile: dict[str, str],
    explicit_keys: set[str] | None = None,
    limit: int = 24,
) -> list[OutsmartRelationStage]:
    cleaned_keys = {str(value or "").strip() for value in explicit_keys or set() if str(value or "").strip()}
    if cleaned_keys:
        rows = (
            db.query(OutsmartRelationStage)
            .filter(or_(OutsmartRelationStage.relation_no.in_(list(cleaned_keys)), OutsmartRelationStage.debtor_no.in_(list(cleaned_keys))))
            .all()
        )
        if rows:
            return rows
    name_key = str(profile.get("name_key") or "")
    if not name_key:
        return []
    query = db.query(OutsmartRelationStage).filter(OutsmartRelationStage.name_norm == name_key)
    zip_key = str(profile.get("zip_key") or "")
    if zip_key:
        query = query.filter(OutsmartRelationStage.zip_norm == zip_key)
    rows = query.order_by(OutsmartRelationStage.updated_at.desc(), OutsmartRelationStage.id.desc()).limit(max(4, int(limit))).all()
    return _crm_select_unique_outsmart_relation_rows(
        rows,
        street_key=str(profile.get("street_key") or ""),
        city_key=str(profile.get("city_key") or ""),
    )


def _crm_outsmart_keys_from_relation_rows(rows: list[OutsmartRelationStage]) -> set[str]:
    out: set[str] = set()
    for row in rows:
        for value in (row.debtor_no, row.relation_no):
            key = _crm_normalize_key(value)
            if key:
                out.add(key)
    return out


def _crm_infer_outsmart_keys_from_profile_maps(
    profile: dict[str, str],
    *,
    exact_profile_map: dict[tuple[str, str, str, str], set[str]],
    name_zip_map: dict[tuple[str, str], set[str]],
) -> set[str]:
    name_key = str(profile.get("name_key") or "")
    zip_key = str(profile.get("zip_key") or "")
    street_key = str(profile.get("street_key") or "")
    city_key = str(profile.get("city_key") or "")
    if not name_key:
        return set()
    exact_key = (name_key, zip_key, street_key, city_key)
    exact_matches = exact_profile_map.get(exact_key, set()) if any(exact_key) else set()
    if len(exact_matches) == 1:
        return set(exact_matches)
    if street_key:
        return set()
    name_zip_matches = name_zip_map.get((name_key, zip_key), set()) if zip_key else set()
    if len(name_zip_matches) == 1:
        return set(name_zip_matches)
    return set()


def _crm_match_sevdesk_contact_stage(
    db: Session,
    *,
    profile: dict[str, str],
    explicit_keys: set[str] | None = None,
    customer_numbers: set[str] | None = None,
    limit: int = 20,
) -> list[SevdeskContactStage]:
    contact_rows: dict[int, SevdeskContactStage] = {}
    cleaned_keys = {str(value or "").strip() for value in explicit_keys or set() if str(value or "").strip()}
    if cleaned_keys:
        for row in (
            db.query(SevdeskContactStage)
            .filter(or_(SevdeskContactStage.sevdesk_contact_id.in_(list(cleaned_keys)), SevdeskContactStage.customer_number.in_(list(cleaned_keys))))
            .all()
        ):
            contact_rows[int(row.id)] = row
    cleaned_numbers = {str(value or "").strip() for value in customer_numbers or set() if str(value or "").strip()}
    if cleaned_numbers:
        for row in (
            db.query(SevdeskContactStage)
            .filter(SevdeskContactStage.customer_number.in_(list(cleaned_numbers)))
            .all()
        ):
            contact_rows[int(row.id)] = row
    if contact_rows:
        return list(contact_rows.values())
    name_key = str(profile.get("name_key") or "")
    if not name_key:
        return []
    rows = (
        db.query(SevdeskContactStage)
        .filter(SevdeskContactStage.name_norm == name_key)
        .order_by(SevdeskContactStage.updated_at.desc(), SevdeskContactStage.id.desc())
        .limit(max(4, int(limit)))
        .all()
    )
    if not rows:
        return []
    zip_key = str(profile.get("zip_key") or "")
    if zip_key:
        exact_zip = [row for row in rows if _crm_normalize_key(row.zip_norm or row.zip_code or "") == zip_key]
        if exact_zip:
            rows = exact_zip
    if cleaned_numbers:
        exact_numbers = [row for row in rows if _crm_clean_text(row.customer_number) in cleaned_numbers]
        if exact_numbers:
            rows = exact_numbers
    return rows


def _crm_merge_signal_rows(db: Session) -> list[dict[str, object]]:
    customers = db.query(MasterCustomer).order_by(MasterCustomer.id.asc()).all()
    if not customers:
        return []
    customer_ids = [int(row.id) for row in customers]
    party_ids = [int(row.party_id) for row in customers]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids)).all()}
    address_map, default_address_map = _crm_party_address_maps(db, party_ids)
    contact_rows = db.query(CustomerContactPerson).filter(CustomerContactPerson.master_customer_id.in_(customer_ids)).all()
    contacts_by_customer: dict[int, list[CustomerContactPerson]] = {}
    for row in contact_rows:
        contacts_by_customer.setdefault(int(row.master_customer_id), []).append(row)
    identity_rows = db.query(ExternalIdentity).filter(ExternalIdentity.master_customer_id.in_(customer_ids)).all()
    identities_by_customer: dict[int, list[ExternalIdentity]] = {}
    for row in identity_rows:
        identities_by_customer.setdefault(int(row.master_customer_id), []).append(row)
    relation_rows = db.query(OutsmartRelationStage).all()
    exact_profile_map: dict[tuple[str, str, str, str], set[str]] = {}
    name_zip_map: dict[tuple[str, str], set[str]] = {}
    for row in relation_rows:
        canonical_key = _crm_canonical_identifier(row.debtor_no or row.relation_no)
        if not canonical_key:
            continue
        name_key = _crm_normalize_key(row.name_norm or row.name or "")
        zip_key = _crm_normalize_key(row.zip_norm or row.zip_code or "")
        street_key = _crm_normalize_key(row.street_norm or row.street or "")
        city_key = _crm_normalize_key(row.city_norm or row.city or "")
        exact_key = (name_key, zip_key, street_key, city_key)
        exact_profile_map.setdefault(exact_key, set()).add(canonical_key)
        if name_key and zip_key:
            name_zip_map.setdefault((name_key, zip_key), set()).add(canonical_key)
    out: list[dict[str, object]] = []
    for customer in customers:
        party = parties.get(int(customer.party_id))
        addresses = address_map.get(int(customer.party_id), [])
        default_address = default_address_map.get(int(customer.party_id))
        profile = _crm_customer_stage_profile(party, default_address)
        emails: set[str] = set()
        phones: set[str] = set()
        for address in addresses:
            email_norm = _crm_normalize_email(address.email)
            phone_norm = _crm_normalize_phone(address.phone)
            if email_norm:
                emails.add(email_norm)
            if phone_norm:
                phones.add(phone_norm)
        for contact in contacts_by_customer.get(int(customer.id), []):
            email_norm = _crm_normalize_email(contact.email)
            phone_norm = _crm_normalize_phone(contact.phone)
            if email_norm:
                emails.add(email_norm)
            if phone_norm:
                phones.add(phone_norm)
        outsmart_keys: set[str] = set()
        sevdesk_identities: list[ExternalIdentity] = []
        outsmart_primary = False
        for identity in identities_by_customer.get(int(customer.id), []):
            system_name = _crm_normalize_key(identity.system_name)
            if system_name == "sevdesk":
                sevdesk_identities.append(identity)
            if system_name == "outsmart":
                key_norm = _crm_canonical_identifier(identity.external_key or identity.external_id) or _crm_normalize_key(identity.external_key or identity.external_id)
                if key_norm:
                    outsmart_keys.add(key_norm)
                if bool(identity.is_primary):
                    outsmart_primary = True
        inferred_outsmart_keys: set[str] = set()
        if not outsmart_keys:
            inferred_outsmart_keys = _crm_infer_outsmart_keys_from_profile_maps(
                profile,
                exact_profile_map=exact_profile_map,
                name_zip_map=name_zip_map,
            )
            outsmart_keys.update(inferred_outsmart_keys)
        out.append(
            {
                "customer": customer,
                "party": party,
                "default_address": default_address,
                "name_key": str(profile.get("name_key") or ""),
                "zip_code": str(profile.get("zip_key") or ""),
                "emails": emails,
                "phones": phones,
                "outsmart_keys": outsmart_keys,
                "inferred_outsmart_keys": inferred_outsmart_keys,
                "outsmart_primary": outsmart_primary,
                "sevdesk_identities": sevdesk_identities,
            }
        )
    return out


def _crm_build_merge_candidates(db: Session, q: str = "") -> list[dict[str, object]]:
    signal_rows = _crm_merge_signal_rows(db)
    if not signal_rows:
        return []
    by_id = {int(item["customer"].id): item for item in signal_rows}
    rejected = _crm_merge_rejections(db)
    pair_reasons: dict[str, dict[str, object]] = {}

    def add_reason(customer_ids: list[int], reason_label: str) -> None:
        ids = sorted({int(value) for value in customer_ids if int(value or 0) > 0})
        if len(ids) < 2:
            return
        for idx, left in enumerate(ids):
            for right in ids[idx + 1 :]:
                pair_key = _crm_merge_pair_key(left, right)
                payload = pair_reasons.setdefault(pair_key, {"ids": (left, right), "reasons": []})
                reasons = payload["reasons"]
                if reason_label not in reasons:
                    reasons.append(reason_label)

    name_zip_groups: dict[tuple[str, str], list[int]] = {}
    email_groups: dict[str, list[int]] = {}
    phone_groups: dict[str, list[int]] = {}
    outsmart_groups: dict[str, list[int]] = {}
    for item in signal_rows:
        customer_id = int(item["customer"].id)
        name_key = str(item["name_key"] or "")
        zip_code = str(item["zip_code"] or "")
        if name_key and zip_code:
            name_zip_groups.setdefault((name_key, zip_code), []).append(customer_id)
        for email_key in item["emails"]:
            email_groups.setdefault(email_key, []).append(customer_id)
        for phone_key in item["phones"]:
            phone_groups.setdefault(phone_key, []).append(customer_id)
        for outsmart_key in item["outsmart_keys"]:
            outsmart_groups.setdefault(outsmart_key, []).append(customer_id)

    for (_, _), ids in name_zip_groups.items():
        add_reason(ids, "Gleicher Name + PLZ")
    for email_key, ids in email_groups.items():
        add_reason(ids, f"Gleiche Mail: {email_key}")
    for phone_key, ids in phone_groups.items():
        add_reason(ids, f"Gleiche Telefonnummer: {phone_key}")
    for outsmart_key, ids in outsmart_groups.items():
        add_reason(ids, f"Gleiche OutSmart-Nummer: {outsmart_key}")

    query_norm = _crm_normalize_key(q)
    rows: list[dict[str, object]] = []
    for pair_key, payload in pair_reasons.items():
        if pair_key in rejected:
            continue
        left_id, right_id = payload["ids"]
        left = by_id.get(int(left_id))
        right = by_id.get(int(right_id))
        if not left or not right:
            continue
        ordered = sorted(
            (left, right),
            key=lambda item: (
                0 if item["outsmart_primary"] else 1,
                0 if item["outsmart_keys"] else 1,
                0 if _crm_normalize_key(item["customer"].status) == "active" else 1,
                int(item["customer"].id),
            ),
        )
        master = ordered[0]
        candidate = ordered[1]
        reason_text = " | ".join(str(value) for value in payload["reasons"])
        search_blob = " ".join(
            [
                str(master["party"].display_name if master["party"] else ""),
                str(candidate["party"].display_name if candidate["party"] else ""),
                reason_text,
                " ".join(sorted(master["emails"])),
                " ".join(sorted(candidate["emails"])),
                " ".join(sorted(master["outsmart_keys"])),
                " ".join(sorted(candidate["outsmart_keys"])),
            ]
        )
        if query_norm and query_norm not in _crm_normalize_key(search_blob):
            continue
        rows.append(
            {
                "pair_key": pair_key,
                "master_customer": master["customer"],
                "master_party": master["party"],
                "master_address": master["default_address"],
                "candidate_customer": candidate["customer"],
                "candidate_party": candidate["party"],
                "candidate_address": candidate["default_address"],
                "reasons": payload["reasons"],
                "sevdesk_identities": candidate["sevdesk_identities"],
                "master_outsmart_keys": sorted(master["outsmart_keys"]),
                "candidate_outsmart_keys": sorted(candidate["outsmart_keys"]),
            }
        )
    rows.sort(key=lambda item: (-len(item["reasons"]), int(item["master_customer"].id), int(item["candidate_customer"].id)))
    return rows


def _crm_merge_reason_flags(reasons: list[str] | tuple[str, ...]) -> dict[str, bool]:
    values = [str(value or "") for value in reasons]
    return {
        "same_name_zip": any(_crm_normalize_key(value) == _crm_normalize_key("Gleicher Name + PLZ") for value in values),
        "same_email": any(_crm_normalize_key(value).startswith(_crm_normalize_key("Gleiche Mail")) for value in values),
        "same_phone": any(_crm_normalize_key(value).startswith(_crm_normalize_key("Gleiche Telefonnummer")) for value in values),
        "same_outsmart": any(_crm_normalize_key(value).startswith(_crm_normalize_key("Gleiche OutSmart-Nummer")) for value in values),
    }


def _crm_merge_candidate_is_auto_safe(item: dict[str, object], preview: dict[str, object]) -> bool:
    if list(preview.get("warnings") or []):
        return False
    flags = _crm_merge_reason_flags(item.get("reasons") or [])
    master_party = item.get("master_party")
    candidate_party = item.get("candidate_party")
    master_address = item.get("master_address")
    candidate_address = item.get("candidate_address")
    master_name = _crm_normalize_key(getattr(master_party, "display_name", ""))
    candidate_name = _crm_normalize_key(getattr(candidate_party, "display_name", ""))
    same_name = bool(master_name and candidate_name and (master_name == candidate_name or master_name in candidate_name or candidate_name in master_name))
    same_zip = bool(
        _crm_normalize_key(getattr(master_address, "zip_code", ""))
        and _crm_normalize_key(getattr(master_address, "zip_code", "")) == _crm_normalize_key(getattr(candidate_address, "zip_code", ""))
    )
    counts = preview.get("counts") or {}
    if flags["same_outsmart"]:
        return True
    if flags["same_email"] and (same_name or same_zip):
        return True
    if flags["same_phone"] and same_name and same_zip:
        return True
    if flags["same_email"] and flags["same_phone"]:
        return True
    if flags["same_name_zip"] and flags["same_email"]:
        return True
    if int(counts.get("external_identities") or 0) <= 1 and flags["same_name_zip"] and flags["same_phone"] and same_name:
        return True
    return False


def _crm_merge_ai_input_payload(item: dict[str, object]) -> dict[str, object]:
    master_address = item.get("master_address")
    candidate_address = item.get("candidate_address")
    master_outsmart_keys = list(item.get("master_outsmart_keys") or [])
    candidate_outsmart_keys = list(item.get("candidate_outsmart_keys") or [])
    return {
        "master_id": int(item["master_customer"].id),
        "candidate_id": int(item["candidate_customer"].id),
        "master_name": str(item["master_party"].display_name or ""),
        "candidate_name": str(item["candidate_party"].display_name or ""),
        "master_email": str(getattr(master_address, "email", "") or ""),
        "candidate_email": str(getattr(candidate_address, "email", "") or ""),
        "master_phone": str(getattr(master_address, "phone", "") or ""),
        "candidate_phone": str(getattr(candidate_address, "phone", "") or ""),
        "master_zip": str(getattr(master_address, "zip_code", "") or ""),
        "candidate_zip": str(getattr(candidate_address, "zip_code", "") or ""),
        "master_outsmart_key": str(master_outsmart_keys[0] if master_outsmart_keys else ""),
        "candidate_outsmart_key": str(candidate_outsmart_keys[0] if candidate_outsmart_keys else ""),
    }


def _crm_merge_ai_result(item: dict[str, object], db: Session, *, force_refresh: bool = False) -> dict[str, object]:
    payload = _crm_merge_ai_input_payload(item)
    preview = build_customer_merge_preview(
        db,
        source_customer=db.get(MasterCustomer, int(item["candidate_customer"].id)),
        target_customer=db.get(MasterCustomer, int(item["master_customer"].id)),
    )
    result = ai_evaluate_merge_candidate(
        db,
        settings=_openai_settings(db, include_secret=True),
        input_payload=payload,
        related_object_id=int(item["master_customer"].id),
        force_refresh=force_refresh,
    )
    output = result.get("output") if isinstance(result.get("output"), dict) else {}
    score = float(output.get("score") or 0.0)
    flags = _crm_merge_reason_flags(item.get("reasons") or [])
    can_merge = False
    if not list(preview.get("warnings") or []):
        if flags["same_outsmart"] and score >= 0.7:
            can_merge = True
        elif flags["same_email"] and flags["same_name_zip"] and score >= 0.7:
            can_merge = True
        elif flags["same_phone"] and flags["same_name_zip"] and score >= 0.75:
            can_merge = True
        elif flags["same_email"] and flags["same_phone"] and score >= 0.75:
            can_merge = True
    result["can_merge"] = can_merge
    result["preview"] = preview
    return result


def _crm_auto_merge_candidates(db: Session, *, q: str = "", limit: int = 0) -> dict[str, int]:
    rows = _crm_build_merge_candidates(db, q=q)
    if int(limit or 0) > 0:
        rows = rows[: int(limit)]
    summary = {"merged": 0, "manual": 0, "skipped": 0, "errors": 0}
    for item in rows:
        target = db.get(MasterCustomer, int(item["master_customer"].id))
        source = db.get(MasterCustomer, int(item["candidate_customer"].id))
        if not target or not source:
            summary["skipped"] += 1
            continue
        if _crm_normalize_key(target.status) == "inactive" or _crm_normalize_key(source.status) == "inactive":
            summary["skipped"] += 1
            continue
        preview = build_customer_merge_preview(db, source_customer=source, target_customer=target)
        if not _crm_merge_candidate_is_auto_safe(item, preview):
            summary["manual"] += 1
            continue
        try:
            merge_master_customers(db, target_customer=target, source_customer=source, actor_label="Auto-Merge")
            summary["merged"] += 1
        except CustomerMergeConflict:
            summary["manual"] += 1
        except Exception:
            summary["errors"] += 1
    return summary


def _crm_ai_merge_candidates(db: Session, *, q: str = "", limit: int = 0, force_refresh: bool = False) -> dict[str, int]:
    rows = _crm_build_merge_candidates(db, q=q)
    if int(limit or 0) > 0:
        rows = rows[: int(limit)]
    summary = {"merged": 0, "manual": 0, "skipped": 0, "errors": 0}
    for item in rows:
        target = db.get(MasterCustomer, int(item["master_customer"].id))
        source = db.get(MasterCustomer, int(item["candidate_customer"].id))
        if not target or not source:
            summary["skipped"] += 1
            continue
        if _crm_normalize_key(target.status) == "inactive" or _crm_normalize_key(source.status) == "inactive":
            summary["skipped"] += 1
            continue
        try:
            ai_result = _crm_merge_ai_result(item, db, force_refresh=force_refresh)
            if not bool(ai_result.get("can_merge")):
                summary["manual"] += 1
                continue
            merge_master_customers(db, target_customer=target, source_customer=source, actor_label="KI-Merge")
            summary["merged"] += 1
        except CustomerMergeConflict:
            summary["manual"] += 1
        except Exception:
            summary["errors"] += 1
    return summary


def _crm_set_case_role(
    db: Session,
    *,
    crm_case_id: int,
    role_type: str,
    master_customer_id: int | None = None,
    service_location_id: int | None = None,
    address_id: int | None = None,
    note: str | None = None,
) -> None:
    row = (
        db.query(RoleAssignment)
        .filter(RoleAssignment.case_id == int(crm_case_id), RoleAssignment.role_type == str(role_type))
        .one_or_none()
    )
    if row is None:
        row = RoleAssignment(case_id=int(crm_case_id), role_type=str(role_type))
    row.master_customer_id = int(master_customer_id) if int(master_customer_id or 0) > 0 else None
    row.service_location_id = int(service_location_id) if int(service_location_id or 0) > 0 else None
    row.address_id = int(address_id) if int(address_id or 0) > 0 else None
    row.note = _crm_clean_text(note or "") or None
    db.add(row)


