@app.post("/crm/kunden/neu")
async def crm_customer_new_post(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    form = await request.form()
    form_data = _extract_form_data(form)
    form_errors: dict[str, str] = {}
    known_domains = _crm_known_email_domains(db)
    party_type = _crm_normalize_key(form.get("party_type")) or "company"
    display_name = _crm_party_display_name(form.get("display_name"), form.get("first_name"), form.get("last_name"))
    status = _crm_normalize_key(form.get("status")) or "active"
    note = _crm_clean_text(form.get("note") or "") or None
    address_payload = _crm_parse_address_payload(form, prefix="address_")
    address_validation_result: dict[str, object] = {}
    address_email_validation_result: dict[str, object] = {}
    if party_type not in CRM_PARTY_TYPE_CHOICES:
        form_errors["party_type"] = "Bitte einen gültigen Kundentyp wählen."
    if not display_name:
        form_errors["display_name"] = "Ein Anzeigename ist Pflicht."
    if status not in CRM_CUSTOMER_STATUS_CHOICES:
        form_errors["status"] = "Bitte einen gültigen Status wählen."
    if _crm_address_payload_has_content(address_payload):
        address_probe = CrmAddress(party_id=0, is_default=True, active=True)
        _crm_apply_address_payload(address_probe, address_payload)
        address_validation_result = _crm_validate_address_row(address_probe)
        if str(address_validation_result.get("status") or "") == "invalid":
            form_errors["address_street"] = str(address_validation_result.get("message") or "Adresse ist ungueltig.")
        address_email_validation_result = _crm_validate_email_value(address_probe.email, known_domains=known_domains)
        if str(address_email_validation_result.get("status") or "") in {"invalid", "review", "undeliverable"}:
            form_errors["address_email"] = str(address_email_validation_result.get("message") or "E-Mail-Adresse bitte pruefen.")
    if form_errors:
        for message in form_errors.values():
            _flash(request, message, "error")
        return _crm_render_customer_form(
            request,
            user=user,
            page_title="Kunde anlegen",
            form_action="/crm/kunden/neu",
            customer=None,
            party=None,
            default_address=None,
            form_data=form_data,
            form_errors=form_errors,
        )
    party = Party(
        party_type=party_type,
        display_name=display_name,
        first_name=_crm_clean_text(form.get("first_name") or "") or None,
        last_name=_crm_clean_text(form.get("last_name") or "") or None,
        active=form.get("active") == "on",
        note=note,
        created_at=_utcnow_naive(),
        updated_at=_utcnow_naive(),
    )
    db.add(party)
    db.flush()
    customer = MasterCustomer(
        party_id=int(party.id),
        customer_no_internal=_crm_next_customer_no(db),
        status=status,
        note=note,
        created_at=_utcnow_naive(),
        updated_at=_utcnow_naive(),
    )
    db.add(customer)
    db.flush()
    if _crm_address_payload_has_content(address_payload):
        address = CrmAddress(
            party_id=int(party.id),
            is_default=True,
            active=True,
        )
        _crm_apply_address_payload(address, address_payload)
        if not address.label:
            address.label = "Hauptadresse"
        _crm_apply_address_validation_result(address, address_validation_result)
        _crm_apply_email_validation_result(
            address,
            address_email_validation_result,
            status_attr="email_validation_status",
            message_attr="email_validation_message",
            suggestion_attr="email_validation_suggestion",
            checked_attr="email_validated_at",
        )
        db.add(address)
    try:
        db.commit()
    except Exception as exc:
        db.rollback()
        _flash(request, _friendly_db_write_error(exc), "error")
        return _crm_render_customer_form(
            request,
            user=user,
            page_title="Kunde anlegen",
            form_action="/crm/kunden/neu",
            customer=None,
            party=None,
            default_address=None,
            form_data=form_data,
            form_errors={"__all__": _friendly_db_write_error(exc)},
        )
    _flash(request, "Kunde angelegt.", "info")
    return RedirectResponse(f"/crm/kunden/{int(customer.id)}", status_code=302)


@app.get("/crm/kunden/{customer_id}", response_class=HTMLResponse)
def crm_customer_detail(
    customer_id: int,
    request: Request,
    user=Depends(require_user),
    timeline_filter: str = "all",
    sevdesk_q: str = "",
    db: Session = Depends(db_session),
):
    customer = db.get(MasterCustomer, customer_id)
    if not customer:
        raise HTTPException(status_code=404)
    party = db.get(Party, int(customer.party_id))
    if not party:
        raise HTTPException(status_code=404)
    outsmart_workorders_total = int(db.query(OutsmartWorkorder).filter(OutsmartWorkorder.master_customer_id == int(customer.id)).count())
    contact_backfill = _crm_backfill_customer_contact_data(db, customer)
    location_backfill = _crm_backfill_customer_service_locations(db, customer)
    address_cleanup = dedupe_party_addresses(db, int(party.id))
    if (
        int(contact_backfill.get("updated") or 0) > 0
        or int(location_backfill.get("created") or 0) > 0
        or int(location_backfill.get("updated") or 0) > 0
        or int(address_cleanup.get("deleted") or 0) > 0
        or int(address_cleanup.get("updated") or 0) > 0
        or int(address_cleanup.get("relinked_service_locations") or 0) > 0
        or int(address_cleanup.get("relinked_role_assignments") or 0) > 0
    ):
        db.commit()
        party = db.get(Party, int(customer.party_id))
    customer_init_summary = _customer_init_customer_summary(db, int(customer.id))
    outsmart_stage_workorders_total = int(customer_init_summary.get("workorder_count") or 0)
    sevdesk_stage_documents_total = int(customer_init_summary.get("order_count") or 0) + int(customer_init_summary.get("invoice_count") or 0)
    if outsmart_stage_workorders_total > outsmart_workorders_total:
        try:
            workorder_backfill = _outsmart_backfill_existing_workorders(db, customer_id=int(customer.id))
            if any(int(workorder_backfill.get(key) or 0) > 0 for key in ("matched_customer", "matched_case", "contact_updates", "updated_rows")):
                db.commit()
        except Exception as exc:
            db.rollback()
            _flash(request, f"OutSmart-Nachverknüpfung fehlgeschlagen: {exc}", "error")
    try:
        outsmart_live_refresh = _customer_refresh_outsmart_live_workorders(db, int(customer.id), limit=6)
        if any(int(outsmart_live_refresh.get(key) or 0) > 0 for key in ("created", "updated", "events")):
            db.commit()
    except Exception as exc:
        db.rollback()
        _flash(request, f"OutSmart-Liveabgleich fehlgeschlagen: {exc}", "error")
    outsmart_workorders_total = int(db.query(OutsmartWorkorder).filter(OutsmartWorkorder.master_customer_id == int(customer.id)).count())
    addresses = (
        db.query(CrmAddress)
        .filter(CrmAddress.party_id == int(party.id))
        .order_by(CrmAddress.is_default.desc(), CrmAddress.active.desc(), CrmAddress.id.asc())
        .all()
    )
    default_address = _crm_pick_default_address(addresses)
    contact_rows_raw = (
        db.query(CustomerContactPerson)
        .filter(CustomerContactPerson.master_customer_id == int(customer.id))
        .order_by(CustomerContactPerson.active.desc(), CustomerContactPerson.id.asc())
        .all()
    )
    contact_party_ids = [int(row.party_id) for row in contact_rows_raw if int(row.party_id or 0) > 0]
    contact_parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(contact_party_ids)).all()} if contact_party_ids else {}
    contact_rows = [{"row": row, "party": contact_parties.get(int(row.party_id or 0))} for row in contact_rows_raw]
    header_summary = _crm_customer_header_summary(customer, party, default_address, contact_rows)
    identities = (
        db.query(ExternalIdentity)
        .filter(ExternalIdentity.master_customer_id == int(customer.id))
        .order_by(ExternalIdentity.system_name.asc(), ExternalIdentity.external_type.asc(), ExternalIdentity.id.asc())
        .all()
    )
    outsmart_settings = _outsmart_settings(db, include_secret=False)
    outsmart_relation_link = (
        db.query(ExternalLink)
        .filter(
            ExternalLink.system_name == "outsmart",
            ExternalLink.object_type == "master_customer",
            ExternalLink.object_id == int(customer.id),
        )
        .one_or_none()
    )
    outsmart_relation_url = (
        _outsmart_resolve_deep_link(
            outsmart_settings,
            entity_type="relation",
            row_id=str(outsmart_relation_link.external_row_id or "").strip() or None,
            external_key=str(outsmart_relation_link.external_key or "").strip() or None,
            current_url=outsmart_relation_link.deep_link_url,
        )
        if outsmart_relation_link
        else ""
    )
    paperless_settings = _paperless_settings(db, include_secret=False)
    sevdesk_document_rows = _customer_combined_sevdesk_document_rows(db, int(customer.id), limit=120)
    sevdesk_stage_document_rows = _customer_sevdesk_stage_document_rows(db, int(customer.id), limit=400)
    paperless_document_rows = _customer_paperless_document_rows(
        db,
        int(customer.id),
        limit=80,
        document_rows=sevdesk_document_rows,
        stage_document_rows=sevdesk_stage_document_rows,
    )
    object_backfill = _crm_backfill_customer_objects_from_documents(
        db,
        customer,
        document_rows=sevdesk_document_rows,
    )
    if any(int(object_backfill.get(key) or 0) > 0 for key in ("created", "updated", "deleted")):
        db.commit()
    customer_paperless_workorder_refs = _paperless_customer_outsmart_refs(db, int(customer.id), limit=24)
    paperless_link_rows = []
    for link in _paperless_links_for_object(db, "customer", int(customer.id)):
        item = _document_inbox_item_from_paperless_id(db, str(link.paperless_document_id or ""))
        blob = _document_search_blob(item) if item is not None else str(link.paperless_title or "")
        score, _reasons, _details, matched_refs = _paperless_customer_document_match(
            text=blob,
            title=getattr(item, "title", None) if item is not None else link.paperless_title,
            document_type=getattr(item, "document_type", None) if item is not None else "",
            correspondent=getattr(item, "correspondent", None) if item is not None else "",
            customer=customer,
            party=party,
            default_address=default_address,
            identities=identities,
            contact_rows=contact_rows,
            workorder_refs=customer_paperless_workorder_refs,
        )
        if score >= 14 and matched_refs:
            paperless_link_rows.append(link)
    local_attachments = _attachments_for_entity(db, "customer", int(customer.id))
    recent_case_rows = _crm_recent_case_rows(db, int(customer.id), limit=6) if _internal_service_orders_enabled() else []
    outsmart_workorder_rows = _customer_outsmart_workorder_rows(db, int(customer.id), limit=12)
    customer_objects = _customer_objects_for_customer(db, int(customer.id), limit=12)
    finance_summary = _customer_finance_summary(
        db,
        int(customer.id),
        document_rows=sevdesk_document_rows,
        stage_document_rows=sevdesk_stage_document_rows,
        paperless_rows=paperless_document_rows,
    )
    invoice_address_rows = _customer_invoice_address_rows(
        db,
        customer,
        party,
        document_rows=sevdesk_document_rows,
        stage_document_rows=sevdesk_stage_document_rows,
    )
    service_location_cards = _customer_service_location_cards(db, int(customer.id), limit=16)
    quality_rows = _crm_customer_quality_rows(customer, addresses, contact_rows, service_location_cards)
    purchase_order_rows = _customer_purchase_order_rows(db, int(customer.id), limit=8)
    recent_offer_rows = _customer_recent_offer_sidebar_rows(
        db,
        int(customer.id),
        limit=3,
        document_rows=sevdesk_document_rows,
        stage_document_rows=sevdesk_stage_document_rows,
    )
    recent_invoice_rows = _customer_recent_invoice_sidebar_rows(
        db,
        int(customer.id),
        limit=3,
        document_rows=sevdesk_document_rows,
        stage_document_rows=sevdesk_stage_document_rows,
        paperless_rows=paperless_document_rows,
    )
    recent_receipt_rows = _customer_recent_receipt_sidebar_rows(
        db,
        int(customer.id),
        limit=3,
        paperless_rows=paperless_document_rows,
        attachments=local_attachments,
    )
    contract_rows = _customer_contract_rows(db, int(customer.id), limit=24)
    task_rows = _customer_task_rows(db, int(customer.id), limit=24)
    activity_rows = _customer_activity_rows(
        db,
        int(customer.id),
        limit=60,
        recent_case_rows=recent_case_rows,
        recent_offer_rows=recent_offer_rows,
        recent_invoice_rows=recent_invoice_rows,
        task_rows=task_rows,
        outsmart_workorder_rows=outsmart_workorder_rows,
        paperless_rows=paperless_document_rows,
        purchase_order_rows=purchase_order_rows,
    )
    paperless_candidate_items = _paperless_customer_candidate_items(db, int(customer.id), limit=10)
    paperless_candidate_rows = [
        {
            "row": row,
            "scan": meta.get("customer_scan") if isinstance(meta.get("customer_scan"), dict) else {},
            "paperless_url": paperless_build_document_url(paperless_settings, row.paperless_document_id),
        }
        for row in paperless_candidate_items
        for meta in [_json_dict(row.metadata_json)]
    ]
    header_summary["first_contact_at"] = _customer_first_contact_at(
        db,
        int(customer.id),
        document_rows=sevdesk_document_rows,
        stage_document_rows=sevdesk_stage_document_rows,
    )
    service_location_ids = {int(row.service_location_id or 0) for row in contract_rows + task_rows if int(getattr(row, "service_location_id", 0) or 0) > 0}
    service_location_map = {int(row.id): row for row in db.query(ServiceLocation).filter(ServiceLocation.id.in_(service_location_ids or [0])).all()} if service_location_ids else {}
    assigned_user_ids = {int(row.assigned_user_id or 0) for row in task_rows if int(row.assigned_user_id or 0) > 0}
    assigned_user_map = {int(row.id): row for row in db.query(User).filter(User.id.in_(assigned_user_ids or [0])).all()} if assigned_user_ids else {}
    return templates.TemplateResponse(
        "crm/customer_detail.html",
        _ctx(
            request,
            user=user,
            customer=customer,
            party=party,
            default_address=default_address,
            header_summary=header_summary,
            addresses=addresses,
            contact_rows=contact_rows,
            identities=identities,
            finance_summary=finance_summary,
            invoice_address_rows=invoice_address_rows,
            service_location_cards=service_location_cards,
            quality_rows=quality_rows,
            recent_case_rows=recent_case_rows,
            customer_objects=customer_objects,
            recent_offer_rows=recent_offer_rows,
            recent_invoice_rows=recent_invoice_rows,
            recent_receipt_rows=recent_receipt_rows,
            contract_rows=contract_rows,
            task_rows=task_rows,
            task_user_map=assigned_user_map,
            service_location_map=service_location_map,
            activity_rows=activity_rows,
            sevdesk_stage_documents_total=sevdesk_stage_documents_total,
            outsmart_enabled=bool(outsmart_settings.get("enabled")),
            outsmart_relation_link=outsmart_relation_link,
            outsmart_relation_url=outsmart_relation_url,
            customer_init_summary=customer_init_summary,
            paperless_links=paperless_link_rows,
            paperless_candidate_rows=paperless_candidate_rows,
            local_attachments=local_attachments,
            paperless_build_url=lambda document_id: paperless_build_document_url(paperless_settings, document_id),
            outsmart_workorders_total=outsmart_workorders_total,
            outsmart_stage_workorders_total=outsmart_stage_workorders_total,
            sevdesk_documents_total=len(sevdesk_document_rows),
        ),
    )


@app.post("/crm/kunden/{customer_id}/paperless/pruefen")
def crm_customer_paperless_scan(customer_id: int, request: Request, user=Depends(require_user), db: Session = Depends(db_session)):
    customer = db.get(MasterCustomer, customer_id)
    if not customer:
        raise HTTPException(status_code=404)
    party = db.get(Party, int(customer.party_id or 0))
    if not party:
        raise HTTPException(status_code=404)
    addresses = (
        db.query(CrmAddress)
        .filter(CrmAddress.party_id == int(party.id))
        .order_by(CrmAddress.is_default.desc(), CrmAddress.active.desc(), CrmAddress.id.asc())
        .all()
    )
    default_address = _crm_pick_default_address(addresses)
    contact_rows_raw = (
        db.query(CustomerContactPerson)
        .filter(CustomerContactPerson.master_customer_id == int(customer.id))
        .order_by(CustomerContactPerson.active.desc(), CustomerContactPerson.id.asc())
        .all()
    )
    contact_party_ids = [int(row.party_id) for row in contact_rows_raw if int(row.party_id or 0) > 0]
    contact_parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(contact_party_ids)).all()} if contact_party_ids else {}
    contact_rows = [{"row": row, "party": contact_parties.get(int(row.party_id))} for row in contact_rows_raw]
    identities = (
        db.query(ExternalIdentity)
        .filter(ExternalIdentity.master_customer_id == int(customer.id))
        .order_by(ExternalIdentity.system_name.asc(), ExternalIdentity.external_type.asc(), ExternalIdentity.id.asc())
        .all()
    )
    try:
        summary = _paperless_scan_customer_documents(
            db,
            customer=customer,
            party=party,
            default_address=default_address,
            identities=identities,
            contact_rows=contact_rows,
            limit=16,
        )
        db.commit()
        _flash(
            request,
            f"Paperless geprueft: {int(summary.get('queries') or 0)} Suchlaeufe, {int(summary.get('fetched') or 0)} Dokumente gelesen, {int(summary.get('suggested') or 0)} Kundentreffer vorgemerkt.",
            "info",
        )
    except Exception as exc:
        db.rollback()
        _flash(request, f"Paperless-Prüfung fehlgeschlagen: {exc}", "error")
    return RedirectResponse(f"/crm/kunden/{int(customer.id)}", status_code=302)


@app.post("/crm/kunden/{customer_id}/datenqualitaet/pruefen")
def crm_customer_quality_scan(customer_id: int, request: Request, user=Depends(require_user), db: Session = Depends(db_session)):
    customer = db.get(MasterCustomer, customer_id)
    if not customer:
        raise HTTPException(status_code=404)
    party = db.get(Party, int(customer.party_id or 0))
    if not party:
        raise HTTPException(status_code=404)
    known_domains = _crm_known_email_domains(db)
    address_cache: dict[str, dict[str, object]] = {}
    email_cache: dict[str, dict[str, object]] = {}
    summary = {
        "addresses_checked": 0,
        "emails_checked": 0,
        "issues": 0,
        "autocorrected": 0,
    }
    try:
        addresses = db.query(CrmAddress).filter(CrmAddress.party_id == int(party.id)).all()
        for row in addresses:
            address_result = _crm_validate_address_row(row, cache=address_cache)
            db.add(row)
            if _crm_address_payload_has_content(
                {
                    "street": row.street,
                    "house_no": row.house_no,
                    "zip_code": row.zip_code,
                    "city": row.city,
                    "country_code": row.country_code,
                    "email": row.email,
                    "phone": row.phone,
                    "label": row.label,
                }
            ):
                summary["addresses_checked"] = int(summary["addresses_checked"]) + 1
            if bool(address_result.get("auto_corrected")):
                summary["autocorrected"] = int(summary["autocorrected"]) + 1
            if str(address_result.get("status") or "") in {"invalid", "review", "partial", "unknown"}:
                summary["issues"] = int(summary["issues"]) + 1
            email_result = _crm_validate_email_value(row.email, known_domains=known_domains, cache=email_cache)
            email_status = _crm_apply_email_validation_result(
                row,
                email_result,
                status_attr="email_validation_status",
                message_attr="email_validation_message",
                suggestion_attr="email_validation_suggestion",
                checked_attr="email_validated_at",
            )
            if email_status:
                summary["emails_checked"] = int(summary["emails_checked"]) + 1
            if email_status in {"invalid", "review", "undeliverable", "unknown"}:
                summary["issues"] = int(summary["issues"]) + 1
            db.add(row)

        contact_rows = db.query(CustomerContactPerson).filter(CustomerContactPerson.master_customer_id == int(customer.id)).all()
        for row in contact_rows:
            email_result = _crm_validate_email_value(row.email, known_domains=known_domains, cache=email_cache)
            email_status = _crm_apply_email_validation_result(
                row,
                email_result,
                status_attr="email_validation_status",
                message_attr="email_validation_message",
                suggestion_attr="email_validation_suggestion",
                checked_attr="email_validated_at",
            )
            if email_status:
                summary["emails_checked"] = int(summary["emails_checked"]) + 1
            if email_status in {"invalid", "review", "undeliverable", "unknown"}:
                summary["issues"] = int(summary["issues"]) + 1
            db.add(row)

        location_rows = db.query(ServiceLocation).filter(ServiceLocation.master_customer_id == int(customer.id)).all()
        for row in location_rows:
            email_result = _crm_validate_email_value(row.contact_email, known_domains=known_domains, cache=email_cache)
            email_status = _crm_apply_email_validation_result(
                row,
                email_result,
                status_attr="contact_email_validation_status",
                message_attr="contact_email_validation_message",
                suggestion_attr="contact_email_validation_suggestion",
                checked_attr="contact_email_validated_at",
            )
            if email_status:
                summary["emails_checked"] = int(summary["emails_checked"]) + 1
            if email_status in {"invalid", "review", "undeliverable", "unknown"}:
                summary["issues"] = int(summary["issues"]) + 1
            db.add(row)

        db.commit()
        _flash(
            request,
            f"Datenqualitaet geprueft: {int(summary['addresses_checked'])} Adressen, {int(summary['emails_checked'])} E-Mails, {int(summary['autocorrected'])} Adressen automatisch normalisiert, {int(summary['issues'])} offene Hinweise.",
            "info",
        )
    except Exception as exc:
        db.rollback()
        _flash(request, f"Datenqualitaetspruefung fehlgeschlagen: {exc}", "error")
    return RedirectResponse(f"/crm/kunden/{int(customer.id)}", status_code=302)


