@app.get("/crm/sevdesk-stage/{kind}/{stage_id}", response_class=HTMLResponse)
def crm_sevdesk_stage_detail(kind: str, stage_id: int, request: Request, user=Depends(require_user), db: Session = Depends(db_session)):
    kind_key = _crm_normalize_key(kind)
    if kind_key == "invoice":
        row = db.get(SevdeskInvoiceStage, stage_id)
    elif kind_key == "order":
        row = db.get(SevdeskOrderStage, stage_id)
    else:
        raise HTTPException(status_code=404)
    if row is None:
        raise HTTPException(status_code=404)
    payload = _crm_sevdesk_stage_document_detail_payload(kind_key, row)
    return templates.TemplateResponse(
        "crm/sevdesk_stage_detail.html",
        _ctx(
            request,
            user=user,
            kind=kind_key,
            row=row,
            payload=payload,
            raw_json_pretty=json.dumps(_json_dict(getattr(row, "raw_json", "")), indent=2, ensure_ascii=False),
            external_url=_sevdesk_document_external_url(
                _sevdesk_settings(db, include_secret=False),
                kind=kind_key,
                document_id=getattr(row, 'sevdesk_invoice_id' if kind_key == 'invoice' else 'sevdesk_order_id', ''),
                payload=_json_dict(getattr(row, "raw_json", "")),
            ),
        ),
    )


@app.get("/crm/sevdesk-live/{kind}/{document_id}", response_class=HTMLResponse)
def crm_sevdesk_live_detail(kind: str, document_id: str, request: Request, user=Depends(require_user), db: Session = Depends(db_session)):
    kind_key = _crm_normalize_key(kind)
    if kind_key not in {"invoice", "order"}:
        raise HTTPException(status_code=404)
    settings = _sevdesk_settings(db, include_secret=True)
    if not bool(settings.get("enabled")) or not bool(settings.get("api_token") or settings.get("token")):
        raise HTTPException(status_code=404)
    path = f"/{'Invoice' if kind_key == 'invoice' else 'Order'}/{str(document_id).strip()}"
    payload = _sevdesk_first_object(sevdesk_request_json(settings, method="GET", path=path))
    if not payload:
        raise HTTPException(status_code=404)
    detail_payload = _crm_sevdesk_live_document_detail_payload(kind_key, payload)
    return templates.TemplateResponse(
        "crm/sevdesk_stage_detail.html",
        _ctx(
            request,
            user=user,
            kind=kind_key,
            row=None,
            payload=detail_payload,
            raw_json_pretty=json.dumps(payload, indent=2, ensure_ascii=False),
            external_url=_sevdesk_document_external_url(
                _sevdesk_settings(db, include_secret=False),
                kind=kind_key,
                document_id=document_id,
                payload=payload,
            ),
        ),
    )


