@app.post("/crm/kunden/{customer_id}/bearbeiten")
async def crm_customer_edit_post(customer_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    customer = db.get(MasterCustomer, customer_id)
    if not customer:
        raise HTTPException(status_code=404)
    party = db.get(Party, int(customer.party_id))
    if not party:
        raise HTTPException(status_code=404)
    default_address = _crm_pick_default_address(
        db.query(CrmAddress).filter(CrmAddress.party_id == int(party.id)).order_by(CrmAddress.is_default.desc(), CrmAddress.id.asc()).all()
    )
    form = await request.form()
    form_data = _extract_form_data(form)
    form_errors: dict[str, str] = {}
    known_domains = _crm_known_email_domains(db)
    party_type = _crm_normalize_key(form.get("party_type")) or "company"
    display_name = _crm_party_display_name(form.get("display_name"), form.get("first_name"), form.get("last_name"))
    status = _crm_normalize_key(form.get("status")) or customer.status
    note = _crm_clean_text(form.get("note") or "") or None
    address_payload = _crm_parse_address_payload(form, prefix="address_")
    address_validation_result: dict[str, object] = {}
    address_email_validation_result: dict[str, object] = {}
    if party_type not in CRM_PARTY_TYPE_CHOICES:
        form_errors["party_type"] = "Bitte einen gültigen Kundentyp wählen."
    if not display_name:
        form_errors["display_name"] = "Ein Anzeigename ist Pflicht."
    if status not in CRM_CUSTOMER_STATUS_CHOICES:
        form_errors["status"] = "Bitte einen gültigen Status wählen."
    if _crm_address_payload_has_content(address_payload):
        address_probe = CrmAddress(party_id=int(party.id), is_default=True, active=True)
        _crm_apply_address_payload(address_probe, address_payload)
        address_validation_result = _crm_validate_address_row(address_probe)
        if str(address_validation_result.get("status") or "") == "invalid":
            form_errors["address_street"] = str(address_validation_result.get("message") or "Adresse ist ungueltig.")
        address_email_validation_result = _crm_validate_email_value(address_probe.email, known_domains=known_domains)
        if str(address_email_validation_result.get("status") or "") in {"invalid", "review", "undeliverable"}:
            form_errors["address_email"] = str(address_email_validation_result.get("message") or "E-Mail-Adresse bitte pruefen.")
    if form_errors:
        for message in form_errors.values():
            _flash(request, message, "error")
        return _crm_render_customer_form(
            request,
            user=user,
            page_title=f"Kunde bearbeiten: {customer.customer_no_internal}",
            form_action=f"/crm/kunden/{int(customer.id)}/bearbeiten",
            customer=customer,
            party=party,
            default_address=default_address,
            form_data=form_data,
            form_errors=form_errors,
        )
    party.party_type = party_type
    party.display_name = display_name
    party.first_name = _crm_clean_text(form.get("first_name") or "") or None
    party.last_name = _crm_clean_text(form.get("last_name") or "") or None
    party.active = form.get("active") == "on"
    party.note = note
    party.updated_at = _utcnow_naive()
    customer.status = status
    customer.note = note
    customer.updated_at = _utcnow_naive()
    db.add(party)
    db.add(customer)
    if _crm_address_payload_has_content(address_payload):
        address = default_address or CrmAddress(party_id=int(party.id), active=True)
        _crm_apply_address_payload(address, address_payload)
        address.is_default = True
        if not address.label:
            address.label = "Hauptadresse"
        _crm_apply_address_validation_result(address, address_validation_result)
        _crm_apply_email_validation_result(
            address,
            address_email_validation_result,
            status_attr="email_validation_status",
            message_attr="email_validation_message",
            suggestion_attr="email_validation_suggestion",
            checked_attr="email_validated_at",
        )
        db.add(address)
        db.flush()
        _crm_clear_default_addresses(db, int(party.id), int(address.id))
    try:
        db.commit()
    except Exception as exc:
        db.rollback()
        _flash(request, _friendly_db_write_error(exc), "error")
        return _crm_render_customer_form(
            request,
            user=user,
            page_title=f"Kunde bearbeiten: {customer.customer_no_internal}",
            form_action=f"/crm/kunden/{int(customer.id)}/bearbeiten",
            customer=customer,
            party=party,
            default_address=default_address,
            form_data=form_data,
            form_errors={"__all__": _friendly_db_write_error(exc)},
        )
    _flash(request, "Kunde gespeichert.", "info")
    return RedirectResponse(f"/crm/kunden/{int(customer.id)}", status_code=302)


@app.get("/crm/kunden/{customer_id}/adressen/neu", response_class=HTMLResponse)
def crm_customer_address_new_get(
    customer_id: int,
    request: Request,
    user=Depends(require_admin),
    usage_type: str = "",
    db: Session = Depends(db_session),
):
    customer = db.get(MasterCustomer, customer_id)
    if not customer:
        raise HTTPException(status_code=404)
    party = db.get(Party, int(customer.party_id))
    if not party:
        raise HTTPException(status_code=404)
    usage_type_key = _crm_normalize_key(usage_type) or "other"
    if usage_type_key not in CRM_ADDRESS_USAGE_CHOICES:
        usage_type_key = "other"
    default_label = {
        "main": "Hauptadresse",
        "billing": "Rechnungsadresse",
        "service": "Leistungsort",
        "postal": "Postadresse",
        "other": "Adresse",
    }.get(usage_type_key, "Adresse")
    return _crm_render_address_form(
        request,
        user=user,
        customer=customer,
        party=party,
        row=None,
        page_title="Adresse anlegen",
        form_action=f"/crm/kunden/{int(customer.id)}/adressen/neu",
        form_data={"usage_type": usage_type_key, "label": default_label},
        form_errors={},
    )


@app.post("/crm/kunden/{customer_id}/adressen/neu")
async def crm_customer_address_new_post(customer_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    customer = db.get(MasterCustomer, customer_id)
    if not customer:
        raise HTTPException(status_code=404)
    party = db.get(Party, int(customer.party_id))
    if not party:
        raise HTTPException(status_code=404)
    form = await request.form()
    form_data = _extract_form_data(form)
    form_errors: dict[str, str] = {}
    known_domains = _crm_known_email_domains(db)
    payload = _crm_parse_address_payload(form)
    address_probe = CrmAddress(party_id=int(party.id), active=form.get("active") == "on", is_default=form.get("is_default") == "on")
    _crm_apply_address_payload(address_probe, payload)
    address_validation_result: dict[str, object] = {}
    email_validation_result: dict[str, object] = {}
    if not _crm_address_payload_has_content(payload):
        form_errors["street"] = "Bitte mindestens Anschrift oder Kontaktdaten eingeben."
    else:
        address_validation_result = _crm_validate_address_row(address_probe)
        if str(address_validation_result.get("status") or "") == "invalid":
            form_errors["street"] = str(address_validation_result.get("message") or "Adresse ist ungueltig.")
        email_validation_result = _crm_validate_email_value(address_probe.email, known_domains=known_domains)
        if str(email_validation_result.get("status") or "") in {"invalid", "review", "undeliverable"}:
            form_errors["email"] = str(email_validation_result.get("message") or "E-Mail-Adresse bitte pruefen.")
    if form_errors:
        for message in form_errors.values():
            _flash(request, message, "error")
        return _crm_render_address_form(
            request,
            user=user,
            customer=customer,
            party=party,
            row=None,
            page_title="Adresse anlegen",
            form_action=f"/crm/kunden/{int(customer.id)}/adressen/neu",
            form_data=form_data,
            form_errors=form_errors,
        )
    row = CrmAddress(
        party_id=int(party.id),
        active=form.get("active") == "on",
        is_default=form.get("is_default") == "on",
    )
    _crm_apply_address_payload(row, payload)
    if not row.label:
        row.label = "Adresse"
    _crm_apply_address_validation_result(row, address_validation_result)
    _crm_apply_email_validation_result(
        row,
        email_validation_result,
        status_attr="email_validation_status",
        message_attr="email_validation_message",
        suggestion_attr="email_validation_suggestion",
        checked_attr="email_validated_at",
    )
    db.add(row)
    db.flush()
    if bool(row.is_default):
        _crm_clear_default_addresses(db, int(party.id), int(row.id))
    try:
        db.commit()
    except Exception as exc:
        db.rollback()
        _flash(request, _friendly_db_write_error(exc), "error")
        return _crm_render_address_form(
            request,
            user=user,
            customer=customer,
            party=party,
            row=None,
            page_title="Adresse anlegen",
            form_action=f"/crm/kunden/{int(customer.id)}/adressen/neu",
            form_data=form_data,
            form_errors={"__all__": _friendly_db_write_error(exc)},
        )
    _flash(request, "Adresse angelegt.", "info")
    return RedirectResponse(f"/crm/kunden/{int(customer.id)}", status_code=302)


