@app.post("/crm/kunden/{customer_id}/standorte/neu")
async def crm_location_new_post(customer_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    customer = db.get(MasterCustomer, customer_id)
    if not customer:
        raise HTTPException(status_code=404)
    party = db.get(Party, int(customer.party_id))
    if not party:
        raise HTTPException(status_code=404)
    address_rows = (
        db.query(CrmAddress)
        .filter(CrmAddress.party_id == int(party.id))
        .order_by(CrmAddress.is_default.desc(), CrmAddress.id.asc())
        .all()
    )
    address_options = [{"id": int(row.id), "label": _crm_address_summary(row) or (row.label or f"Adresse {row.id}")} for row in address_rows]
    form = await request.form()
    form_data = _extract_form_data(form)
    form_errors: dict[str, str] = {}
    known_domains = _crm_known_email_domains(db)
    location_label = _crm_clean_text(form.get("location_label") or "")
    selected_address_id = _to_int(form.get("existing_address_id"), 0)
    address_payload = _crm_parse_address_payload(form, prefix="address_")
    address_validation_result: dict[str, object] = {}
    address_email_validation_result: dict[str, object] = {}
    location_email_validation_result = _crm_validate_email_value(form.get("contact_email"), known_domains=known_domains)
    if not location_label:
        form_errors["location_label"] = "Eine Standortbezeichnung ist Pflicht."
    selected_address = db.get(CrmAddress, selected_address_id) if selected_address_id > 0 else None
    if selected_address and int(selected_address.party_id or 0) != int(party.id):
        selected_address = None
        form_errors["address_street"] = "Die ausgewählte Adresse gehört nicht zu diesem Kunden."
    if selected_address is None and not _crm_address_payload_has_content(address_payload):
        form_errors["address_street"] = "Bitte eine vorhandene Adresse wählen oder eine neue Adresse erfassen."
    if str(location_email_validation_result.get("status") or "") in {"invalid", "review", "undeliverable"}:
        form_errors["contact_email"] = str(location_email_validation_result.get("message") or "E-Mail-Adresse bitte pruefen.")
    if selected_address is None or _crm_address_payload_has_content(address_payload):
        address_probe = CrmAddress(party_id=int(party.id), active=True, is_default=False)
        _crm_apply_address_payload(address_probe, address_payload)
        address_validation_result = _crm_validate_address_row(address_probe)
        if str(address_validation_result.get("status") or "") == "invalid":
            form_errors["address_street"] = str(address_validation_result.get("message") or "Adresse ist ungueltig.")
        address_email_validation_result = _crm_validate_email_value(address_probe.email, known_domains=known_domains)
        if str(address_email_validation_result.get("status") or "") in {"invalid", "review", "undeliverable"}:
            form_errors["address_email"] = str(address_email_validation_result.get("message") or "E-Mail-Adresse bitte pruefen.")
    if form_errors:
        for message in form_errors.values():
            _flash(request, message, "error")
        return _crm_render_location_form(
            request,
            user=user,
            customer=customer,
            party=party,
            row=None,
            address_row=None,
            address_options=address_options,
            selected_address_id=selected_address_id,
            page_title="Standort anlegen",
            form_action=f"/crm/kunden/{int(customer.id)}/standorte/neu",
            form_data=form_data,
            form_errors=form_errors,
        )
    address_row = selected_address
    if address_row is None:
        address_row = CrmAddress(party_id=int(party.id), active=True, is_default=False)
        _crm_apply_address_payload(address_row, address_payload)
        if not _crm_clean_text(address_row.usage_type):
            address_row.usage_type = "service"
        if not address_row.label:
            address_row.label = location_label
        _crm_apply_address_validation_result(address_row, address_validation_result)
        _crm_apply_email_validation_result(
            address_row,
            address_email_validation_result,
            status_attr="email_validation_status",
            message_attr="email_validation_message",
            suggestion_attr="email_validation_suggestion",
            checked_attr="email_validated_at",
        )
        db.add(address_row)
        db.flush()
    else:
        if _crm_address_payload_has_content(address_payload):
            _crm_apply_address_payload(address_row, address_payload)
            if not _crm_clean_text(address_row.usage_type):
                address_row.usage_type = "service"
            if not address_row.label:
                address_row.label = location_label
            _crm_apply_address_validation_result(address_row, address_validation_result)
            _crm_apply_email_validation_result(
                address_row,
                address_email_validation_result,
                status_attr="email_validation_status",
                message_attr="email_validation_message",
                suggestion_attr="email_validation_suggestion",
                checked_attr="email_validated_at",
            )
            db.add(address_row)
    row = ServiceLocation(
        master_customer_id=int(customer.id),
        party_id=int(party.id),
        address_id=int(address_row.id),
        location_label=location_label,
        contact_name=_crm_clean_text(form.get("contact_name") or "") or None,
        contact_email=_crm_clean_text(form.get("contact_email") or "") or None,
        contact_phone=_crm_clean_text(form.get("contact_phone") or "") or None,
        note=_crm_clean_text(form.get("note") or "") or None,
        active=form.get("active") == "on",
    )
    _crm_apply_email_validation_result(
        row,
        location_email_validation_result,
        status_attr="contact_email_validation_status",
        message_attr="contact_email_validation_message",
        suggestion_attr="contact_email_validation_suggestion",
        checked_attr="contact_email_validated_at",
    )
    db.add(row)
    try:
        db.commit()
    except Exception as exc:
        db.rollback()
        _flash(request, _friendly_db_write_error(exc), "error")
        return _crm_render_location_form(
            request,
            user=user,
            customer=customer,
            party=party,
            row=None,
            address_row=address_row if getattr(address_row, "id", None) else None,
            address_options=address_options,
            selected_address_id=selected_address_id,
            page_title="Standort anlegen",
            form_action=f"/crm/kunden/{int(customer.id)}/standorte/neu",
            form_data=form_data,
            form_errors={"__all__": _friendly_db_write_error(exc)},
        )
    _flash(request, "Standort angelegt.", "info")
    return RedirectResponse(f"/crm/kunden/{int(customer.id)}", status_code=302)


