@app.post("/serviceauftraege/neu")
async def crm_case_new_post(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    _require_internal_service_orders_enabled()
    form = await request.form()
    form_data = _extract_form_data(form)
    form_errors: dict[str, str] = {}
    title = _crm_clean_text(form.get("title") or "")
    status = _crm_normalize_key(form.get("status")) or "open"
    priority = _crm_normalize_key(form.get("priority")) or "normal"
    order_type = _crm_normalize_key(form.get("order_type")) or "service"
    ordering_party_id = _to_int(form.get("ordering_party_id"), 0)
    service_location_id = _to_int(form.get("service_location_id"), 0)
    invoice_recipient_id = _to_int(form.get("invoice_recipient_id"), 0) or ordering_party_id
    customer_object_id = _to_int(form.get("customer_object_id"), 0)
    requested_start_at_raw = str(form.get("requested_start_at") or "").strip()
    requested_end_at_raw = str(form.get("requested_end_at") or "").strip()
    proposed_start_at_raw = str(form.get("proposed_start_at") or "").strip()
    proposed_end_at_raw = str(form.get("proposed_end_at") or "").strip()
    service_contact_name = _crm_clean_text(form.get("service_contact_name") or "") or None
    service_contact_phone = _crm_clean_text(form.get("service_contact_phone") or "") or None
    service_contact_email = _crm_clean_text(form.get("service_contact_email") or "") or None
    device_label = _crm_clean_text(form.get("device_label") or "") or None
    customer_issue = _outsmart_clean_multiline(form.get("customer_issue") or "") or None
    customer_visible_note = _outsmart_clean_multiline(form.get("customer_visible_note") or "") or None
    work_instructions = _outsmart_clean_multiline(form.get("work_instructions") or "") or None
    material_summary = _outsmart_clean_multiline(form.get("material_summary") or "") or None
    spare_part_status = _crm_normalize_key(form.get("spare_part_status")) or "unknown"
    spare_part_note = _outsmart_clean_multiline(form.get("spare_part_note") or "") or None
    schedule_hint = _outsmart_clean_multiline(form.get("schedule_hint") or "") or None
    next_step = _crm_normalize_key(form.get("next_step")) or "none"
    if not title:
        form_errors["title"] = "Ein Titel ist Pflicht."
    if status not in CRM_CASE_STATUS_CHOICES:
        form_errors["status"] = "Bitte einen gültigen Status wählen."
    if priority not in CRM_CASE_PRIORITY_CHOICES:
        form_errors["priority"] = "Bitte eine gültige Priorität wählen."
    if order_type not in CRM_CASE_ORDER_TYPE_CHOICES:
        form_errors["order_type"] = "Bitte eine gueltige Auftragsart waehlen."
    if spare_part_status not in CRM_CASE_SPARE_PART_STATUS_CHOICES:
        form_errors["spare_part_status"] = "Bitte einen gueltigen Ersatzteilstatus waehlen."
    if next_step not in CRM_CASE_NEXT_STEP_CHOICES:
        form_errors["next_step"] = "Bitte einen gueltigen naechsten Schritt waehlen."
    ordering_party = db.get(MasterCustomer, ordering_party_id) if ordering_party_id > 0 else None
    service_location = db.get(ServiceLocation, service_location_id) if service_location_id > 0 else None
    invoice_recipient = db.get(MasterCustomer, invoice_recipient_id) if invoice_recipient_id > 0 else None
    customer_object = db.get(CustomerObject, customer_object_id) if customer_object_id > 0 else None
    if ordering_party is None:
        form_errors["ordering_party_id"] = "Bitte einen Auftraggeber wählen."
    if service_location is None:
        form_errors["service_location_id"] = "Bitte einen Leistungsort wählen."
    if invoice_recipient is None:
        form_errors["invoice_recipient_id"] = "Bitte einen Rechnungsempfänger wählen."
    if customer_object_id > 0 and customer_object is None:
        form_errors["customer_object_id"] = "Bitte ein gültiges Objekt wählen."
    if customer_object and int(service_location_id or 0) > 0 and int(customer_object.service_location_id or 0) not in (0, int(service_location_id)):
        form_errors["customer_object_id"] = "Das Objekt gehört nicht zum gewählten Leistungsort."
    elif customer_object and int(ordering_party_id or 0) > 0 and int(customer_object.master_customer_id or 0) not in (0, int(ordering_party_id)):
        form_errors["customer_object_id"] = "Das Objekt gehört nicht zum gewählten Auftraggeber."
    try:
        requested_start_at = _parse_datetime_input(requested_start_at_raw)
    except ValueError as exc:
        requested_start_at = None
        form_errors["requested_start_at"] = str(exc)
    try:
        requested_end_at = _parse_datetime_input(requested_end_at_raw)
    except ValueError as exc:
        requested_end_at = None
        form_errors["requested_end_at"] = str(exc)
    try:
        proposed_start_at = _parse_datetime_input(proposed_start_at_raw)
    except ValueError as exc:
        proposed_start_at = None
        form_errors["proposed_start_at"] = str(exc)
    try:
        proposed_end_at = _parse_datetime_input(proposed_end_at_raw)
    except ValueError as exc:
        proposed_end_at = None
        form_errors["proposed_end_at"] = str(exc)
    if requested_start_at and requested_end_at and requested_end_at < requested_start_at:
        form_errors["requested_end_at"] = "Das gewünschte Ende muss nach dem Beginn liegen."
    if proposed_start_at and proposed_end_at and proposed_end_at < proposed_start_at:
        form_errors["proposed_end_at"] = "Das vorgeschlagene Ende muss nach dem Beginn liegen."
    if form_errors:
        for message in form_errors.values():
            _flash(request, message, "error")
        return _crm_render_case_form(
            request,
            user=user,
            row=None,
            page_title="Auftrag anlegen",
            form_action="/serviceauftraege/neu",
            form_data=form_data,
            form_errors=form_errors,
            selected_ordering_party_id=ordering_party_id,
            selected_service_location_id=service_location_id,
            selected_invoice_recipient_id=invoice_recipient_id,
            selected_customer_object_id=customer_object_id,
            db=db,
        )
    row = CrmCase(
        case_no=_crm_next_case_no(db),
        title=title,
        status=status,
        priority=priority,
        order_type=order_type,
        service_contact_name=service_contact_name,
        service_contact_phone=service_contact_phone,
        service_contact_email=service_contact_email,
        requested_start_at=requested_start_at,
        requested_end_at=requested_end_at,
        proposed_start_at=proposed_start_at,
        proposed_end_at=proposed_end_at,
        customer_object_id=int(customer_object.id) if customer_object else None,
        device_label=device_label,
        customer_issue=customer_issue,
        customer_visible_note=customer_visible_note,
        work_instructions=work_instructions,
        material_summary=material_summary,
        spare_part_status=spare_part_status,
        spare_part_note=spare_part_note,
        schedule_hint=schedule_hint,
        next_step=next_step,
        source_system="local",
        note=_outsmart_clean_multiline(form.get("note") or "") or None,
        created_at=_utcnow_naive(),
        updated_at=_utcnow_naive(),
    )
    db.add(row)
    db.flush()
    _, ordering_default_map = _crm_party_address_maps(db, [int(ordering_party.party_id), int(invoice_recipient.party_id)])
    _crm_set_case_role(
        db,
        crm_case_id=int(row.id),
        role_type=CRM_ROLE_ORDERING_PARTY,
        master_customer_id=int(ordering_party.id),
        address_id=int(ordering_default_map.get(int(ordering_party.party_id)).id) if ordering_default_map.get(int(ordering_party.party_id)) else None,
    )
    _crm_set_case_role(
        db,
        crm_case_id=int(row.id),
        role_type=CRM_ROLE_SERVICE_LOCATION,
        master_customer_id=int(service_location.master_customer_id or 0) or None,
        service_location_id=int(service_location.id),
        address_id=int(service_location.address_id or 0) or None,
    )
    _crm_set_case_role(
        db,
        crm_case_id=int(row.id),
        role_type=CRM_ROLE_INVOICE_RECIPIENT,
        master_customer_id=int(invoice_recipient.id),
        address_id=int(ordering_default_map.get(int(invoice_recipient.party_id)).id) if ordering_default_map.get(int(invoice_recipient.party_id)) else None,
    )
    try:
        db.commit()
    except Exception as exc:
        db.rollback()
        _flash(request, _friendly_db_write_error(exc), "error")
        return _crm_render_case_form(
            request,
            user=user,
            row=None,
            page_title="Auftrag anlegen",
            form_action="/serviceauftraege/neu",
            form_data=form_data,
            form_errors={"__all__": _friendly_db_write_error(exc)},
            selected_ordering_party_id=ordering_party_id,
            selected_service_location_id=service_location_id,
            selected_invoice_recipient_id=invoice_recipient_id,
            selected_customer_object_id=customer_object_id,
            db=db,
        )
    _flash(request, "Auftrag angelegt.", "info")
    return RedirectResponse(f"/serviceauftraege/{int(row.id)}", status_code=302)


