@app.post("/serviceauftraege/{case_id}/weiter")
async def crm_case_next_step(case_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    _require_internal_service_orders_enabled()
    row = db.get(CrmCase, case_id)
    if not row:
        raise HTTPException(status_code=404)
    case_context = _crm_case_context(db, int(row.id))
    ordering_customer = case_context.get("ordering_customer")
    service_location = case_context.get("service_location")
    form = await request.form()
    action = _crm_normalize_key(form.get("action")) or "none"
    if action not in CRM_CASE_NEXT_STEP_CHOICES:
        _flash(request, "Unbekannter Verarbeitungsschritt.", "error")
        return RedirectResponse(f"/serviceauftraege/{int(row.id)}", status_code=302)
    row.next_step = action
    row.updated_at = _utcnow_naive()
    db.add(row)
    _crm_add_timeline_event(
        db,
        case_id=int(row.id),
        master_customer_id=int(ordering_customer.id) if ordering_customer else None,
        service_location_id=int(service_location.id) if service_location else None,
        customer_object_id=int(row.customer_object_id or 0) or None,
        source_system="local",
        event_type="case_next_step",
        title=f"Weiter: {_crm_case_next_step_label(action)}",
        body=row.title,
        event_ts=_utcnow_naive(),
        external_ref=f"case_next_step:{int(row.id)}:{action}",
        meta={"next_step": action},
    )
    db.commit()
    if action == "invoice":
        return RedirectResponse(f"/crm/rechnungen/neu?case_id={int(row.id)}", status_code=302)
    if action == "replacement_offer":
        return RedirectResponse(f"/crm/angebote/neu?case_id={int(row.id)}", status_code=302)
    if action == "spare_part":
        _flash(request, "Auftrag ist jetzt auf Ersatzteil-Nachbearbeitung markiert.", "info")
    else:
        _flash(request, "Weiteren Schritt zurückgesetzt.", "info")
    return RedirectResponse(f"/serviceauftraege/{int(row.id)}", status_code=302)


