def _upsert_document_inbox_item(db: Session, payload: dict) -> DocumentInboxItem | None:
    document_id = str(payload.get("id") or payload.get("document_id") or "").strip()
    if not document_id:
        return None
    row = db.query(DocumentInboxItem).filter(DocumentInboxItem.paperless_document_id == document_id).one_or_none()
    created_date = None
    created_raw = ""
    for key in ("added", "modified", "created", "created_date"):
        value = str(payload.get(key) or "").strip()
        if value:
            created_raw = value
            break
    if created_raw:
        try:
            created_date = dt.datetime.fromisoformat(created_raw.replace("Z", "+00:00")).replace(tzinfo=None)
        except Exception:
            created_date = None
    if not row:
        row = DocumentInboxItem(
            paperless_document_id=document_id,
            source_kind="paperless",
            workflow_state="draft",
            status="new",
            created_at=_utcnow_naive(),
        )
    elif not str(row.source_kind or "").strip():
        row.source_kind = _document_inbox_source_kind(row) or "paperless"
    if not str(row.workflow_state or "").strip():
        row.workflow_state = _document_inbox_effective_workflow_state(row)
    row.title = str(payload.get("title") or payload.get("original_file_name") or "").strip() or row.title
    row.correspondent = str(payload.get("correspondent_name") or payload.get("correspondent") or "").strip() or row.correspondent
    row.document_type = str(payload.get("document_type_name") or payload.get("document_type") or "").strip() or row.document_type
    row.created_date = created_date or row.created_date
    merged_meta = _purchase_document_merge_metadata(row.metadata_json, payload)
    row.metadata_json = json.dumps(merged_meta, ensure_ascii=False)
    db.add(row)
    db.flush()
    return row


def _paperless_document_download_url(document_id: str | int | None) -> str:
    value = str(document_id or "").strip()
    if not value:
        return ""
    return f"/crm/paperless/{quote(value, safe='')}/download"


def _paperless_sync_documents_page(
    settings: dict[str, str | bool],
    *,
    page: int = 1,
    page_size: int = PAPERLESS_SYNC_PAGE_SIZE,
    query: str | None = None,
) -> dict[str, object]:
    payload = paperless_request_json(
        settings,
        method="GET",
        path="/api/documents/",
        query={
            "page_size": str(max(1, int(page_size))),
            "page": str(max(1, int(page))),
            "ordering": "-created_date",
            **({"query": str(query).strip()} if str(query or "").strip() else {}),
        },
    )
    if isinstance(payload, dict):
        return payload
    if isinstance(payload, list):
        return {"results": [row for row in payload if isinstance(row, dict)], "next": None}
    return {"results": [], "next": None}


def _paperless_sync_inbox_once(
    db: Session,
    *,
    force_full: bool = False,
    max_pages: int | None = None,
    page_size: int | None = None,
) -> dict[str, int]:
    settings = _paperless_settings(db, include_secret=True)
    mode = str(settings.get("mode") or "poll_api").strip() or "poll_api"
    summary = {"fetched": 0, "created": 0, "updated": 0, "pages": 0}
    if not bool(settings.get("enabled")) or not bool(settings.get("token")) or mode != "poll_api":
        return summary
    page_limit = max(1, int(max_pages or PAPERLESS_SYNC_MAX_PAGES))
    effective_page_size = max(20, int(page_size or PAPERLESS_SYNC_PAGE_SIZE))
    last_sync_at = None if force_full else _crm_coerce_datetime(_system_setting_get(db, PAPERLESS_SETTING_LAST_SYNC_AT, "") or "")
    newest_created_at: dt.datetime | None = None
    reached_known_rows = False
    for page_no in range(1, page_limit + 1):
        page_payload = _paperless_sync_documents_page(settings, page=page_no, page_size=effective_page_size)
        rows = [row for row in list(page_payload.get("results") or []) if isinstance(row, dict)]
        summary["pages"] += 1
        if not rows:
            break
        for payload in rows:
            created_at = _crm_coerce_datetime(
                payload.get("added")
                or payload.get("modified")
                or payload.get("created")
                or payload.get("created_date")
            )
            if created_at is not None and (newest_created_at is None or created_at > newest_created_at):
                newest_created_at = created_at
            if last_sync_at is not None and created_at is not None and created_at <= last_sync_at:
                reached_known_rows = True
                break
            document_id = str(payload.get("id") or payload.get("document_id") or "").strip()
            existed = False
            if document_id:
                existed = db.query(DocumentInboxItem.id).filter(DocumentInboxItem.paperless_document_id == document_id).first() is not None
            item = _upsert_document_inbox_item(db, payload)
            if item is None:
                continue
            summary["fetched"] += 1
            if existed:
                summary["updated"] += 1
            else:
                summary["created"] += 1
        if reached_known_rows or not page_payload.get("next"):
            break
    if newest_created_at is not None:
        _paperless_set_last_sync_at(db, newest_created_at)
    elif force_full:
        _paperless_set_last_sync_at(db)
    return summary


def _link_inbox_item_to_object(
    db: Session,
    *,
    item: DocumentInboxItem,
    object_type: str,
    object_id: int,
    paperless_title: str | None = None,
) -> None:
    _ensure_paperless_link(
        db,
        object_type=object_type,
        object_id=int(object_id),
        paperless_document_id=item.paperless_document_id,
        paperless_title=paperless_title or item.title,
    )
    item.status = "matched"
    item.suggested_object_type = str(object_type)
    item.suggested_object_id = int(object_id)
    if not _document_inbox_normalize_kind(getattr(item, "draft_kind", "")):
        object_kind_map = {
            "purchase_order": "bestellung",
            "goods_receipt": "lieferschein",
            "purchase_invoice": "eingangsrechnung",
            "incoming_voucher_draft": "eingangsrechnung",
            "invoice_draft": "ausgangsrechnung",
        }
        inferred_kind = object_kind_map.get(str(object_type or "").strip())
        if inferred_kind:
            item.draft_kind = inferred_kind
    if str(object_type or "").strip() in {"purchase_order", "goods_receipt", "purchase_invoice", "incoming_voucher_draft", "invoice_draft"}:
        _document_inbox_progress_state(item, "prepared")
    else:
        _document_inbox_progress_state(item, "matched")
    db.add(item)
    _document_timeline_add(
        db,
        object_type=str(object_type),
        object_id=int(object_id),
        title=f"Dokument zugeordnet: {item.title or item.paperless_document_id}",
        paperless_document_id=item.paperless_document_id,
        external_ref=f"paperless:{item.paperless_document_id}:{object_type}:{int(object_id)}",
    )


def _paperless_export_and_link(
    db: Session,
    *,
    settings: dict[str, str | bool],
    object_type: str,
    object_id: int,
    title: str,
    lines: list[str],
) -> str:
    export_path = _build_plaintext_export(title, lines)
    result = paperless_upload_document(
        export_path,
        settings,
        title=title,
        mime="text/plain",
    )
    document_id = str(result.get("document_id") or "").strip()
    if not document_id:
        raise ValueError("Paperless hat keine Dokument-ID zurückgegeben.")
    _ensure_paperless_link(
        db,
        object_type=object_type,
        object_id=int(object_id),
        paperless_document_id=document_id,
        paperless_title=title,
    )
    return document_id


