@app.post("/einkauf/dokumente/upload-inbox")
async def einkauf_document_inbox_upload(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    _ = user
    form = await request.form()
    upload: UploadFile = form.get("file")  # type: ignore
    if upload is None or not upload.filename:
        _flash(request, "Bitte eine PDF-, JPG- oder PNG-Datei auswählen.", "error")
        return RedirectResponse("/einkauf/dokumente", status_code=302)
    if not _purchase_document_supported(upload.filename, upload.content_type):
        _flash(request, "Nur PDF, JPG und PNG werden unterstützt.", "error")
        return RedirectResponse("/einkauf/dokumente", status_code=302)
    abs_path = _purchase_document_storage_path(upload.filename)
    payload = await upload.read()
    if not payload:
        _flash(request, "Die Datei ist leer.", "error")
        return RedirectResponse("/einkauf/dokumente", status_code=302)
    abs_path.write_bytes(payload)
    try:
        item = _purchase_document_upload_to_inbox(
            db,
            abs_path=abs_path,
            title=Path(str(upload.filename)).name,
            mime_type=str(upload.content_type or "application/octet-stream"),
            metadata={
                "source": "manual_upload",
                "local_file_path": str(abs_path),
                "original_file_name": Path(str(upload.filename)).name,
            },
            created_at=_utcnow_naive(),
        )
        db.commit()
        _flash(request, "Dokument in den Einkaufs-Dokumenteneingang übernommen.", "info")
        return RedirectResponse(f"/einkauf/dokumente/{int(item.id)}", status_code=302)
    except Exception as exc:
        db.rollback()
        _flash(request, f"Upload fehlgeschlagen: {exc}", "error")
        return RedirectResponse("/einkauf/dokumente", status_code=302)


@app.post("/einkauf/dokumente/abrufen")
def einkauf_document_inbox_fetch(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    settings = _paperless_settings(db, include_secret=True)
    mode = str(settings.get("mode") or "poll_api").strip()
    if mode != "poll_api":
        _flash(request, "Paperless-Abruf ist im aktuellen Modus deaktiviert.", "warn")
        return RedirectResponse("/einkauf/dokumente", status_code=302)
    try:
        summary = _paperless_sync_inbox_once(db, max_pages=4)
        db.commit()
        _flash(request, f"{int(summary.get('fetched') or 0)} Dokument(e) aus Paperless geprüft.", "info")
    except Exception as exc:
        db.rollback()
        _flash(request, f"Paperless-Abruf fehlgeschlagen: {exc}", "error")
    return RedirectResponse("/einkauf/dokumente", status_code=302)


