@app.get("/einkauf/dokumente/{item_id:int}/quelle")
def einkauf_document_source_file(item_id: int, request: Request, user=Depends(require_user), db: Session = Depends(db_session)):
    _ = request, user
    item = db.get(DocumentInboxItem, item_id)
    if not item:
        raise HTTPException(status_code=404)
    abs_path = _purchase_document_source_abs_path(db, item)
    if abs_path is None or not abs_path.is_file():
        raise HTTPException(status_code=404)
    suffix = abs_path.suffix.lower()
    media_type = "application/octet-stream"
    if suffix == ".pdf":
        media_type = "application/pdf"
    elif suffix == ".png":
        media_type = "image/png"
    elif suffix in {".jpg", ".jpeg"}:
        media_type = "image/jpeg"
    return FileResponse(path=str(abs_path), media_type=media_type, filename=abs_path.name)


@app.post("/einkauf/dokumente/{item_id:int}")
async def einkauf_document_match_post(item_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    item = db.get(DocumentInboxItem, item_id)
    if not item:
        raise HTTPException(status_code=404)
    form = await request.form()
    intent = str(form.get("intent") or "").strip().lower()
    if intent == "classification":
        draft_kind = str(form.get("draft_kind") or "").strip()
        workflow_state = str(form.get("workflow_state") or "").strip()
        use_ai_kind = form.get("use_ai_kind") == "1"
        if use_ai_kind:
            ai_result = _document_inbox_ai_result(db, item)
            draft_kind = _document_inbox_guess_kind(item, ai_output=dict((ai_result or {}).get("output") or {}))
        _document_inbox_apply_classification(item, draft_kind=draft_kind, workflow_state=workflow_state)
        if not str(item.workflow_state or "").strip():
            item.workflow_state = _document_inbox_effective_workflow_state(item)
        db.add(item)
        db.commit()
        _flash(
            request,
            f"Belegtyp gespeichert: {_document_inbox_kind_label(item.draft_kind)} | {_document_inbox_workflow_label(item.workflow_state)}.",
            "info",
        )
        if form.get("open_next") == "1":
            next_action = _document_inbox_next_action(item)
            if next_action.get("url"):
                return RedirectResponse(str(next_action.get("url")), status_code=302)
            if str(next_action.get("hint") or "").strip():
                _flash(request, str(next_action.get("hint")), "warn")
        return RedirectResponse(f"/einkauf/dokumente/{item_id}", status_code=302)
    object_type = (form.get("object_type") or "").strip()
    if object_type == "ignored":
        item.status = "ignored"
        db.add(item)
        db.commit()
        _flash(request, "Dokument ignoriert.", "info")
        return RedirectResponse("/einkauf/dokumente", status_code=302)
    object_id = 0
    if object_type == "purchase_order":
        object_id = _to_int(form.get("purchase_order_id"), 0)
    elif object_type == "goods_receipt":
        object_id = _to_int(form.get("goods_receipt_id"), 0)
    elif object_type == "purchase_invoice":
        object_id = _to_int(form.get("purchase_invoice_id"), 0)
    elif object_type == "supplier":
        object_id = _to_int(form.get("supplier_id"), 0)
    if object_id <= 0:
        _flash(request, "Bitte ein Zielobjekt auswählen.", "error")
        return RedirectResponse(f"/einkauf/dokumente/{item_id}", status_code=302)
    _link_inbox_item_to_object(db, item=item, object_type=object_type, object_id=int(object_id))
    db.commit()
    _flash(request, "Dokument zugeordnet.", "info")
    return RedirectResponse("/einkauf/dokumente", status_code=302)


