@app.post("/einkauf/buchungskonten")
async def einkauf_accounting_accounts_post(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    _ = user
    form = await request.form()
    account_id = _to_int(form.get("account_id"), 0)
    row = db.get(AccountingAccount, account_id) if account_id > 0 else AccountingAccount(created_at=_utcnow_naive())
    if row is None:
        raise HTTPException(status_code=404)
    account_number = str(form.get("account_number") or "").strip()
    label = str(form.get("label") or "").strip()
    if not account_number or not label:
        _flash(request, "Kontonummer und Bezeichnung sind Pflicht.", "error")
        return RedirectResponse("/einkauf/buchungskonten", status_code=302)
    row.account_framework = str(form.get("account_framework") or "SKR03").strip() or "SKR03"
    row.account_number = account_number
    row.label = label
    row.category = str(form.get("category") or "").strip() or None
    row.source_type = str(form.get("source_type") or row.source_type or "manual").strip() or "manual"
    row.sevdesk_account_datev_id = str(form.get("sevdesk_account_datev_id") or "").strip() or None
    row.default_tax_rule_id = str(form.get("default_tax_rule_id") or "").strip() or None
    row.note = str(form.get("note") or "").strip() or None
    row.active = form.get("active") == "on"
    row.favorite = form.get("favorite") == "on"
    keywords_raw = str(form.get("keywords") or "").replace("\n", ",")
    keywords = [part.strip() for part in keywords_raw.split(",") if part.strip()]
    row.keywords_json = json.dumps(keywords, ensure_ascii=False) if keywords else None
    row.updated_at = _utcnow_naive()
    db.add(row)
