@app.post("/einkauf/buchungskonten/import")
async def einkauf_accounting_accounts_import(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    _ = user
    form = await request.form()
    upload: UploadFile = form.get("csv_file")  # type: ignore
    if upload is None or not upload.filename:
        _flash(request, "Bitte eine CSV-Datei auswählen.", "error")
        return RedirectResponse("/einkauf/buchungskonten", status_code=302)
    raw = await upload.read()
    if not raw:
        _flash(request, "Die CSV-Datei ist leer.", "error")
        return RedirectResponse("/einkauf/buchungskonten", status_code=302)
    text = ""
    for encoding in ("utf-8-sig", "utf-8", "latin-1"):
        try:
            text = raw.decode(encoding)
            break
        except Exception:
            text = ""
    if not text:
        _flash(request, "CSV konnte nicht gelesen werden.", "error")
        return RedirectResponse("/einkauf/buchungskonten", status_code=302)

    def normalize_header(value: str) -> str:
        return re.sub(r"[^a-z0-9]+", "", str(value or "").strip().lower())

    header_map = {
        "accountnumber": "account_number",
        "kontonummer": "account_number",
        "konto": "account_number",
        "number": "account_number",
        "label": "label",
        "bezeichnung": "label",
        "name": "label",
        "accountframework": "account_framework",
        "kontenrahmen": "account_framework",
        "framework": "account_framework",
        "category": "category",
        "kategorie": "category",
        "sourcetype": "source_type",
        "quelle": "source_type",
        "sevdeskaccountdatevid": "sevdesk_account_datev_id",
        "accountdatevid": "sevdesk_account_datev_id",
        "defaulttaxruleid": "default_tax_rule_id",
        "taxruleid": "default_tax_rule_id",
        "keywords": "keywords",
        "schlagwoerter": "keywords",
        "schlagworte": "keywords",
        "note": "note",
        "notiz": "note",
        "favorite": "favorite",
        "favorit": "favorite",
        "active": "active",
        "aktiv": "active",
    }

    imported = 0
    for raw_row in csv.DictReader(io.StringIO(text)):
        normalized_row = {header_map.get(normalize_header(key), key): str(value or "").strip() for key, value in raw_row.items()}
        account_number = str(normalized_row.get("account_number") or "").strip()
        label = str(normalized_row.get("label") or "").strip()
        if not account_number or not label:
            continue
        framework = str(normalized_row.get("account_framework") or "SKR03").strip() or "SKR03"
        row = (
            db.query(AccountingAccount)
            .filter(AccountingAccount.account_framework == framework, AccountingAccount.account_number == account_number)
            .one_or_none()
        )
        if row is None:
            row = AccountingAccount(account_framework=framework, account_number=account_number, created_at=_utcnow_naive())
        row.label = label
        row.category = str(normalized_row.get("category") or "").strip() or row.category
        row.source_type = str(normalized_row.get("source_type") or "import").strip() or "import"
        row.sevdesk_account_datev_id = str(normalized_row.get("sevdesk_account_datev_id") or "").strip() or row.sevdesk_account_datev_id
        row.default_tax_rule_id = str(normalized_row.get("default_tax_rule_id") or "").strip() or row.default_tax_rule_id
        row.note = str(normalized_row.get("note") or "").strip() or row.note
        keywords = [part.strip() for part in str(normalized_row.get("keywords") or "").replace("\n", ",").split(",") if part.strip()]
        if keywords:
            row.keywords_json = json.dumps(keywords, ensure_ascii=False)
        if str(normalized_row.get("favorite") or "").strip().lower() in {"1", "true", "ja", "yes", "y"}:
            row.favorite = True
        if str(normalized_row.get("active") or "").strip().lower() in {"0", "false", "nein", "no", "n"}:
            row.active = False
        else:
            row.active = True
        row.updated_at = _utcnow_naive()
        db.add(row)
        imported += 1
    db.commit()
    _flash(request, f"{imported} Buchungskonto/-konten importiert.", "info")
    return RedirectResponse("/einkauf/buchungskonten", status_code=302)


