def _sevdesk_document_external_url(
    settings: dict[str, str | bool],
    *,
    kind: str,
    document_id: str | int | None,
    payload: dict[str, object] | None = None,
    document_type: str | None = None,
) -> str:
    entity = "invoice" if _crm_normalize_key(kind) == "invoice" else "order"
    payload_dict = payload if isinstance(payload, dict) else {}
    resolved_document_type = (
        str(document_type or "").strip()
        or sevdesk_first_value(payload_dict, ("invoiceType", "orderType", "type"))
        or ("RE" if entity == "invoice" else "AN")
    )
    return sevdesk_build_web_url(
        settings,
        entity_type=entity,
        object_id=document_id,
        document_type=resolved_document_type,
    )


