def _customer_purchase_order_rows(db: Session, customer_id: int, limit: int = 12) -> list[dict[str, object]]:
    customer = db.get(MasterCustomer, int(customer_id or 0))
    party = db.get(Party, int(customer.party_id or 0)) if customer and int(customer.party_id or 0) > 0 else None
    if customer is None:
        return []
    service_orders_enabled = _internal_service_orders_enabled()
    case_rows = (
        db.query(CrmCase)
        .join(RoleAssignment, RoleAssignment.case_id == CrmCase.id)
        .filter(RoleAssignment.master_customer_id == int(customer_id))
        .order_by(CrmCase.updated_at.desc(), CrmCase.id.desc())
        .limit(80)
        .all()
    ) if service_orders_enabled else []
    case_numbers = [str(row.case_no or "").strip() for row in case_rows if str(row.case_no or "").strip()]
    normalized_case_numbers = [value.lower() for value in case_numbers]
    customer_no = str(customer.customer_no_internal or "").strip().lower()
    customer_name = _crm_clean_text(party.display_name if party else "").lower()
    orders = (
        db.query(PurchaseOrder)
        .order_by(func.coalesce(PurchaseOrder.sent_at, PurchaseOrder.confirmed_at, PurchaseOrder.updated_at, PurchaseOrder.order_date, PurchaseOrder.created_at).desc(), PurchaseOrder.id.desc())
        .limit(400)
        .all()
    )
    if not orders:
        return []
    order_ids = [int(row.id) for row in orders]
    line_rows = (
        db.query(PurchaseOrderLine)
        .filter(PurchaseOrderLine.purchase_order_id.in_(order_ids or [0]))
        .order_by(PurchaseOrderLine.purchase_order_id.asc(), PurchaseOrderLine.id.asc())
        .all()
    )
    product_ids = [int(row.product_id) for row in line_rows if int(row.product_id or 0) > 0]
    products = {int(row.id): row for row in db.query(Product).filter(Product.id.in_(product_ids or [0])).all()} if product_ids else {}
    suppliers = {int(row.id): row for row in db.query(Supplier).filter(Supplier.id.in_([int(item.supplier_id) for item in orders if int(item.supplier_id or 0) > 0] or [0])).all()}
    line_map: dict[int, list[PurchaseOrderLine]] = {}
    for row in line_rows:
        line_map.setdefault(int(row.purchase_order_id or 0), []).append(row)
    out: list[dict[str, object]] = []
    for row in orders:
        lines = line_map.get(int(row.id), [])
        line_descriptions = []
        spare_part_match = False
        for line in lines[:10]:
            product = products.get(int(line.product_id or 0))
            product_label = _crm_clean_text(getattr(product, "sales_name", None) or getattr(product, "name", None))
            if product_label:
                line_descriptions.append(product_label)
            if product and _crm_normalize_key(getattr(product, "item_type", "")) in {"spare_part", "accessory"}:
                spare_part_match = True
            if _crm_clean_text(line.note):
                line_descriptions.append(_crm_clean_text(line.note))
        search_blob = " ".join(
            [
                str(row.po_number or ""),
                str(row.order_no or ""),
                str(row.note or ""),
                " ".join(line_descriptions),
            ]
        ).lower()
        matched_case_numbers = [case_no for case_no in case_numbers if case_no.lower() in search_blob][:3]
        if customer_no and customer_no in search_blob:
            pass
        elif customer_name and customer_name in search_blob:
            pass
        elif matched_case_numbers:
            pass
        else:
            continue
        if not spare_part_match and "ersatz" not in search_blob and "spare" not in search_blob:
            continue
        timestamp = row.sent_at or row.confirmed_at or row.updated_at or row.order_date or row.created_at
        subtitle_parts = [
            _crm_clean_text(getattr(suppliers.get(int(row.supplier_id or 0)), "name", None)),
            _purchase_status_label(row.status),
        ]
        if service_orders_enabled and matched_case_numbers:
            subtitle_parts.append(" / ".join(matched_case_numbers))
        out.append(
            {
                "row": row,
                "timestamp": timestamp or _utcnow_naive(),
                "title": str(row.po_number or row.order_no or f"Bestellung {int(row.id)}"),
                "subtitle": " | ".join([part for part in subtitle_parts if part]),
                "detail_url": f"/einkauf/bestellungen/{int(row.id)}",
                "amount_cents": _purchase_order_sum_cents(lines),
            }
        )
    out.sort(key=lambda item: (_crm_sort_datetime(item.get("timestamp")), str(item.get("title") or "")), reverse=True)
    return out[: max(1, int(limit))]


def _customer_activity_dedupe_key(item: dict[str, object]) -> str:
    explicit = str(item.get("dedupe_key") or "").strip()
    if explicit:
        return explicit
    detail_url = str(item.get("detail_url") or "").strip()
    if detail_url:
        return f"url:{detail_url}"
    return f"{_crm_normalize_key(item.get('type_label') or 'eintrag')}:{_crm_normalize_key(item.get('title') or '')}"


def _customer_activity_priority(item: dict[str, object]) -> tuple[int, int, int, dt.datetime, str]:
    return (
        int(item.get("_source_rank") or 0),
        1 if str(item.get("detail_url") or "").strip() else 0,
        1 if str(item.get("subtitle") or "").strip() else 0,
        _crm_sort_datetime(item.get("timestamp")),
        str(item.get("title") or ""),
    )


def _customer_activity_rows(
    db: Session,
    customer_id: int,
    limit: int = 40,
    *,
    recent_case_rows: list[dict[str, object]] | None = None,
    recent_offer_rows: list[dict[str, object]] | None = None,
    recent_invoice_rows: list[dict[str, object]] | None = None,
    task_rows: list[CustomerTask] | None = None,
    outsmart_workorder_rows: list[dict[str, object]] | None = None,
    paperless_rows: list[dict[str, object]] | None = None,
    purchase_order_rows: list[dict[str, object]] | None = None,
) -> list[dict[str, object]]:
    items: list[dict[str, object]] = []
    service_orders_enabled = _internal_service_orders_enabled()
    for row in (
        db.query(EmailMessage)
        .filter(EmailMessage.master_customer_id == int(customer_id))
        .order_by(func.coalesce(EmailMessage.received_at, EmailMessage.sent_at, EmailMessage.fetched_at).desc(), EmailMessage.id.desc())
        .limit(18)
        .all()
    ):
        items.append(
            {
                "timestamp": row.received_at or row.sent_at or row.fetched_at or _utcnow_naive(),
                "type_label": "E-Mail",
                "title": _crm_clean_text(row.subject) or _crm_clean_text(row.snippet) or "E-Mail",
                "subtitle": _crm_clean_text(row.from_text or row.from_email or row.to_emails),
                "detail_url": f"/mail/threads/{int(row.thread_id)}#mail-message-{int(row.id)}" if int(row.thread_id or 0) > 0 else "",
                "dedupe_key": f"mail:{int(row.id)}",
                "_source_rank": 80,
            }
        )
    if service_orders_enabled:
        effective_recent_case_rows = recent_case_rows if recent_case_rows is not None else _crm_recent_case_rows(db, int(customer_id), limit=12)
        for item in effective_recent_case_rows[:12]:
            row = item.get("row")
            if not row:
                continue
            items.append(
                {
                    "timestamp": row.updated_at or row.created_at or _utcnow_naive(),
                    "type_label": "Serviceauftrag",
                    "title": f"{row.case_no} | {row.title}",
                    "subtitle": f"{item.get('role_label') or ''} | {_crm_case_status_label(row.status)}",
                    "detail_url": f"/serviceauftraege/{int(row.id)}",
                    "dedupe_key": f"serviceorder:{int(row.id)}",
                    "_source_rank": 85,
                }
            )
    effective_recent_offer_rows = recent_offer_rows if recent_offer_rows is not None else _customer_recent_offer_sidebar_rows(db, int(customer_id), limit=8)
    for item in effective_recent_offer_rows[:8]:
        offer_no = _crm_normalize_invoice_no(str(item.get("title") or ""))
        items.append(
            {
                "timestamp": item.get("timestamp") or _utcnow_naive(),
                "type_label": "Angebot",
                "title": str(item.get("title") or "Angebot"),
                "subtitle": str(item.get("subtitle") or ""),
                "detail_url": str(item.get("detail_url") or ""),
                "dedupe_key": f"offer:{offer_no}" if offer_no else "",
                "_source_rank": 95,
            }
        )
    effective_recent_invoice_rows = recent_invoice_rows if recent_invoice_rows is not None else _customer_recent_invoice_sidebar_rows(db, int(customer_id), limit=8)
    for item in effective_recent_invoice_rows[:8]:
        invoice_no = _crm_normalize_invoice_no(str(item.get("title") or ""))
        items.append(
            {
                "timestamp": item.get("timestamp") or _utcnow_naive(),
                "type_label": "Rechnung",
                "title": str(item.get("title") or "Rechnung"),
                "subtitle": str(item.get("subtitle") or ""),
                "detail_url": str(item.get("detail_url") or ""),
                "dedupe_key": f"invoice:{invoice_no}" if invoice_no else "",
                "_source_rank": 100,
            }
        )
    effective_outsmart_workorder_rows = outsmart_workorder_rows if outsmart_workorder_rows is not None else _customer_outsmart_workorder_rows(db, int(customer_id), limit=12)
    for item in effective_outsmart_workorder_rows[:12]:
        row = item.get("row")
        if not row:
            continue
        items.append(
            {
                "timestamp": item.get("event_date") or row.scheduled_start or row.scheduled_end or row.updated_at or row.created_at or _utcnow_naive(),
                "type_label": "Arbeitsauftrag",
                "title": str(row.workorder_no or "Arbeitsauftrag"),
                "subtitle": str(item.get("display", {}).get("status_label") or row.status or "-"),
                "detail_url": f"/outsmart/arbeitsauftraege/{int(row.id)}",
                "dedupe_key": f"workorder:{int(row.id)}",
                "_source_rank": 110,
            }
        )
    effective_task_rows = task_rows if task_rows is not None else _customer_task_rows(db, int(customer_id), limit=12)
    effective_task_rows = sorted(
        list(effective_task_rows),
        key=lambda row: (_crm_sort_datetime(row.updated_at or row.created_at), int(row.id or 0)),
        reverse=True,
    )
    for row in effective_task_rows[:12]:
        items.append(
            {
                "timestamp": row.updated_at or row.created_at or _utcnow_naive(),
                "type_label": _crm_task_entry_type_label(row.entry_type),
                "title": str(row.title or _crm_task_entry_type_label(row.entry_type)),
                "subtitle": _crm_task_status_label(row.status),
                "detail_url": f"/crm/kunden/{int(customer_id)}#customer-task-{int(row.id)}",
                "dedupe_key": f"task:{int(row.id)}",
                "_source_rank": 75,
            }
        )
    effective_paperless_rows = paperless_rows if paperless_rows is not None else _customer_paperless_document_rows(db, int(customer_id), limit=12)
    for row in effective_paperless_rows[:12]:
        invoice_numbers = [str(value or "") for value in list(row.get("invoice_numbers") or []) if str(value or "").strip()]
        invoice_no = _crm_normalize_invoice_no(invoice_numbers[0] if invoice_numbers else "")
        items.append(
            {
                "timestamp": row.get("event_date") or row.get("created_at") or _utcnow_naive(),
                "type_label": "Beleg",
                "title": str(row.get("title") or "Dokument"),
                "subtitle": str(row.get("document_type") or row.get("correspondent") or ""),
                "detail_url": str(row.get("detail_url") or ""),
                "dedupe_key": (f"invoice:{invoice_no}" if invoice_no else f"paperless:{row.get('paperless_document_id') or row.get('detail_url') or row.get('title') or ''}"),
                "_source_rank": 60 if invoice_no else 70,
            }
        )
    effective_purchase_order_rows = purchase_order_rows if purchase_order_rows is not None else _customer_purchase_order_rows(db, int(customer_id), limit=8)
    for item in effective_purchase_order_rows[:8]:
        row = item.get("row")
        if row is None:
            continue
        items.append(
            {
                "timestamp": item.get("timestamp") or row.updated_at or row.created_at or _utcnow_naive(),
                "type_label": "Ersatzteilbestellung",
                "title": str(item.get("title") or row.po_number or f"Bestellung {int(row.id)}"),
                "subtitle": str(item.get("subtitle") or ""),
                "detail_url": str(item.get("detail_url") or f"/einkauf/bestellungen/{int(row.id)}"),
                "dedupe_key": f"purchase-order:{int(row.id)}",
                "_source_rank": 80,
            }
        )
    for payload in _crm_timeline_rows_for_customer(db, int(customer_id), limit=24, timeline_filter="all"):
        if str(payload.get("group_key") or "") != "event":
            continue
        detail_url = str(payload.get("detail_url") or "")
        if not service_orders_enabled and detail_url.startswith("/serviceauftraege/"):
            continue
        if not service_orders_enabled and str(payload.get("type_label") or "").strip().lower() == "serviceauftrag":
            continue
        row = payload.get("row")
        if row is None:
            continue
        timeline_key = f"timeline:{int(row.id)}"
        if int(row.outsmart_workorder_id or 0) > 0:
            timeline_key = f"workorder:{int(row.outsmart_workorder_id)}"
        elif _crm_normalize_key(getattr(row, "source_system", "")) == "sevdesk":
            candidates = _crm_invoice_number_candidates(str(row.title or ""), str(row.body or ""), str(row.external_ref or ""))
            normalized = _crm_normalize_invoice_no(candidates[0]) if candidates else ""
            if normalized:
                if "angebot" in _crm_normalize_key(row.title or "") or "order" in _crm_normalize_key(row.external_ref or ""):
                    timeline_key = f"offer:{normalized}"
                else:
                    timeline_key = f"invoice:{normalized}"
        items.append(
            {
                "timestamp": row.event_ts or _utcnow_naive(),
                "type_label": str(payload.get("type_label") or "Eintrag"),
                "title": str(row.title or "Eintrag"),
                "subtitle": _crm_clean_text(row.body)[:200],
                "detail_url": detail_url,
                "dedupe_key": timeline_key,
                "_source_rank": 40,
            }
        )
    deduped: dict[str, dict[str, object]] = {}
    for item in items:
        key = _customer_activity_dedupe_key(item)
        current = deduped.get(key)
        if current is None or _customer_activity_priority(item) > _customer_activity_priority(current):
            deduped[key] = item
    rows = list(deduped.values())
    rows.sort(key=lambda item: (_crm_sort_datetime(item.get("timestamp")), str(item.get("title") or "")), reverse=True)
    return [
        {key: value for key, value in item.items() if not str(key).startswith("_") and key != "dedupe_key"}
        for item in rows[: max(1, int(limit))]
    ]


def _customer_first_contact_at(
    db: Session,
    customer_id: int,
    *,
    document_rows: list[dict[str, object]] | None = None,
    stage_document_rows: list[dict[str, object]] | None = None,
) -> dt.datetime | None:
    candidates: list[dt.datetime] = []
    customer = db.get(MasterCustomer, int(customer_id or 0))
    if customer and customer.created_at:
        candidates.append(customer.created_at)
    email_first = (
        db.query(func.min(func.coalesce(EmailMessage.received_at, EmailMessage.sent_at, EmailMessage.fetched_at)))
        .filter(EmailMessage.master_customer_id == int(customer_id))
        .scalar()
    )
    if isinstance(email_first, dt.datetime):
        candidates.append(email_first)
    if _internal_service_orders_enabled():
        case_first = db.query(func.min(CrmCase.created_at)).join(RoleAssignment, RoleAssignment.case_id == CrmCase.id).filter(RoleAssignment.master_customer_id == int(customer_id)).scalar()
        if isinstance(case_first, dt.datetime):
            candidates.append(case_first)
    workorder_first = (
        db.query(func.min(func.coalesce(OutsmartWorkorder.scheduled_start, OutsmartWorkorder.created_at, OutsmartWorkorder.updated_at)))
        .filter(OutsmartWorkorder.master_customer_id == int(customer_id))
        .scalar()
    )
    if isinstance(workorder_first, dt.datetime):
        candidates.append(workorder_first)
    effective_document_rows = document_rows if document_rows is not None else _customer_combined_sevdesk_document_rows(db, int(customer_id), limit=160)
    for item in effective_document_rows:
        event_date = item.get("event_date") or item.get("updated_at")
        if isinstance(event_date, dt.datetime):
            candidates.append(event_date)
    effective_stage_rows = stage_document_rows if stage_document_rows is not None else _customer_sevdesk_stage_document_rows(db, int(customer_id), limit=160)
    for item in effective_stage_rows:
        event_date = item.get("event_date") or item.get("updated_at")
        if isinstance(event_date, dt.datetime):
            candidates.append(event_date)
    return min(candidates) if candidates else None


def _crm_add_timeline_event(
    db: Session,
    *,
    case_id: int | None = None,
    master_customer_id: int | None = None,
    service_location_id: int | None = None,
    customer_object_id: int | None = None,
    outsmart_workorder_id: int | None = None,
    source_system: str,
    event_type: str,
    title: str,
    body: str | None = None,
    event_ts: dt.datetime | None = None,
    external_ref: str | None = None,
    meta: dict | None = None,
) -> CrmTimelineEvent:
    query = db.query(CrmTimelineEvent).filter(
        CrmTimelineEvent.source_system == str(source_system),
        CrmTimelineEvent.event_type == str(event_type),
        CrmTimelineEvent.title == str(title),
        CrmTimelineEvent.external_ref == (str(external_ref or "").strip() or None),
    )
    if case_id is None:
        query = query.filter(CrmTimelineEvent.case_id.is_(None))
    else:
        query = query.filter(CrmTimelineEvent.case_id == int(case_id))
    if outsmart_workorder_id is None:
        query = query.filter(CrmTimelineEvent.outsmart_workorder_id.is_(None))
    else:
        query = query.filter(CrmTimelineEvent.outsmart_workorder_id == int(outsmart_workorder_id))
    existing = query.order_by(CrmTimelineEvent.id.desc()).first()
    if existing:
        existing.body = str(body or "").strip() or None
        existing.event_ts = event_ts or existing.event_ts
        existing.meta_json = json.dumps(meta, ensure_ascii=False) if isinstance(meta, dict) and meta else existing.meta_json
        db.add(existing)
        db.flush()
        return existing
    row = CrmTimelineEvent(
        case_id=int(case_id) if int(case_id or 0) > 0 else None,
        master_customer_id=int(master_customer_id) if int(master_customer_id or 0) > 0 else None,
        service_location_id=int(service_location_id) if int(service_location_id or 0) > 0 else None,
        customer_object_id=int(customer_object_id) if int(customer_object_id or 0) > 0 else None,
        outsmart_workorder_id=int(outsmart_workorder_id) if int(outsmart_workorder_id or 0) > 0 else None,
        source_system=str(source_system),
        event_type=str(event_type),
        title=str(title),
        body=str(body or "").strip() or None,
        event_ts=event_ts or _utcnow_naive(),
        external_ref=str(external_ref or "").strip() or None,
        meta_json=json.dumps(meta, ensure_ascii=False) if isinstance(meta, dict) and meta else None,
        created_at=_utcnow_naive(),
    )
    db.add(row)
    db.flush()
    return row


def _crm_timeline_row_payload(db: Session, row: CrmTimelineEvent) -> dict[str, object]:
    meta = _json_dict(row.meta_json)
    detail_url = ""
    detail_label = ""
    paperless_url = ""
    group_key = "event"
    type_label = "Eintrag"
    if int(row.outsmart_workorder_id or 0) > 0:
        detail_url = f"/outsmart/arbeitsauftraege/{int(row.outsmart_workorder_id)}"
        detail_label = "Arbeitsauftrag öffnen"
        group_key = "event"
        type_label = _sync_job_entity_label("workorder")
    elif str(row.source_system or "").strip() == "mail":
        ref_value = str(row.external_ref or "").strip()
        match = re.match(r"mail:(\d+)", ref_value)
        thread_match = re.match(r"mail_thread:(\d+)", ref_value)
        message = db.get(EmailMessage, int(match.group(1))) if match else None
        if message and int(message.thread_id or 0) > 0:
            detail_url = f"/mail/threads/{int(message.thread_id)}#mail-message-{int(message.id)}"
            detail_label = "Mail-Thread öffnen"
        elif thread_match:
            detail_url = f"/mail/threads/{int(thread_match.group(1))}"
            detail_label = "Mail-Thread öffnen"
        elif int(meta.get("thread_id") or 0) > 0:
            detail_url = f"/mail/threads/{int(meta.get('thread_id') or 0)}"
            detail_label = "Mail-Thread öffnen"
        group_key = "mail"
        type_label = "E-Mail"
    elif str(row.source_system or "").strip() in ("paperless", "local_upload"):
        if str(meta.get("paperless_document_id") or "").strip():
            inbox_item = _document_inbox_item_from_paperless_id(db, str(meta.get("paperless_document_id") or ""))
            if inbox_item:
                detail_url = f"/crm/dokumente/{int(inbox_item.id)}"
                detail_label = "Dokument öffnen"
            paperless_url = paperless_build_document_url(_paperless_settings(db, include_secret=False), str(meta.get("paperless_document_id") or ""))
        elif int(meta.get("attachment_id") or 0) > 0:
            detail_url = f"/dokumente/lokal/{int(meta.get('attachment_id') or 0)}"
            detail_label = "Datei herunterladen"
        group_key = "document"
        type_label = "Dokument"
    elif str(row.source_system or "").strip() == "outsmart":
        type_label = _sync_job_entity_label("workorder")
    return {
        "row": row,
        "group_key": group_key,
        "type_label": type_label,
        "detail_url": detail_url,
        "detail_label": detail_label,
        "paperless_url": paperless_url,
    }


def _crm_timeline_rows_for_case(db: Session, case_id: int, limit: int = 40, timeline_filter: str = "all") -> list[dict[str, object]]:
    query = db.query(CrmTimelineEvent).filter(CrmTimelineEvent.case_id == int(case_id))
    rows = query.order_by(CrmTimelineEvent.event_ts.desc(), CrmTimelineEvent.id.desc()).limit(limit).all()
    filter_key = str(timeline_filter or "all").strip().lower()
    out = []
    for row in rows:
        payload = _crm_timeline_row_payload(db, row)
        if filter_key == "mail" and payload["group_key"] != "mail":
            continue
        if filter_key == "document" and payload["group_key"] != "document":
            continue
        out.append(payload)
    return out


def _crm_timeline_rows_for_customer(db: Session, customer_id: int, limit: int = 20, timeline_filter: str = "all") -> list[dict[str, object]]:
    query = db.query(CrmTimelineEvent).filter(CrmTimelineEvent.master_customer_id == int(customer_id))
    rows = query.order_by(CrmTimelineEvent.event_ts.desc(), CrmTimelineEvent.id.desc()).limit(limit).all()
    filter_key = str(timeline_filter or "all").strip().lower()
    out = []
    for row in rows:
        payload = _crm_timeline_row_payload(db, row)
        if filter_key == "mail" and payload["group_key"] != "mail":
            continue
        if filter_key == "document" and payload["group_key"] != "document":
            continue
        out.append(payload)
    return out


def _outsmart_customer_default_address(db: Session, customer: MasterCustomer | None) -> CrmAddress | None:
    if not customer:
        return None
    _, default_map = _crm_party_address_maps(db, [int(customer.party_id)])
    return default_map.get(int(customer.party_id))


def _outsmart_upsert_relation_customer(db: Session, payload: dict) -> tuple[MasterCustomer | None, str]:
    relation_key = _outsmart_relation_key(payload)
    row_id = _outsmart_row_id(payload)
    debtor_key = _outsmart_pick(payload, ("DebtorNo", "debtor_no"))
    customer_no_key = _outsmart_pick(payload, ("CustomerNo", "customer_no"))
    display_name = _outsmart_pick(payload, ("CompanyName", "company_name", "Name", "name", "RelationName", "relation_name", "DisplayName", "display_name"))
    if not display_name and not relation_key:
        return None, "skipped"
    customer = _crm_customer_from_outsmart_identity(db, payload)
    created = customer is None
    if customer is None:
        party = Party(
            party_type="company",
            display_name=display_name or relation_key,
            active=True,
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
        db.add(party)
        db.flush()
        customer = MasterCustomer(
            party_id=int(party.id),
            customer_no_internal=_crm_next_customer_no(db),
            status="active",
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
        db.add(customer)
        db.flush()
    party = db.get(Party, int(customer.party_id))
    if not party:
        return None, "skipped"
    changed = created
    if display_name and display_name != str(party.display_name or ""):
        party.display_name = display_name
        changed = True
    email_value = _outsmart_pick(payload, ("Email", "email", "EmailAddress", "email_address", "Mail"))
    phone_value = _outsmart_pick(payload, ("Phone", "phone", "Telephone", "telephone", "MobilePhone", "mobile_phone"))
    street_value = _outsmart_pick(payload, ("Street", "street", "Address", "address", "Address1", "address1"))
    house_no_value = _outsmart_pick(payload, ("HouseNo", "house_no"))
    zip_value = _outsmart_pick(payload, ("ZipCode", "zip_code", "PostalCode", "postal_code", "Postcode"))
    city_value = _outsmart_pick(payload, ("City", "city", "Place"))
    country_value = _outsmart_pick(payload, ("CountryCode", "country_code", "Country", "country")) or "DE"
    address = _outsmart_customer_default_address(db, customer)
    if address is None and any((street_value, zip_value, city_value, email_value, phone_value)):
        address = CrmAddress(party_id=int(party.id), label="Hauptadresse", is_default=True, active=True)
        db.add(address)
        db.flush()
        _crm_clear_default_addresses(db, int(party.id), int(address.id))
        changed = True
    if address is not None:
        new_values = {
            "street": street_value or address.street,
            "house_no": house_no_value or address.house_no,
            "zip_code": zip_value or address.zip_code,
            "city": city_value or address.city,
            "country_code": country_value or address.country_code,
            "email": email_value or address.email,
            "phone": phone_value or address.phone,
        }
        for key, value in new_values.items():
            if getattr(address, key) != value:
                setattr(address, key, value)
                changed = True
        if not address.label:
            address.label = "Hauptadresse"
        db.add(address)
    party.updated_at = _utcnow_naive()
    customer.updated_at = _utcnow_naive()
    db.add(party)
    db.add(customer)
    identities = [
        ("debtor", debtor_key or relation_key, debtor_key or row_id, True),
        ("relation", relation_key or debtor_key, row_id or relation_key, not debtor_key),
        ("customerNumber", customer_no_key, customer_no_key, False),
    ]
    for external_type, external_key, external_id, primary_flag in identities:
        key_value = str(external_key or "").strip()
        if not key_value:
            continue
        row = (
            db.query(ExternalIdentity)
            .filter(
                ExternalIdentity.system_name == "outsmart",
                ExternalIdentity.external_type == external_type,
                ExternalIdentity.external_key == key_value,
            )
            .one_or_none()
        )
        if row is None:
            row = ExternalIdentity(
                master_customer_id=int(customer.id),
                system_name="outsmart",
                external_type=external_type,
                external_key=key_value,
                external_id=str(external_id or "").strip() or None,
                is_primary=bool(primary_flag),
                created_at=_utcnow_naive(),
            )
            changed = True
        else:
            if int(row.master_customer_id or 0) != int(customer.id):
                row.master_customer_id = int(customer.id)
                changed = True
            if str(row.external_id or "") != str(external_id or ""):
                row.external_id = str(external_id or "").strip() or None
                changed = True
            if bool(primary_flag) and not bool(row.is_primary):
                row.is_primary = True
                changed = True
        db.add(row)
    deep_link = _outsmart_resolve_deep_link(
        _outsmart_settings(db, include_secret=False),
        entity_type="relation",
        payload=payload,
        row_id=row_id or None,
        external_key=relation_key or debtor_key,
    )
    _upsert_external_link(
        db,
        system_name="outsmart",
        object_type="master_customer",
        object_id=int(customer.id),
        external_key=debtor_key or relation_key or customer.customer_no_internal,
        external_row_id=row_id or None,
        deep_link_url=deep_link or None,
    )
    return customer, ("created" if created else "updated" if changed else "skipped")


def _outsmart_upsert_project_case(db: Session, payload: dict) -> tuple[CrmCase | None, str]:
    project_key = _outsmart_project_key(payload)
    row_id = _outsmart_row_id(payload)
    title = _outsmart_pick(payload, ("ProjectName", "project_name", "Name", "name", "Description", "description")) or project_key
    if not title and not project_key:
        return None, "skipped"
    row = _crm_case_by_project_key(db, row_id or project_key)
    created = row is None
    if row is None:
        case_no = project_key or _crm_next_case_no(db)
        if db.query(CrmCase).filter(CrmCase.case_no == case_no).count() > 0:
            case_no = _crm_next_case_no(db)
        row = CrmCase(
            case_no=case_no,
            title=title or case_no,
            status=_outsmart_status_to_case_status(_outsmart_pick(payload, ("Status", "status"))),
            priority="normal",
            order_type="service",
            next_step="none",
            source_system="outsmart",
            note=_outsmart_pick(payload, ("Description", "description", "Remark", "remark")) or None,
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
        db.add(row)
        db.flush()
    changed = created
    if title and row.title != title:
        row.title = title
        changed = True
    status = _outsmart_status_to_case_status(_outsmart_pick(payload, ("Status", "status")))
    if row.status != status:
        row.status = status
        changed = True
    note_value = _outsmart_pick(payload, ("Description", "description", "Remark", "remark")) or None
    if note_value and row.note != note_value:
        row.note = note_value
        changed = True
    row.updated_at = _utcnow_naive()
    db.add(row)
    customer = _crm_customer_from_outsmart_identity(db, payload)
    if customer:
        address = _outsmart_customer_default_address(db, customer)
        _crm_set_case_role(
            db,
            crm_case_id=int(row.id),
            role_type=CRM_ROLE_ORDERING_PARTY,
            master_customer_id=int(customer.id),
            address_id=int(address.id) if address else None,
        )
        _crm_set_case_role(
            db,
            crm_case_id=int(row.id),
            role_type=CRM_ROLE_INVOICE_RECIPIENT,
            master_customer_id=int(customer.id),
            address_id=int(address.id) if address else None,
        )
        location = _crm_default_location_for_customer(db, int(customer.id))
        if location:
            _crm_set_case_role(
                db,
                crm_case_id=int(row.id),
                role_type=CRM_ROLE_SERVICE_LOCATION,
                master_customer_id=int(customer.id),
                service_location_id=int(location.id),
                address_id=int(location.address_id or 0) or None,
            )
    deep_link = _outsmart_resolve_deep_link(
        _outsmart_settings(db, include_secret=False),
        entity_type="project",
        payload=payload,
        row_id=row_id or None,
        external_key=project_key,
    )
    _upsert_external_link(
        db,
        system_name="outsmart",
        object_type="crm_case_project",
        object_id=int(row.id),
        external_key=project_key or row.case_no,
        external_row_id=row_id or None,
        deep_link_url=deep_link or None,
    )
    return row, ("created" if created else "updated" if changed else "skipped")


def _outsmart_upsert_customer_object(db: Session, payload: dict) -> tuple[CustomerObject | None, str]:
    object_key = _outsmart_object_key(payload)
    row_id = _outsmart_row_id(payload)
    if not object_key and not row_id:
        return None, "skipped"
    row = None
    if object_key:
        row = db.query(CustomerObject).filter(CustomerObject.external_object_code == object_key).one_or_none()
    if row is None and row_id:
        row = db.query(CustomerObject).filter(CustomerObject.external_row_id == row_id).one_or_none()
    created = row is None
    customer = _crm_customer_from_outsmart_identity(db, payload)
    location = _crm_default_location_for_customer(db, int(customer.id)) if customer else None
    if row is None:
        row = CustomerObject(
            master_customer_id=int(customer.id) if customer else None,
            service_location_id=int(location.id) if location else None,
            external_object_code=object_key or row_id,
            external_row_id=row_id or None,
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
    changed = created
    values = {
        "master_customer_id": int(customer.id) if customer else row.master_customer_id,
        "service_location_id": int(location.id) if location else row.service_location_id,
        "external_object_code": object_key or row.external_object_code,
        "external_row_id": row_id or row.external_row_id,
        "supplier_label": _outsmart_pick(payload, ("Supplier", "supplier", "SupplierName", "supplier_name")) or row.supplier_label,
        "brand_label": _outsmart_pick(payload, ("Brand", "brand", "Manufacturer", "manufacturer")) or row.brand_label,
        "model_label": _outsmart_pick(payload, ("Model", "model", "ModelName", "model_name")) or row.model_label,
        "type_label": _outsmart_pick(payload, ("Type", "type", "TypeName", "type_name")) or row.type_label,
        "serial_no": _outsmart_pick(payload, ("SerialNo", "serial_no", "SerialNumber", "serial_number")) or row.serial_no,
        "image_url": _outsmart_pick_url(payload, ("ImageUrl", "image_url", "PhotoUrl", "photo_url")) or row.image_url,
        "deep_link_url": _outsmart_resolve_deep_link(
            _outsmart_settings(db, include_secret=False),
            entity_type="object",
            payload=payload,
            row_id=row_id or None,
            external_key=object_key,
            current_url=row.deep_link_url,
        ),
    }
    for key, value in values.items():
        if getattr(row, key) != value:
            setattr(row, key, value)
            changed = True
    warranty_until = _outsmart_parse_datetime(_outsmart_pick(payload, ("WarrantyUntil", "warranty_until", "WarrantyDate")))
    installation_date = _outsmart_parse_datetime(_outsmart_pick(payload, ("InstallationDate", "installation_date", "DateInstalled")))
    inspection_date = _outsmart_parse_datetime(_outsmart_pick(payload, ("InspectionDate", "inspection_date", "NextInspectionDate")))
    for key, value in (("warranty_until", warranty_until), ("installation_date", installation_date), ("inspection_date", inspection_date)):
        if value is not None and getattr(row, key) != value:
            setattr(row, key, value)
            changed = True
    freefields = payload.get("FreeFields") or payload.get("freefields") or payload.get("Freefields") or {}
    object_parts = payload.get("ObjectParts") or payload.get("object_parts") or payload.get("Parts") or []
    freefields_json = json.dumps(freefields, ensure_ascii=False) if freefields else None
    object_parts_json = json.dumps(object_parts, ensure_ascii=False) if object_parts else None
    if row.freefields_json != freefields_json:
        row.freefields_json = freefields_json
        changed = True
    if row.object_parts_json != object_parts_json:
        row.object_parts_json = object_parts_json
        changed = True
    row.updated_at = _utcnow_naive()
    db.add(row)
    db.flush()
    _upsert_external_link(
        db,
        system_name="outsmart",
        object_type="customer_object",
        object_id=int(row.id),
        external_key=row.external_object_code,
        external_row_id=row.external_row_id,
        deep_link_url=row.deep_link_url,
    )
    return row, ("created" if created else "updated" if changed else "skipped")


def _outsmart_match_case_for_workorder(db: Session, payload: dict) -> CrmCase | None:
    for candidate in (
        _outsmart_workorder_key(payload),
        _outsmart_pick(payload, ("JobNr", "job_nr")),
        _outsmart_pick(payload, ("Reference", "reference")),
        _outsmart_pick(payload, ("ExternalReference", "external_reference")),
    ):
        row = _crm_case_by_outsmart_workorder_key(db, candidate)
        if row:
            return row
    project_key = _outsmart_project_key(payload)
    if project_key:
        row = _crm_case_by_project_key(db, project_key)
        if row:
            return row
    return None


def _outsmart_match_customer_object(db: Session, payload: dict) -> CustomerObject | None:
    object_key = _outsmart_object_key(payload)
    row_id = _outsmart_pick(payload, ("ObjectRowId", "object_row_id")) or _outsmart_row_id(payload)
    if object_key:
        row = db.query(CustomerObject).filter(CustomerObject.external_object_code == object_key).one_or_none()
        if row:
            return row
    if row_id:
        row = db.query(CustomerObject).filter(CustomerObject.external_row_id == row_id).one_or_none()
        if row:
            return row
    return None


def _crm_case_sync_from_outsmart_workorder(
    db: Session,
    *,
    crm_case: CrmCase | None,
    workorder_row: OutsmartWorkorder,
    customer: MasterCustomer | None,
    location: ServiceLocation | None,
    customer_object: CustomerObject | None,
) -> bool:
    if crm_case is None:
        return False
    changed = False
    mapped_status = _outsmart_status_to_case_status(workorder_row.status)
    if mapped_status in CRM_CASE_STATUS_CHOICES and _crm_normalize_key(crm_case.status) != mapped_status:
        crm_case.status = mapped_status
        changed = True
    if (
        mapped_status == "completed"
        and _crm_normalize_key(crm_case.next_step or "") in {"", "none"}
        and _crm_normalize_key(crm_case.spare_part_status or "") not in {"check_required", "to_order", "ordered"}
        and _crm_normalize_key(crm_case.order_type or "") != "replacement"
    ):
        crm_case.next_step = "invoice"
        changed = True
    if not _crm_clean_text(crm_case.order_type or ""):
        display = _outsmart_prepare_workorder_view(workorder_row)
        inferred_type = _crm_case_order_type_from_outsmart(str(display.get("type_of_work_label") or ""))
        if inferred_type in CRM_CASE_ORDER_TYPE_CHOICES:
            crm_case.order_type = inferred_type
            changed = True
        if not crm_case.customer_visible_note and _crm_clean_text(str(display.get("customer_issue") or "")):
            crm_case.customer_visible_note = str(display.get("customer_issue") or "").strip() or None
            changed = True
        if not crm_case.material_summary and int(display.get("material_total_gross_cents") or 0) > 0:
            crm_case.material_summary = f"{len(display.get('material_rows') or [])} Materialpositionen aus OutSmart uebernommen."
            changed = True
    if (crm_case.requested_start_at is None) and workorder_row.scheduled_start is not None:
        crm_case.requested_start_at = workorder_row.scheduled_start
        changed = True
    if (crm_case.requested_end_at is None) and workorder_row.scheduled_end is not None:
        crm_case.requested_end_at = workorder_row.scheduled_end
        changed = True
    if (crm_case.proposed_start_at is None) and workorder_row.scheduled_start is not None:
        crm_case.proposed_start_at = workorder_row.scheduled_start
        changed = True
    if (crm_case.proposed_end_at is None) and workorder_row.scheduled_end is not None:
        crm_case.proposed_end_at = workorder_row.scheduled_end
        changed = True
    if customer_object and int(crm_case.customer_object_id or 0) <= 0:
        crm_case.customer_object_id = int(customer_object.id)
        changed = True
    if customer and int(crm_case.id or 0) > 0:
        default_address = _crm_customer_default_address(db, customer)
        _crm_set_case_role(
            db,
            crm_case_id=int(crm_case.id),
            role_type=CRM_ROLE_ORDERING_PARTY,
            master_customer_id=int(customer.id),
            address_id=int(default_address.id) if default_address else None,
        )
        _crm_set_case_role(
            db,
            crm_case_id=int(crm_case.id),
            role_type=CRM_ROLE_INVOICE_RECIPIENT,
            master_customer_id=int(customer.id),
            address_id=int(default_address.id) if default_address else None,
        )
    if location and int(crm_case.id or 0) > 0:
        _crm_set_case_role(
            db,
            crm_case_id=int(crm_case.id),
            role_type=CRM_ROLE_SERVICE_LOCATION,
            master_customer_id=int(location.master_customer_id or 0) or None,
            service_location_id=int(location.id),
            address_id=int(location.address_id or 0) or None,
        )
    if changed:
        crm_case.updated_at = _utcnow_naive()
        db.add(crm_case)
    return changed


def _outsmart_upsert_workorder_summary(db: Session, payload: dict) -> tuple[OutsmartWorkorder | None, str, bool]:
    workorder_no = _outsmart_workorder_key(payload)
    row_id = _outsmart_row_id(payload)
    if not workorder_no and not row_id:
        return None, "skipped", False
    row = None
    if workorder_no:
        row = db.query(OutsmartWorkorder).filter(OutsmartWorkorder.workorder_no == workorder_no).one_or_none()
    if row is None and row_id:
        row = db.query(OutsmartWorkorder).filter(OutsmartWorkorder.external_row_id == row_id).one_or_none()
    created = row is None
    case_row = _outsmart_match_case_for_workorder(db, payload)
    customer = _crm_customer_from_outsmart_identity(db, payload)
    if customer:
        _outsmart_apply_customer_contact_fallback(db, customer, payload)
    customer_object = _outsmart_match_customer_object(db, payload)
    location = None
    if case_row:
        role_map = _crm_case_role_map(db, [int(case_row.id)]).get(int(case_row.id), {})
        service_role = role_map.get(CRM_ROLE_SERVICE_LOCATION)
        if service_role and int(service_role.service_location_id or 0) > 0:
            location = db.get(ServiceLocation, int(service_role.service_location_id))
    if location is None and customer_object and int(customer_object.service_location_id or 0) > 0:
        location = db.get(ServiceLocation, int(customer_object.service_location_id))
    if location is None and customer:
        location = _crm_default_location_for_customer(db, int(customer.id))
    if row is None:
        row = OutsmartWorkorder(
            workorder_no=workorder_no or row_id,
            external_row_id=row_id or None,
            case_id=int(case_row.id) if case_row else None,
            master_customer_id=int(customer.id) if customer else None,
            service_location_id=int(location.id) if location else None,
            customer_object_id=int(customer_object.id) if customer_object else None,
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
    payload_sections = _outsmart_work_description_sections(
        _outsmart_pick(payload, ("WorkDescription", "work_description", "Description", "description"))
    )
    derived_short_description = (
        _outsmart_pick(payload, ("ShortWorkDescription", "short_work_description", "ShortDescription", "short_description"))
        or _outsmart_build_short_description(payload_sections)
    )
    old_status = str(row.status or "")
    old_start = row.scheduled_start.isoformat() if row.scheduled_start else ""
    old_end = row.scheduled_end.isoformat() if row.scheduled_end else ""
    values = {
        "workorder_no": workorder_no or row.workorder_no,
        "external_row_id": row_id or row.external_row_id,
        "case_id": int(case_row.id) if case_row else row.case_id,
        "master_customer_id": int(customer.id) if customer else row.master_customer_id,
        "service_location_id": int(location.id) if location else row.service_location_id,
        "customer_object_id": int(customer_object.id) if customer_object else row.customer_object_id,
        "project_external_key": _outsmart_project_key(payload) or row.project_external_key,
        "status": _outsmart_pick(payload, ("Status", "status", "StatusText", "status_text")) or row.status,
        "employee_name": _outsmart_pick(payload, ("EmployeeName", "employee_name", "Employee", "employee", "MechanicName", "mechanic_name")) or row.employee_name,
        "short_description": derived_short_description or row.short_description,
        "work_description": _outsmart_pick(payload, ("WorkDescription", "work_description", "Description", "description")) or row.work_description,
        "internal_work_description": _outsmart_pick(payload, ("InternalWorkDescription", "internal_work_description", "InternalDescription")) or row.internal_work_description,
        "pdf_url": _outsmart_pick_url(payload, ("PdfUrl", "pdf_url")) or row.pdf_url,
        "word_url": _outsmart_pick_url(payload, ("WordUrl", "word_url")) or row.word_url,
        "deep_link_url": _outsmart_resolve_deep_link(
            _outsmart_settings(db, include_secret=False),
            entity_type="workorder",
            payload=payload,
            row_id=row_id or None,
            external_key=workorder_no,
            current_url=row.deep_link_url,
        ),
    }
    changed = created
    for key, value in values.items():
        if getattr(row, key) != value:
            setattr(row, key, value)
            changed = True
    start_value, end_value = _outsmart_workorder_schedule_from_payload(payload)
    if start_value is not None and row.scheduled_start != start_value:
        row.scheduled_start = start_value
        changed = True
    if end_value is not None and row.scheduled_end != end_value:
        row.scheduled_end = end_value
        changed = True
    for field_name, payload_key in (
        ("forms_json", payload.get("Forms") or payload.get("forms") or []),
        ("photos_json", payload.get("Photos") or payload.get("photos") or []),
        ("materials_json", payload.get("Materials") or payload.get("materials") or []),
        ("workperiods_json", payload.get("WorkPeriods") or payload.get("workperiods") or payload.get("Workperiods") or []),
        ("workobjects_json", payload.get("WorkObjects") or payload.get("workobjects") or []),
        ("employees_json", payload.get("Employees") or payload.get("employees") or []),
    ):
        json_value = json.dumps(payload_key, ensure_ascii=False) if payload_key else None
        if getattr(row, field_name) != json_value:
            setattr(row, field_name, json_value)
            changed = True
    raw_json = json.dumps(payload, ensure_ascii=False) if payload else None
    if row.raw_json != raw_json:
        row.raw_json = raw_json
        changed = True
    row.last_synced_at = _utcnow_naive()
    row.updated_at = _utcnow_naive()
    db.add(row)
    db.flush()
    _upsert_external_link(
        db,
        system_name="outsmart",
        object_type="outsmart_workorder",
        object_id=int(row.id),
        external_key=row.workorder_no,
        external_row_id=row.external_row_id,
        deep_link_url=row.deep_link_url,
    )
    if case_row:
        _upsert_external_link(
            db,
            system_name="outsmart",
            object_type="crm_case_workorder",
            object_id=int(case_row.id),
            external_key=row.workorder_no,
            external_row_id=row.external_row_id,
            deep_link_url=row.deep_link_url,
        )
        _crm_case_sync_from_outsmart_workorder(
            db,
            crm_case=case_row,
            workorder_row=row,
            customer=customer,
            location=location,
            customer_object=customer_object,
        )
    event_changed = created or old_status != str(row.status or "") or old_start != (row.scheduled_start.isoformat() if row.scheduled_start else "") or old_end != (row.scheduled_end.isoformat() if row.scheduled_end else "")
    if event_changed:
        status_label = _outsmart_status_label(row.status)
        schedule_text = ""
        if row.scheduled_start or row.scheduled_end:
            schedule_text = _format_datetime_local(row.scheduled_start) if row.scheduled_start else "-"
            if row.scheduled_end:
                schedule_text = f"{schedule_text} bis {_format_datetime_local(row.scheduled_end)}"
        body_parts = [status_label]
        if schedule_text:
            body_parts.append(schedule_text)
        if row.employee_name:
            body_parts.append(row.employee_name)
        if row.short_description:
            body_parts.append(row.short_description)
        _crm_add_timeline_event(
            db,
            case_id=int(case_row.id) if case_row else None,
            master_customer_id=int(customer.id) if customer else None,
            service_location_id=int(location.id) if location else None,
            customer_object_id=int(customer_object.id) if customer_object else None,
            outsmart_workorder_id=int(row.id),
            source_system="outsmart",
            event_type="workorder_update" if not created else "workorder_import",
            title=f"OutSmart: {row.workorder_no}",
            body=" | ".join([part for part in body_parts if _crm_clean_text(part)]),
            event_ts=row.scheduled_start or _utcnow_naive(),
            external_ref=row.external_row_id or row.workorder_no,
            meta={"status": row.status, "deep_link_url": row.deep_link_url},
        )
    return row, ("created" if created else "updated" if changed else "skipped"), event_changed


def _outsmart_backfill_existing_workorders(db: Session, *, customer_id: int | None = None, limit: int = 0) -> dict[str, int]:
    query = db.query(OutsmartWorkorder).order_by(OutsmartWorkorder.id.asc())
    if int(customer_id or 0) > 0:
        workorder_keys = {
            str(item["row"].workorder_no or "").strip()
            for item in _customer_outsmart_stage_workorder_rows(db, int(customer_id), limit=5000)
            if str(item["row"].workorder_no or "").strip()
        }
        if workorder_keys:
            query = query.filter(
                or_(
                    OutsmartWorkorder.master_customer_id == int(customer_id),
                    OutsmartWorkorder.workorder_no.in_(list(workorder_keys)),
                )
            )
        else:
            query = query.filter(OutsmartWorkorder.master_customer_id == int(customer_id))
    rows = query.limit(int(limit)) if int(limit or 0) > 0 else query
    summary = {"matched_customer": 0, "matched_case": 0, "contact_updates": 0, "updated_rows": 0}
    for row in rows.all():
        payload = _json_dict(row.raw_json)
        if not payload:
            continue
        changed = False
        customer = _crm_customer_from_outsmart_identity(db, payload)
        if customer and int(row.master_customer_id or 0) != int(customer.id):
            row.master_customer_id = int(customer.id)
            summary["matched_customer"] += 1
            changed = True
        if customer and _outsmart_apply_customer_contact_fallback(db, customer, payload):
            summary["contact_updates"] += 1
        if int(row.case_id or 0) <= 0:
            case_row = _outsmart_match_case_for_workorder(db, payload)
            if case_row:
                row.case_id = int(case_row.id)
                summary["matched_case"] += 1
                changed = True
        if int(row.customer_object_id or 0) <= 0:
            customer_object = _outsmart_match_customer_object(db, payload)
            if customer_object:
                row.customer_object_id = int(customer_object.id)
                changed = True
        if int(row.service_location_id or 0) <= 0:
            if int(row.customer_object_id or 0) > 0:
                customer_object = db.get(CustomerObject, int(row.customer_object_id))
                if customer_object and int(customer_object.service_location_id or 0) > 0:
                    row.service_location_id = int(customer_object.service_location_id)
                    changed = True
            if int(row.service_location_id or 0) <= 0 and int(row.master_customer_id or 0) > 0:
                location = _crm_default_location_for_customer(db, int(row.master_customer_id))
                if location:
                    row.service_location_id = int(location.id)
                    changed = True
        if changed:
            row.updated_at = _utcnow_naive()
            db.add(row)
            summary["updated_rows"] += 1
    return summary


def _outsmart_import_relations_once(db: Session) -> dict[str, object]:
    settings = _outsmart_settings(db, include_secret=True)
    job = _start_sync_job(db, system_name="outsmart", direction="pull", entity_type="relation", log_text="OutSmart Relations importieren")
    summary = {"created": 0, "updated": 0, "skipped": 0, "errors": 0, "messages": []}
    try:
        rows = _outsmart_extract_rows(outsmart_fetch_relations(settings))
        for payload in rows:
            try:
                _, state = _outsmart_upsert_relation_customer(db, payload)
                summary[state] = int(summary.get(state, 0)) + 1
            except Exception as exc:
                summary["errors"] = int(summary.get("errors", 0)) + 1
                summary["messages"].append(str(exc))
        _finish_sync_job(db, job, status="done", log_text=json.dumps(summary, ensure_ascii=False))
        _outsmart_set_last_sync_at(db)
        return summary
    except Exception as exc:
        _finish_sync_job(db, job, status="failed", log_text=str(exc))
        raise


