OFFER_STATUS_CHOICES = ("draft", "prepared", "pushed", "sent", "accepted", "rejected", "expired")
INVOICE_DRAFT_STATUS_CHOICES = ("draft", "prepared", "pushed", "sent", "partially_paid", "paid", "cancelled")
INCOMING_VOUCHER_STATUS_CHOICES = ("draft", "prepared", "pushed", "booked", "paid", "disputed")
DUNNING_STATUS_CHOICES = ("open", "waiting", "escalated", "paid", "closed")
SEVDESK_PAYMENT_TYPE_CHOICES = ("FULL_PAYMENT", "N", "CB", "O", "OF")


def _offer_status_label(value: str | None) -> str:
    mapping = {
        "draft": "Entwurf",
        "prepared": "Vorbereitet",
        "pushed": "In sevDesk angelegt",
        "sent": "Versendet",
        "accepted": "Angenommen",
        "rejected": "Abgelehnt",
        "expired": "Abgelaufen",
    }
    return mapping.get(_crm_normalize_key(value), str(value or "").strip() or "-")


def _invoice_draft_status_label(value: str | None) -> str:
    mapping = {
        "draft": "Entwurf",
        "prepared": "Vorbereitet",
        "pushed": "In sevDesk angelegt",
        "sent": "Versendet",
        "partially_paid": "Teilbezahlt",
        "paid": "Bezahlt",
        "cancelled": "Storniert",
    }
    return mapping.get(_crm_normalize_key(value), str(value or "").strip() or "-")


def _invoice_draft_customer_visible(row: InvoiceDraft | None) -> bool:
    if row is None:
        return False
    status = _crm_normalize_key(getattr(row, "status", ""))
    if status in {"draft", "prepared"}:
        return False
    if status in {"pushed", "sent", "partially_paid", "paid", "cancelled"}:
        return True
    return bool(str(getattr(row, "sevdesk_invoice_number", "") or "").strip() or str(getattr(row, "pdf_url_local", "") or "").strip())


def _incoming_voucher_status_label(value: str | None) -> str:
    mapping = {
        "draft": "Entwurf",
        "prepared": "Vorbereitet",
        "pushed": "In sevDesk angelegt",
        "booked": "Verbucht",
        "paid": "Bezahlt",
        "disputed": "Strittig",
    }
    return mapping.get(_crm_normalize_key(value), str(value or "").strip() or "-")


def _dunning_status_label(value: str | None) -> str:
    mapping = {
        "open": "Offen",
        "waiting": "Warten",
        "escalated": "Eskaliert",
        "paid": "Bezahlt",
        "closed": "Geschlossen",
    }
    return mapping.get(_crm_normalize_key(value), str(value or "").strip() or "-")


def _sevdesk_payment_type_label(value: str | None) -> str:
    mapping = {
        "FULL_PAYMENT": "Vollzahlung",
        "N": "Normal",
        "CB": "Chargeback",
        "O": "Offen",
        "OF": "Offene Forderung",
    }
    return mapping.get(str(value or "").strip().upper(), str(value or "").strip() or "-")


def _parse_float_input(raw: str | None, field_label: str, default: float = 0.0, minimum: float = 0.0) -> float:
    text = str(raw or "").strip().replace(",", ".")
    if not text:
        value = float(default)
    else:
        try:
            value = float(text)
        except Exception:
            raise ValueError(f"{field_label} ist ungültig.")
    return value if value >= minimum else minimum


def _parse_tax_rate_input(raw: str | None, default: float = VAT_RATE_STANDARD) -> float:
    text = str(raw or "").strip().replace(",", ".")
    if not text:
        return float(default)
    try:
        value = float(text)
    except Exception:
        return float(default)
    if value > 1:
        value = value / 100.0
    if value < 0:
        value = 0.0
    return value


def _format_qty_value(value: float | int | None) -> str:
    if value is None:
        return ""
    try:
        num = float(value)
    except Exception:
        return str(value)
    if abs(num - int(num)) < 0.00001:
        return str(int(num))
    return f"{num:.2f}".rstrip("0").rstrip(".")


def _draft_line_total_cents(qty: float | int | None, unit_price_net: int | None) -> int:
    if unit_price_net is None:
        return 0
    try:
        return int(round(float(qty or 0) * float(unit_price_net)))
    except Exception:
        return 0


def _offer_total_cents(lines: list[OfferDraftLine]) -> int:
    return sum(_draft_line_total_cents(getattr(line, "qty", 0), getattr(line, "unit_price_net", None)) for line in lines)


def _invoice_draft_total_cents(lines: list[InvoiceDraftLine]) -> int:
    return sum(_draft_line_total_cents(getattr(line, "qty", 0), getattr(line, "unit_price_net", None)) for line in lines)


def _draft_line_detail_rows(lines: list[object]) -> list[dict[str, object]]:
    out: list[dict[str, object]] = []
    for line in lines:
        qty = float(getattr(line, "qty", 0) or 0)
        unit = str(getattr(line, "unit", "Stk") or "Stk")
        unit_price_net = getattr(line, "unit_price_net", None)
        try:
            vat_rate = float(getattr(line, "tax_rate", VAT_RATE_STANDARD) or VAT_RATE_STANDARD)
        except Exception:
            vat_rate = float(VAT_RATE_STANDARD)
        line_net_cents = _draft_line_total_cents(qty, unit_price_net)
        unit_price_gross_cents = _gross_cents_from_net(unit_price_net, vat_rate) if unit_price_net is not None else None
        line_gross_cents = _gross_cents_from_net(line_net_cents, vat_rate) if line_net_cents else 0
        out.append(
            {
                "text": str(getattr(line, "text", "") or "").strip() or "-",
                "qty_label": _format_qty_value(qty),
                "unit": unit,
                "tax_rate_label": f"{_format_qty_value(vat_rate * 100.0)}%",
                "unit_price_net_cents": int(unit_price_net or 0) if unit_price_net is not None else None,
                "unit_price_gross_cents": unit_price_gross_cents,
                "line_net_cents": line_net_cents,
                "line_gross_cents": int(line_gross_cents or 0),
            }
        )
    return out


def _draft_total_gross_cents(lines: list[object]) -> int:
    total = 0
    for line in lines:
        try:
            vat_rate = float(getattr(line, "tax_rate", VAT_RATE_STANDARD) or VAT_RATE_STANDARD)
        except Exception:
            vat_rate = float(VAT_RATE_STANDARD)
        line_net_cents = _draft_line_total_cents(getattr(line, "qty", 0), getattr(line, "unit_price_net", None))
        total += int(_gross_cents_from_net(line_net_cents, vat_rate) or 0)
    return total


def _crm_note_preview(value: str | None, limit: int = 180) -> str:
    text = _crm_clean_text(_crm_strip_markup_text(value))
    if len(text) <= int(limit):
        return text
    return text[: max(0, int(limit) - 3)].rstrip() + "..."


def _invoice_draft_line_rows(rows: list[InvoiceDraftLine], price_mode: str = "net") -> list[dict[str, str]]:
    effective_mode = _draft_price_mode(price_mode)
    out: list[dict[str, str]] = []
    for row in rows:
        try:
            tax_rate = float(row.tax_rate or VAT_RATE_STANDARD)
        except Exception:
            tax_rate = float(VAT_RATE_STANDARD)
        display_price_cents = row.unit_price_net
        if effective_mode == "gross" and row.unit_price_net is not None:
            display_price_cents = _gross_cents_from_net(row.unit_price_net, tax_rate)
        out.append(
            {
                "product_id": str(row.product_id or ""),
                "text": str(row.text or ""),
                "qty": _format_qty_value(row.qty),
                "unit": str(row.unit or "Stk"),
                "unit_price": _format_eur(display_price_cents).replace(" €", "") if display_price_cents is not None else "",
                "tax_rate": _format_qty_value((tax_rate or VAT_RATE_STANDARD) * 100.0),
            }
        )
    while len(out) < 1:
        out.append({"product_id": "", "text": "", "qty": "", "unit": "Stk", "unit_price": "", "tax_rate": "19"})
    return out


