def _offer_line_rows_from_form_data(form_data: dict[str, str | list[str]]) -> list[dict[str, str]]:
    def _values(key: str) -> list[str]:
        raw = form_data.get(key)
        if isinstance(raw, list):
            return [str(item or "") for item in raw]
        if raw is None:
            return []
        return [str(raw or "")]

    product_ids = _values("line_product_id")
    texts = _values("line_text")
    qtys = _values("line_qty")
    units = _values("line_unit")
    prices = _values("line_unit_price")
    if not prices:
        prices = _values("line_unit_price_net")
    taxes = _values("line_tax_rate")
    max_len = max(len(product_ids), len(texts), len(qtys), len(units), len(prices), len(taxes), 1)
    out: list[dict[str, str]] = []
    for idx in range(max_len):
        out.append(
            {
                "product_id": product_ids[idx] if idx < len(product_ids) else "",
                "text": texts[idx] if idx < len(texts) else "",
                "qty": qtys[idx] if idx < len(qtys) else "",
                "unit": (units[idx] if idx < len(units) else "") or "Stk",
                "unit_price": prices[idx] if idx < len(prices) else "",
                "tax_rate": (taxes[idx] if idx < len(taxes) else "") or "19",
            }
        )
    return out


