def _draft_document_address_fields(row: object, *, service_location: ServiceLocation | None = None) -> dict[str, object]:
    street = _crm_clean_text(
        f"{str(getattr(row, 'billing_street', '') or '').strip()} {str(getattr(row, 'billing_house_no', '') or '').strip()}"
    )
    payload: dict[str, object] = {}
    if str(getattr(row, "billing_name", "") or "").strip():
        payload["addressName"] = str(getattr(row, "billing_name", "") or "").strip()
    if street:
        payload["addressStreet"] = street
    if str(getattr(row, "billing_zip_code", "") or "").strip():
        payload["addressZip"] = str(getattr(row, "billing_zip_code", "") or "").strip()
    if str(getattr(row, "billing_city", "") or "").strip():
        payload["addressCity"] = str(getattr(row, "billing_city", "") or "").strip()
    if str(getattr(row, "billing_country_code", "") or "").strip():
        payload["addressCountry"] = str(getattr(row, "billing_country_code", "") or "").strip()
    if service_location and str(service_location.location_label or "").strip():
        payload["addressName2"] = str(service_location.location_label or "").strip()
    return payload


def _offer_reference_label(row: OfferDraft) -> str:
    return str(row.sevdesk_order_number or f"ANG-{int(row.id):04d}")


def _invoice_reference_label(row: InvoiceDraft) -> str:
    return str(row.sevdesk_invoice_number or f"RE-ENTW-{int(row.id):04d}")


def _sevdesk_voucher_rows(db: Session, lines: list[IncomingVoucherDraftLine]) -> list[dict[str, object]]:
    out: list[dict[str, object]] = []
    for line in lines:
        payload: dict[str, object] = {
            "taxRate": round(float(line.tax_rate or VAT_RATE_STANDARD) * 100.0, 2),
            "sumNet": round(float(line.sum_net or 0) / 100.0, 2) if line.sum_net is not None else None,
            "sumGross": round(float(line.sum_gross or 0) / 100.0, 2) if line.sum_gross is not None else None,
            "comment": line.comment,
            "costCenterId": line.cost_center_id,
            "net": bool(line.sum_net is not None and line.sum_gross is None),
        }
        account_row = _find_accounting_account_by_number(db, line.account_datev_id)
        account_datev_id = str(getattr(account_row, "sevdesk_account_datev_id", "") or "").strip()
        if account_datev_id:
            payload["accountDatev"] = {"id": account_datev_id, "objectName": "AccountDatev"}
        elif str(line.account_datev_id or "").strip():
            payload["accountDatevId"] = str(line.account_datev_id or "").strip()
        if str(line.tax_rule_id or "").strip():
            payload["taxRuleId"] = str(line.tax_rule_id or "").strip()
            payload["taxRule"] = {"id": str(line.tax_rule_id or "").strip(), "objectName": "TaxRule"}
        if str(line.cost_center_id or "").strip():
            payload["costCentre"] = {"id": str(line.cost_center_id or "").strip(), "objectName": "CostCentre"}
        out.append(payload)
    return out


def _invoice_draft_total_due_cents(db: Session, row: InvoiceDraft) -> int:
    lines = _invoice_draft_db_rows(db, int(row.id))
    return _invoice_draft_total_cents(lines)


def _invoice_draft_open_amount_cents(db: Session, row: InvoiceDraft) -> int:
    total = _invoice_draft_total_due_cents(db, row)
    if _crm_normalize_key(row.status) == "paid":
        return 0
    if _crm_normalize_key(row.status) == "partially_paid":
        return max(0, total // 2)
    return total


def _invoice_draft_open_amount_display_cents(row: InvoiceDraft, total_gross_cents: int) -> int:
    status_key = _crm_normalize_key(getattr(row, "status", ""))
    if status_key in {"paid", "cancelled"}:
        return 0
    if status_key == "partially_paid":
        return max(0, int(total_gross_cents or 0) // 2)
    return max(0, int(total_gross_cents or 0))


def _sevdesk_transaction_text(payload: dict[str, object] | None) -> str:
    if not isinstance(payload, dict):
        return ""
    parts = []
    for key in ("payeeName", "paymtPurpose", "text", "reference", "description", "name"):
        value = str(payload.get(key) or "").strip()
        if value:
            parts.append(value)
    return " | ".join(parts)


def _sevdesk_transaction_check_account_id(payload: dict[str, object] | None) -> str:
    if not isinstance(payload, dict):
        return ""
    check_account = payload.get("checkAccount")
    if isinstance(check_account, dict):
        return str(sevdesk_first_value(check_account, ("id", "ID")) or "").strip()
    return str(sevdesk_first_value(payload, ("checkAccountId",)) or "").strip()


def _sevdesk_transaction_check_account_label(payload: dict[str, object] | None) -> str:
    if not isinstance(payload, dict):
        return ""
    check_account = payload.get("checkAccount")
    if isinstance(check_account, dict):
        return str(sevdesk_first_value(check_account, ("name", "displayName", "id")) or "").strip()
    return ""


def _sevdesk_transaction_date(payload: dict[str, object] | None) -> dt.datetime | None:
    return _crm_coerce_datetime(sevdesk_first_value(payload or {}, ("date", "bookingDate", "entryDate", "create")))


def _voucher_reference_tokens(
    row: IncomingVoucherDraft | None,
    *,
    supplier_name: str = "",
    purchase_invoice_no: str = "",
    description: str = "",
) -> list[str]:
    parts = [
        str(getattr(row, "description", "") or ""),
        str(getattr(row, "linked_document_id", "") or ""),
        str(description or ""),
        str(purchase_invoice_no or ""),
    ]
    if supplier_name:
        parts.append(supplier_name)
    tokens: list[str] = []
    for part in parts:
        for token in re.findall(r"[A-Z0-9][A-Z0-9./_-]{2,}", str(part or "").upper()):
            token = token.strip("._-/")
            if len(token) >= 4 and any(ch.isdigit() for ch in token):
                tokens.append(token)
    return list(dict.fromkeys(tokens))


def _voucher_match_context(
    row: IncomingVoucherDraft | None,
    *,
    supplier_name: str = "",
    purchase_invoice_no: str = "",
    description: str = "",
    gross_total: int | None = None,
    voucher_date: dt.datetime | None = None,
    due_date: dt.datetime | None = None,
) -> dict[str, object]:
    resolved_gross_total = int(gross_total if gross_total is not None else (getattr(row, "gross_total", 0) or 0))
    resolved_description = str(description or getattr(row, "description", "") or "").strip()
    return {
        "row": row,
        "supplier_name": str(supplier_name or "").strip(),
        "purchase_invoice_no": str(purchase_invoice_no or "").strip(),
        "description": resolved_description,
        "gross_total": resolved_gross_total,
        "voucher_date": voucher_date or getattr(row, "voucher_date", None),
        "due_date": due_date or getattr(row, "due_date", None),
        "reference_tokens": _voucher_reference_tokens(
            row,
            supplier_name=supplier_name,
            purchase_invoice_no=purchase_invoice_no,
            description=resolved_description,
        ),
    }


def _voucher_transaction_candidate_rows(
    db: Session,
    settings: dict[str, str | bool],
    *,
    context: dict[str, object],
    limit: int = 8,
) -> dict[str, object]:
    supplier_name = str(context.get("supplier_name") or "").strip()
    gross_total = abs(int(context.get("gross_total") or 0))
    reference_tokens = [str(item or "").strip() for item in list(context.get("reference_tokens") or []) if str(item or "").strip()]
    if not bool(settings.get("enabled")) or not str(settings.get("api_token") or "").strip() or gross_total <= 0:
        return {"rows": [], "best": None, "auto_candidate": None, "error": ""}
    search = supplier_name or (reference_tokens[0] if reference_tokens else "")
    now = _utcnow_naive()
    start_date = (now - dt.timedelta(days=120)).date().isoformat() + "T00:00:00"
    error = ""
    try:
        tx_rows = sevdesk_get_transactions(
            settings,
            start_date=start_date,
            search=search,
            amount=str(round(float(gross_total) / 100.0, 2)),
            only_debit=True,
            limit=120,
        )
    except Exception as exc:
        tx_rows = []
        error = str(exc)
    scored_rows: list[dict[str, object]] = []
    supplier_norm = _crm_normalize_key(supplier_name)
    description_norm = _crm_normalize_key(str(context.get("description") or ""))
    for tx in tx_rows:
        amount_cents = abs(_sevdesk_transaction_amount_cents(tx))
        if amount_cents <= 0:
            continue
        tx_text = _sevdesk_transaction_text(tx)
        tx_text_norm = _crm_normalize_key(tx_text)
        reasons: list[str] = []
        score = 0
        amount_delta = abs(amount_cents - gross_total)
        if gross_total and amount_delta == 0:
            score += 1
            reasons.append("Betrag identisch")
        elif gross_total and amount_delta <= 100:
            reasons.append("Betrag fast identisch")
        supplier_match = False
        if supplier_norm and supplier_norm in tx_text_norm:
            supplier_match = True
        elif supplier_name:
            supplier_tokens = [token for token in re.split(r"[^a-z0-9]+", supplier_norm) if len(token) >= 4]
            if supplier_tokens and sum(1 for token in supplier_tokens if token in tx_text_norm) >= 2:
                supplier_match = True
        if supplier_match:
            score += 1
            reasons.append("Lieferant erkannt")
        reference_hits = [token for token in reference_tokens if token and token.lower() in tx_text.lower()]
        if reference_hits:
            score += 1
            reasons.append("Rechnungsreferenz erkannt")
        tx_date = _sevdesk_transaction_date(tx)
        target_dates = [value for value in (context.get("voucher_date"), context.get("due_date")) if isinstance(value, dt.datetime)]
        if tx_date and target_dates:
            if min(abs((tx_date.date() - value.date()).days) for value in target_dates) <= 21:
                score += 1
                reasons.append("Datum plausibel")
        elif description_norm and description_norm and description_norm[:18] in tx_text_norm:
            score += 1
            reasons.append("Beschreibung erkannt")
        if score <= 0 and amount_delta > 100:
            continue
        scored_rows.append(
            {
                "row": tx,
                "tx_id": sevdesk_first_value(tx, ("id", "ID")),
                "amount_cents": amount_cents,
                "score": score,
                "reasons": reasons,
                "amount_delta": amount_delta,
                "text": tx_text,
                "check_account_id": _sevdesk_transaction_check_account_id(tx),
                "check_account_label": _sevdesk_transaction_check_account_label(tx),
                "date": tx_date,
            }
        )
    scored_rows.sort(
        key=lambda item: (
            -int(item.get("score") or 0),
            int(item.get("amount_delta") or 0),
            abs((item.get("date").date() - now.date()).days) if isinstance(item.get("date"), dt.datetime) else 9999,
            str(item.get("tx_id") or ""),
        )
    )
    best = scored_rows[0] if scored_rows else None
    auto_candidate = None
    if best and int(best.get("score") or 0) >= 2:
        second_score = int(scored_rows[1].get("score") or 0) if len(scored_rows) > 1 else -1
        second_delta = int(scored_rows[1].get("amount_delta") or 999999) if len(scored_rows) > 1 else 999999
        if second_score < int(best.get("score") or 0) or second_delta > int(best.get("amount_delta") or 0):
            auto_candidate = best
    return {
        "rows": scored_rows[: max(1, int(limit))],
        "best": best,
        "auto_candidate": auto_candidate,
        "error": error,
    }


def _transaction_avis_candidate(
    db: Session,
    tx: dict[str, object] | None,
    *,
    limit_vouchers: int = 24,
) -> dict[str, object] | None:
    if not isinstance(tx, dict):
        return None
    amount_cents = abs(_sevdesk_transaction_amount_cents(tx))
    if amount_cents <= 0:
        return None
    tx_text = _sevdesk_transaction_text(tx)
    tx_text_norm = _crm_normalize_key(tx_text)
    open_rows = (
        db.query(IncomingVoucherDraft)
        .filter(IncomingVoucherDraft.status.in_(("prepared", "pushed", "booked")))
        .order_by(IncomingVoucherDraft.due_date.asc(), IncomingVoucherDraft.id.desc())
        .limit(max(6, int(limit_vouchers)))
        .all()
    )
    supplier_map = {int(row.id): row for row in _active_suppliers(db)}
    invoice_map = {
        int(row.id): row
        for row in db.query(PurchaseInvoice)
        .filter(PurchaseInvoice.id.in_([int(item.purchase_invoice_id) for item in open_rows if int(item.purchase_invoice_id or 0) > 0]))
        .all()
    } if open_rows else {}
    candidate_rows: list[dict[str, object]] = []
    for row in open_rows:
        gross_total = abs(int(row.gross_total or 0))
        if gross_total <= 0 or gross_total > amount_cents:
            continue
        supplier = supplier_map.get(int(row.supplier_id or 0))
        purchase_invoice = invoice_map.get(int(row.purchase_invoice_id or 0))
        context = _voucher_match_context(
            row,
            supplier_name=str(getattr(supplier, "name", "") or ""),
            purchase_invoice_no=str(getattr(purchase_invoice, "invoice_no", "") or ""),
        )
        reasons = []
        supplier_norm = _crm_normalize_key(str(getattr(supplier, "name", "") or ""))
        if supplier_norm and supplier_norm in tx_text_norm:
            reasons.append("Lieferant erkannt")
        refs = [token for token in list(context.get("reference_tokens") or []) if str(token or "").lower() in tx_text.lower()]
        if refs:
            reasons.append("Rechnungsreferenz erkannt")
        if reasons:
            candidate_rows.append({"row": row, "supplier": supplier, "invoice": purchase_invoice, "gross_total": gross_total, "reasons": reasons})
    if len(candidate_rows) < 2:
        return None
    best_group: dict[str, object] | None = None
    max_group_size = min(5, len(candidate_rows))
    for group_size in range(2, max_group_size + 1):
        for group in combinations(candidate_rows, group_size):
            total = sum(int(item.get("gross_total") or 0) for item in group)
            if total != amount_cents:
                continue
            reason_set = []
            for item in group:
                reason_set.extend([str(reason or "").strip() for reason in list(item.get("reasons") or []) if str(reason or "").strip()])
            distinct_suppliers = {int(item["row"].supplier_id or 0) for item in group}
            score = len(set(reason_set)) + (1 if len(distinct_suppliers) == 1 else 0)
            payload = {"rows": list(group), "total_cents": total, "score": score, "reason_text": ", ".join(sorted(set(reason_set)))}
            if best_group is None or int(payload["score"]) > int(best_group.get("score") or 0):
                best_group = payload
    return best_group


def _sevdesk_payment_payload(*, check_account_id: str, booking_date: dt.datetime | None, amount_cents: int, booking_type: str, transaction_id: str = "") -> dict[str, object]:
    payload: dict[str, object] = {
        "checkAccount": {"id": str(check_account_id), "objectName": "CheckAccount"},
        "amount": round(float(amount_cents or 0) / 100.0, 2),
        "date": (booking_date or _utcnow_naive()).date().isoformat(),
        "type": str(booking_type or "FULL_PAYMENT").strip().upper() or "FULL_PAYMENT",
    }
    if str(transaction_id or "").strip():
        payload["checkAccountTransaction"] = {"id": str(transaction_id).strip(), "objectName": "CheckAccountTransaction"}
    return payload


def _sevdesk_transaction_amount_cents(payload: dict[str, object] | None) -> int:
    text = str(sevdesk_first_value(payload or {}, ("amount", "sum", "value", "Value", "Betrag")) or "").strip().replace(".", "").replace(",", ".")
    if not text:
        return 0
    try:
        return int(round(float(text) * 100))
    except Exception:
        return 0


def _reconciliation_candidate_rows(db: Session, amount_cents: int) -> dict[str, list[dict[str, object]]]:
    invoice_rows = (
        db.query(InvoiceDraft)
        .filter(InvoiceDraft.status.in_(("sent", "pushed", "partially_paid")))
        .order_by(InvoiceDraft.due_date.asc(), InvoiceDraft.id.desc())
        .limit(80)
        .all()
    )
    voucher_rows = (
        db.query(IncomingVoucherDraft)
        .filter(IncomingVoucherDraft.status.in_(("prepared", "pushed", "booked")))
        .order_by(IncomingVoucherDraft.due_date.asc(), IncomingVoucherDraft.id.desc())
        .limit(80)
        .all()
    )
    outgoing = []
    incoming = []
    for row in invoice_rows:
        open_amount = _invoice_draft_open_amount_cents(db, row)
        if amount_cents and open_amount != abs(int(amount_cents)):
            continue
        outgoing.append({"row": row, "open_amount": open_amount})
    for row in voucher_rows:
        gross = int(row.gross_total or 0)
        if amount_cents and gross != abs(int(amount_cents)):
            continue
        incoming.append({"row": row, "open_amount": gross})
    return {"invoice_drafts": outgoing[:12], "voucher_drafts": incoming[:12]}


def _invoice_draft_reference_label(row: InvoiceDraft) -> str:
    return str(row.sevdesk_invoice_number or f"RE-ENTWURF-{int(row.id):04d}")


def _ensure_dunning_case_for_invoice(db: Session, row: InvoiceDraft) -> DunningCase | None:
    existing = db.query(DunningCase).filter(DunningCase.invoice_draft_id == int(row.id)).one_or_none()
    status_key = _crm_normalize_key(row.status)
    if status_key in ("paid", "cancelled"):
        if existing:
            existing.status = "paid" if status_key == "paid" else "closed"
            existing.amount_due = 0
            existing.updated_at = _utcnow_naive()
            db.add(existing)
        return existing
    if int(row.master_customer_id or 0) <= 0:
        return existing
    due_date = row.due_date or row.invoice_date
    amount_due = _invoice_draft_open_amount_cents(db, row)
    if existing is None:
        existing = DunningCase(
            invoice_draft_id=int(row.id),
            sevdesk_invoice_id=str(row.sevdesk_invoice_id or "").strip() or None,
            customer_id=int(row.master_customer_id),
            current_level=1,
            due_date=due_date,
            amount_due=amount_due,
            status="open",
            next_action_at=due_date,
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
    else:
        existing.sevdesk_invoice_id = str(row.sevdesk_invoice_id or "").strip() or None
        existing.customer_id = int(row.master_customer_id)
        existing.due_date = due_date
        existing.amount_due = amount_due
        if existing.status not in ("paid", "closed"):
            existing.status = "open" if amount_due > 0 else "paid"
        existing.updated_at = _utcnow_naive()
    db.add(existing)
    db.flush()
    return existing


def _dunning_rows(db: Session) -> list[dict[str, object]]:
    draft_rows = (
        db.query(InvoiceDraft)
        .filter(InvoiceDraft.status.in_(("sent", "pushed", "partially_paid", "paid")))
        .order_by(InvoiceDraft.due_date.asc(), InvoiceDraft.id.desc())
        .all()
    )
    for row in draft_rows:
        _ensure_dunning_case_for_invoice(db, row)
    db.flush()
    cases = (
        db.query(DunningCase)
        .order_by(DunningCase.next_action_at.asc(), DunningCase.id.desc())
        .all()
    )
    customer_map = _crm_customer_labels_map(db, [int(row.customer_id) for row in cases if int(row.customer_id or 0) > 0])
    invoice_map = {int(row.id): row for row in draft_rows}
    return [
        {
            "row": row,
            "customer_label": customer_map.get(int(row.customer_id), "-"),
            "invoice": invoice_map.get(int(row.invoice_draft_id or 0)),
        }
        for row in cases
    ]


def _render_offer_form(
    request: Request,
    *,
    user,
    db: Session,
    page_title: str,
    form_action: str,
    row: OfferDraft | None,
    form_data: dict[str, str | list[str]],
    form_errors: dict[str, str],
    line_rows: list[dict[str, str]],
    selected_case_id: int,
    selected_customer_id: int,
    selected_service_location_id: int,
):
    case_context = _crm_case_context(db, selected_case_id) if selected_case_id > 0 else {}
    effective_customer_id = int(
        selected_customer_id
        or getattr(row, "master_customer_id", 0)
        or (int(case_context.get("invoice_customer").id) if case_context.get("invoice_customer") else 0)
        or (int(case_context.get("ordering_customer").id) if case_context.get("ordering_customer") else 0)
        or 0
    )
    effective_price_mode = _draft_price_mode(_form_scalar(form_data, "price_mode", getattr(row, "price_mode", "net") or "net"))
    effective_service_location_id = int(
        selected_service_location_id
        or getattr(row, "service_location_id", 0)
        or (int(case_context.get("service_location").id) if case_context.get("service_location") else 0)
        or 0
    )
    billing_fields = _draft_billing_form_data(
        db,
        customer_id=effective_customer_id,
        case_context=case_context,
        existing=row,
    )
    ai_offer_input = {
        "case_id": int(selected_case_id or 0) or None,
        "master_customer_id": effective_customer_id or None,
        "case_title": str(getattr(case_context.get("row"), "title", "") or ""),
        "case_no": str(getattr(case_context.get("row"), "case_no", "") or ""),
        "customer_name": str(getattr(getattr(case_context.get("ordering_customer"), "party", None), "display_name", "") or ""),
        "invoice_recipient_id": int(getattr(case_context.get("invoice_customer"), "id", 0) or 0) or None,
        "product_id": int(line_rows[0]["product_id"]) if line_rows and str(line_rows[0].get("product_id") or "").isdigit() else None,
        "line_hint": str(line_rows[0].get("text") or "") if line_rows else "",
    }
    ai_offer_result = ai_prepare_offer_draft(
        db,
        settings=_openai_settings(db, include_secret=True),
        input_payload=ai_offer_input,
        related_object_id=int(row.id) if row else None,
    ) if ai_offer_input["case_id"] or ai_offer_input["master_customer_id"] or ai_offer_input["line_hint"] else None
    return templates.TemplateResponse(
        "crm/offer_form.html",
        _ctx(
            request,
            user=user,
            row=row,
            page_title=page_title,
            form_action=form_action,
            form_data=form_data,
            form_errors=form_errors,
            first_error_field_id="",
            case_options=_mail_case_options(db),
            customer_options=_crm_customer_options(db, include_ids=[effective_customer_id], limit=400),
            location_options=_crm_location_options(
                db,
                include_ids=[effective_service_location_id],
                customer_ids=[effective_customer_id],
                limit=400 if effective_customer_id > 0 else 200,
            ),
            products=_active_products_for_einkauf(db, [int(item["product_id"]) for item in line_rows if str(item.get("product_id") or "").isdigit()]),
            line_rows=line_rows,
            price_mode=effective_price_mode,
            selected_case_id=int(selected_case_id or 0),
            selected_customer_id=effective_customer_id,
            selected_service_location_id=effective_service_location_id,
            case_context=case_context,
            billing_fields=billing_fields,
            closing_templates=_offer_closing_template_rows(db),
            selected_closing_template_id=_to_int(_form_scalar(form_data, "closing_template_id"), 0),
            ai_offer_result=ai_offer_result,
            ai_offer_review=ai_find_review_item(db, int(ai_offer_result["log"].id)) if ai_offer_result else None,
        ),
    )


