@app.post("/crm/angebote/neu")
async def crm_offer_new_post(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    form = await request.form()
    form_data = _extract_form_data(form)
    form_errors: dict[str, str] = {}
    selected_case_id = _to_int(form.get("case_id"), 0) if _internal_service_orders_enabled() else 0
    selected_customer_id = _to_int(form.get("master_customer_id"), 0)
    selected_service_location_id = _to_int(form.get("service_location_id"), 0)
    case_context = _crm_case_context(db, selected_case_id) if selected_case_id > 0 else {}
    if _internal_service_orders_enabled() and selected_case_id > 0 and not db.get(CrmCase, selected_case_id):
        form_errors["case_id"] = "Serviceauftrag wurde nicht gefunden."
    if selected_customer_id <= 0 and case_context:
        context_customer = case_context.get("invoice_customer") or case_context.get("ordering_customer")
        if context_customer:
            selected_customer_id = int(context_customer.id or 0)
    if selected_service_location_id <= 0 and case_context.get("service_location"):
        selected_service_location_id = int(case_context.get("service_location").id or 0)
    if selected_customer_id <= 0 or not db.get(MasterCustomer, selected_customer_id):
        form_errors["master_customer_id"] = "Kunde ist erforderlich."
    if selected_service_location_id > 0 and not db.get(ServiceLocation, selected_service_location_id):
        form_errors["service_location_id"] = "Leistungsort wurde nicht gefunden."
    price_mode = _draft_price_mode(form.get("price_mode"))
    intro_text = str(form.get("intro_text") or "").strip()
    closing_template_id = _to_int(form.get("closing_template_id"), 0)
    closing_text = str(form.get("closing_text") or "").strip()
    if not closing_text and closing_template_id > 0:
        template_row = db.get(MailTemplate, closing_template_id)
        if template_row and str(template_row.template_key or "").startswith(OFFER_CLOSING_TEMPLATE_PREFIX):
            closing_text = str(template_row.body_template or "").strip()
    line_rows, line_errors, extra_product_ids = _parse_offer_line_input(db, form)
    form_errors.update(line_errors)
    if not line_rows:
        form_errors["lines"] = "Mindestens eine Angebotsposition ist erforderlich."
    if form_errors:
        return _render_offer_form(
            request,
            user=user,
            db=db,
            page_title="Angebot anlegen",
            form_action="/crm/angebote/neu",
            row=None,
            form_data=form_data,
            form_errors=form_errors,
            line_rows=_offer_line_rows_from_form_data(form_data),
            selected_case_id=selected_case_id,
            selected_customer_id=selected_customer_id,
            selected_service_location_id=selected_service_location_id,
        )
    billing_payload = _draft_billing_payload_from_form(form)
    draft = OfferDraft(
        case_id=selected_case_id or None,
        master_customer_id=selected_customer_id or None,
        service_location_id=selected_service_location_id or None,
        ordering_party_assignment_id=int((case_context.get("ordering_role").id if case_context.get("ordering_role") else 0) or 0) or None,
        service_location_assignment_id=int((case_context.get("service_role").id if case_context.get("service_role") else 0) or 0) or None,
        invoice_recipient_assignment_id=int((case_context.get("invoice_role").id if case_context.get("invoice_role") else 0) or 0) or None,
        status="prepared",
        currency=str((_sevdesk_settings(db, include_secret=False).get("default_currency") or "EUR")),
        price_mode=price_mode,
        intro_text=intro_text or None,
        closing_text=closing_text or None,
        note=intro_text or None,
        **billing_payload,
        created_at=_utcnow_naive(),
        updated_at=_utcnow_naive(),
    )
    db.add(draft)
    db.flush()
    for entry in line_rows:
        db.add(OfferDraftLine(offer_draft_id=int(draft.id), **entry))
    if str(form.get("save_closing_template_name") or "").strip() and closing_text:
        _save_offer_closing_template(
            db,
            template_name=str(form.get("save_closing_template_name") or ""),
            closing_text=closing_text,
        )
    db.commit()
    _flash(request, "Angebot gespeichert.", "info")
    return RedirectResponse(f"/crm/angebote/{int(draft.id)}", status_code=302)


